fun Modifier.bounceClick(
    enabled: Boolean = true,
    onClick: () -> Unit
) = composed {
    var isPressed by remember { mutableStateOf(false) }
    val scale by animateFloatAsState(
        targetValue = if (isPressed) 0.95f else 1.0f,
        animationSpec = spring(
            dampingRatio = Spring.DampingRatioMediumBouncy,
            stiffness = Spring.StiffnessMedium
        ),
        label = "bounceScale"
    )

    this
        .graphicsLayer {
            scaleX = scale
            scaleY = scale
        }
        .pointerInput(enabled) {
            if (!enabled) return@pointerInput
            awaitPointerEventScope {
                while (true) {
                    val down = awaitFirstDown()
                    isPressed = true
                    val up = waitForUpOrCancellation()
                    isPressed = false
                    if (up != null) {
                        onClick()
                    }
                }
            }
        }
}

class BubbleAnimState(
    val startX: Float,
    val startY: Float,
    val targetX: Float,
    val targetY: Float,
    val radiusSecive: androidx.compose.ui.unit.Dp,
    val delay: Int
) {
    var currentX by mutableStateOf(0f)
    var currentY by mutableStateOf(0f)
    var alpha by mutableStateOf(0f)
    var currentRadius by mutableStateOf(radiusSecive)
}

@Composable
fun BubbleEffectContainer(
    isSelected: Boolean,
    modifier: Modifier = Modifier,
    content: @Composable () -> Unit
) {
    val density = androidx.compose.ui.platform.LocalDensity.current
    val bubbles = remember { mutableStateListOf<BubbleAnimState>() }
    
    LaunchedEffect(isSelected) {
        if (isSelected) {
            bubbles.clear()
            // Spawn 10 premium translucent soap bubbles
            val count = 10
            for (i in 0 until count) {
                // semi-random angles to create a splash effect upward and outward
                val angle = -Math.PI / 2 + (Math.random() * Math.PI * 0.8 - Math.PI * 0.4) // upward arc
                val distance = 40f + (Math.random() * 60f).toFloat()
                val targetX = (Math.cos(angle) * distance).toFloat()
                val targetY = (Math.sin(angle) * distance).toFloat()
                
                bubbles.add(
                    BubbleAnimState(
                        startX = 0f,
                        startY = 10f, // start slightly lower from bottom bar
                        targetX = targetX,
                        targetY = targetY,
                        radiusSecive = (4 + (Math.random() * 6)).dp,
                        delay = i * 35 // staggered
                    )
                )
            }
            
            val startTime = System.currentTimeMillis()
            val totalDuration = 800L
            while (System.currentTimeMillis() - startTime < totalDuration) {
                val elapsed = System.currentTimeMillis() - startTime
                for (bubble in bubbles) {
                    val bubbleElapsed = elapsed - bubble.delay
                    if (bubbleElapsed > 0) {
                        val progress = (bubbleElapsed.toFloat() / 500f).coerceIn(0f, 1f)
                        // cubic ease out
                        val easedProgress = 1f - (1f - progress) * (1f - progress) * (1f - progress)
                        
                        bubble.currentX = bubble.startX + (bubble.targetX - bubble.startX) * easedProgress
                        // drift up faster
                        bubble.currentY = bubble.startY + (bubble.targetY - bubble.startY) * easedProgress - (45f * easedProgress)
                        bubble.alpha = 1f - easedProgress
                        bubble.currentRadius = bubble.radiusSecive * (0.4f + 0.9f * easedProgress)
                    } else {
                        bubble.alpha = 0f
                    }
                }
                delay(16)
            }
            bubbles.clear()
        }
    }

    val scale by androidx.compose.animation.core.animateFloatAsState(
        targetValue = if (isSelected) 1.22f else 1.0f,
        animationSpec = androidx.compose.animation.core.spring(
            dampingRatio = androidx.compose.animation.core.Spring.DampingRatioMediumBouncy,
            stiffness = androidx.compose.animation.core.Spring.StiffnessLow
        ),
        label = "tab_scale"
    )

    val glowAlpha by androidx.compose.animation.core.animateFloatAsState(
        targetValue = if (isSelected) 1.0f else 0.0f,
        animationSpec = androidx.compose.animation.core.tween(durationMillis = 250),
        label = "tab_glow"
    )

    Box(
        modifier = modifier,
        contentAlignment = Alignment.Center
    ) {
        if (glowAlpha > 0f) {
            Box(
                modifier = Modifier
                    .size(48.dp)
                    .drawBehind {
                        drawCircle(
                            brush = Brush.radialGradient(
                                colors = listOf(
                                    RazorBlue.copy(alpha = 0.5f * glowAlpha),
                                    InstaPink.copy(alpha = 0.15f * glowAlpha),
                                    Color.Transparent
                                ),
                                center = Offset(size.width / 2f, size.height / 2f),
                                radius = size.width * 0.7f
                            )
                        )
                    }
            )
        }

        // Draw the bubbles floating behind / around the icon
        Canvas(modifier = Modifier.fillMaxSize()) {
            bubbles.forEach { bubble ->
                if (bubble.alpha > 0f) {
                    val currentRadiusPx = with(density) { bubble.currentRadius.toPx() }
                    val centerOffset = Offset(
                        x = size.width / 2f + bubble.currentX,
                        y = size.height / 2f + bubble.currentY
                    )
                    
                    // Glass bubble outline with soft rainbow/teal tint
                    drawCircle(
                        color = Color(0xFF81D4FA).copy(alpha = bubble.alpha * 0.8f),
                        radius = currentRadiusPx,
                        center = centerOffset,
                        style = Stroke(width = with(density) { 1.dp.toPx() })
                    )
                    
                    // Bubble body ambient glow
                    drawCircle(
                        brush = Brush.radialGradient(
                            colors = listOf(
                                Color(0x66B2EBF2).copy(alpha = bubble.alpha * 0.4f),
                                Color(0x33F8BBD0).copy(alpha = bubble.alpha * 0.2f),
                                Color.Transparent
                             ),
                            center = centerOffset,
                            radius = currentRadiusPx
                        ),
                        radius = currentRadiusPx,
                        center = centerOffset
                    )

                    // Bubble specular highlight (shiny spot)
                    drawCircle(
                        color = Color.White.copy(alpha = bubble.alpha * 0.9f),
                        radius = currentRadiusPx * 0.25f,
                        center = Offset(
                            x = centerOffset.x - currentRadiusPx * 0.35f,
                            y = centerOffset.y - currentRadiusPx * 0.35f
                        )
                    )
                }
            }
        }
        Box(
            modifier = Modifier.graphicsLayer {
                scaleX = scale
                scaleY = scale
            },
            contentAlignment = Alignment.Center
        ) {
            content()
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun SocialHubApp(viewModel: SocialHubViewModel) {
    val localContext = androidx.compose.ui.platform.LocalContext.current
    val gso = androidx.compose.runtime.remember {
        val webClientIdResId = localContext.resources.getIdentifier("default_web_client_id", "string", localContext.packageName)
        val webClientId = if (webClientIdResId != 0) localContext.getString(webClientIdResId) else null
        
        val builder = com.google.android.gms.auth.api.signin.GoogleSignInOptions.Builder(
            com.google.android.gms.auth.api.signin.GoogleSignInOptions.DEFAULT_SIGN_IN
        ).requestEmail()
        
        if (webClientId != null) {
            builder.requestIdToken(webClientId)
        }
        builder.build()
    }
    val googleSignInClient = androidx.compose.runtime.remember {
        com.google.android.gms.auth.api.signin.GoogleSignIn.getClient(localContext, gso)
    }

    val handleLogout = androidx.compose.runtime.remember {
        {
            try {
                googleSignInClient.signOut()
            } catch (e: Exception) {}
            viewModel.logoutUser()
        }
    }

    val googleSignInLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (result.resultCode == android.app.Activity.RESULT_OK) {
            val task = com.google.android.gms.auth.api.signin.GoogleSignIn.getSignedInAccountFromIntent(result.data)
            try {
                val account = task.getResult(com.google.android.gms.common.api.ApiException::class.java)
                val idToken = account?.idToken ?: ""
                val email = account?.email ?: ""
                if (idToken.isNotBlank()) {
                    viewModel.loginWithGoogleFirebaseToken(idToken, email)
                } else if (email.isNotBlank()) {
                    // Local sandbox mode if client ID / Google Services properties are missing or pending configuration
                    viewModel.loginWithGoogleFirebaseToken("", email)
                } else {
                    viewModel.setLoginError("Could not retrieve credentials from Google Account.")
                }
            } catch (e: Exception) {
                viewModel.setLoginError("Google Sign-In failed: " + e.getLocalizedMessage())
            }
        } else {
            viewModel.setLoginError("Google Sign-In cancelled or failed.")
        }
    }
    val isUserLoggedIn by viewModel.isUserLoggedIn.collectAsStateWithLifecycle()
    val loginErrorMessage by viewModel.loginErrorMessage.collectAsStateWithLifecycle()
    val registerErrorMessage by viewModel.registerErrorMessage.collectAsStateWithLifecycle()
    val isAuthenticating by viewModel.isAuthenticating.collectAsStateWithLifecycle()
    val remoteWelcomeMessage by viewModel.remoteWelcomeMessage.collectAsStateWithLifecycle()
    val remoteWelcomeSubMessage by viewModel.remoteWelcomeSubMessage.collectAsStateWithLifecycle()

    val isEmailVerified by viewModel.isEmailVerified.collectAsStateWithLifecycle()
    val userEmail by viewModel.userEmail.collectAsStateWithLifecycle()
    val emailOtpSent by viewModel.emailOtpSent.collectAsStateWithLifecycle()
    val isOtpVerifying by viewModel.isOtpVerifying.collectAsStateWithLifecycle()
    val otpErrorMessage by viewModel.otpErrorMessage.collectAsStateWithLifecycle()

    if (!isUserLoggedIn) {
        CyberLoginAndSignUpScreen(
            isAuthenticating = isAuthenticating,
            loginErrorMessage = loginErrorMessage,
            registerErrorMessage = registerErrorMessage,
            onLogin = { email, pwd -> viewModel.loginUser(email, pwd) },
            onRegister = { email, phone, pwd, confPwd -> viewModel.registerUser(email, phone, pwd, confPwd) },
            onTabChanged = { viewModel.clearAuthErrors() },
            onGoogleLogin = { typedEmail ->
                if (typedEmail.isBlank()) {
                    val signInIntent = googleSignInClient.signInIntent
                    googleSignInLauncher.launch(signInIntent)
                } else {
                    viewModel.loginWithGoogleFirebaseToken("", typedEmail)
                }
            },
            welcomeMessage = remoteWelcomeMessage,
            welcomeSubMessage = remoteWelcomeSubMessage
        )
        return
    }

    if (false && !isEmailVerified) {
        MandatoryEmailVerificationScreen(
            emailOtpSent = emailOtpSent,
            isOtpVerifying = isOtpVerifying,
            otpErrorMessage = otpErrorMessage,
            userEmail = userEmail,
            onSendOtp = { viewModel.sendEmailOtp(it) },
            onVerifyOtp = { viewModel.verifyEmailOtp(it) },
            onLogout = handleLogout
        )
        return
    }

    val isAppUnlocked by viewModel.isAppUnlocked.collectAsStateWithLifecycle()
    val extBiometricStartupLock by viewModel.extBiometricStartupLock.collectAsStateWithLifecycle()

    if (extBiometricStartupLock && !isAppUnlocked) {
        AppLockScreen(
            onUnlockWithPin = { viewModel.unlockApp(it) },
            onUnlockWithBiometric = { viewModel.triggerBiometricMockUnlock() },
            onLogout = handleLogout
        )
        return
    }

    val currentScreen by viewModel.currentScreen.collectAsStateWithLifecycle()
    val isDataFetching by viewModel.isDataFetching.collectAsStateWithLifecycle()
    val walletBalance by viewModel.walletBalance.collectAsStateWithLifecycle()
    val activeCheckoutInfo by viewModel.activeCheckoutInfo.collectAsStateWithLifecycle()
    val activeNotification by viewModel.activeNotification.collectAsStateWithLifecycle()
    val adminApiUrl by viewModel.adminApiUrl.collectAsStateWithLifecycle()
    val bannerSyncStatus by viewModel.bannerSyncStatus.collectAsStateWithLifecycle()
    val externalBannersState by viewModel.externalBannersState.collectAsStateWithLifecycle()
    val isNetworkAvailable by viewModel.isNetworkAvailable.collectAsStateWithLifecycle()

    val isLagWatchdogEnabled by viewModel.isLagWatchdogEnabled.collectAsStateWithLifecycle()
    val isLaggingOrHanging by viewModel.isLaggingOrHanging.collectAsStateWithLifecycle()
    val lagCountdown by viewModel.lagCountdown.collectAsStateWithLifecycle()
    val watchdogStatus by viewModel.watchdogStatus.collectAsStateWithLifecycle()
    val measuredDelayMs by viewModel.measuredDelayMs.collectAsStateWithLifecycle()

    val context = androidx.compose.ui.platform.LocalContext.current
    var showPermissionsOnboarding by remember {
        mutableStateOf(
            if (android.os.Build.VERSION.SDK_INT >= 33) {
                listOf(
                    android.Manifest.permission.CAMERA,
                    android.Manifest.permission.RECORD_AUDIO,
                    android.Manifest.permission.READ_MEDIA_IMAGES,
                    android.Manifest.permission.READ_MEDIA_VIDEO,
                    android.Manifest.permission.READ_MEDIA_AUDIO,
                    "android.permission.POST_NOTIFICATIONS"
                )
            } else {
                listOf(
                    android.Manifest.permission.CAMERA,
                    android.Manifest.permission.RECORD_AUDIO,
                    android.Manifest.permission.READ_EXTERNAL_STORAGE
                )
            }.any {
                androidx.core.content.ContextCompat.checkSelfPermission(context, it) != android.content.pm.PackageManager.PERMISSION_GRANTED
            }
        )
    }

    val userName by viewModel.userProfileName.collectAsStateWithLifecycle()
    val userHandle by viewModel.userProfileHandle.collectAsStateWithLifecycle()
    val userBio by viewModel.userProfileBio.collectAsStateWithLifecycle()
    val userLink by viewModel.userProfileLink.collectAsStateWithLifecycle()
    val userDp by viewModel.userProfileDp.collectAsStateWithLifecycle()
    val userBanner by viewModel.userProfileBanner.collectAsStateWithLifecycle()
    val userVibeIndex by viewModel.userVibeIndex.collectAsStateWithLifecycle()

    val userVerified by viewModel.userVerified.collectAsStateWithLifecycle()
    val userBronzeName by viewModel.userBronzeName.collectAsStateWithLifecycle()
    val userBronzePrice by viewModel.userBronzePrice.collectAsStateWithLifecycle()
    val userBronzePerks by viewModel.userBronzePerks.collectAsStateWithLifecycle()
    val userSilverName by viewModel.userSilverName.collectAsStateWithLifecycle()
    val userSilverPrice by viewModel.userSilverPrice.collectAsStateWithLifecycle()
    val userSilverPerks by viewModel.userSilverPerks.collectAsStateWithLifecycle()
    val userGoldName by viewModel.userGoldName.collectAsStateWithLifecycle()
    val userGoldPrice by viewModel.userGoldPrice.collectAsStateWithLifecycle()
    val userGoldPerks by viewModel.userGoldPerks.collectAsStateWithLifecycle()

    var isHeaderSearchActive by remember { mutableStateOf(false) }
    var headerSearchQuery by remember { mutableStateOf("") }

    val creators by viewModel.creators.collectAsStateWithLifecycle(initialValue = emptyList())
    val posts by viewModel.posts.collectAsStateWithLifecycle(initialValue = emptyList())
    val followedPosts by viewModel.followedPosts.collectAsStateWithLifecycle(initialValue = emptyList())
    val subscriptions by viewModel.subscriptions.collectAsStateWithLifecycle(initialValue = emptyList())
    val transactions by viewModel.transactions.collectAsStateWithLifecycle(initialValue = emptyList())
    val chatMessages by viewModel.chatMessages.collectAsStateWithLifecycle(initialValue = emptyList())
    val events by viewModel.events.collectAsStateWithLifecycle(initialValue = emptyList())
    val products by viewModel.marketplaceProducts.collectAsStateWithLifecycle(initialValue = emptyList())
    val banners by viewModel.marketplaceBanners.collectAsStateWithLifecycle(initialValue = emptyList())

    // Trending topics states
    val trendingTopics by viewModel.trendingTopics.collectAsStateWithLifecycle(initialValue = emptyList())
    val isTrendingFetching by viewModel.isTrendingFetching.collectAsStateWithLifecycle(initialValue = false)
    val selectedTopicInsight by viewModel.selectedTopicInsight.collectAsStateWithLifecycle(initialValue = null)
    val isGeneratingInsight by viewModel.isGeneratingInsight.collectAsStateWithLifecycle(initialValue = false)
    val securityLogs by viewModel.securityLogs.collectAsStateWithLifecycle(initialValue = emptyList())

    // Direct local state for splits
    var marioPizzaSplitPaid by remember { mutableStateOf(false) }
    var activeInAppVideoPost by remember { mutableStateOf<Post?>(null) }
    var showNotificationCenter by remember { mutableStateOf(false) }

    val filteredPosts = remember(followedPosts, headerSearchQuery) {
        if (headerSearchQuery.isBlank()) {
            followedPosts
        } else {
            followedPosts.filter {
                it.caption.contains(headerSearchQuery, ignoreCase = true) ||
                it.creatorName.contains(headerSearchQuery, ignoreCase = true) ||
                it.creatorHandle.contains(headerSearchQuery, ignoreCase = true)
            }
        }
    }

    val filteredCreators = remember(creators, headerSearchQuery) {
        if (headerSearchQuery.isBlank()) {
            emptyList()
        } else {
            creators.filter {
                it.isVerified && (it.name.contains(headerSearchQuery, ignoreCase = true) ||
                it.handle.contains(headerSearchQuery, ignoreCase = true) ||
                it.description.contains(headerSearchQuery, ignoreCase = true))
            }
        }
    }

    val filteredAllPosts = remember(posts, headerSearchQuery) {
        if (headerSearchQuery.isBlank()) {
            posts
        } else {
            posts.filter {
                it.caption.contains(headerSearchQuery, ignoreCase = true) ||
                it.creatorName.contains(headerSearchQuery, ignoreCase = true) ||
                it.creatorHandle.contains(headerSearchQuery, ignoreCase = true)
            }
        }
    }

    val hasBackstackTopLevel by viewModel.canGoBack.collectAsStateWithLifecycle()
    androidx.activity.compose.BackHandler(enabled = hasBackstackTopLevel) {
        viewModel.navigateBack()
    }

    Scaffold(
        topBar = {
            if (currentScreen !is Screen.Wallet) {
                val hasBackstack by viewModel.canGoBack.collectAsStateWithLifecycle()
                TopAppBar(
                    navigationIcon = {
                        if (hasBackstack) {
