                            }
                        }

                        // ADVANCED NOTIFICATION CENTER BELL WITH BADGE
                        val notificationsListState by viewModel.notificationsList.collectAsStateWithLifecycle()
                        val unreadCount = notificationsListState.count { !it.isRead }

                        IconButton(onClick = { showNotificationCenter = true }) {
                            Box {
                                Icon(
                                    imageVector = Icons.Default.Notifications,
                                    contentDescription = "Notifications",
                                    tint = MaterialTheme.colorScheme.onBackground
                                )
                                if (unreadCount > 0) {
                                    Box(
                                        modifier = Modifier
                                            .align(Alignment.TopEnd)
                                            .size(14.dp)
                                            .background(Color(0xFFFF5252), CircleShape)
                                            .border(1.dp, MaterialTheme.colorScheme.background, CircleShape),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(
                                            text = if (unreadCount > 9) "9+" else unreadCount.toString(),
                                            color = Color.White,
                                            fontSize = 8.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                    }
                                }
                            }
                        }
                        
                        // SECURE TECH GLOWING WALLET PILL - Page 1 & Page 5 (Category F Integration)
                        if (currentScreen !is Screen.Feed && currentScreen !is Screen.LiveEvents && currentScreen !is Screen.Chat && currentScreen !is Screen.Settings) {
                            Surface(
                                onClick = { viewModel.navigateTo(Screen.Wallet) },
                                shape = RoundedCornerShape(20.dp),
                                color = ObsidianDark,
                                border = BorderStroke(1.5.dp, RazorBlue),
