sealed class StreamItem {
    data class VideoPost(val post: Post) : StreamItem()
    data class Advertisement(
        val id: String,
        val sponsorName: String,
        val sponsorAvatar: String,
        val caption: String,
        val imageUrl: String,
        val ctaText: String,
        val url: String
    ) : StreamItem()
}

data class MockAd(
    val id: String,
    val sponsorName: String,
    val sponsorAvatar: String,
    val caption: String,
    val imageUrl: String,
    val ctaText: String,
    val url: String
)

sealed class CreatorFeedItem {
    data class CreatorPost(val post: Post) : CreatorFeedItem()
    data class CreatorAd(val ad: MockAd) : CreatorFeedItem()
}

