                                        onCreatorClick = { onCreatorClick(post.creatorId) },
                                        isCreatorVerified = creators.find { it.id == post.creatorId }?.isVerified ?: true,
                                        onVideoClick = { onVideoClick(post) },
                                        isActiveVideo = false,
                                        isInViewport = isPostInViewport.value
                                    )
                                }
                            }
                            is CreatorFeedItem.CreatorAd -> {
                                val isAdInViewport = remember(visibleCreatorAdIdsState) {
                                    derivedStateOf {
                                        visibleCreatorAdIdsState.value.contains(item.ad.id)
                                    }
                                }

                                EntranceAnimationContainer {
                                    InstagramAdCard(
                                        sponsorName = item.ad.sponsorName,
                                        sponsorAvatar = item.ad.sponsorAvatar,
                                        caption = item.ad.caption,
                                        imageUrl = item.ad.imageUrl,
                                        ctaText = item.ad.ctaText,
                                        onDismissAd = { dismissedAds.add(item.ad.id) },
                                        onCtaClick = { activeAdBrowser = Pair(item.ad.sponsorName, item.ad.url) },
                                        isInViewport = isAdInViewport.value
                                    )
                                }
                            }
                        }
                    }
                } else {
                    items(streamItems, key = { item ->
                        when (item) {
                            is StreamItem.VideoPost -> "video_${item.post.id}"
                            is StreamItem.Advertisement -> "ad_${item.id}"
                        }
                    }) { item ->
                        when (item) {
                            is StreamItem.VideoPost -> {
                                val post = item.post
                                val hasSubscription = subscriptions.any {
                                    it.creatorId == post.creatorId &&
                                    (it.tierName == "GOLD" || 
                                     (it.tierName == "SILVER" && post.requiredTier != "GOLD") || 
                                     (it.tierName == "BRONZE" && post.requiredTier == "BRONZE"))
                                }
                                val isLocked = false

                                EntranceAnimationContainer {
                                    PostCard(
                                        post = post,
                                        isLocked = isLocked,
                                        onLike = { onLike(post) },
                                        onTip = { amt -> onTip(post, amt) },
                                        onUnlock = { onUnlock(post.creatorId) },
                                        onCreatorClick = { onCreatorClick(post.creatorId) },
                                        isCreatorVerified = creators.find { it.id == post.creatorId }?.isVerified ?: true,
                                        onVideoClick = { onVideoClick(post) },
                                        isActiveVideo = (activeVideoIdState.value == post.id),
                                        isInViewport = (visibleVideoIdsState.value.contains(post.id))
                                    )
                                }
                            }
                            is StreamItem.Advertisement -> {
                                EntranceAnimationContainer {
                                    InstagramAdCard(
                                        sponsorName = item.sponsorName,
                                        sponsorAvatar = item.sponsorAvatar,
                                        caption = item.caption,
                                        imageUrl = item.imageUrl,
                                        ctaText = item.ctaText,
                                        onDismissAd = { dismissedAds.add(item.id) },
                                        onCtaClick = { activeAdBrowser = Pair(item.sponsorName, item.url) }
                                    )
                                }
                            }
                        }
                    }
                }

                item {
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 16.dp),
                        horizontalAlignment = Alignment.CenterHorizontally
                    ) {
                        Button(
                            onClick = { onLoadMorePosts() },
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0x3300FF88)),
                            border = BorderStroke(1.dp, RazorTeal.copy(0.4f)),
                            shape = RoundedCornerShape(12.dp),
                            modifier = Modifier.testTag("load_more_posts_btn")
                        ) {
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(8.dp),
                                modifier = Modifier.padding(horizontal = 12.dp, vertical = 2.dp)
                            ) {
                                Icon(
                                    imageVector = Icons.Default.Refresh,
                                    contentDescription = null,
                                    tint = RazorTeal,
                                    modifier = Modifier.size(16.dp)
                                )
                                Text("LOAD MORE CREATOR FEEDS", color = RazorTeal, fontWeight = FontWeight.Bold, fontSize = 11.sp, letterSpacing = 0.5.sp)
                            }
                        }
                    }
                }
            }
        }

        // Floating Action Button to post dynamically
        FloatingActionButton(
            onClick = { showNewPostDialog = true },
            containerColor = RazorTeal,
            contentColor = Color.Black,
            shape = CircleShape,
            modifier = Modifier
                .align(Alignment.BottomEnd)
                .padding(bottom = 76.dp, end = 20.dp)
                .testTag("new_post_fab")
        ) {
            Icon(
                imageVector = Icons.Default.Create,
                contentDescription = "New Post Icon",
                modifier = Modifier.size(24.dp)
            )
        }
    }

    if (showStoryStudio) {
        CreativeStudioDialog(
            onDismiss = { showStoryStudio = false },
            onPublish = { caption, attachedImg -> 
                // Publish as a regular feed post as well
                onPublishPost(caption, null, attachedImg)
                
                // Safely extract the pure media URL to display in the Stories bar
                val newSnapImg = if (!attachedImg.isNullOrBlank()) {
                    val firstSegment = attachedImg.split(",").first()
                    if (firstSegment.contains("|")) {
                        firstSegment.split("|").first()
                    } else {
                        firstSegment
                    }
                } else {
                    "https://images.unsplash.com/photo-1542751371-adc38448a05e?w=800"
                }
                
                creatorSnaps.add(
                    0,
                    CreatorSnap(
                        id = "user_snap_${System.currentTimeMillis()}",
                        creatorId = "me_user",
                        creatorName = "You",
                        creatorHandle = "me_creator",
                        creatorAvatar = "https://images.unsplash.com/photo-1534528741775-53994a69daeb?w=150",
                        imageUrl = newSnapImg,
                        caption = caption,
                        durationSeconds = 10,
                        isPremium = false,
                        likesCount = 0
                    )
                )
            }
        )
    }

    if (showNewPostDialog) {
        NewPostDialog(
            creators = creators,
            onDismiss = { showNewPostDialog = false },
            onPublish = onPublishPost
        )
    }

    if (activePlayingSnap != null) {
        SnapPlaybackOverlay(
            snaps = creatorSnaps.filter { !it.isPremium },
            initialSnap = activePlayingSnap!!,
            subscriptions = subscriptions,
            likedSnapIds = likedSnapIds,
            onLikeToggle = { snap, isLiked ->
                if (isLiked) {
                    if (!likedSnapIds.contains(snap.id)) {
                        likedSnapIds.add(snap.id)
                    }
                    viewModel.triggerUserLikedStoryNotification(
                        creatorName = snap.creatorName,
                        creatorHandle = snap.creatorHandle,
                        storyCaption = snap.caption
                    )
                    viewModel.triggerStoryLikeNotification(
                        likerName = "You",
                        likerHandle = "your_handle",
                        storyCaption = snap.caption
                    )
                } else {
                    likedSnapIds.remove(snap.id)
                }
                val snapIdx = creatorSnaps.indexOfFirst { it.id == snap.id }
                if (snapIdx != -1) {
                    val current = creatorSnaps[snapIdx]
                    creatorSnaps[snapIdx] = current.copy(
                        likesCount = current.likesCount + (if (isLiked) 1 else -1)
                    )
                }
            },
            onVisitProfile = { pId ->
                activePlayingSnap = null
                onCreatorClick(pId)
            },
            onDismiss = { activePlayingSnap = null }
        )
    }

    selectedGridPost?.let { post ->
        Dialog(onDismissRequest = { selectedGridPost = null }) {
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .clip(RoundedCornerShape(24.dp))
                    .background(ObsidianDark)
                    .border(1.2.dp, Brush.linearGradient(colors = listOf(Color.White.copy(0.3f), Color.White.copy(0.05f))), RoundedCornerShape(24.dp))
                    .padding(vertical = 12.dp)
            ) {
                Column {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(horizontal = 16.dp, vertical = 6.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = "POST EXPLORER DETAILS",
                            fontWeight = FontWeight.ExtraBold,
                            color = InstaPink,
                            fontSize = 11.5.sp,
                            letterSpacing = 0.8.sp
                        )
                        IconButton(onClick = { selectedGridPost = null }) {
                            Icon(
                                imageVector = Icons.Default.Close,
                                contentDescription = "Close Detail Modal",
                                tint = Color.White,
                                modifier = Modifier.size(18.dp)
                            )
                        }
                    }

                    val hasSubscription = subscriptions.any {
                        it.creatorId == post.creatorId &&
                        (it.tierName == "GOLD" || 
                         (it.tierName == "SILVER" && post.requiredTier != "GOLD") || 
                         (it.tierName == "BRONZE" && post.requiredTier == "BRONZE"))
                    }
                    val isLocked = false

                    PostCard(
                        post = post,
                        isLocked = isLocked,
                        onLike = { onLike(post) },
                        onTip = { amt -> onTip(post, amt) },
                        onUnlock = { 
                            selectedGridPost = null
                            onUnlock(post.creatorId) 
                        },
                        onCreatorClick = {
                            selectedGridPost = null
                            onCreatorClick(post.creatorId)
                        },
                        isCreatorVerified = creators.find { it.id == post.creatorId }?.isVerified ?: true,
                        onVideoClick = { onVideoClick(post) },
                        isActiveVideo = true
                    )
                }
            }
        }
    }

    activeAdBrowser?.let { adDetails ->
        SimulatedBrowserDialog(
            sponsorName = adDetails.first,
            url = adDetails.second,
            onDismiss = { activeAdBrowser = null }
        )
    }
}

@Composable
fun NewPostDialog(
    creators: List<Creator>,
    onDismiss: () -> Unit,
    onPublish: (String, Creator?, String?) -> Unit
) {
    Dialog(
        onDismissRequest = onDismiss,
        properties = androidx.compose.ui.window.DialogProperties(
            usePlatformDefaultWidth = false,
            decorFitsSystemWindows = false
        )
    ) {
        // Core state fields
        var captionText by remember { mutableStateOf("") }
        var selectedCreator by remember { mutableStateOf<Creator?>(null) }
        var showCreatorDropdown by remember { mutableStateOf(false) }

    val context = androidx.compose.ui.platform.LocalContext.current
        var attachedMediaType by remember { mutableStateOf<String?>(null) } // "attached_image", "attached_video", "attached_audio"
        var permissionStatusMessage by remember { mutableStateOf<String?>(null) }
        var requestedPermissionType by remember { mutableStateOf<String?>(null) }

        // Core client-side file properties
        var realAttachedUri by remember { mutableStateOf<android.net.Uri?>(null) }
        var attachedFileName by remember { mutableStateOf<String?>(null) }
        var attachedFileSizeStr by remember { mutableStateOf<String?>(null) }
        var attachedFileMimeType by remember { mutableStateOf<String?>(null) }
        var fileValidationErrorMessage by remember { mutableStateOf<String?>(null) }

        // Simulation parameters for playground validation testing in the preview
        var simFileType by remember { mutableStateOf("image/png") }
        var simFileName by remember { mutableStateOf("cyberpunk_shot.png") }
        var simFileSizeMB by remember { mutableStateOf("3.5") }

        // --- NEW INSTAGRAM-STYLE & ADVANCED FEATURES STATES ---
        var selectedFilter by remember { mutableStateOf("Normal") }

        // Local client-side validator helper
        fun validateFile(
            fileName: String,
            fileSizeInBytes: Long,
            mimeType: String?
        ): Pair<Boolean, String> {
            val extension = fileName.substringAfterLast('.', "").lowercase()
            val resolvedType = mimeType ?: when (extension) {
                "png", "jpg", "jpeg", "webp", "gif" -> "image/$extension"
                "mp4", "mkv", "3gp", "webm", "mov" -> "video/$extension"
                "mp3", "wav", "ogg", "m4a" -> "audio/$extension"
                else -> "unknown/unknown"
            }

            val isImage = resolvedType.startsWith("image/") || listOf("png", "jpg", "jpeg", "webp", "gif").contains(extension)
            val isVideo = resolvedType.startsWith("video/") || listOf("mp4", "mkv", "3gp", "webm", "mov").contains(extension)
            val isAudio = resolvedType.startsWith("audio/") || listOf("mp3", "wav", "ogg", "m4a").contains(extension)

            if (!isImage && !isVideo && !isAudio) {
                return Pair(false, "Unsupported file format ($resolvedType). Only Image, Video, and Audio media types are permitted.")
            }

            val sizeInMB = fileSizeInBytes / (1024.0 * 1024.0)
            if (isImage) {
                if (fileSizeInBytes > 5 * 1024 * 1024) {
                    val formattedSize = String.format("%.2f", sizeInMB)
                    return Pair(false, "Image is too large ($formattedSize MB). Max limit is 5.0 MB to prevent client performance bottlenecks.")
                }
            } else if (isVideo) {
                if (fileSizeInBytes > 20 * 1024 * 1024) {
                    val formattedSize = String.format("%.2f", sizeInMB)
                    return Pair(false, "Video is too large ($formattedSize MB). Max limit is 20.0 MB to prevent play/buffer bottlenecks.")
                }
            } else if (isAudio) {
                if (fileSizeInBytes > 8 * 1024 * 1024) {
                    val formattedSize = String.format("%.2f", sizeInMB)
                    return Pair(false, "Audio is too large ($formattedSize MB). Max limit is 8.0 MB to minimize telemetry memory footprint.")
                }
            }

            return Pair(true, "Validation passed successfully!")
        }

        // Real media activity selector launcher
        val mediaPickerLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
            contract = androidx.activity.result.contract.ActivityResultContracts.GetContent()
        ) { uri: android.net.Uri? ->
            if (uri != null) {
                val resolver = context.contentResolver
                var fileName = "imported_media_file"
                var fileSize: Long = 0
                val mimeType = resolver.getType(uri)

                try {
                    resolver.query(uri, null, null, null, null)?.use { cursor ->
                        val nameIndex = cursor.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
                        val sizeIndex = cursor.getColumnIndex(android.provider.OpenableColumns.SIZE)
                        if (cursor.moveToFirst()) {
                            if (nameIndex != -1) {
                                val retrievedName = cursor.getString(nameIndex)
                                if (!retrievedName.isNullOrBlank()) {
                                    fileName = retrievedName
                                }
                            }
                            if (sizeIndex != -1) {
                                fileSize = cursor.getLong(sizeIndex)
                            }
                        }
                    }
                } catch (e: Exception) {
                    android.util.Log.e("SocialHubUI", "Cursor file info retrieval failed: ${e.message}")
                }

                if (fileSize <= 0) {
                    try {
                        resolver.openInputStream(uri)?.use { stream ->
                            fileSize = stream.available().toLong()
                        }
                    } catch (e: Exception) {
                        android.util.Log.e("SocialHubUI", "Fallback size retrieval failed: ${e.message}")
                    }
                }

                val (isValid, errorMsg) = validateFile(fileName, fileSize, mimeType)
                if (isValid) {
                    realAttachedUri = uri
                    attachedFileName = fileName
                    val sizeInMB = fileSize / (1024.0 * 1024.0)
                    attachedFileSizeStr = String.format("%.2f MB", sizeInMB)
                    attachedFileMimeType = mimeType ?: "unknown"
                    fileValidationErrorMessage = null

                    val ext = fileName.substringAfterLast('.', "").lowercase()
                    attachedMediaType = when {
                        mimeType?.startsWith("image/") == true || listOf("png", "jpg", "jpeg", "webp", "gif").contains(ext) -> "attached_image"
                        mimeType?.startsWith("video/") == true || listOf("mp4", "mkv", "3gp", "webm", "mov").contains(ext) -> "attached_video"
                        mimeType?.startsWith("audio/") == true || listOf("mp3", "wav", "ogg", "m4a").contains(ext) -> "attached_audio"
                        else -> "attached_image"
                    }
                    permissionStatusMessage = "✅ Validated & attached: $fileName ($attachedFileSizeStr)"
                } else {
                    fileValidationErrorMessage = errorMsg
                    permissionStatusMessage = "❌ Validation Failed: $errorMsg"
                    realAttachedUri = null
                    attachedFileName = null
                    attachedFileSizeStr = null
                    attachedFileMimeType = null
                    attachedMediaType = null
                }
            }
        }

        val singlePermissionLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
            contract = androidx.activity.result.contract.ActivityResultContracts.RequestMultiplePermissions()
        ) { results ->
            val allGranted = results.values.all { it }
            if (allGranted) {
                permissionStatusMessage = "✅ Provisioned successfully! Initializing device engine."
                when (requestedPermissionType) {
                    "camera" -> {
                        attachedMediaType = "attached_image"
                        permissionStatusMessage = "📸 Captured live high-definition cyber snapshot!"
                    }
                    "media" -> {
                        try {
                            mediaPickerLauncher.launch("*/*")
                        } catch (e: Exception) {
                            permissionStatusMessage = "⚠️ Media warehouse launch failed: ${e.message}"
                        }
                    }
                    "mic" -> {
                        attachedMediaType = "attached_audio"
                        permissionStatusMessage = "🎙️ Synchronized voice telemetry note successfully!"
                    }
                    "video" -> {
                        attachedMediaType = "attached_video"
                        permissionStatusMessage = "📹 Recorded premium cybernetic cinematic reel stream!"
                    }
                }
            } else {
                permissionStatusMessage = "❌ Access requested was denied. Running sandbox fallback simulation!"
                when (requestedPermissionType) {
                    "camera" -> { attachedMediaType = "attached_image" }
                    "media" -> {
                        try {
                            mediaPickerLauncher.launch("*/*")
                        } catch (e: Exception) {
                            permissionStatusMessage = "⚠️ Media warehouse launch failed: ${e.message}"
                        }
                    }
                    "mic" -> { attachedMediaType = "attached_audio" }
                    "video" -> { attachedMediaType = "attached_video" }
                }
            }
        }

        val tryAttach: (String) -> Unit = { type ->
            requestedPermissionType = type
            val permissionsNeeded = when (type) {
                "camera" -> arrayOf(android.Manifest.permission.CAMERA)
                "mic" -> arrayOf(android.Manifest.permission.RECORD_AUDIO)
                "video" -> arrayOf(android.Manifest.permission.CAMERA, android.Manifest.permission.RECORD_AUDIO)
                "media" -> {
                    if (android.os.Build.VERSION.SDK_INT >= 33) {
                        arrayOf(
                            android.Manifest.permission.READ_MEDIA_IMAGES,
                            android.Manifest.permission.READ_MEDIA_VIDEO,
                            android.Manifest.permission.READ_MEDIA_AUDIO
                        )
                    } else {
                        arrayOf(android.Manifest.permission.READ_EXTERNAL_STORAGE)
                    }
                }
                else -> emptyArray()
            }
            
            val allGranted = permissionsNeeded.all {
                androidx.core.content.ContextCompat.checkSelfPermission(context, it) == android.content.pm.PackageManager.PERMISSION_GRANTED
            }
            
            if (allGranted) {
                permissionStatusMessage = "✅ Access verified. Device ready."
                when (type) {
                    "camera" -> {
                        attachedMediaType = "attached_image"
                        permissionStatusMessage = "📸 Captured live high-definition cyber snapshot!"
                    }
                    "media" -> {
                        try {
                            mediaPickerLauncher.launch("*/*")
                        } catch (e: Exception) {
                            permissionStatusMessage = "⚠️ Media warehouse picking failed: ${e.message}"
                        }
                    }
                    "mic" -> {
                        attachedMediaType = "attached_audio"
                        permissionStatusMessage = "🎙️ Synchronized voice telemetry note successfully!"
                    }
                    "video" -> {
                        attachedMediaType = "attached_video"
                        permissionStatusMessage = "📹 Recorded premium cybernetic cinematic reel stream!"
                    }
                }
            } else {
                permissionStatusMessage = "📡 Requesting OS system permissions..."
                singlePermissionLauncher.launch(permissionsNeeded)
            }
        }

        // Theme and Visual Gradients mapping for the Poster Designer
        val posterThemes = listOf(
            "Cyber Neon" to Brush.linearGradient(colors = listOf(Color(0xFFC00A63), Color(0xFF1E085E), Color(0xFF00FFCC))),
            "Solar Flare" to Brush.radialGradient(colors = listOf(Color(0xFFFF9E00), Color(0xFFFF0055), Color(0xFF3B0014))),
            "Emerald Aurora" to Brush.linearGradient(colors = listOf(Color(0xFF00FF87), Color(0xFF60EFFF), Color(0xFF0061FF))),
            "Midnight Blue" to Brush.linearGradient(colors = listOf(Color(0xFF020024), Color(0xFF090979), Color(0xFF00d4ff))),
            "Sakura Dream" to Brush.radialGradient(colors = listOf(Color(0xFFFFD2FC), Color(0xFFFFA9C4), Color(0xFFE47BFF)))
        )

        val posterThemeImages = mapOf(
            "Cyber Neon" to "https://images.unsplash.com/photo-1550684848-fac1c5b4e853?w=800",
            "Solar Flare" to "https://images.unsplash.com/photo-1541701494587-cb58502866ab?w=800",
            "Emerald Aurora" to "https://images.unsplash.com/photo-1557683316-973673baf926?w=800",
            "Midnight Blue" to "https://images.unsplash.com/photo-1506318137071-a8e063b4bec0?w=800",
            "Sakura Dream" to "https://images.unsplash.com/photo-1522441815192-d9f04eb0615c?w=800"
        )

        // Photo filters lists with color matrices
        val filtersList = listOf("Normal", "Cyber Teal", "Moonlight", "Sepia Retro", "Solar Flare", "Vaporwave")
        val filterMatrix = when (selectedFilter) {
            "Cyber Teal" -> floatArrayOf(
                0.7f, 0f, 0.3f, 0f, 0f,
                0f, 1.2f, 0.1f, 0f, 0f,
                0f, 0.3f, 1.5f, 0f, 0f,
                0f, 0f, 0f, 1f, 0f
            )
            "Moonlight" -> floatArrayOf(
                0.33f, 0.33f, 0.33f, 0f, 0f,
                0.33f, 0.33f, 0.33f, 0f, 0f,
                0.33f, 0.33f, 0.33f, 0f, 0f,
                0f, 0f, 0f, 1f, 0f
            )
            "Sepia Retro" -> floatArrayOf(
                0.393f, 0.769f, 0.189f, 0f, 0f,
                0.349f, 0.686f, 0.168f, 0f, 0f,
                0.272f, 0.534f, 0.131f, 0f, 0f,
                0f, 0f, 0f, 1f, 0f
            )
            "Solar Flare" -> floatArrayOf(
                1.3f, 0f, 0f, 0f, 25f,
                0f, 0.8f, 0f, 0f, 0f,
                0f, 0f, 0.8f, 0f, 0f,
                0f, 0f, 0f, 1f, 0f
            )
            "Vaporwave" -> floatArrayOf(
                0.9f, 0f, 0.9f, 0f, 0f,
                0f, 1.0f, 0f, 0f, 0f,
                0.5f, 0f, 1.3f, 0f, 0f,
                0f, 0f, 0f, 1f, 0f
            )
            else -> null
        }

        // Locations list
        val locationSuggestions = listOf("Neo Tokyo 🗼", "Silicon Valley 🚀", "Metaverse City 🌐", "The Cyber Matrix 💻", "Creator Hub HQ 🏨")
        // Soundtracks list
        val soundtrackSuggestions = listOf("Synthwave Beat 🎵", "Future Lofi 🎧", "Ambient Breeze 🌌", "Tokyo Drift 🏎️", "Cyber pulse ⚡")

        // Main full screen or immersive Dialog Card
        Card(
            modifier = Modifier
                .fillMaxWidth(0.96f)
                .fillMaxHeight(0.95f)
                .systemBarsPadding()
                .imePadding(),
            shape = RoundedCornerShape(24.dp),
            colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0B21)),
            border = BorderStroke(1.5.dp, RazorTeal.copy(alpha = 0.5f))
        ) {
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(14.dp)
            ) {
                // INSTAGRAM-STYLE HEADER BAR
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(bottom = 12.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        IconButton(onClick = onDismiss) {
                            Icon(
                                imageVector = Icons.AutoMirrored.Filled.ArrowBack,
                                contentDescription = "Back",
                                tint = Color.White
                            )
                        }
                        Spacer(modifier = Modifier.width(4.dp))
                        Text(
                            text = "New Post",
                            color = Color.White,
                            style = MaterialTheme.typography.titleMedium,
                            fontWeight = FontWeight.Black
                        )
                    }



                    // Share Button (Publish Action)
                    Button(
                        onClick = {
                            val resolvedContentMedia = realAttachedUri?.toString() ?: attachedMediaType ?: "attached_image"
                            onPublish(captionText.ifBlank { "Uncaptioned creative drop from Creator Hub ✨" }, selectedCreator, resolvedContentMedia)
                            onDismiss()
                        },
                        colors = ButtonDefaults.buttonColors(
                            containerColor = RazorTeal,
                            contentColor = Color.Black
                        ),
                        shape = RoundedCornerShape(12.dp),
                        contentPadding = PaddingValues(horizontal = 14.dp, vertical = 6.dp)
                    ) {
                        Text("Share", fontWeight = FontWeight.Black, fontSize = 12.sp)
                    }
                }

                // SCROLLABLE COMPOSING WORKSPACE
                Column(
                    modifier = Modifier
                        .weight(1f)
                        .verticalScroll(rememberScrollState()),
                    verticalArrangement = Arrangement.spacedBy(14.dp)
                ) {
                    // 1. INSTAGRAM SQUARE PREVIEW & ART POSTER GENERATOR
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .aspectRatio(1f)
                            .clip(RoundedCornerShape(16.dp))
                            .border(1.2.dp, RazorTeal.copy(alpha = 0.3f), RoundedCornerShape(16.dp))
                            .background(Color(0xFF06030F))
                    ) {
                        // Render user media preview (camera snaps, gallery pics, simulated streams)
                        if (attachedMediaType == "attached_image") {
                            Box(modifier = Modifier.fillMaxSize()) {
                                AsyncImage(
                                    model = realAttachedUri?.toString() ?: "https://images.unsplash.com/photo-1509198397868-475647b2a1e5?w=800",
                                    contentDescription = "Selected media",
                                    modifier = Modifier.fillMaxSize(),
                                    contentScale = androidx.compose.ui.layout.ContentScale.Crop,
                                    colorFilter = if (filterMatrix != null) androidx.compose.ui.graphics.ColorFilter.colorMatrix(androidx.compose.ui.graphics.ColorMatrix(filterMatrix)) else null
                                )
                                
                                // Visual filter badge
                                Box(
                                    modifier = Modifier
                                        .align(Alignment.TopStart)
                                        .padding(10.dp)
                                        .background(Color.Black.copy(alpha = 0.65f), RoundedCornerShape(8.dp))
                                        .padding(horizontal = 8.dp, vertical = 4.dp)
                                ) {
                                    Text("Filter: $selectedFilter", color = RazorTeal, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        } else if (attachedMediaType == "attached_audio") {
                            // Pulse waves
                            Column(
                                modifier = Modifier
                                    .fillMaxSize()
                                    .background(Color(0xFF1F163D))
                                    .padding(24.dp),
                                verticalArrangement = Arrangement.Center,
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Icon(imageVector = Icons.Default.MusicNote, contentDescription = null, tint = RazorTeal, modifier = Modifier.size(48.dp))
                                Spacer(modifier = Modifier.height(14.dp))
                                Text("VOICE TELEMETRY AUDIO", color = Color.White, fontWeight = FontWeight.Bold, fontSize = 12.sp)
                                Spacer(modifier = Modifier.height(16.dp))
                                Row(
                                    modifier = Modifier.fillMaxWidth(0.8f).height(40.dp),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    listOf(20, 45, 15, 60, 30, 80, 50, 10, 70, 35, 55, 25).forEach { barH ->
                                        Box(
                                            modifier = Modifier
                                                .width(4.dp)
                                                .height(barH.dp)
                                                .clip(CircleShape)
                                                .background(RazorTeal)
                                        )
                                    }
                                }
                            }
                        } else if (attachedMediaType == "attached_video") {
                            Box(
                                modifier = Modifier
                                    .fillMaxSize()
                                    .background(Color.Black),
                                contentAlignment = Alignment.Center
                            ) {
                                AsyncImage(
                                    model = "https://images.unsplash.com/photo-1492691527719-9d1e07e534b4?w=800",
                                    contentDescription = "Video placeholder",
                                    modifier = Modifier.fillMaxSize(),
                                    contentScale = androidx.compose.ui.layout.ContentScale.Crop,
                                    alpha = 0.6f
                                )
                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                    Icon(imageVector = Icons.Default.PlayArrow, contentDescription = null, tint = InstaPink, modifier = Modifier.size(54.dp))
                                    Spacer(modifier = Modifier.height(8.dp))
                                    Text("REEL STREAM CAPTURED", color = Color.White, fontWeight = FontWeight.Black, fontSize = 11.sp, letterSpacing = 1.sp)
                                }
                            }
                        } else {
                            // Empty state placeholder with interactive selection buttons
                            Column(
                                modifier = Modifier
                                    .fillMaxSize()
                                    .padding(20.dp),
                                verticalArrangement = Arrangement.Center,
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Icon(imageVector = Icons.Default.Collections, contentDescription = null, tint = RazorBlue, modifier = Modifier.size(40.dp))
                                Spacer(modifier = Modifier.height(10.dp))
                                Text("No hardware media attached yet", color = Color.White, fontSize = 13.sp, fontWeight = FontWeight.Bold)
                                Text("Use sandbox simulations or hardware picker below to attach.", color = GrayText, fontSize = 11.sp, textAlign = TextAlign.Center)
                                Spacer(modifier = Modifier.height(14.dp))
                                Button(
                                    onClick = { tryAttach("media") },
                                    colors = ButtonDefaults.buttonColors(containerColor = RazorBlue),
                                    shape = RoundedCornerShape(8.dp)
                                ) {
                                    Text("Browse Library 📁", color = Color.Black, fontWeight = FontWeight.Bold, fontSize = 11.sp)
                                }
                            }
                        }
                    }

                    // 2. INSTAGRAM FILTER CAROUSEL (Show filters when we have attached image in media tab)
                    if (attachedMediaType == "attached_image") {
                        Column {
                            Text("PHOTO FILTERS", color = RazorTeal, fontSize = 9.5.sp, fontWeight = FontWeight.Black, letterSpacing = 1.sp)
                            Spacer(modifier = Modifier.height(6.dp))
                            LazyRow(
                                horizontalArrangement = Arrangement.spacedBy(10.dp),
                                modifier = Modifier.fillMaxWidth()
                            ) {
                                items(filtersList) { filter ->
                                    val isSelected = selectedFilter == filter
                                    Card(
                                        modifier = Modifier
                                            .width(74.dp)
                                            .clickable { selectedFilter = filter },
                                        shape = RoundedCornerShape(10.dp),
                                        colors = CardDefaults.cardColors(containerColor = if (isSelected) RazorTeal.copy(alpha = 0.15f) else Color(0xFF191331)),
                                        border = BorderStroke(1.2.dp, if (isSelected) RazorTeal else Color.White.copy(alpha = 0.12f))
                                    ) {
                                        Column(
                                            horizontalAlignment = Alignment.CenterHorizontally,
                                            modifier = Modifier.padding(6.dp)
                                        ) {
                                            // Mini filtered circle preview
                                            Box(
                                                modifier = Modifier
                                                    .size(36.dp)
                                                    .clip(CircleShape)
                                                    .background(Color.DarkGray)
                                            ) {
                                                AsyncImage(
                                                    model = realAttachedUri?.toString() ?: "https://images.unsplash.com/photo-1509198397868-475647b2a1e5?w=200",
                                                    contentDescription = null,
                                                    modifier = Modifier.fillMaxSize(),
                                                    contentScale = androidx.compose.ui.layout.ContentScale.Crop,
                                                    colorFilter = when (filter) {
                                                        "Cyber Teal" -> androidx.compose.ui.graphics.ColorFilter.colorMatrix(androidx.compose.ui.graphics.ColorMatrix(floatArrayOf(0.7f, 0f, 0.3f, 0f, 0f, 0f, 1.2f, 0.1f, 0f, 0f, 0f, 0.3f, 1.5f, 0f, 0f, 0f, 0f, 0f, 1f, 0f)))
                                                        "Moonlight" -> androidx.compose.ui.graphics.ColorFilter.colorMatrix(androidx.compose.ui.graphics.ColorMatrix(floatArrayOf(0.33f, 0.33f, 0.33f, 0f, 0f, 0.33f, 0.33f, 0.33f, 0f, 0f, 0.33f, 0.33f, 0.33f, 0f, 0f, 0f, 0f, 0f, 1f, 0f)))
                                                        "Sepia Retro" -> androidx.compose.ui.graphics.ColorFilter.colorMatrix(androidx.compose.ui.graphics.ColorMatrix(floatArrayOf(0.393f, 0.769f, 0.189f, 0f, 0f, 0.349f, 0.686f, 0.168f, 0f, 0f, 0.272f, 0.534f, 0.131f, 0f, 0f, 0f, 0f, 0f, 1f, 0f)))
                                                        "Solar Flare" -> androidx.compose.ui.graphics.ColorFilter.colorMatrix(androidx.compose.ui.graphics.ColorMatrix(floatArrayOf(1.3f, 0f, 0f, 0f, 25f, 0f, 0.8f, 0f, 0f, 0f, 0f, 0f, 0.8f, 0f, 0f, 0f, 0f, 0f, 1f, 0f)))
                                                        "Vaporwave" -> androidx.compose.ui.graphics.ColorFilter.colorMatrix(androidx.compose.ui.graphics.ColorMatrix(floatArrayOf(0.9f, 0f, 0.9f, 0f, 0f, 0f, 1.0f, 0f, 0f, 0f, 0.5f, 0f, 1.3f, 0f, 0f, 0f, 0f, 0f, 1f, 0f)))
                                                        else -> null
                                                    }
                                                )
                                            }
                                            Spacer(modifier = Modifier.height(4.dp))
                                            Text(
                                                text = filter,
                                                color = if (isSelected) RazorTeal else Color.White.copy(alpha = 0.7f),
                                                fontSize = 8.sp,
                                                fontWeight = FontWeight.Bold,
                                                maxLines = 1
                                            )
                                        }
                                    }
                                }
                            }
                        }
                        Spacer(modifier = Modifier.height(2.dp))
                    }

                    // 4. COMPOSITION SECTION (Caption input next to small 1:1 image thumbnail)
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .clip(RoundedCornerShape(12.dp))
                            .background(Color.Black.copy(alpha = 0.25f))
                            .padding(10.dp),
                        verticalAlignment = Alignment.Top
                    ) {
                        // 1:1 Small Thumbnail on the Left
                        Box(
                            modifier = Modifier
                                .size(48.dp)
                                .clip(RoundedCornerShape(8.dp))
                                .border(1.dp, Color.White.copy(alpha = 0.15f), RoundedCornerShape(8.dp))
                                .background(Color.DarkGray)
                        ) {
                            AsyncImage(
                                model = realAttachedUri?.toString() ?: "https://images.unsplash.com/photo-1509198397868-475647b2a1e5?w=200",
                                contentDescription = null,
                                modifier = Modifier.fillMaxSize(),
                                contentScale = androidx.compose.ui.layout.ContentScale.Crop,
                                colorFilter = if (filterMatrix != null) androidx.compose.ui.graphics.ColorFilter.colorMatrix(androidx.compose.ui.graphics.ColorMatrix(filterMatrix)) else null
                            )
                        }

                        Spacer(modifier = Modifier.width(10.dp))

                        // Text Field on the Right
                        Column(modifier = Modifier.weight(1f)) {
                            Box(modifier = Modifier.height(54.dp)) {
                                BasicTextField(
                                    value = captionText,
                                    onValueChange = {
                                        val deduped = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, captionText)
                                        if (deduped.length <= 280) captionText = deduped
                                    },
                                    textStyle = LocalTextStyle.current.copy(color = Color.White, fontSize = 13.5.sp),
                                    modifier = Modifier.fillMaxSize()
                                )
                                if (captionText.isEmpty()) {
                                    Text(
                                        text = "Write a caption for your poster...",
                                        color = GrayText,
                                        fontSize = 13.sp
                                    )
                                }
                            }
                            
                            // Character count & AI Caption Enhancer
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                // AI Assistant Button
                                Box(
                                    modifier = Modifier
                                        .background(RazorTeal.copy(alpha = 0.15f), RoundedCornerShape(8.dp))
                                        .border(1.dp, RazorTeal.copy(alpha = 0.3f), RoundedCornerShape(8.dp))
                                        .clickable {
                                            val tags = listOf("#CreatorLabs", "#NeonVibe", "#Web3Hub", "#CloudPoster", "#DigitalArt")
                                            val tagString = tags.shuffled().take(3).joinToString(" ")
                                            val dynamicSentences = listOf(
                                                "Synchronizing digital waves in real-time.",
                                                "Broadcasting direct from the creative cyber matrix.",
                                                "High fidelity lifestyle drop in the cloud.",
                                                "Crafting virtual statements that push boundaries."
                                            )
                                            val line = dynamicSentences.random()
                                            captionText = if (captionText.isBlank()) {
                                                "$line $tagString ⚡"
                                            } else {
                                                "$captionText\n\n$line $tagString ✨"
                                            }
                                        }
                                        .padding(horizontal = 8.dp, vertical = 4.dp)
                                ) {
                                    Row(verticalAlignment = Alignment.CenterVertically) {
                                        Icon(imageVector = Icons.Default.AutoAwesome, contentDescription = null, tint = RazorTeal, modifier = Modifier.size(11.dp))
                                        Spacer(modifier = Modifier.width(4.dp))
                                        Text("✨ AI Cyber Caption", color = RazorTeal, fontSize = 9.sp, fontWeight = FontWeight.Black)
                                    }
                                }

                                Text(
                                    text = "${captionText.length}/280",
                                    color = if (captionText.length >= 250) Color.Red else GrayText,
                                    fontSize = 11.sp,
                                    fontFamily = FontFamily.Monospace
                                )
                            }
                        }
                    }

                    // --- HIGH PERFORMANCE MEDIA ATTACHMENT ACTION BAR ---
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .clip(RoundedCornerShape(12.dp))
                            .background(Color.Black.copy(alpha = 0.3f))
                            .border(1.dp, Color.White.copy(alpha = 0.08f), RoundedCornerShape(12.dp))
                            .padding(12.dp)
                    ) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text(
                                text = "ATTACH CREATIVE MEDIA SHOT",
                                fontSize = 10.sp,
                                fontWeight = FontWeight.Black,
                                color = RazorTeal,
                                letterSpacing = 1.sp
                            )
                            if (attachedMediaType != null) {
                                Text(
                                    text = "REMOVE ❌",
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold,
                                    color = Color.Red,
                                    modifier = Modifier.clickable {
                                        realAttachedUri = null
                                        attachedFileName = null
                                        attachedFileSizeStr = null
                                        attachedFileMimeType = null
                                        attachedMediaType = null
                                        permissionStatusMessage = null
                                    }
                                )
                            }
                        }
                        
                        Spacer(modifier = Modifier.height(8.dp))
                        
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Box(
                                modifier = Modifier
                                    .weight(1f)
                                    .clip(RoundedCornerShape(8.dp))
                                    .background(if (attachedMediaType == "attached_image" && realAttachedUri != null) RazorBlue.copy(0.15f) else Color.White.copy(0.04f))
                                    .border(1.dp, if (attachedMediaType == "attached_image" && realAttachedUri != null) RazorBlue else Color.White.copy(0.08f), RoundedCornerShape(8.dp))
                                    .clickable { tryAttach("media") }
                                    .padding(vertical = 8.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                    Icon(imageVector = Icons.Default.Collections, contentDescription = null, tint = RazorBlue, modifier = Modifier.size(16.dp))
                                    Spacer(modifier = Modifier.height(4.dp))
                                    Text("Library 📁", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            Box(
                                modifier = Modifier
                                    .weight(1f)
                                    .clip(RoundedCornerShape(8.dp))
                                    .background(if (attachedMediaType == "attached_image" && realAttachedUri == null) RazorTeal.copy(0.15f) else Color.White.copy(0.04f))
                                    .border(1.dp, if (attachedMediaType == "attached_image" && realAttachedUri == null) RazorTeal else Color.White.copy(0.08f), RoundedCornerShape(8.dp))
                                    .clickable { tryAttach("camera") }
                                    .padding(vertical = 8.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                    Icon(imageVector = Icons.Default.PhotoCamera, contentDescription = null, tint = RazorTeal, modifier = Modifier.size(16.dp))
                                    Spacer(modifier = Modifier.height(4.dp))
                                    Text("Camera 📸", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            Box(
                                modifier = Modifier
                                    .weight(1f)
                                    .clip(RoundedCornerShape(8.dp))
                                    .background(if (attachedMediaType == "attached_audio") InstaPink.copy(0.15f) else Color.White.copy(0.04f))
                                    .border(1.dp, if (attachedMediaType == "attached_audio") InstaPink else Color.White.copy(0.08f), RoundedCornerShape(8.dp))
                                    .clickable { tryAttach("mic") }
                                    .padding(vertical = 8.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                    Icon(imageVector = Icons.Default.Mic, contentDescription = null, tint = InstaPink, modifier = Modifier.size(16.dp))
                                    Spacer(modifier = Modifier.height(4.dp))
                                    Text("Voice 🎙️", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            Box(
                                modifier = Modifier
                                    .weight(1f)
                                    .clip(RoundedCornerShape(8.dp))
                                    .background(if (attachedMediaType == "attached_video") Color.Yellow.copy(0.15f) else Color.White.copy(0.04f))
                                    .border(1.dp, if (attachedMediaType == "attached_video") Color.Yellow else Color.White.copy(0.08f), RoundedCornerShape(8.dp))
                                    .clickable { tryAttach("video") }
                                    .padding(vertical = 8.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                    Icon(imageVector = Icons.Default.PlayCircle, contentDescription = null, tint = Color.Yellow, modifier = Modifier.size(16.dp))
                                    Spacer(modifier = Modifier.height(4.dp))
                                    Text("Video 📹", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }

                        if (!permissionStatusMessage.isNullOrBlank()) {
                            Spacer(modifier = Modifier.height(8.dp))
                            Text(
                                text = permissionStatusMessage!!,
                                color = if (permissionStatusMessage!!.contains("❌")) Color.Red else RazorTeal,
                                fontSize = 9.5.sp,
                                fontWeight = FontWeight.Medium
                            )
                        }
                    }

                    Spacer(modifier = Modifier.height(14.dp))

                    // 5. POST AS AUTHOR SELECTOR
                    Column(modifier = Modifier.fillMaxWidth()) {
                        Text(
                            text = "POST AS AUTHOR",
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Black,
                            color = RazorBlue,
                            letterSpacing = 1.sp
                        )
                        Spacer(modifier = Modifier.height(4.dp))
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .clip(RoundedCornerShape(12.dp))
                                .background(Color(0xFF1B1437).copy(alpha = 0.4f))
                                .border(1.dp, Color.White.copy(alpha = 0.12f), RoundedCornerShape(12.dp))
                                .clickable { showCreatorDropdown = !showCreatorDropdown }
                                .padding(horizontal = 12.dp, vertical = 10.dp)
                        ) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Box(
                                        modifier = Modifier
                                            .size(28.dp)
                                            .clip(CircleShape)
                                            .background(if (selectedCreator == null) RazorBlue else RazorTeal),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(
                                            text = selectedCreator?.name?.take(2) ?: "ME",
                                            color = Color.Black,
                                            fontWeight = FontWeight.Bold,
                                            fontSize = 11.sp
                                        )
                                    }
                                    Spacer(modifier = Modifier.width(10.dp))
                                    Column {
                                        Text(
                                            text = selectedCreator?.name ?: "Current User Profile (Me)",
                                            color = Color.White,
                                            fontWeight = FontWeight.Bold,
                                            fontSize = 12.5.sp
                                        )
                                        Text(
                                            text = "@${selectedCreator?.handle ?: "me"}",
                                            color = GrayText,
                                            fontSize = 10.5.sp
                                        )
                                    }
                                }
                                Icon(
                                    imageVector = if (showCreatorDropdown) Icons.Default.ArrowDropUp else Icons.Default.ArrowDropDown,
                                    contentDescription = null,
                                    tint = Color.White
                                )
                            }
                        }

                        if (showCreatorDropdown) {
                            Card(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(top = 4.dp)
                                    .heightIn(max = 160.dp),
                                shape = RoundedCornerShape(12.dp),
                                colors = CardDefaults.cardColors(containerColor = Color(0xFF1B1437)),
                                border = BorderStroke(1.dp, RazorTeal.copy(alpha = 0.3f))
                            ) {
                                LazyColumn {
                                    item {
                                        Row(
                                            modifier = Modifier
                                                .fillMaxWidth()
                                                .clickable {
                                                    selectedCreator = null
                                                    showCreatorDropdown = false
                                                }
                                                .padding(horizontal = 12.dp, vertical = 8.dp),
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            Box(
                                                modifier = Modifier
                                                    .size(24.dp)
                                                    .clip(CircleShape)
                                                    .background(RazorBlue),
                                                contentAlignment = Alignment.Center
                                            ) {
                                                Text("ME", color = Color.Black, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                            }
                                            Spacer(modifier = Modifier.width(10.dp))
                                            Text("Current User (Me)", color = Color.White, fontSize = 12.sp)
                                        }
                                    }

                                    items(creators) { creator ->
                                        Row(
                                            modifier = Modifier
                                                .fillMaxWidth()
                                                .clickable {
                                                    selectedCreator = creator
                                                    showCreatorDropdown = false
                                                }
                                                .padding(horizontal = 12.dp, vertical = 8.dp),
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            Box(
                                                modifier = Modifier
                                                    .size(24.dp)
                                                    .clip(CircleShape)
                                                    .background(RazorTeal),
                                                contentAlignment = Alignment.Center
                                            ) {
                                                Text(creator.name.take(2).uppercase(), color = Color.Black, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                            }
                                            Spacer(modifier = Modifier.width(10.dp))
                                            Column {
                                                Text(creator.name, color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                                Text("@${creator.handle}", color = GrayText, fontSize = 10.sp)
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }




                }
            }
        }
    }
}

@Composable
fun StoriesBar(
    snaps: List<CreatorSnap>,
    subscriptions: List<Subscription>,
    onSnapClick: (CreatorSnap) -> Unit,
    onCreateStoryClick: () -> Unit,
    userVibeIndex: Int = 0
) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 14.dp, vertical = 6.dp),
        shape = RoundedCornerShape(24.dp),
        colors = CardDefaults.cardColors(containerColor = Color(0xFF130E26).copy(alpha = 0.5f)),
        border = BorderStroke(1.2.dp, Brush.linearGradient(listOf(Color.White.copy(alpha = 0.12f), Color.White.copy(alpha = 0.02f))))
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(vertical = 12.dp)
        ) {
            LazyRow(
                contentPadding = PaddingValues(horizontal = 14.dp),
                horizontalArrangement = Arrangement.spacedBy(16.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                // Your Shot (with + click button) - Page 1
                item {
                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        modifier = Modifier.bounceClick { onCreateStoryClick() }
                    ) {
                        Box(modifier = Modifier.size(72.dp)) {
                            // Profile Avatar Frame
                            Box(
                                modifier = Modifier
                                    .size(64.dp)
                                    .clip(CircleShape)
                                    .background(
                                        Brush.linearGradient(
                                            colors = listOf(Color(0xFF2E1B4E), Color(0xFF100B26))
                                        )
                                    )
                                    .border(
                                        width = 3.dp,
                                        brush = when (userVibeIndex) {
                                            1 -> Brush.linearGradient(colors = listOf(Color(0xFFFF007F), Color(0xFFFF5E62))) // Love Neon Vibe
                                            2 -> Brush.linearGradient(colors = listOf(Color(0xFF00FFCC), Color(0xFF3A7BD5))) // Deep Sea Vibe
                                            3 -> Brush.linearGradient(colors = listOf(Color(0xFFFFB300), Color(0xFFF7797D))) // Cosmic Sunset
                                            4 -> Brush.linearGradient(colors = listOf(Color(0xFF8A2387), Color(0xFFE94057))) // Matrix Aura
                                            else -> Brush.linearGradient(colors = listOf(RazorTeal, RazorBlue)) // Default Aura
                                        },
                                        shape = CircleShape
                                    ),
                                contentAlignment = Alignment.Center
                            ) {
                                Box(
                                    modifier = Modifier
                                        .size(54.dp)
                                        .clip(CircleShape)
                                        .background(Color(0xFF1B153B)),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text(
                                        "YOU", 
                                        color = RazorTeal, 
                                        fontWeight = FontWeight.Black, 
                                        fontSize = 13.sp, 
                                        letterSpacing = 1.sp,
                                        fontFamily = FontFamily.SansSerif
                                    )
                                }
                            }
                            // Plus Badge Circle - Page 1
                            Box(
                                modifier = Modifier
                                    .size(22.dp)
                                    .clip(CircleShape)
                                    .background(RazorTeal)
                                    .border(2.dp, ObsidianDark, CircleShape)
                                    .align(Alignment.BottomEnd),
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(imageVector = Icons.Default.Add, contentDescription = "Add Shot", tint = Color.Black, modifier = Modifier.size(14.dp))
                            }
                        }
                        Spacer(modifier = Modifier.height(6.dp))
                        Text(
                            text = "Your Shot", 
                            color = Color.White, 
                            fontSize = 11.sp, 
                            fontWeight = FontWeight.ExtraBold,
                            letterSpacing = 0.2.sp
                        )
                    }
                }

                // Dynamic Creator Snaps listed as Shots! Like Instagram stories.
                items(snaps) { snap ->
                    val hasSubscription = subscriptions.any {
                        it.creatorId == snap.creatorId &&
                        (it.tierName == "GOLD" || 
                         (it.tierName == "SILVER" && snap.requiredTier != "GOLD") || 
                         (it.tierName == "BRONZE" && snap.requiredTier == "BRONZE"))
                    }
                    val isLocked = false // Premium lock removed for stories/shots as requested

                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        modifier = Modifier.bounceClick { onSnapClick(snap) }
                    ) {
                        Box(
                            modifier = Modifier
                                .size(72.dp)
                                .padding(2.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            // Glowing ring around Shot avatar
                            Box(
                                modifier = Modifier
                                    .size(68.dp)
                                    .clip(CircleShape)
                                    .background(Color.Transparent)
                                    .border(
                                        width = 2.5.dp,
                                        brush = Brush.linearGradient(
                                            colors = if (isLocked) listOf(InstaPink, LightText.copy(alpha = 0.2f))
                                                    else listOf(RazorTeal, RazorBlue)
                                        ),
                                        shape = CircleShape
                                    ),
                                contentAlignment = Alignment.Center
                            ) {
                                Box(
                                    modifier = Modifier
                                        .size(58.dp)
                                        .clip(CircleShape)
                                        .background(Color(0xFF130E22)),
                                    contentAlignment = Alignment.Center
                                ) {
                                    AsyncImage(
                                        model = snap.creatorAvatar,
                                        contentDescription = "Shot Avatar",
                                        modifier = Modifier
                                            .fillMaxSize()
                                            .alpha(if (isLocked) 0.5f else 0.95f),
                                        contentScale = ContentScale.Crop
                                    )
                                }
                            }

                            // Lock indicator badge on top of glowing avatar boundary
                            if (isLocked) {
                                Box(
                                    modifier = Modifier
                                        .size(18.dp)
                                        .clip(CircleShape)
                                        .background(InstaPink)
                                        .align(Alignment.BottomEnd),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Lock,
                                        contentDescription = "Locked Shot",
                                        tint = Color.Black,
                                        modifier = Modifier.size(10.dp)
                                    )
                                }
                            }
                        }
                        Spacer(modifier = Modifier.height(6.dp))
                        Text(
                            text = snap.creatorName.split(" ").firstOrNull() ?: snap.creatorHandle,
                            color = if (isLocked) LightText.copy(alpha = 0.7f) else Color.White,
                            fontSize = 11.sp,
                            fontWeight = if (isLocked) FontWeight.Medium else FontWeight.ExtraBold,
                            maxLines = 1,
                            overflow = TextOverflow.Ellipsis
                        )
                    }
                }
            }
        }
    }
}

@Composable
fun PostCard(
    post: Post,
    isLocked: Boolean,
    onLike: () -> Unit,
    onTip: (Double) -> Unit,
    onUnlock: () -> Unit,
    onCreatorClick: () -> Unit = {},
    isCreatorVerified: Boolean = true,
    onVideoClick: (() -> Unit)? = null,
    isActiveVideo: Boolean = false,
    isInViewport: Boolean = true
) {
    var isLikedLocal by remember(post.id, post.isLiked) { mutableStateOf(post.isLiked) }
    var likesCountLocal by remember(post.id, post.likesCount) { mutableStateOf(post.likesCount) }
    val scale = remember { Animatable(1f) }
    val commentScale = remember { Animatable(1f) }
    val commentRotation = remember { Animatable(0f) }
    val coroutineScope = rememberCoroutineScope()

    var commentsCount by remember(post.id) { mutableStateOf(84) }
    var showCommentsDialog by remember { mutableStateOf(false) }
    var showShareDialog by remember { mutableStateOf(false) }
    var showTipModal by remember { mutableStateOf(false) }

    val interactionSource = remember { androidx.compose.foundation.interaction.MutableInteractionSource() }
    val isHovered by interactionSource.collectIsHoveredAsState()
    val hoverScale by androidx.compose.animation.core.animateFloatAsState(
        targetValue = if (isHovered) 1.02f else 1f,
        animationSpec = androidx.compose.animation.core.spring(dampingRatio = androidx.compose.animation.core.Spring.DampingRatioMediumBouncy, stiffness = androidx.compose.animation.core.Spring.StiffnessLow),
        label = "hoverScale"
    )

    val commentsList = remember(post.id) {
        mutableStateListOf<String>().apply {
            when (post.creatorId) {
                "alex_johnson" -> {
                    addAll(listOf(
                        "This espresso pull looks incredibly clean! ☕️",
                        "What origin coffee beans is this? Savoring it!",
                        "Awesome latte art patterns. Always a masterclass.",
                        "The crema consistency is amazing. Next level."
                    ))
                }
                "aura_music" -> {
                    addAll(listOf(
                        "This ambient synth line is magnificent! 🌌🎹",
                        "Which oscillator waveform did you tune?",
                        "Perfect background study tracks right here.",
                        "Beautiful synthwave sunset frequencies."
                    ))
                }
                "alex_future" -> {
                    addAll(listOf(
                        "Superb market analysis. Bronze tier is so valuable! 📈",
                        "What is your forecast for NVIDIA silicon targets this month?",
                        "Excellent detail. Incredibly crisp charts.",
                        "Substantial financial reports as always."
                    ))
                }
                else -> {
                    addAll(listOf(
                        "This looks like pristine digital craft! ✨⚡️",
                        "Incredible, love the cyberpunk tech vibe.",
                        "Looking forward to the next update!",
                        "Superb layout and visual content."
                    ))
                }
            }
        }
    }
    
    // Sync comments count
    LaunchedEffect(commentsList.size) {
        commentsCount = commentsList.size
    }

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 14.dp, vertical = 8.dp)
            .scale(hoverScale)
            .hoverable(interactionSource),
        shape = RoundedCornerShape(24.dp),
        colors = CardDefaults.cardColors(containerColor = CardBackground),
        border = BorderStroke(1.dp, MinimalBorder)
    ) {
        Column(modifier = Modifier.fillMaxWidth()) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(14.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                // Profile Avatar Circular Indicator with ultra-polished pink-orange fluid gradient border
                Box(
                    modifier = Modifier
                        .size(44.dp)
                        .clip(CircleShape)
                        .background(
                            Brush.linearGradient(
                                colors = listOf(RazorBlue, InstaPink)
                            )
                        )
                        .clickable { onCreatorClick() }
                        .padding(2.5.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Box(
                        modifier = Modifier
                            .fillMaxSize()
                            .clip(CircleShape)
                            .background(ObsidianDark),
                        contentAlignment = Alignment.Center
                    ) {
                        if (post.creatorAvatar.startsWith("http")) {
                            AsyncImage(
                                model = post.creatorAvatar,
                                contentDescription = "Creator Avatar",
                                modifier = Modifier.fillMaxSize(),
                                contentScale = ContentScale.Crop
                            )
                        } else {
                            Text(
                                text = post.creatorName.take(1).uppercase(),
                                fontWeight = FontWeight.ExtraBold,
                                color = InstaPink,
                                fontSize = 15.sp
                            )
                        }
                    }
                }
                Spacer(modifier = Modifier.width(10.dp))
                Column(
                    modifier = Modifier.clickable { onCreatorClick() }
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Text(
                            text = post.creatorName,
                            style = MaterialTheme.typography.titleMedium,
                            fontWeight = FontWeight.Bold,
                            color = LightText
                        )
                        if (isCreatorVerified) {
                            Spacer(modifier = Modifier.width(4.dp))
                            Icon(
                                imageVector = Icons.Default.CheckCircle,
                                contentDescription = "Verified status checked",
                                tint = RazorTeal,
                                modifier = Modifier.size(15.dp)
                            )
                        }
                    }
                    Text(
                        text = "2 hours ago • San Francisco",
                        style = MaterialTheme.typography.bodySmall,
                        color = GrayText
                    )
                }
                Spacer(modifier = Modifier.weight(1f))
                Icon(imageVector = Icons.Default.MoreHoriz, contentDescription = "More Options", tint = LightText)
            }

            if (isLocked) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .aspectRatio(1.25f)
                        .background(
                            Brush.radialGradient(
                                colors = listOf(MinimalLavenderContainer, ObsidianDark)
                            )
                        ),
                    contentAlignment = Alignment.Center
                ) {
                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        modifier = Modifier.padding(24.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Default.Lock,
                            contentDescription = "Hidden post contents",
                            tint = InstaPink,
                            modifier = Modifier.size(50.dp)
                        )
                        Spacer(modifier = Modifier.height(12.dp))
                        Text(
                            text = "Premium Locked Content",
                            style = MaterialTheme.typography.titleMedium,
                            fontWeight = FontWeight.ExtraBold,
                            color = LightText
                        )
                        Spacer(modifier = Modifier.height(4.dp))
                        Text(
                            text = "Unlock this subscriber post via secure premium routing subscription.",
                            style = MaterialTheme.typography.bodySmall,
                            color = GrayText,
                            textAlign = TextAlign.Center
                        )
                        Spacer(modifier = Modifier.height(14.dp))
                        Button(
                            onClick = onUnlock,
                            colors = ButtonDefaults.buttonColors(containerColor = RazorBlue),
                            shape = RoundedCornerShape(20.dp),
                            modifier = Modifier.testTag("unlock_sub_button")
                        ) {
                            Text("Unlock Portfolio Post", fontWeight = FontWeight.Black, color = Color.Black)
                        }
                    }
                }
            } else {
                var heartVisible by remember { mutableStateOf(false) }
                val heartScale = remember { Animatable(0f) }

                var isPlayingInline by remember { mutableStateOf(false) }
                var showControls by remember { mutableStateOf(false) }
                var isMutedInline by remember { mutableStateOf(false) }
                var videoProgress by remember { mutableStateOf(0f) }
                var isDragging by remember { mutableStateOf(false) }
                var controlTimerJob by remember { mutableStateOf<kotlinx.coroutines.Job?>(null) }
                var isBuffering by remember { mutableStateOf(false) }

                LaunchedEffect(isActiveVideo, isInViewport) {
                    if (!isInViewport) {
                        isPlayingInline = false
                    } else {
                        isPlayingInline = isActiveVideo
                    }
                }

                // Simulate buffering when video starts playing or is active and in viewport
                LaunchedEffect(isPlayingInline, isInViewport) {
                    if (isPlayingInline && isInViewport) {
                        isBuffering = true
                        delay(1200) // 1.2 second loading/buffering spinner simulation
                        isBuffering = false
                    } else {
                        isBuffering = false
                    }
                }

                LaunchedEffect(isDragging) {
                    if (!isDragging && isPlayingInline && isInViewport) {
                        isBuffering = true
                        delay(700) // Shorter buffer on drag/seek release
                        isBuffering = false
                    }
                }

                // Smooth playback ticker - ONLY active when in viewport and not buffering
                LaunchedEffect(isPlayingInline, isBuffering, isInViewport) {
                    if (isPlayingInline && !isBuffering && isInViewport) {
                        var lastTime = System.currentTimeMillis()
                        while (isPlayingInline && !isBuffering && isInViewport) {
                            delay(16)
                            if (!isDragging) {
                                val now = System.currentTimeMillis()
                                val elapsed = now - lastTime
                                videoProgress = (videoProgress + (elapsed.toFloat() / 12000f)) % 1.0f
                                lastTime = now
                            } else {
                                lastTime = System.currentTimeMillis()
                            }
                        }
                    }
                }

                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .aspectRatio(1.25f)
                        .background(Color(0xFF130E22))
                        .pointerInput(post.id) {
                            detectTapGestures(
                                onTap = {
                                    if (post.contentImage == "attached_video") {
                                        if (!isPlayingInline) {
                                            isPlayingInline = true
                                            showControls = true
                                            controlTimerJob?.cancel()
                                            controlTimerJob = coroutineScope.launch {
                                                delay(5000)
                                                showControls = false
                                            }
                                        } else {
                                            showControls = !showControls
                                            if (showControls) {
                                                controlTimerJob?.cancel()
                                                controlTimerJob = coroutineScope.launch {
                                                    delay(5000)
                                                    showControls = false
                                                }
                                            }
                                        }
                                    }
                                },
                                onDoubleTap = { offset ->
                                    if (!isLikedLocal) {
                                        isLikedLocal = true
                                        likesCountLocal += 1
                                        onLike()
                                    }
                                    coroutineScope.launch {
                                        heartVisible = true
                                        heartScale.snapTo(0f)
                                        heartScale.animateTo(
                                            1.5f,
                                            animationSpec = spring(
                                                dampingRatio = Spring.DampingRatioHighBouncy,
                                                stiffness = Spring.StiffnessMedium
                                            )
                                        )
                                        delay(500)
                                        heartScale.animateTo(0f, animationSpec = tween(200))
                                        heartVisible = false
                                    }
                                }
                            )
                        }
                ) {
                    val firstImage = if (post.contentImage.contains(",")) {
                        post.contentImage.split(",").firstOrNull() ?: post.contentImage
                    } else {
                        post.contentImage
                    }

                    val imageUrl = if (firstImage.startsWith("http") || firstImage.startsWith("content:") || firstImage.startsWith("file:")) {
                        firstImage
                    } else {
                        when (firstImage) {
                            "latte_art" -> "https://images.unsplash.com/photo-1541167760496-1628856ab772?w=800&auto=format&fit=crop&q=80"
                            "music_studio" -> "https://images.unsplash.com/photo-1598488035139-bdbb2231ce04?w=800&auto=format&fit=crop&q=80"
                            "attached_image" -> "https://images.unsplash.com/photo-1509198397868-475647b2a1e5?w=800&auto=format&fit=crop&q=80"
                            "attached_audio" -> "https://images.unsplash.com/photo-1484755560695-a4c68e910a14?w=800&auto=format&fit=crop&q=80"
                            "attached_video" -> "https://images.unsplash.com/photo-1492691527719-9d1e07e534b4?w=800&auto=format&fit=crop&q=80"
                            else -> "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?w=800&auto=format&fit=crop&q=80"
                        }
                    }

                    AsyncImage(
                        model = imageUrl,
                        contentDescription = "Post Content Image",
                        modifier = Modifier.fillMaxSize().alpha(if (isPlayingInline) 0.85f else 0.95f),
                        contentScale = ContentScale.Crop
                    )

                    // If it contains multiple images, draw a beautiful multi-photo badge indicator
                    if (post.contentImage.contains(",")) {
                        val imgCount = post.contentImage.split(",").size
                        Box(
                            modifier = Modifier
                                .align(Alignment.TopEnd)
                                .padding(12.dp)
                                .background(Color.Black.copy(0.6f), RoundedCornerShape(8.dp))
                                .border(1.dp, RazorTeal.copy(0.4f), RoundedCornerShape(8.dp))
                                .padding(horizontal = 8.dp, vertical = 4.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                Icon(
                                    imageVector = Icons.Default.Collections,
                                    contentDescription = "Multiple pictures",
                                    tint = RazorTeal,
                                    modifier = Modifier.size(12.dp)
                                )
                                Text(
                                    text = "1/$imgCount",
                                    color = Color.White,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }

                    Canvas(modifier = Modifier.fillMaxSize()) {
                        val canvasWidth = size.width
                        val canvasHeight = size.height
                        
                        when (post.contentImage) {
                            "attached_image" -> {
                                // Cyber focus target design
                                val cx = canvasWidth / 2
                                val cy = canvasHeight / 2
                                drawCircle(
                                    color = RazorBlue.copy(alpha = 0.2f),
                                    radius = 100.dp.toPx(),
                                    center = Offset(cx, cy)
                                )
                                drawCircle(
                                    color = RazorTeal,
                                    radius = 70.dp.toPx(),
                                    center = Offset(cx, cy),
                                    style = Stroke(width = 2.dp.toPx())
                                )
                                drawCircle(
                                    color = RazorTeal.copy(alpha = 0.5f),
                                    radius = 12.dp.toPx(),
                                    center = Offset(cx, cy)
                                )
                                // Crosshairs
                                drawLine(color = RazorTeal, start = Offset(cx - 90.dp.toPx(), cy), end = Offset(cx - 30.dp.toPx(), cy), strokeWidth = 3f)
                                drawLine(color = RazorTeal, start = Offset(cx + 30.dp.toPx(), cy), end = Offset(cx + 90.dp.toPx(), cy), strokeWidth = 3f)
                                drawLine(color = RazorTeal, start = Offset(cx, cy - 90.dp.toPx()), end = Offset(cx, cy - 30.dp.toPx()), strokeWidth = 3f)
                                drawLine(color = RazorTeal, start = Offset(cx, cy + 30.dp.toPx()), end = Offset(cx, cy + 90.dp.toPx()), strokeWidth = 3f)
                                
                                // corner brackets
                                drawLine(color = RazorBlue, start = Offset(10.dp.toPx(), 10.dp.toPx()), end = Offset(40.dp.toPx(), 10.dp.toPx()), strokeWidth = 5f)
                                drawLine(color = RazorBlue, start = Offset(10.dp.toPx(), 10.dp.toPx()), end = Offset(10.dp.toPx(), 40.dp.toPx()), strokeWidth = 5f)
                                drawLine(color = RazorBlue, start = Offset(canvasWidth - 40.dp.toPx(), 10.dp.toPx()), end = Offset(canvasWidth - 10.dp.toPx(), 10.dp.toPx()), strokeWidth = 5f)
                                drawLine(color = RazorBlue, start = Offset(canvasWidth - 10.dp.toPx(), 10.dp.toPx()), end = Offset(canvasWidth - 10.dp.toPx(), 40.dp.toPx()), strokeWidth = 5f)
                            }
                            "attached_audio" -> {
                                // Pulse frequency equalizer bars
                                val centerY = canvasHeight / 2
                                val barCount = 18
                                val gap = canvasWidth / (barCount + 1)
                                val baseHeights = listOf(30, 80, 110, 40, 90, 130, 150, 70, 100, 120, 80, 50, 90, 130, 110, 40, 60, 30)
                                for (i in 0 until barCount) {
                                    val barX = gap * (i + 1)
                                    val barH = baseHeights[i % baseHeights.size].dp.toPx()
                                    drawLine(
                                        color = RazorTeal,
                                        start = Offset(barX, centerY - barH / 2),
                                        end = Offset(barX, centerY + barH / 2),
                                        strokeWidth = 6.dp.toPx()
                                    )
                                }
                            }
                            "attached_video" -> {
                                if (!isPlayingInline) {
                                    val cx = canvasWidth / 2
                                    val cy = canvasHeight / 2
                                    
                                    // top segment
                                    drawRect(
                                        color = Color.Black.copy(alpha = 0.5f),
                                        topLeft = Offset(0f, 0f),
                                        size = androidx.compose.ui.geometry.Size(canvasWidth, 30.dp.toPx())
                                    )
                                    // bottom segment
                                    drawRect(
                                        color = Color.Black.copy(alpha = 0.5f),
                                        topLeft = Offset(0f, canvasHeight - 30.dp.toPx()),
                                        size = androidx.compose.ui.geometry.Size(canvasWidth, 30.dp.toPx())
                                    )
                                    
                                    // triangle play
                                    val path = Path().apply {
                                        val side = 35.dp.toPx()
                                        val startX = cx - side / 3
                                        val startY = cy - side / 2
                                        moveTo(startX, startY)
                                        lineTo(startX + side, cy)
                                        lineTo(startX, startY + side)
                                        close()
                                    }
                                    drawPath(path = path, color = InstaPink)
                                    drawCircle(
                                        color = InstaPink,
                                        radius = 32.dp.toPx(),
                                        center = Offset(cx, cy),
                                        style = Stroke(width = 3.dp.toPx())
                                    )
                                } else {
                                    // Live Instagram-style equalizer waves when playing
                                    if (!isMutedInline) {
                                        val count = 12
                                        val gap = canvasWidth / (count + 1)
                                        val pulse = videoProgress
                                        for (i in 0 until count) {
                                            val barX = gap * (i + 1)
                                            val waveFactor = kotlin.math.sin((i * 0.4f + pulse * 2 * 3.14159f).toDouble()).toFloat()
                                            val barHeight = (25.dp.toPx() + 20.dp.toPx() * waveFactor)
                                            drawLine(
                                                color = RazorTeal.copy(alpha = 0.7f),
                                                start = Offset(barX, canvasHeight - 40.dp.toPx() - barHeight / 2),
                                                end = Offset(barX, canvasHeight - 40.dp.toPx() + barHeight / 2),
                                                strokeWidth = 3.dp.toPx()
                                            )
                                        }
                                    }
                                }
                            }
                            "latte_art" -> {
                                // Draw stylized coffee cup and espresso vector art on canvas - Page 1
                                val cupCenter = Offset(canvasWidth / 2, canvasHeight / 2)
                                val cupRadius = 90.dp.toPx()
                                
                                // Cup Shadow Background
                                drawCircle(
                                    color = Color(0xFF5D4037).copy(alpha = 0.6f),
                                    radius = cupRadius + 20f,
                                    center = cupCenter
                                )
                                // Cup Frame
                                drawCircle(
                                    color = Color(0xFFECEFF1),
                                    radius = cupRadius,
                                    center = cupCenter,
                                    style = Stroke(width = 8.dp.toPx())
                                )
                                // Espresso fill
                                drawCircle(
                                    color = Color(0xFF3E2723),
                                    radius = cupRadius - 5.dp.toPx(),
                                    center = cupCenter
                                )
                                // Crema Swirl Latte Art Details
                                for (i in 1..4) {
                                    drawCircle(
                                        color = Color(0xFFD7CCC8).copy(alpha = 0.2f * i),
                                        radius = (i * 18).dp.toPx(),
                                        center = cupCenter,
                                        style = Stroke(width = 4.dp.toPx())
                                    )
                                }
                            }
                            "music_studio" -> {
                                for (i in 0..10) {
                                    drawLine(
                                        color = Color.White.copy(alpha = 0.08f),
                                        start = Offset((canvasWidth / 10) * i, 0f),
                                        end = Offset((canvasWidth / 10) * i, canvasHeight),
                                        strokeWidth = 2f
                                    )
                                }
                                val pathPoints = listOf(
                                    Offset(0f, canvasHeight * 0.7f),
                                    Offset(canvasWidth * 0.2f, canvasHeight * 0.4f),
                                    Offset(canvasWidth * 0.4f, canvasHeight * 0.8f),
                                    Offset(canvasWidth * 0.6f, canvasHeight * 0.3f),
                                    Offset(canvasWidth * 0.8f, canvasHeight * 0.6f),
                                    Offset(canvasWidth, canvasHeight * 0.5f)
                                )
                                for (i in 0 until pathPoints.size - 1) {
                                    drawLine(
                                        color = RazorBlue,
                                        start = pathPoints[i],
                                        end = pathPoints[i+1],
                                        strokeWidth = 6f
                                    )
                                }
                            }
                            else -> {
                                drawLine(
                                    color = Color.White.copy(alpha = 0.05f),
                                    start = Offset(0f, 0f),
                                    end = Offset(canvasWidth, canvasHeight),
                                    strokeWidth = 5f
                                )
                            }
                        }
                    }

                    // Floating overlays depending on content resource types
                    if (post.contentImage == "attached_image") {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            modifier = Modifier
                                .align(Alignment.BottomEnd)
                                .padding(14.dp)
                                .clip(RoundedCornerShape(6.dp))
                                .background(ObsidianDark.copy(alpha = 0.75f))
                                .padding(horizontal = 8.dp, vertical = 4.dp)
                        ) {
                            Icon(imageVector = Icons.Default.CheckCircle, contentDescription = "Camera check", tint = RazorTeal, modifier = Modifier.size(12.dp))
                            Spacer(modifier = Modifier.width(4.dp))
                            Text(text = "LIVE SNAPSHOT 4K", color = RazorTeal, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                        }
                    } else if (post.contentImage == "attached_audio") {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            modifier = Modifier
                                .align(Alignment.Center)
                                .clip(RoundedCornerShape(30.dp))
                                .background(Color.Black.copy(alpha = 0.8f))
                                .padding(horizontal = 16.dp, vertical = 8.dp)
                        ) {
                            Icon(imageVector = Icons.Default.PlayCircle, contentDescription = "Play sound stream", tint = RazorTeal, modifier = Modifier.size(20.dp))
                            Spacer(modifier = Modifier.width(8.dp))
                            Text(text = "PLAY SOUND LOG (0:42)", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                        }
                    } else if (post.contentImage == "attached_video") {
                        // Always-visible Speaker Icon Toggle in Top-Right Corner
                        IconButton(
                            onClick = {
                                isMutedInline = !isMutedInline
                                controlTimerJob?.cancel()
                                controlTimerJob = coroutineScope.launch {
                                    delay(5000)
                                    showControls = false
                                }
                            },
                            modifier = Modifier
                                .align(Alignment.TopEnd)
                                .padding(12.dp)
                                .size(32.dp)
                                .background(Color.Black.copy(alpha = 0.6f), CircleShape)
                        ) {
                            Icon(
                                imageVector = if (isMutedInline) Icons.AutoMirrored.Filled.VolumeOff else Icons.AutoMirrored.Filled.VolumeUp,
                                contentDescription = "Speaker Toggle Corner",
                                tint = if (isMutedInline) Color.Red else RazorTeal,
                                modifier = Modifier.size(16.dp)
                            )
                        }

                        VideoPlayerControls(
                            isPlayingInline = isPlayingInline,
                            isMutedInline = isMutedInline,
                            showControls = showControls,
                            progressProvider = { videoProgress },
                            isDragging = isDragging,
                            onProgressChange = { videoProgress = it },
                            onDraggingChange = { isDragging = it },
                            onMuteToggle = {
                                isMutedInline = !isMutedInline
                                controlTimerJob?.cancel()
                                controlTimerJob = coroutineScope.launch {
                                    delay(5000)
                                    showControls = false
                                }
                            },
                            onPlayPauseToggle = {
                                isPlayingInline = !isPlayingInline
                                controlTimerJob?.cancel()
                                controlTimerJob = coroutineScope.launch {
                                    delay(5000)
                                    showControls = false
                                }
                            },
                            onFullScreenClick = if (onVideoClick != null) { { onVideoClick.invoke() } } else null
                        )

                        if (!isPlayingInline) {
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                modifier = Modifier
                                    .align(Alignment.BottomStart)
                                    .padding(14.dp)
                                    .clip(RoundedCornerShape(6.dp))
                                    .background(ObsidianDark.copy(alpha = 0.75f))
                                    .padding(horizontal = 8.dp, vertical = 4.dp)
                            ) {
                                Box(modifier = Modifier.size(8.dp).clip(CircleShape).background(Color.Red))
                                Spacer(modifier = Modifier.width(6.dp))
                                Text(text = "HIGH-FI STREAM ACTIVE", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        if (isBuffering) {
                            Box(
                                modifier = Modifier
                                    .fillMaxSize()
                                    .background(Color.Black.copy(alpha = 0.45f)),
                                contentAlignment = Alignment.Center
                            ) {
                                CircularProgressIndicator(
                                    color = RazorTeal,
                                    strokeWidth = 3.dp,
                                    modifier = Modifier.size(36.dp)
                                )
                            }
                        }

                        // Duration tags removed as requested
                    }

                    // Page 1 Floating tag for Brand Location coffee place
                    if (post.contentImage == "latte_art") {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            modifier = Modifier
                                .align(Alignment.BottomStart)
                                .padding(14.dp)
                                .clip(RoundedCornerShape(6.dp))
                                .background(ObsidianDark.copy(alpha = 0.75f))
                                .padding(horizontal = 8.dp, vertical = 4.dp)
                        ) {
                            Icon(imageVector = Icons.Default.LocalOffer, contentDescription = "Tag symbol", tint = RazorTeal, modifier = Modifier.size(12.dp))
                            Spacer(modifier = Modifier.width(4.dp))
                            Text(text = "Blue Bottle", color = RazorTeal, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                        }
                    }

                    // Double-tap Pop heart overlay animation
                    if (heartVisible) {
                        Icon(
                            imageVector = Icons.Default.Favorite,
                            contentDescription = "Double tap heart animation",
                            tint = Color(0xFFFF2D7F),
                            modifier = Modifier
                                .size(100.dp)
                                .align(Alignment.Center)
                                .graphicsLayer {
                                    scaleX = heartScale.value
                                    scaleY = heartScale.value
                                }
                        )
                    }
                }
            }

            Text(
                text = post.caption,
                style = MaterialTheme.typography.bodyMedium,
                color = LightText,
                modifier = Modifier.padding(14.dp)
            )

            // Dynamic bottom row items - Page 1
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 14.dp, vertical = 10.dp),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    modifier = Modifier
                        .clip(RoundedCornerShape(8.dp))
                        .clickable {
                            isLikedLocal = !isLikedLocal
                            if (isLikedLocal) {
                                likesCountLocal += 1
                            } else {
                                likesCountLocal -= 1
                            }
                            onLike()
                            coroutineScope.launch {
                                scale.snapTo(1f)
                                scale.animateTo(
                                    targetValue = 1.4f,
                                    animationSpec = spring(
                                        dampingRatio = Spring.DampingRatioHighBouncy,
                                        stiffness = Spring.StiffnessMedium
                                    )
                                )
                                scale.animateTo(
                                    targetValue = 1f,
                                    animationSpec = spring(
                                        dampingRatio = Spring.DampingRatioMediumBouncy,
                                        stiffness = Spring.StiffnessLow
                                    )
                                )
                            }
                        }
                        .padding(horizontal = 8.dp, vertical = 4.dp)
                ) {
                    Icon(
                        imageVector = if (isLikedLocal) Icons.Default.Favorite else Icons.Outlined.FavoriteBorder,
                        contentDescription = "Like button",
                        tint = if (isLikedLocal) InstaPink else GrayText,
                        modifier = Modifier
                            .graphicsLayer {
                                scaleX = scale.value
                                scaleY = scale.value
                            }
                            .size(22.dp)
                    )
                    Spacer(modifier = Modifier.width(6.dp))
                    Text(
                        text = if (likesCountLocal >= 1000) {
                            String.format("%.1fk", likesCountLocal / 1000.0)
                        } else {
                            likesCountLocal.toString()
                        },
                        color = LightText,
                        fontWeight = FontWeight.Bold,
                        fontSize = 13.sp
                    )
                }

                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    modifier = Modifier
                        .clip(RoundedCornerShape(8.dp))
                        .clickable {
                            showCommentsDialog = true
                            coroutineScope.launch {
                                launch {
                                    commentScale.snapTo(1f)
                                    commentScale.animateTo(1.3f, spring(dampingRatio = Spring.DampingRatioHighBouncy))
                                    commentScale.animateTo(1f, spring(dampingRatio = Spring.DampingRatioMediumBouncy))
                                }
                                launch {
                                    commentRotation.snapTo(0f)
                                    commentRotation.animateTo(15f, tween(100))
                                    commentRotation.animateTo(-15f, tween(100))
                                    commentRotation.animateTo(0f, tween(100))
                                }
                            }
                        }
                        .padding(horizontal = 8.dp, vertical = 4.dp)
                ) {
                    Icon(
                        imageVector = Icons.Default.ChatBubbleOutline, 
                        contentDescription = "Comments button", 
                        tint = GrayText, 
                        modifier = Modifier
                            .graphicsLayer {
                                scaleX = commentScale.value
                                scaleY = commentScale.value
                                rotationZ = commentRotation.value
                            }
                            .size(20.dp)
                    )
                    Spacer(modifier = Modifier.width(6.dp))
                    Text(text = "$commentsCount", color = LightText, fontWeight = FontWeight.Bold, fontSize = 13.sp)
                }

                IconButton(
                    onClick = { showShareDialog = true },
                    modifier = Modifier.size(36.dp)
                ) {
                    Icon(
                        imageVector = Icons.Default.Share,
                        contentDescription = "Share post",
                        tint = LightText,
                        modifier = Modifier.size(20.dp)
                    )
                }
            }

            Text(
                text = "View all $commentsCount comments",
                style = MaterialTheme.typography.bodySmall,
                color = GrayText,
                modifier = Modifier
                    .clip(RoundedCornerShape(4.dp))
                    .clickable {
                        showCommentsDialog = true
                    }
                    .padding(start = 14.dp, bottom = 14.dp, top = 2.dp, end = 14.dp)
            )
        }
    }

    if (showCommentsDialog) {
        CommentDialog(
            post = post,
            comments = commentsList,
            onAddComment = { text ->
                commentsList.add(text)
            },
            onDismiss = { showCommentsDialog = false }
        )
    }

    if (showShareDialog) {
        ShareDialog(
            title = "Post by ${post.creatorName}",
            shareUrl = "https://socialhub.com/posts/post_${post.id}",
            onDismiss = { showShareDialog = false }
        )
    }

    if (showTipModal) {
        var customAmountStr by remember { mutableStateOf("") }
        var selectedAmount by remember { mutableStateOf<Double?>(null) }
        var paymentSuccess by remember { mutableStateOf(false) }
        val activeTipAmount = customAmountStr.toDoubleOrNull() ?: selectedAmount ?: 0.0

        androidx.compose.ui.window.Dialog(onDismissRequest = { showTipModal = false }) {
            Card(
                shape = RoundedCornerShape(24.dp),
                colors = CardDefaults.cardColors(containerColor = ObsidianDark),
                border = BorderStroke(1.5.dp, RazorTeal),
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(16.dp)
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(20.dp),
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    // Header
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Icon(
                                imageVector = Icons.Default.Paid,
                                contentDescription = null,
                                tint = RazorTeal,
                                modifier = Modifier.size(24.dp)
                            )
                            Spacer(modifier = Modifier.width(8.dp))
                            Text(
                                text = "Send Tip to Creator",
                                color = Color.White,
                                fontWeight = FontWeight.Black,
                                fontSize = 16.sp
                            )
                        }
                        IconButton(
                            onClick = { showTipModal = false },
                            modifier = Modifier.size(28.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Default.Close,
                                contentDescription = "Close Tip Modal",
                                tint = GrayText,
                                modifier = Modifier.size(18.dp)
                            )
                        }
                    }

                    Spacer(modifier = Modifier.height(12.dp))

                    // Creator avatar preview & label
                    Box(
                        modifier = Modifier
                            .size(54.dp)
                            .background(
                                Brush.linearGradient(
                                    colors = listOf(RazorBlue, RazorTeal)
                                ),
                                CircleShape
                            )
                            .padding(2.dp)
                            .background(Color.Black, CircleShape)
                            .padding(4.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = post.creatorName.take(1).uppercase(),
                            color = RazorTeal,
                            fontSize = 20.sp,
                            fontWeight = FontWeight.Black,
                            fontFamily = FontFamily.Monospace
                        )
                    }

                    Spacer(modifier = Modifier.height(6.dp))

                    Text(
                        text = post.creatorName,
                        color = Color.White,
                        fontWeight = FontWeight.Bold,
                        fontSize = 14.sp
                    )
                    Text(
                        text = "@${post.creatorHandle}",
                        color = RazorBlue,
                        fontWeight = FontWeight.Medium,
                        fontSize = 11.sp,
                        fontFamily = FontFamily.Monospace
                    )

                    Spacer(modifier = Modifier.height(14.dp))

                    // 'Coming Soon' Indicator for payment gateway processing (as requested!)
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        shape = RoundedCornerShape(12.dp),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF1B1437)),
                        border = BorderStroke(1.dp, SafeGold.copy(alpha = 0.5f))
                    ) {
                        Row(
                            modifier = Modifier.padding(10.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Icon(
                                imageVector = Icons.Default.Warning,
                                contentDescription = "Coming Soon Warning",
                                tint = SafeGold,
                                modifier = Modifier.size(18.dp)
                            )
                            Spacer(modifier = Modifier.width(8.dp))
                            Column {
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Text(
                                        text = "PAYMENT PROCESSING",
                                        color = Color.White,
                                        fontWeight = FontWeight.Black,
                                        fontSize = 9.sp
                                    )
                                    Spacer(modifier = Modifier.width(6.dp))
                                    Box(
                                        modifier = Modifier
                                            .background(SafeGold, RoundedCornerShape(4.dp))
                                            .padding(horizontal = 4.dp, vertical = 1.dp)
                                    ) {
                                        Text(
                                            text = "COMING SOON",
                                            color = Color.Black,
                                            fontWeight = FontWeight.Black,
                                            fontSize = 7.sp
                                        )
                                    }
                                }
                                Spacer(modifier = Modifier.height(2.dp))
                                Text(
                                    text = "Credit card processing is currently offline. Your virtual wallet balance will be used in simulation sandbox.",
                                    color = GrayText,
                                    fontSize = 9.sp,
                                    lineHeight = 11.sp
                                )
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    Text(
                        text = "Choose Predefined Amount:",
                        color = LightText,
                        fontWeight = FontWeight.Bold,
                        fontSize = 11.sp,
                        modifier = Modifier.align(Alignment.Start).padding(bottom = 6.dp)
                    )

                    // Predefined amounts grid
                    val amounts = listOf(2.0, 5.0, 10.0, 20.0, 50.0, 100.0)
                    androidx.compose.foundation.lazy.grid.LazyVerticalGrid(
                        columns = androidx.compose.foundation.lazy.grid.GridCells.Fixed(3),
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(84.dp),
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        items(amounts.size) { index ->
                            val amt = amounts[index]
                            val isSelected = selectedAmount == amt && customAmountStr.isEmpty()
                            Button(
                                onClick = {
                                    selectedAmount = amt
                                    customAmountStr = ""
                                },
                                colors = ButtonDefaults.buttonColors(
                                    containerColor = if (isSelected) RazorTeal else Color(0xFF130E29),
                                    contentColor = if (isSelected) Color.Black else Color.White
                                ),
                                shape = RoundedCornerShape(10.dp),
                                border = BorderStroke(
                                    width = 1.dp,
                                    color = if (isSelected) RazorTeal else MinimalBorder
                                ),
                                contentPadding = PaddingValues(0.dp),
                                modifier = Modifier.height(36.dp)
                            ) {
                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.Center
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Paid,
                                        contentDescription = null,
                                        tint = if (isSelected) Color.Black else RazorTeal,
                                        modifier = Modifier.size(11.dp)
                                    )
                                    Spacer(modifier = Modifier.width(3.dp))
                                    Text(
                                        text = "$${amt.toInt()}",
                                        fontWeight = FontWeight.Black,
                                        fontSize = 12.sp
                                    )
                                }
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(12.dp))

                    Text(
                        text = "Or Enter Custom Amount:",
                        color = LightText,
                        fontWeight = FontWeight.Bold,
                        fontSize = 11.sp,
                        modifier = Modifier.align(Alignment.Start).padding(bottom = 6.dp)
                    )

                    // Custom input
                    OutlinedTextField(
                        value = customAmountStr,
                        onValueChange = {
                            if (it.isEmpty() || it.toDoubleOrNull() != null) {
                                customAmountStr = it
                                selectedAmount = null
                            }
                        },
                        placeholder = { Text("0.00", color = GrayText, fontSize = 12.sp) },
                        prefix = { Text("$ ", color = RazorTeal, fontSize = 12.sp, fontWeight = FontWeight.Bold) },
                        singleLine = true,
                        shape = RoundedCornerShape(10.dp),
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(48.dp),
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedTextColor = Color.White,
                            unfocusedTextColor = Color.White,
                            focusedBorderColor = RazorTeal,
                            unfocusedBorderColor = MinimalBorder
                        ),
                        textStyle = androidx.compose.ui.text.TextStyle(fontSize = 12.sp)
                    )

                    Spacer(modifier = Modifier.height(20.dp))

                    // Dynamic Tip Action Button
                    Button(
                        onClick = {
                            if (activeTipAmount > 0.0) {
                                onTip(activeTipAmount)
                                paymentSuccess = true
                            }
                        },
                        enabled = activeTipAmount > 0.0,
                        colors = ButtonDefaults.buttonColors(
                            containerColor = RazorTeal,
                            disabledContainerColor = Color.Gray.copy(alpha = 0.3f)
                        ),
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(44.dp)
                            .testTag("submit_tip_button")
                    ) {
                        Text(
                            text = if (activeTipAmount > 0.0) "Send $${String.format("%.2f", activeTipAmount)} Tip" else "Enter Amount",
                            color = if (activeTipAmount > 0.0) Color.Black else Color.White.copy(alpha = 0.6f),
                            fontWeight = FontWeight.Black,
                            fontSize = 13.sp
                        )
                    }
                }
            }
        }

        // Inside the Tip success dialog
        if (paymentSuccess) {
            androidx.compose.ui.window.Dialog(onDismissRequest = { 
                paymentSuccess = false
                showTipModal = false
            }) {
                Card(
                    shape = RoundedCornerShape(24.dp),
                    colors = CardDefaults.cardColors(containerColor = ObsidianDark),
                    border = BorderStroke(1.5.dp, RazorTeal),
                    modifier = Modifier.padding(16.dp)
                ) {
                    Column(
                        modifier = Modifier.padding(20.dp),
                        horizontalAlignment = Alignment.CenterHorizontally
                    ) {
                        Icon(
                            imageVector = Icons.Default.CheckCircle,
                            contentDescription = "Success",
                            tint = RazorTeal,
                            modifier = Modifier.size(48.dp)
                        )
                        Spacer(modifier = Modifier.height(12.dp))
                        Text(
                            text = "Tip Sent! 🎉",
                            fontWeight = FontWeight.Black,
                            color = Color.White,
                            style = MaterialTheme.typography.titleMedium,
                            textAlign = androidx.compose.ui.text.style.TextAlign.Center
                        )
                        Spacer(modifier = Modifier.height(8.dp))
                        Text(
                            text = "You successfully tipped $${String.format("%.2f", activeTipAmount)} to ${post.creatorName} via our in-app secure ledger. Thank you for supporting creators!",
                            color = LightText,
                            fontSize = 11.sp,
                            textAlign = androidx.compose.ui.text.style.TextAlign.Center
                        )
                        Spacer(modifier = Modifier.height(16.dp))
                        Button(
                            onClick = { 
                                paymentSuccess = false
                                showTipModal = false
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = RazorTeal)
                        ) {
                            Text("Done", color = Color.Black, fontWeight = FontWeight.Bold)
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun VideoPlayerControls(
    isPlayingInline: Boolean,
    isMutedInline: Boolean,
    showControls: Boolean,
    progressProvider: () -> Float,
    isDragging: Boolean,
    onProgressChange: (Float) -> Unit,
    onDraggingChange: (Boolean) -> Unit,
    onMuteToggle: () -> Unit,
    onPlayPauseToggle: () -> Unit,
    onFullScreenClick: (() -> Unit)?
) {
    if (isPlayingInline && showControls) {
        // Centered Play/Pause Button
        Box(
            modifier = Modifier.fillMaxSize(),
            contentAlignment = Alignment.Center
        ) {
            IconButton(
                onClick = onPlayPauseToggle,
                modifier = Modifier
                    .size(50.dp)
                    .background(Color.Black.copy(alpha = 0.65f), CircleShape)
            ) {
                Icon(
                    imageVector = if (isPlayingInline) Icons.Default.Pause else Icons.Default.PlayArrow,
                    contentDescription = "Play/Pause Inline",
                    tint = RazorTeal,
                    modifier = Modifier.size(28.dp)
                )
            }
        }

        // Bottom Overlay: Mute, Full Screen, Progress bar
        Box(
            modifier = Modifier.fillMaxSize(),
            contentAlignment = Alignment.BottomStart
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(
                        Brush.verticalGradient(
                            colors = listOf(Color.Transparent, Color.Black.copy(0.85f))
                        )
                    )
                    .padding(horizontal = 12.dp, vertical = 8.dp)
            ) {
                // Slim Draggable Seekable Progress Bar via Canvas (Lag-Free & Smooth)
                Canvas(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(16.dp)
                        .pointerInput(Unit) {
                            detectTapGestures(
                                onPress = { offset ->
                                    onDraggingChange(true)
                                    val clickX = offset.x
                                    val w = size.width
                                    if (w > 0) {
                                        onProgressChange((clickX / w.toFloat()).coerceIn(0f, 1f))
                                    }
                                    try {
                                        awaitRelease()
                                    } finally {
                                        onDraggingChange(false)
                                    }
                                }
                            )
                        }
                        .pointerInput(Unit) {
                            detectDragGestures(
                                onDragStart = { offset ->
                                    onDraggingChange(true)
                                    val clickX = offset.x
                                    val w = size.width
                                    if (w > 0) {
                                        onProgressChange((clickX / w.toFloat()).coerceIn(0f, 1f))
                                    }
                                },
                                onDragEnd = { onDraggingChange(false) },
                                onDragCancel = { onDraggingChange(false) },
                                onDrag = { change, _ ->
                                    change.consume()
                                    val dragX = change.position.x
                                    val w = size.width
                                    if (w > 0) {
                                        onProgressChange((dragX / w.toFloat()).coerceIn(0f, 1f))
                                    }
                                }
                            )
                        }
                ) {
                    val currentProgress = progressProvider()
                    val w = size.width
                    val h = size.height
                    val centerY = h / 2

                    // 1. Background line
                    drawRoundRect(
                        color = Color.White.copy(alpha = 0.2f),
                        topLeft = Offset(0f, centerY - 2.dp.toPx()),
                        size = androidx.compose.ui.geometry.Size(w, 4.dp.toPx()),
                        cornerRadius = androidx.compose.ui.geometry.CornerRadius(2.dp.toPx(), 2.dp.toPx())
                    )

                    // 2. Active progress line
                    val progressWidth = w * currentProgress
                    drawRoundRect(
                        color = RazorTeal,
                        topLeft = Offset(0f, centerY - 2.dp.toPx()),
                        size = androidx.compose.ui.geometry.Size(progressWidth, 4.dp.toPx()),
                        cornerRadius = androidx.compose.ui.geometry.CornerRadius(2.dp.toPx(), 2.dp.toPx())
                    )

                    // 3. Tiny thumb handle
                    val thumbRadius = if (isDragging) 6.dp.toPx() else 4.dp.toPx()
                    val thumbColor = if (isDragging) Color.White else RazorTeal
                    drawCircle(
                        color = thumbColor,
                        radius = thumbRadius,
                        center = Offset(progressWidth.coerceIn(0f, w), centerY)
                    )
                }

                Spacer(modifier = Modifier.height(6.dp))

                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    // Mute button & live timing
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        IconButton(
                            onClick = onMuteToggle,
                            modifier = Modifier.size(24.dp)
                        ) {
                            Icon(
                                imageVector = if (isMutedInline) Icons.AutoMirrored.Filled.VolumeOff else Icons.AutoMirrored.Filled.VolumeUp,
                                contentDescription = "Mute Inline",
                                tint = if (isMutedInline) Color.Red else RazorTeal,
                                modifier = Modifier.size(16.dp)
                            )
                        }

                        VideoTimerText(progressProvider = progressProvider)
                    }

                    // Full screen button
                    if (onFullScreenClick != null) {
                        Button(
                            onClick = onFullScreenClick,
                            colors = ButtonDefaults.buttonColors(containerColor = Color.Black.copy(0.5f)),
                            border = BorderStroke(1.dp, RazorTeal.copy(0.5f)),
                            shape = RoundedCornerShape(8.dp),
                            contentPadding = PaddingValues(horizontal = 8.dp, vertical = 2.dp),
                            modifier = Modifier.height(26.dp)
                        ) {
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                Icon(
                                    imageVector = Icons.AutoMirrored.Filled.Launch,
                                    contentDescription = "Full Screen",
                                    tint = RazorTeal,
                                    modifier = Modifier.size(14.dp)
                                )
                                Text(
                                    "Full Screen",
                                    color = Color.White,
                                    fontSize = 9.sp,
                                    fontWeight = FontWeight.Black
                                )
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun VideoTimerText(progressProvider: () -> Float) {
    Text(
        text = "0:${String.format("%02d", (progressProvider() * 12).toInt())} / 0:12",
        color = Color.White.copy(0.8f),
        fontSize = 10.sp,
        fontFamily = FontFamily.Monospace,
        fontWeight = FontWeight.Bold
    )
}

@Composable
fun EntranceAnimationContainer(
    content: @Composable () -> Unit
) {
    var visible by remember { mutableStateOf(false) }
    val alpha by androidx.compose.animation.core.animateFloatAsState(
        targetValue = if (visible) 1f else 0f,
        animationSpec = androidx.compose.animation.core.tween(durationMillis = 300, easing = androidx.compose.animation.core.LinearOutSlowInEasing),
        label = "entranceAlpha"
    )
    val translationY by androidx.compose.animation.core.animateFloatAsState(
        targetValue = if (visible) 0f else 30f,
        animationSpec = androidx.compose.animation.core.tween(durationMillis = 300, easing = androidx.compose.animation.core.LinearOutSlowInEasing),
        label = "entranceY"
    )
    
    LaunchedEffect(Unit) {
        visible = true
    }
    
    Box(
        modifier = Modifier.graphicsLayer {
            this.alpha = alpha
            this.translationY = translationY
        }
    ) {
        content()
    }
}

// ============================================
// SCREEN 2: CREATIVE STUDIO DIALOG PANEL (Page 2)
// ============================================
fun saveBitmapToCache(context: android.content.Context, bitmap: android.graphics.Bitmap): String? {
    return try {
        val cachePath = java.io.File(context.cacheDir, "story_images")
        cachePath.mkdirs()
        val file = java.io.File(cachePath, "captured_${System.currentTimeMillis()}.jpg")
        val stream = java.io.FileOutputStream(file)
        bitmap.compress(android.graphics.Bitmap.CompressFormat.JPEG, 90, stream)
        stream.close()
        file.absolutePath
    } catch (e: Exception) {
        e.printStackTrace()
        null
    }
}

data class SelectedMedia(
    val url: String,
    val isVideo: Boolean,
    val duration: String = "",
    var filter: String = "None",
    var sticker: String? = null,
    var playbackSpeed: String = "1.0 Normal"
)

data class GalleryMedia(
    val id: String,
    val url: String,
    val isVideo: Boolean,
    val duration: String = "",
    val name: String
)

@Composable
fun CreativeStudioDialog(onDismiss: () -> Unit, onPublish: (String, String?) -> Unit) {
    Dialog(
        onDismissRequest = onDismiss,
        properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = false)
    ) {
        val coroutineScope = rememberCoroutineScope()
        var isPublishing by remember { mutableStateOf(false) }
        var publishingStage by remember { mutableStateOf("") }
        var publishingProgress by remember { mutableStateOf(0f) }
        var currentStageIndex by remember { mutableStateOf(0) }

        var currentStep by remember { mutableStateOf(0) } // Step 0: Choose Source, Step 1: Media Picker, Step 2: Editor
        var captionText by remember { mutableStateOf("") }
        var selectedMediaList by remember { mutableStateOf<List<SelectedMedia>>(emptyList()) }
        var activePreviewItem by remember { mutableStateOf<GalleryMedia?>(null) }
        
    val context = androidx.compose.ui.platform.LocalContext.current

        val cameraLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
            contract = androidx.activity.result.contract.ActivityResultContracts.TakePicturePreview()
        ) { bitmap ->
            if (bitmap != null) {
                val path = saveBitmapToCache(context, bitmap)
                if (path != null) {
                    val fileUri = "file://$path"
                    selectedMediaList = selectedMediaList + SelectedMedia(url = fileUri, isVideo = false)
                    currentStep = 2 // Transition directly to editor when captured!
                }
            }
        }

        val galleryLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
            contract = androidx.activity.result.contract.ActivityResultContracts.GetMultipleContents()
        ) { uris ->
            if (uris != null && uris.isNotEmpty()) {
                selectedMediaList = selectedMediaList + uris.map { SelectedMedia(url = it.toString(), isVideo = false) }
                currentStep = 2 // Transition directly to editor when picked!
            }
        }

        val mockGalleryItems = remember {
            listOf(
                GalleryMedia("pic_1", "https://images.unsplash.com/photo-1542751371-adc38448a05e?w=800", false, "", "Neon Arcade"),
                GalleryMedia("pic_2", "https://images.unsplash.com/photo-1511512578047-dfb367046420?w=800", false, "", "Cyber Alley"),
                GalleryMedia("pic_3", "https://images.unsplash.com/photo-1563089145-599997674d42?w=800", false, "", "Glitch Abstract"),
                GalleryMedia("pic_4", "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?w=800", false, "", "Vaporwave Waves"),
                GalleryMedia("pic_5", "https://images.unsplash.com/photo-1503899036084-c55cdd92da26?w=800", false, "", "Tokyo Lights"),
                GalleryMedia("pic_6", "https://images.unsplash.com/photo-1515621061946-eff1c2a352bd?w=800", false, "", "Neon Ride"),
                GalleryMedia("vid_1", "https://images.unsplash.com/photo-1509198397868-475647b2a1e5?w=800", true, "0:15", "Cyber Drift"),
                GalleryMedia("vid_2", "https://images.unsplash.com/photo-1492691527719-9d1e07e534b4?w=800", true, "0:08", "Live Beats"),
                GalleryMedia("vid_3", "https://images.unsplash.com/photo-1519608487953-e999c86e7455?w=800", true, "0:12", "Night Rain"),
                GalleryMedia("vid_4", "https://images.unsplash.com/photo-1538481199705-c710c4e965fc?w=800", true, "0:10", "Retro Station")
            )
        }

        val highlightedItem = activePreviewItem ?: mockGalleryItems.first()

        if (currentStep == 0) {
            // Step 0: Choose Source Dialog
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .background(ObsidianDark)
                    .padding(top = 28.dp)
            ) {
                // Header of Option Selection
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 16.dp, vertical = 12.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    IconButton(onClick = onDismiss) {
                        Icon(imageVector = Icons.Default.Close, contentDescription = "Close", tint = Color.White)
                    }
                    Text(
                        text = "NEW STORY SHOT",
                        color = RazorTeal,
                        fontWeight = FontWeight.Black,
                        fontSize = 15.sp,
                        letterSpacing = 1.2.sp
                    )
                    Spacer(modifier = Modifier.size(48.dp)) // Symmetry spacer
                }

                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .weight(1f)
                        .padding(horizontal = 24.dp),
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.Center
                ) {
                    Box(
                        modifier = Modifier
                            .size(72.dp)
                            .clip(CircleShape)
                            .background(RazorTeal.copy(alpha = 0.15f))
                            .border(1.5.dp, RazorTeal, CircleShape),
                        contentAlignment = Alignment.Center
                    ) {
                        Icon(
                            imageVector = Icons.Default.Whatshot,
                            contentDescription = "New Shot",
                            tint = RazorTeal,
                            modifier = Modifier.size(36.dp)
                        )
                    }

                    Spacer(modifier = Modifier.height(20.dp))

                    Text(
                        text = "CHOOSE YOUR SHOT SOURCE",
                        color = Color.White,
                        fontWeight = FontWeight.Black,
                        fontSize = 18.sp,
                        letterSpacing = 0.5.sp
                    )
                    Text(
                        text = "Capture or select real-time media to post directly",
                        color = Color.White.copy(0.6f),
                        fontSize = 12.sp,
                        modifier = Modifier.padding(top = 6.dp, bottom = 32.dp)
                    )

                    // Option 1: Live Camera Capture
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 8.dp)
                            .clickable { cameraLauncher.launch(null) },
                        colors = CardDefaults.cardColors(containerColor = Color.White.copy(0.04f)),
                        shape = RoundedCornerShape(16.dp),
                        border = BorderStroke(1.2.dp, RazorTeal.copy(0.3f))
                    ) {
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(18.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Box(
                                modifier = Modifier
                                    .size(48.dp)
                                    .clip(CircleShape)
                                    .background(RazorTeal.copy(0.12f)),
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(
                                    imageVector = Icons.Default.PhotoCamera,
                                    contentDescription = "Live Camera",
                                    tint = RazorTeal,
                                    modifier = Modifier.size(22.dp)
                                )
                            }
                            Spacer(modifier = Modifier.width(16.dp))
                            Column(modifier = Modifier.weight(1f)) {
                                Text(
                                    text = "Live Device Camera",
                                    color = Color.White,
                                    fontWeight = FontWeight.Bold,
                                    fontSize = 14.sp
                                )
                                Text(
                                    text = "Capture a real-time live photo with your camera",
                                    color = Color.White.copy(0.6f),
                                    fontSize = 11.sp,
                                    modifier = Modifier.padding(top = 2.dp)
                                )
                            }
                            Icon(imageVector = Icons.Default.ChevronRight, contentDescription = null, tint = RazorTeal, modifier = Modifier.size(20.dp))
                        }
                    }

                    // Option 2: System File Media Picker
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 8.dp)
                            .clickable { galleryLauncher.launch("image/*") },
                        colors = CardDefaults.cardColors(containerColor = Color.White.copy(0.04f)),
                        shape = RoundedCornerShape(16.dp),
                        border = BorderStroke(1.2.dp, RazorBlue.copy(0.3f))
                    ) {
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(18.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Box(
                                modifier = Modifier
                                    .size(48.dp)
                                    .clip(CircleShape)
                                    .background(RazorBlue.copy(0.12f)),
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(
                                    imageVector = Icons.Default.Folder,
                                    contentDescription = "System Files",
                                    tint = RazorBlue,
                                    modifier = Modifier.size(22.dp)
                                )
                            }
                            Spacer(modifier = Modifier.width(16.dp))
                            Column(modifier = Modifier.weight(1f)) {
                                Text(
                                    text = "System Media Gallery",
                                    color = Color.White,
                                    fontWeight = FontWeight.Bold,
                                    fontSize = 14.sp
                                )
                                Text(
                                    text = "Pick real photos or videos from device gallery",
                                    color = Color.White.copy(0.6f),
                                    fontSize = 11.sp,
                                    modifier = Modifier.padding(top = 2.dp)
                                )
                            }
                            Icon(imageVector = Icons.Default.ChevronRight, contentDescription = null, tint = RazorBlue, modifier = Modifier.size(20.dp))
                        }
                    }


                }
            }
        } else if (currentStep == 1) {
            // Step 1: Instagram style Media Picker with Top preview + Multi Selection grid
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .background(ObsidianDark)
                    .padding(top = 28.dp)
            ) {
                // Media Picker Header
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 16.dp, vertical = 12.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    IconButton(onClick = { currentStep = 0 }) {
                        Icon(imageVector = Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back", tint = Color.White)
                    }
                    
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        Text(
                            text = "GALLERY",
                            color = Color.White,
                            fontWeight = FontWeight.Black,
                            fontSize = 15.sp,
                            letterSpacing = 1.sp
                        )
                        Icon(
                            imageVector = Icons.Default.ArrowDropDown,
                            contentDescription = "Dropdown menu",
                            tint = RazorTeal,
                            modifier = Modifier.size(20.dp)
                        )
                    }

                    Button(
                        onClick = { currentStep = 2 },
                        enabled = selectedMediaList.isNotEmpty(),
                        colors = ButtonDefaults.buttonColors(
                            containerColor = RazorTeal,
                            disabledContainerColor = Color.White.copy(0.12f)
                        ),
                        shape = RoundedCornerShape(20.dp),
                        contentPadding = PaddingValues(horizontal = 16.dp, vertical = 6.dp)
                    ) {
                        Text(
                            text = "Next",
                            color = if (selectedMediaList.isNotEmpty()) Color.Black else GrayText,
                            fontWeight = FontWeight.Bold,
                            fontSize = 13.sp
                        )
                    }
                }

                // Interactive Big Preview Screen (Top Half)
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .weight(0.42f)
                        .background(Color.Black),
                    contentAlignment = Alignment.Center
                ) {
                    AsyncImage(
                        model = highlightedItem.url,
                        contentDescription = "Picker preview active",
                        modifier = Modifier.fillMaxSize(),
                        contentScale = ContentScale.Crop
                    )
                    
                    if (highlightedItem.isVideo) {
                        Box(
                            modifier = Modifier
                                .align(Alignment.Center)
                                .size(54.dp)
                                .clip(CircleShape)
                                .background(Color.Black.copy(0.4f)),
                            contentAlignment = Alignment.Center
                        ) {
                            Icon(imageVector = Icons.Default.PlayArrow, contentDescription = "Play icon", tint = Color.White, modifier = Modifier.size(28.dp))
                        }
                    }
                    
                    Box(
                        modifier = Modifier
                            .align(Alignment.BottomStart)
                            .padding(12.dp)
                            .clip(RoundedCornerShape(6.dp))
                            .background(Color.Black.copy(0.6f))
                            .padding(horizontal = 8.dp, vertical = 4.dp)
                    ) {
                        Text(
                            text = if (highlightedItem.isVideo) "VIDEO • ${highlightedItem.duration}" else "PHOTO",
                            color = if (highlightedItem.isVideo) RazorTeal else Color.White,
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Bold,
                            letterSpacing = 0.5.sp
                        )
                    }
                }

                // Tab Filter Row
                var activeTab by remember { mutableStateOf("All Media") }
                val tabs = listOf("All Media", "Photos", "Videos", "Premium Cyber")
                
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color.Black.copy(0.4f))
                        .padding(vertical = 8.dp, horizontal = 12.dp),
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    tabs.forEach { tabName ->
                        val isTabSelected = activeTab == tabName
                        Box(
                            modifier = Modifier
                                .clip(RoundedCornerShape(20.dp))
                                .background(if (isTabSelected) RazorTeal.copy(0.15f) else Color.Transparent)
                                .border(1.dp, if (isTabSelected) RazorTeal else Color.White.copy(0.2f), RoundedCornerShape(20.dp))
                                .clickable { activeTab = tabName }
                                .padding(horizontal = 14.dp, vertical = 6.dp)
                        ) {
                            Text(
                                text = tabName,
                                color = if (isTabSelected) RazorTeal else Color.White,
                                fontSize = 11.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }
                }

                val filteredItems = remember(activeTab) {
                    when (activeTab) {
                        "Photos" -> mockGalleryItems.filter { !it.isVideo }
                        "Videos" -> mockGalleryItems.filter { it.isVideo }
                        "Premium Cyber" -> mockGalleryItems.take(4)
                        else -> mockGalleryItems
                    }
                }

                // Media Selection Grid
                LazyVerticalGrid(
                    columns = GridCells.Fixed(3),
                    modifier = Modifier
                        .fillMaxWidth()
                        .weight(0.58f)
                        .background(ObsidianDark),
                    contentPadding = PaddingValues(1.dp),
                    horizontalArrangement = Arrangement.spacedBy(1.dp),
                    verticalArrangement = Arrangement.spacedBy(1.dp)
                ) {
                    // Quick Take shortcuts
                    item {
                        Column(
                            modifier = Modifier
                                .aspectRatio(1f)
                                .background(Color.White.copy(0.04f))
                                .clickable { cameraLauncher.launch(null) },
                            horizontalAlignment = Alignment.CenterHorizontally,
                            verticalArrangement = Arrangement.Center
                        ) {
                            Icon(imageVector = Icons.Default.PhotoCamera, contentDescription = "Camera capture link", tint = RazorTeal, modifier = Modifier.size(28.dp))
                            Spacer(modifier = Modifier.height(6.dp))
                            Text("Camera", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                        }
                    }

                    item {
                        Column(
                            modifier = Modifier
                                .aspectRatio(1f)
                                .background(Color.White.copy(0.04f))
                                .clickable { galleryLauncher.launch("image/*") },
                            horizontalAlignment = Alignment.CenterHorizontally,
                            verticalArrangement = Arrangement.Center
                        ) {
                            Icon(imageVector = Icons.Default.Folder, contentDescription = "System picker link", tint = RazorBlue, modifier = Modifier.size(28.dp))
                            Spacer(modifier = Modifier.height(6.dp))
                            Text("More...", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                        }
                    }

                    items(filteredItems) { item ->
                        val selectedIndex = selectedMediaList.indexOfFirst { it.url == item.url }
                        val isSelected = selectedIndex != -1

                        Box(
                            modifier = Modifier
                                .aspectRatio(1f)
                                .clickable {
                                    activePreviewItem = item
                                    if (isSelected) {
                                        selectedMediaList = selectedMediaList.filter { it.url != item.url }
                                    } else {
                                        if (selectedMediaList.size < 4) {
                                            selectedMediaList = selectedMediaList + SelectedMedia(
                                                url = item.url,
                                                isVideo = item.isVideo,
                                                duration = item.duration
                                            )
                                        }
                                    }
                                }
                        ) {
                            AsyncImage(
                                model = item.url,
                                contentDescription = item.name,
                                modifier = Modifier.fillMaxSize(),
                                contentScale = ContentScale.Crop
                            )

                            if (item.isVideo) {
                                Row(
                                    modifier = Modifier
                                        .align(Alignment.BottomStart)
                                        .padding(4.dp)
                                        .clip(RoundedCornerShape(4.dp))
                                        .background(Color.Black.copy(0.6f))
                                        .padding(horizontal = 4.dp, vertical = 2.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Icon(imageVector = Icons.Default.PlayArrow, contentDescription = null, tint = Color.White, modifier = Modifier.size(10.dp))
                                    Spacer(modifier = Modifier.width(2.dp))
                                    Text(item.duration, color = Color.White, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            Box(
                                modifier = Modifier
                                    .align(Alignment.TopEnd)
                                    .padding(8.dp)
                                    .size(22.dp)
                                    .clip(CircleShape)
                                    .then(
                                        if (isSelected) Modifier.background(Brush.linearGradient(listOf(RazorTeal, RazorBlue)))
                                        else Modifier.background(Color.Black.copy(0.4f))
                                    )
                                    .border(
                                        width = 1.dp,
                                        color = if (isSelected) Color.Transparent else Color.White,
                                        shape = CircleShape
                                    ),
                                contentAlignment = Alignment.Center
                            ) {
                                if (isSelected) {
                                    Text(
                                        text = "${selectedIndex + 1}",
                                        color = Color.Black,
                                        fontWeight = FontWeight.Black,
                                        fontSize = 11.sp
                                    )
                                }
                            }
                        }
                    }
                }
            }
        } else {
            // Step 2: Immersive Creative Editor
            var activeEditIndex by remember { mutableStateOf(0) }
            val activeItem = selectedMediaList.getOrNull(activeEditIndex) ?: selectedMediaList.firstOrNull()
            
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .background(ObsidianDark)
                    .padding(top = 28.dp)
            ) {
                // Editor Header
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 16.dp, vertical = 12.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    IconButton(onClick = { currentStep = 1 }) {
                        Icon(imageVector = Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back icon", tint = Color.White)
                    }

                    Text(
                        text = "CREATIVE EDITOR",
                        color = RazorTeal,
                        fontWeight = FontWeight.Black,
                        fontSize = 14.sp,
                        letterSpacing = 1.sp
                    )

                    Button(
                        onClick = {
                            coroutineScope.launch {
                                isPublishing = true
                                publishingProgress = 0f
                                val stages = listOf(
                                    "Compressing and optimizing high-definition media frames..." to 0.15f,
                                    "Encrypting outbound payloads with secure AES-256..." to 0.40f,
                                    "Signing transaction payload with cryptographic keys..." to 0.70f,
                                    "Broadcasting story feed to Decentralized Core Node..." to 1.0f
                                )
                                for (i in stages.indices) {
                                    currentStageIndex = i
                                    publishingStage = stages[i].first
                                    val targetProgress = stages[i].second
                                    while (publishingProgress < targetProgress) {
                                        publishingProgress += 0.05f
                                        kotlinx.coroutines.delay(40)
                                    }
                                    kotlinx.coroutines.delay(200)
                                }
                                val payload = selectedMediaList.joinToString(",") { item ->
                                    "${item.url}|${item.isVideo}|${item.filter}|${item.sticker}"
                                }
                                onPublish(if (captionText.isNotBlank()) captionText else "Shared story media", payload)
                                isPublishing = false
                                onDismiss()
                            }
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = RazorTeal),
                        shape = RoundedCornerShape(20.dp),
                        contentPadding = PaddingValues(horizontal = 16.dp, vertical = 6.dp)
                    ) {
                        Text("Publish", color = Color.Black, fontWeight = FontWeight.Black, fontSize = 13.sp)
                    }
                }

                if (activeItem != null) {
                    // Large active preview display area
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .weight(0.46f)
                            .padding(horizontal = 12.dp)
                            .clip(RoundedCornerShape(16.dp))
                            .background(Color.Black),
                        contentAlignment = Alignment.Center
                    ) {
                        val matrix = remember(activeItem.filter) {
                            androidx.compose.ui.graphics.ColorMatrix().apply {
                                if (activeItem.filter == "Mono Cyber") {
                                    setToSaturation(0f)
                                }
                            }
                        }

                        AsyncImage(
                            model = activeItem.url,
                            contentDescription = "Active live edit view",
                            modifier = Modifier.fillMaxSize(),
                            contentScale = ContentScale.Crop,
                            colorFilter = if (activeItem.filter == "Mono Cyber") androidx.compose.ui.graphics.ColorFilter.colorMatrix(matrix) else null
                        )

                        when (activeItem.filter) {
                            "Cyber Neon" -> {
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(
                                            Brush.linearGradient(
                                                colors = listOf(
                                                    Color(0xFFFF007F).copy(alpha = 0.25f),
                                                    Color(0xFF00F0FF).copy(alpha = 0.25f)
                                                )
                                            )
                                        )
                                )
                            }
                            "Glitch Vapor" -> {
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(
                                            Brush.radialGradient(
                                                colors = listOf(
                                                    Color(0xFF8B008B).copy(alpha = 0.35f),
                                                    Color.Transparent
                                                )
                                            )
                                        )
                                )
                            }
                            "Aqua Haze" -> {
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(
                                            Brush.verticalGradient(
                                                colors = listOf(
                                                    Color(0xFF00FFFF).copy(alpha = 0.2f),
                                                    Color(0xFF008080).copy(alpha = 0.15f)
                                                )
                                            )
                                        )
                                )
                            }
                            "Synthwave Sunset" -> {
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(
                                            Brush.linearGradient(
                                                colors = listOf(
                                                    Color(0xFFFF5E36).copy(alpha = 0.25f),
                                                    Color(0xFFFF007F).copy(alpha = 0.25f)
                                                )
                                            )
                                        )
                                )
                            }
                            "Mono Cyber" -> {
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .border(2.dp, Color(0xFF39FF14).copy(alpha = 0.35f), RoundedCornerShape(16.dp))
                                )
                            }
                        }

                        if (activeItem.isVideo) {
                            Box(
                                modifier = Modifier
                                    .align(Alignment.Center)
                                    .size(54.dp)
                                    .clip(CircleShape)
                                    .background(Color.Black.copy(0.4f)),
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(imageVector = Icons.Default.PlayArrow, contentDescription = "Play preview icon", tint = Color.White, modifier = Modifier.size(28.dp))
                            }
                        }

                        activeItem.sticker?.let { sticker ->
                            Box(
                                modifier = Modifier
                                    .align(Alignment.Center)
                                    .padding(bottom = 60.dp)
                            ) {
                                when (sticker) {
                                    "LIVE 🔴" -> {
                                        Row(
                                            modifier = Modifier
                                                .clip(RoundedCornerShape(8.dp))
                                                .background(Color.Black.copy(alpha = 0.85f))
                                                .border(1.2.dp, Color.Red, RoundedCornerShape(8.dp))
                                                .padding(horizontal = 12.dp, vertical = 6.dp),
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            Box(
                                                modifier = Modifier
                                                    .size(6.dp)
                                                    .clip(CircleShape)
                                                    .background(Color.Red)
                                            )
                                            Spacer(modifier = Modifier.width(6.dp))
                                            Text("LIVE", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }
                                    "NEW SHOT 🔥" -> {
                                        Row(
                                            modifier = Modifier
                                                .clip(RoundedCornerShape(8.dp))
                                                .background(Brush.linearGradient(listOf(Color(0xFFFF5E36), Color(0xFFFF007F))))
                                                .padding(horizontal = 12.dp, vertical = 6.dp),
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            Icon(Icons.Default.Whatshot, null, tint = Color.White, modifier = Modifier.size(12.dp))
                                            Spacer(modifier = Modifier.width(4.dp))
                                            Text("NEW SHOT", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }
                                    "CYBERPUNK 🕶️" -> {
                                        Row(
                                            modifier = Modifier
                                                .clip(RoundedCornerShape(8.dp))
                                                .background(Color.Black.copy(alpha = 0.85f))
                                                .border(1.2.dp, RazorTeal, RoundedCornerShape(8.dp))
                                                .padding(horizontal = 12.dp, vertical = 6.dp),
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            Text("CYBERPUNK 🕶️", color = RazorTeal, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }
                                    "SOUND ON 🎵" -> {
                                        Row(
                                            modifier = Modifier
                                                .clip(RoundedCornerShape(8.dp))
                                                .background(Color(0xFF1B153B))
                                                .border(1.2.dp, RazorBlue, RoundedCornerShape(8.dp))
                                                .padding(horizontal = 12.dp, vertical = 6.dp),
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            Icon(Icons.AutoMirrored.Filled.VolumeUp, null, tint = RazorBlue, modifier = Modifier.size(12.dp))
                                            Spacer(modifier = Modifier.width(4.dp))
                                            Text("SOUND ON", color = RazorBlue, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }
                                }
                            }
                        }

                        Text(
                            text = "${activeItem.filter} • speed ${activeItem.playbackSpeed}",
                            color = Color.White.copy(0.6f),
                            fontSize = 9.sp,
                            fontWeight = FontWeight.Bold,
                            fontFamily = FontFamily.Monospace,
                            modifier = Modifier
                                .align(Alignment.BottomEnd)
                                .padding(12.dp)
