                    }

                    Spacer(modifier = Modifier.height(10.dp))

                    // Media Slider thumbnails selection
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(horizontal = 16.dp),
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        selectedMediaList.forEachIndexed { index, media ->
                            val isThumbnailActive = index == activeEditIndex
                            Box(
                                modifier = Modifier
                                    .size(54.dp)
                                    .clip(RoundedCornerShape(8.dp))
                                    .border(
                                        width = 2.dp,
                                        color = if (isThumbnailActive) RazorTeal else Color.White.copy(0.2f),
                                        shape = RoundedCornerShape(8.dp)
                                    )
                                    .clickable { activeEditIndex = index }
                            ) {
                                AsyncImage(
                                    model = media.url,
                                    contentDescription = null,
                                    modifier = Modifier.fillMaxSize(),
                                    contentScale = ContentScale.Crop
                                )
                                
                                Box(
                                    modifier = Modifier
                                        .align(Alignment.TopStart)
                                        .padding(3.dp)
                                        .size(16.dp)
                                        .clip(CircleShape)
                                        .background(Color.Black.copy(0.7f)),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text("${index + 1}", color = Color.White, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(12.dp))

                    // Editing Option Panels
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .weight(0.54f)
                            .background(Color.Black.copy(0.3f))
                            .padding(vertical = 12.dp, horizontal = 16.dp),
                        verticalArrangement = Arrangement.spacedBy(12.dp)
                    ) {
                        Column {
                            Text("FILTERS", color = Color.White.copy(0.5f), fontSize = 10.sp, fontWeight = FontWeight.Bold, letterSpacing = 1.sp)
                            Spacer(modifier = Modifier.height(6.dp))
                            val filterOptions = listOf("None", "Cyber Neon", "Glitch Vapor", "Aqua Haze", "Synthwave Sunset", "Mono Cyber")
                            LazyRow(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                items(filterOptions) { filterOpt ->
                                    val isSelected = activeItem.filter == filterOpt
                                    Box(
                                        modifier = Modifier
                                            .clip(RoundedCornerShape(8.dp))
                                            .background(if (isSelected) RazorTeal else Color.White.copy(0.06f))
                                            .border(1.dp, if (isSelected) RazorTeal else Color.White.copy(0.15f), RoundedCornerShape(8.dp))
                                            .clickable {
                                                selectedMediaList = selectedMediaList.toMutableList().apply {
                                                    this[activeEditIndex] = activeItem.copy(filter = filterOpt)
                                                }
                                            }
                                            .padding(horizontal = 12.dp, vertical = 6.dp)
                                    ) {
                                        Text(
                                            text = filterOpt,
                                            color = if (isSelected) Color.Black else Color.White,
                                            fontSize = 11.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                    }
                                }
                            }
                        }

                        Column {
                            Text("INTERACTIVE STICKERS", color = Color.White.copy(0.5f), fontSize = 10.sp, fontWeight = FontWeight.Bold, letterSpacing = 1.sp)
                            Spacer(modifier = Modifier.height(6.dp))
                            val stickersOptions = listOf("None", "LIVE 🔴", "NEW SHOT 🔥", "CYBERPUNK 🕶️", "SOUND ON 🎵")
                            LazyRow(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                items(stickersOptions) { stickerOpt ->
                                    val isNone = stickerOpt == "None"
                                    val isSelected = if (isNone) activeItem.sticker == null else activeItem.sticker == stickerOpt
                                    Box(
                                        modifier = Modifier
                                            .clip(RoundedCornerShape(8.dp))
                                            .background(if (isSelected) RazorBlue else Color.White.copy(0.06f))
                                            .border(1.dp, if (isSelected) RazorBlue else Color.White.copy(0.15f), RoundedCornerShape(8.dp))
                                            .clickable {
                                                selectedMediaList = selectedMediaList.toMutableList().apply {
                                                    this[activeEditIndex] = activeItem.copy(
                                                        sticker = if (isNone) null else stickerOpt
                                                    )
                                                }
                                            }
                                            .padding(horizontal = 12.dp, vertical = 6.dp)
                                    ) {
                                        Text(
                                            text = stickerOpt,
                                            color = if (isSelected) Color.Black else Color.White,
                                            fontSize = 11.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                    }
                                }
                            }
                        }

                        if (activeItem.isVideo) {
                            Column {
                                Text("VIDEO SPEED CONTROL", color = Color.White.copy(0.5f), fontSize = 10.sp, fontWeight = FontWeight.Bold, letterSpacing = 1.sp)
                                Spacer(modifier = Modifier.height(6.dp))
                                val speedOptions = listOf("0.5x Slow", "1.0 Normal", "1.5x Fast", "2.0x Hyper")
                                LazyRow(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                    items(speedOptions) { speedOpt ->
                                        val isSelected = activeItem.playbackSpeed == speedOpt
                                        Box(
                                            modifier = Modifier
                                                .clip(RoundedCornerShape(8.dp))
                                                .background(if (isSelected) InstaPink else Color.White.copy(0.06f))
                                                .border(1.dp, if (isSelected) InstaPink else Color.White.copy(0.15f), RoundedCornerShape(8.dp))
                                                .clickable {
                                                    selectedMediaList = selectedMediaList.toMutableList().apply {
                                                        this[activeEditIndex] = activeItem.copy(playbackSpeed = speedOpt)
                                                    }
                                                }
                                                .padding(horizontal = 12.dp, vertical = 6.dp)
                                        ) {
                                            Text(
                                                text = speedOpt,
                                                color = Color.White,
                                                fontSize = 11.sp,
                                                fontWeight = FontWeight.Bold
                                            )
                                        }
                                    }
                                }
                            }
                        }

                        Column {
                            Text("STORY CAPTION", color = Color.White.copy(0.5f), fontSize = 10.sp, fontWeight = FontWeight.Bold, letterSpacing = 1.sp)
                            Spacer(modifier = Modifier.height(6.dp))
                            TextField(
                                value = captionText,
                                onValueChange = { captionText = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, captionText) },
                                placeholder = { Text("Write a futuristic story caption...", color = GrayText, fontSize = 12.sp) },
                                colors = TextFieldDefaults.colors(
                                    focusedContainerColor = Color.White.copy(0.04f),
                                    unfocusedContainerColor = Color.White.copy(0.04f),
                                    focusedTextColor = Color.White,
                                    unfocusedTextColor = Color.White,
                                    cursorColor = RazorTeal,
                                    focusedIndicatorColor = RazorTeal,
                                    unfocusedIndicatorColor = Color.Transparent
                                ),
                                shape = RoundedCornerShape(10.dp),
                                modifier = Modifier.fillMaxWidth(),
                                singleLine = true
                            )
                        }
                    }
                }
            }
        }

        if (isPublishing) {
            Dialog(
                onDismissRequest = {},
                properties = androidx.compose.ui.window.DialogProperties(
                    dismissOnBackPress = false,
                    dismissOnClickOutside = false,
                    usePlatformDefaultWidth = false
                )
            ) {
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .background(Color.Black.copy(alpha = 0.85f)),
                    contentAlignment = Alignment.Center
                ) {
                    Card(
                        modifier = Modifier
                            .fillMaxWidth(0.85f)
                            .padding(24.dp),
                        shape = RoundedCornerShape(24.dp),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0B21)),
                        border = BorderStroke(1.5.dp, RazorTeal.copy(alpha = 0.8f))
                    ) {
                        Column(
                            modifier = Modifier.padding(24.dp),
                            horizontalAlignment = Alignment.CenterHorizontally,
                            verticalArrangement = Arrangement.Center
                        ) {
                            CircularProgressIndicator(
                                progress = { publishingProgress },
                                modifier = Modifier.size(64.dp),
                                color = RazorTeal,
                                strokeWidth = 5.dp,
                                trackColor = Color.White.copy(alpha = 0.1f)
                            )
                            
                            Spacer(modifier = Modifier.height(24.dp))
                            
                            Text(
                                text = "UPLOADING STORY SHOT",
                                color = RazorTeal,
                                fontSize = 12.sp,
                                fontWeight = FontWeight.Black,
                                letterSpacing = 2.sp
                            )
                            
                            Spacer(modifier = Modifier.height(10.dp))
                            
                            Text(
                                text = publishingStage,
                                color = Color.White,
                                fontSize = 12.sp,
                                fontWeight = FontWeight.Medium,
                                textAlign = TextAlign.Center,
                                modifier = Modifier.height(36.dp)
                            )
                            
                            Spacer(modifier = Modifier.height(16.dp))
                            
                            // Progress bar
                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(6.dp)
                                    .clip(RoundedCornerShape(3.dp))
                                    .background(Color.White.copy(alpha = 0.1f))
                            ) {
                                Box(
                                    modifier = Modifier
                                        .fillMaxHeight()
                                        .fillMaxWidth(publishingProgress)
                                        .background(Brush.linearGradient(listOf(RazorTeal, RazorBlue)))
                                )
                            }
                            
                            Spacer(modifier = Modifier.height(8.dp))
                            
                            Text(
                                text = "${(publishingProgress * 100).toInt()}% COMPLETED",
                                color = RazorBlue,
                                fontSize = 10.sp,
                                fontWeight = FontWeight.Bold,
                                fontFamily = FontFamily.Monospace
                            )
                            
                            Spacer(modifier = Modifier.height(16.dp))
                            
                            // Verification steps list
                            Column(
                                modifier = Modifier.fillMaxWidth(),
                                verticalArrangement = Arrangement.spacedBy(6.dp)
                            ) {
                                val steps = listOf(
                                    "Optimize Media Frames",
                                    "Secure AES Payload Encryption",
                                    "Cryptographic Node Signature",
                                    "Decentralized Feed Broadcast"
                                )
                                steps.forEachIndexed { index, stepName ->
                                    val isDone = currentStageIndex > index || (currentStageIndex == index && publishingProgress >= 0.95f)
                                    val isCurrent = currentStageIndex == index && !isDone
                                    Row(
                                        verticalAlignment = Alignment.CenterVertically,
                                        modifier = Modifier.fillMaxWidth()
                                    ) {
                                        Icon(
                                            imageVector = if (isDone) Icons.Default.CheckCircle else if (isCurrent) Icons.Default.Pending else Icons.Default.RadioButtonUnchecked,
                                            contentDescription = null,
                                            tint = if (isDone) RazorTeal else if (isCurrent) RazorBlue else Color.Gray,
                                            modifier = Modifier.size(14.dp)
                                        )
                                        Spacer(modifier = Modifier.width(8.dp))
                                        Text(
                                            text = stepName,
                                            color = if (isDone) Color.White else if (isCurrent) Color.White.copy(alpha = 0.7f) else Color.Gray,
                                            fontSize = 11.sp,
                                            fontWeight = if (isCurrent || isDone) FontWeight.Bold else FontWeight.Normal
                                        )
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun SidebarAction(icon: ImageVector, title: String) {
    Column(
        horizontalAlignment = Alignment.CenterHorizontally,
        modifier = Modifier.padding(horizontal = 4.dp)
    ) {
        Icon(imageVector = icon, contentDescription = title, tint = Color.White, modifier = Modifier.size(20.dp))
        Text(text = title, color = GrayText, fontSize = 8.sp, fontWeight = FontWeight.Bold)
    }
}

// ============================================
// SCREEN 3: CREATORS LISTING (Page 7 linkable) - Converted to Photo Gallery Feed
// ============================================
@Composable
fun CreatorsScreen(
    posts: List<Post>,
    creators: List<Creator>,
    subscriptions: List<Subscription>,
    onLike: (Post) -> Unit,
    onTip: (Post, Double) -> Unit,
    onUnlock: (String) -> Unit,
    onCreatorClick: (String) -> Unit,
    onVideoClick: (Post) -> Unit
) {
    // Filter posts that are pictures/photos (contentImage is not empty and not "attached_video")
    val photoPosts = remember(posts) {
        posts.filter { it.contentImage.isNotEmpty() && it.contentImage != "attached_video" }
    }

    Column(modifier = Modifier.fillMaxSize()) {
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp)
                .clip(RoundedCornerShape(24.dp))
                .background(MinimalSurfaceContainer)
                .padding(16.dp)
        ) {
            Column {
                Text(
                    text = "Photo Gallery Feed",
                    style = MaterialTheme.typography.titleLarge,
                    fontWeight = FontWeight.ExtraBold,
                    color = RazorBlue
                )
                Text(
                    text = "A curated feed of stunning photo updates, creative designs, and artistic captures from across our community.",
                    style = MaterialTheme.typography.bodySmall,
                    color = GrayText,
                    modifier = Modifier.padding(top = 4.dp)
                )
            }
        }

        if (photoPosts.isEmpty()) {
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(24.dp),
                contentAlignment = Alignment.Center
            ) {
                Text(
                    text = "No photo posts found matching the query.",
                    style = MaterialTheme.typography.bodyMedium,
                    color = GrayText
                )
            }
        } else {
            LazyColumn(
                modifier = Modifier.fillMaxSize(),
                contentPadding = PaddingValues(bottom = 16.dp)
            ) {
                items(photoPosts, key = { it.id }) { post ->
                    val hasSubscription = subscriptions.any {
                        it.creatorId == post.creatorId &&
                        (it.tierName == "GOLD" || 
                         (it.tierName == "SILVER" && post.requiredTier != "GOLD") || 
                         (it.tierName == "BRONZE" && post.requiredTier == "BRONZE"))
                    }
                    val isLocked = false
                    val isCreatorVerified = creators.find { it.id == post.creatorId }?.isVerified ?: true

                    EntranceAnimationContainer {
                        PostCard(
                            post = post,
                            isLocked = isLocked,
                            onLike = { onLike(post) },
                            onTip = { amt -> onTip(post, amt) },
                            onUnlock = { onUnlock(post.creatorId) },
                            onCreatorClick = { onCreatorClick(post.creatorId) },
                            isCreatorVerified = isCreatorVerified,
                            onVideoClick = { onVideoClick(post) }
                        )
                    }
                }
            }
        }
    }
}

// ========================================================
// SCREEN 4: MARKETPLACE - REPLACES TICKETS TAB (Page 5)
// ========================================================
@Composable
fun LiveEventsScreen(
    products: List<MarketplaceProduct>,
    banners: List<MarketplaceBanner>,
    externalBannersState: SocialHubViewModel.BannersApiState,
    onRefreshBanners: () -> Unit,
    onProductClick: (MarketplaceProduct) -> Unit,
    walletBalance: Double,
    onPurchaseDirect: (String, Double) -> Unit
) {
    var searchQuery by remember { mutableStateOf("") }
    var selectedCategory by remember { mutableStateOf<String?>(null) } // "Trending", "Stickers", "VIP Access"

    val filteredItems = remember(products, selectedCategory, searchQuery) {
        products.filter { prod ->
            val matchesSearch = searchQuery.isBlank() || 
                prod.name.contains(searchQuery, ignoreCase = true) || 
                prod.creatorName.contains(searchQuery, ignoreCase = true) ||
                prod.description.contains(searchQuery, ignoreCase = true)
            matchesSearch
        }
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .verticalScroll(rememberScrollState())
    ) {
        // Drop head banner - Title, Search
        Column(modifier = Modifier.padding(16.dp)) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Column {
                    Text(
                        text = "SocialHub Store",
                        style = MaterialTheme.typography.headlineMedium,
                        fontWeight = FontWeight.Black,
                        color = Color.White
                    )
                    Text(
                        text = "Dynamic catalog & gear shop",
                        style = MaterialTheme.typography.bodySmall,
                        color = GrayText
                    )
                }
            }

            Spacer(modifier = Modifier.height(16.dp))

            OutlinedTextField(
                value = searchQuery,
                onValueChange = { searchQuery = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, searchQuery) },
                placeholder = { Text("Search catalog products, drops...", color = GrayText) },
                leadingIcon = { Icon(Icons.Default.Search, contentDescription = null, tint = GrayText) },
                colors = OutlinedTextFieldDefaults.colors(
                    focusedBorderColor = RazorBlue,
                    unfocusedBorderColor = MinimalBorder,
                    unfocusedContainerColor = MinimalSurfaceContainer,
                    focusedContainerColor = MinimalSurfaceContainer
                ),
                shape = RoundedCornerShape(20.dp),
                modifier = Modifier.fillMaxWidth(),
                readOnly = false
            )
        }

        Spacer(modifier = Modifier.height(10.dp))

        // 1. Dynamic Paid Promotions / Banner Slider (From API or Safe Fallback)
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 16.dp, vertical = 8.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    text = "FEATURED PROMOTIONS",
                    style = MaterialTheme.typography.labelSmall,
                    fontWeight = FontWeight.Bold,
                    color = RazorTeal,
                    letterSpacing = 1.sp,
                    modifier = Modifier.padding(bottom = 8.dp)
                )

                // Network telemetry indicator badge
                val telemetryText = when (externalBannersState) {
                    is SocialHubViewModel.BannersApiState.Loading -> "📡 SYNCING API..."
                    is SocialHubViewModel.BannersApiState.Success -> "🟢 ADMIN API CONNECTED"
                    is SocialHubViewModel.BannersApiState.Error -> "⚠️ OFFLINE CACHE ACTIVE"
                }
                val telemetryColor = when (externalBannersState) {
                    is SocialHubViewModel.BannersApiState.Loading -> RazorBlue
                    is SocialHubViewModel.BannersApiState.Success -> RazorTeal
                    is SocialHubViewModel.BannersApiState.Error -> Color.Red
                }

                Text(
                    text = telemetryText,
                    fontSize = 7.5.sp,
                    fontWeight = FontWeight.Black,
                    color = telemetryColor,
                    letterSpacing = 0.5.sp,
                    modifier = Modifier.padding(bottom = 8.dp)
                )
            }

            when (externalBannersState) {
                is SocialHubViewModel.BannersApiState.Loading -> {
                    // Ultra-premium shimmering layout container skeleton
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(180.dp)
                            .clip(RoundedCornerShape(20.dp))
                            .background(Color(0xFF130E29))
                            .border(BorderStroke(1.dp, MinimalBorder.copy(alpha = 0.3f)), RoundedCornerShape(20.dp)),
                        contentAlignment = Alignment.Center
                    ) {
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            CircularProgressIndicator(
                                color = RazorTeal,
                                strokeWidth = 2.dp,
                                modifier = Modifier.size(24.dp)
                            )
                            Spacer(modifier = Modifier.height(12.dp))
                            Text(
                                text = "FETCHING PROMOTIONAL CAMPAIGNS...",
                                color = GrayText,
                                fontSize = 8.5.sp,
                                fontWeight = FontWeight.Bold,
                                fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace,
                                letterSpacing = 0.5.sp
                            )
                        }
                    }
                }
                is SocialHubViewModel.BannersApiState.Success -> {
                    val activeBanners = externalBannersState.banners
                    if (activeBanners.isNotEmpty()) {
                        var activeBannerIndex by remember { mutableStateOf(0) }
                        
                        LaunchedEffect(activeBanners.size) {
                            while (true) {
                                kotlinx.coroutines.delay(5000)
                                activeBannerIndex = (activeBannerIndex + 1) % activeBanners.size
                            }
                        }

                        Card(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(180.dp)
                                .clickable {
                                    val activeBanner = activeBanners.getOrNull(activeBannerIndex)
                                    activeBanner?.targetProductId?.let { prodId ->
                                        val targetProduct = products.find { it.id == prodId }
                                        if (targetProduct != null) {
                                            onProductClick(targetProduct)
                                        }
                                    }
                                }
                                .testTag("promo_banner_slider"),
                            shape = RoundedCornerShape(20.dp),
                            colors = CardDefaults.cardColors(containerColor = ObsidianDark),
                            border = BorderStroke(1.dp, MinimalBorder)
                        ) {
                            Box(modifier = Modifier.fillMaxSize()) {
                                val banner = activeBanners[activeBannerIndex]
                                
                                AsyncImage(
                                    model = banner.imageUrl,
                                    contentDescription = banner.title,
                                    contentScale = ContentScale.Crop,
                                    modifier = Modifier.fillMaxSize()
                                )

                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(
                                            androidx.compose.ui.graphics.Brush.verticalGradient(
                                                colors = listOf(
                                                    Color.Black.copy(alpha = 0.15f),
                                                    Color.Black.copy(alpha = 0.85f)
                                                )
                                            )
                                        )
                                )

                                Box(
                                    modifier = Modifier
                                        .align(Alignment.TopEnd)
                                        .padding(12.dp)
                                        .clip(RoundedCornerShape(6.dp))
                                        .background(Color.Black.copy(alpha = 0.75f))
                                        .border(1.dp, RazorBlue.copy(alpha = 0.6f), RoundedCornerShape(6.dp))
                                        .padding(horizontal = 8.dp, vertical = 4.dp)
                                ) {
                                    Text(
                                        text = "LIVE CAMPAIGN",
                                        color = RazorBlue,
                                        fontSize = 8.sp,
                                        fontWeight = FontWeight.Bold,
                                        letterSpacing = 0.5.sp
                                    )
                                }

                                Column(
                                    modifier = Modifier
                                        .align(Alignment.BottomStart)
                                        .padding(16.dp)
                                        .padding(bottom = 8.dp)
                                ) {
                                    Text(
                                        text = banner.title,
                                        style = MaterialTheme.typography.titleMedium,
                                        fontWeight = FontWeight.Black,
                                        color = Color.White
                                    )
                                    Spacer(modifier = Modifier.height(4.dp))
                                    Text(
                                        text = banner.description,
                                        style = MaterialTheme.typography.bodySmall,
                                        color = LightText,
                                        maxLines = 2,
                                        overflow = TextOverflow.Ellipsis
                                    )
                                }

                                Row(
                                    modifier = Modifier
                                        .align(Alignment.BottomCenter)
                                        .padding(bottom = 10.dp),
                                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                                ) {
                                    activeBanners.forEachIndexed { index, _ ->
                                        Box(
                                            modifier = Modifier
                                                .size(6.dp)
                                                .clip(CircleShape)
                                                .background(
                                                    if (index == activeBannerIndex) RazorTeal else Color.White.copy(alpha = 0.3f)
                                                )
                                        )
                                    }
                                }
                            }
                        }
                    }
                }
                is SocialHubViewModel.BannersApiState.Error -> {
                    // Graceful fallback to local database banners
                    if (banners.isNotEmpty()) {
                        var activeBannerIndex by remember { mutableStateOf(0) }
                        
                        LaunchedEffect(banners.size) {
                            while (true) {
                                kotlinx.coroutines.delay(5000)
                                activeBannerIndex = (activeBannerIndex + 1) % banners.size
                            }
                        }

                        Card(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(180.dp)
                                .clickable {
                                    val activeBanner = banners.getOrNull(activeBannerIndex)
                                    activeBanner?.targetProductId?.let { prodId ->
                                        val targetProduct = products.find { it.id == prodId }
                                        if (targetProduct != null) {
                                            onProductClick(targetProduct)
                                        }
                                    }
                                }
                                .testTag("promo_banner_slider_fallback"),
                            shape = RoundedCornerShape(20.dp),
                            colors = CardDefaults.cardColors(containerColor = ObsidianDark),
                            border = BorderStroke(1.dp, Color.Red.copy(0.3f))
                        ) {
                            Box(modifier = Modifier.fillMaxSize()) {
                                val banner = banners[activeBannerIndex]
                                
                                AsyncImage(
                                    model = banner.imageUrl,
                                    contentDescription = banner.title,
                                    contentScale = ContentScale.Crop,
                                    modifier = Modifier.fillMaxSize()
                                )

                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(
                                            androidx.compose.ui.graphics.Brush.verticalGradient(
                                                colors = listOf(
                                                    Color.Black.copy(alpha = 0.2f),
                                                    Color.Black.copy(alpha = 0.85f)
                                                )
                                            )
                                        )
                                )

                                Box(
                                    modifier = Modifier
                                        .align(Alignment.TopEnd)
                                        .padding(12.dp)
                                        .clip(RoundedCornerShape(6.dp))
                                        .background(Color.Black.copy(alpha = 0.7f))
                                        .border(1.dp, Color.Red.copy(alpha = 0.5f), RoundedCornerShape(6.dp))
                                        .padding(horizontal = 8.dp, vertical = 4.dp)
                                ) {
                                    Text(
                                        text = "LOCAL CACHE",
                                        color = Color.Red,
                                        fontSize = 8.sp,
                                        fontWeight = FontWeight.Bold,
                                        letterSpacing = 0.5.sp
                                    )
                                }

                                Column(
                                    modifier = Modifier
                                        .align(Alignment.BottomStart)
                                        .padding(16.dp)
                                        .padding(bottom = 8.dp)
                                ) {
                                    Text(
                                        text = banner.title,
                                        style = MaterialTheme.typography.titleMedium,
                                        fontWeight = FontWeight.Black,
                                        color = Color.White
                                    )
                                    Spacer(modifier = Modifier.height(4.dp))
                                    Text(
                                        text = banner.description,
                                        style = MaterialTheme.typography.bodySmall,
                                        color = LightText,
                                        maxLines = 2,
                                        overflow = TextOverflow.Ellipsis
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }

        // Dynamic Marketplace Products Grid
        Text(
            text = "Dynamic Store Products",
            style = MaterialTheme.typography.titleMedium,
            fontWeight = FontWeight.Bold,
            color = LightText,
            modifier = Modifier.padding(start = 16.dp, top = 20.dp, bottom = 12.dp)
        )

        if (filteredItems.isEmpty()) {
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(vertical = 48.dp, horizontal = 24.dp),
                contentAlignment = Alignment.Center
            ) {
                Column(
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.Center
                ) {
                    Box(
                        modifier = Modifier
                            .size(72.dp)
                            .clip(CircleShape)
                            .background(RazorBlue.copy(alpha = 0.12f))
                            .border(1.dp, RazorBlue.copy(alpha = 0.4f), CircleShape),
                        contentAlignment = Alignment.Center
                    ) {
                        Icon(
                            imageVector = Icons.Default.Search,
                            contentDescription = "No Products Matching Search",
                            tint = RazorBlue,
                            modifier = Modifier.size(32.dp)
                        )
                    }
                    Spacer(modifier = Modifier.height(16.dp))
                    Text(
                        text = "No Products Found",
                        color = Color.White,
                        fontWeight = FontWeight.Bold,
                        fontSize = 15.sp
                    )
                    Spacer(modifier = Modifier.height(6.dp))
                    Text(
                        text = "We couldn't find any items matching your search query. Try typing something else or selecting another category.",
                        color = GrayText,
                        fontSize = 11.5.sp,
                        textAlign = TextAlign.Center,
                        lineHeight = 16.sp,
                        modifier = Modifier.padding(horizontal = 24.dp)
                    )
                }
            }
        } else {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp),
                verticalArrangement = Arrangement.spacedBy(14.dp)
            ) {
                val chunkedItems = filteredItems.chunked(2)
                chunkedItems.forEach { rowItems ->
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(14.dp)
                    ) {
                        rowItems.forEach { product ->
                            Box(modifier = Modifier.weight(1f)) {
                                ShopItemCard(
                                    product = product,
                                    onProductClick = { onProductClick(product) }
                                )
                            }
                        }
                        if (rowItems.size == 1) {
                            Box(modifier = Modifier.weight(1f))
                        }
                    }
                }
            }
        }

        // 2. Real Banner Ads Frame (Reserved Empty Slot for AdMob / Unity Ads)
        Spacer(modifier = Modifier.height(20.dp))
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 16.dp)
                .testTag("real_ads_banner_frame")
        ) {
            Text(
                text = "SPONSOR CORNER",
                style = MaterialTheme.typography.labelSmall,
                fontWeight = FontWeight.Bold,
                color = Color.White.copy(0.4f),
                letterSpacing = 1.sp,
                modifier = Modifier.padding(bottom = 6.dp)
            )

            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(65.dp)
                    .clip(RoundedCornerShape(12.dp))
                    .background(Color.White.copy(0.02f))
                    .border(
                        BorderStroke(
                            1.dp,
                            androidx.compose.ui.graphics.Brush.linearGradient(
                                colors = listOf(
                                    Color.White.copy(0.08f),
                                    Color.White.copy(0.03f)
                                )
                            )
                        ),
                        RoundedCornerShape(12.dp)
                    ),
                contentAlignment = Alignment.Center
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                    modifier = Modifier.padding(horizontal = 12.dp)
                ) {
                    Icon(
                        imageVector = Icons.Default.Campaign,
                        contentDescription = "Ad Slot",
                        tint = Color.White.copy(0.2f),
                        modifier = Modifier.size(20.dp)
                    )
                    Column {
                        Text(
                            text = "REAL-TIME ADVERTISING INTEGRATION FRAME",
                            color = Color.White.copy(0.3f),
                            fontSize = 8.5.sp,
                            fontWeight = FontWeight.Bold,
                            fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace,
                            letterSpacing = 0.5.sp
                        )
                        Text(
                            text = "AdMob / Unity programmatic placement slot (60dp standard banner container)",
                            color = Color.White.copy(0.18f),
                            fontSize = 7.5.sp,
                            fontWeight = FontWeight.Normal
                        )
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(40.dp))
    }
}

@Composable
fun ShopItemCard(
    product: MarketplaceProduct,
    onProductClick: () -> Unit
) {
    val rating = remember(product.id) { 4.5 + (product.id % 5) * 0.1 }
    val downloads = remember(product.id) { "${1200 + (product.id * 350)}+" }
    val category = remember(product.name) {
        when {
            product.name.contains("Audio", ignoreCase = true) || product.name.contains("Synth", ignoreCase = true) -> "AUDIO ENGINE"
            product.name.contains("Wallet", ignoreCase = true) || product.name.contains("Crypto", ignoreCase = true) -> "SECURE FINTECH"
            product.name.contains("Lightroom", ignoreCase = true) || product.name.contains("Cycles", ignoreCase = true) -> "CREATIVE UTILITY"
            product.name.contains("Book", ignoreCase = true) -> "KNOWLEDGE DROPS"
            else -> "SOFTWARE UTILITY"
        }
    }

    Card(
        shape = RoundedCornerShape(24.dp),
        colors = CardDefaults.cardColors(containerColor = Color(0x1F110B29)),
        border = BorderStroke(1.dp, MinimalBorder.copy(alpha = 0.5f)),
        modifier = Modifier
            .fillMaxWidth()
            .clickable { onProductClick() }
    ) {
        Column(modifier = Modifier.fillMaxWidth()) {
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(115.dp)
            ) {
                AsyncImage(
                    model = product.imageUrl,
                    contentDescription = product.name,
                    contentScale = ContentScale.Crop,
                    modifier = Modifier.fillMaxSize()
                )

                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .background(
                            androidx.compose.ui.graphics.Brush.verticalGradient(
                                colors = listOf(Color.Transparent, Color.Black.copy(0.7f))
                            )
                        )
                )

                Box(
                    modifier = Modifier
                        .padding(8.dp)
                        .clip(RoundedCornerShape(8.dp))
                        .background(Color.Black.copy(0.7f))
                        .border(1.dp, RazorBlue.copy(0.3f), RoundedCornerShape(8.dp))
                        .padding(horizontal = 6.dp, vertical = 2.dp)
                        .align(Alignment.TopStart)
                ) {
                    Text(
                        text = category,
                        color = RazorBlue,
                        fontSize = 7.5.sp,
                        fontWeight = FontWeight.Bold,
                        letterSpacing = 0.5.sp
                    )
                }

                Row(
                    modifier = Modifier
                        .padding(8.dp)
                        .clip(RoundedCornerShape(8.dp))
                        .background(Color.Black.copy(0.6f))
                        .padding(horizontal = 6.dp, vertical = 2.dp)
                        .align(Alignment.TopEnd),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    Box(
                        modifier = Modifier
                            .size(5.dp)
                            .clip(CircleShape)
                            .background(RazorTeal)
                    )
                    Text(
                        text = "REAL-TIME",
                        color = RazorTeal,
                        fontSize = 7.5.sp,
                        fontWeight = FontWeight.Black
                    )
                }
            }

            Column(modifier = Modifier.padding(12.dp)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Card(
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier.size(44.dp),
                        border = BorderStroke(1.dp, MinimalBorder),
                        colors = CardDefaults.cardColors(containerColor = ObsidianDark)
                    ) {
                        AsyncImage(
                            model = product.logoUrl,
                            contentDescription = "Logo",
                            contentScale = ContentScale.Crop,
                            modifier = Modifier.fillMaxSize()
                        )
                    }

                    Column(modifier = Modifier.weight(1f)) {
                        Text(
                            text = product.name,
                            style = MaterialTheme.typography.titleSmall,
                            fontWeight = FontWeight.Bold,
                            color = LightText,
                            maxLines = 1,
                            overflow = TextOverflow.Ellipsis
                        )
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(4.dp)
                        ) {
                            Text(
                                text = "by ${product.creatorName}",
                                color = GrayText,
                                fontSize = 10.sp,
                                maxLines = 1,
                                overflow = TextOverflow.Ellipsis
                            )
                            Icon(
                                imageVector = Icons.Default.CheckCircle,
                                contentDescription = "Verified Creator",
                                tint = RazorBlue,
                                modifier = Modifier.size(10.dp)
                            )
                        }
                    }
                }

                Spacer(modifier = Modifier.height(10.dp))

                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Default.Star,
                            contentDescription = "Rating",
                            tint = SafeGold,
                            modifier = Modifier.size(12.dp)
                        )
                        Text(
                            text = String.format("%.1f", rating),
                            color = LightText,
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Text(
                            text = "($downloads)",
                            color = GrayText,
                            fontSize = 9.sp
                        )
                    }

                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(3.dp),
                        modifier = Modifier
                            .clip(RoundedCornerShape(6.dp))
                            .background(RazorTeal.copy(0.1f))
                            .padding(horizontal = 6.dp, vertical = 2.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Default.CheckCircle,
                            contentDescription = "Secure Check",
                            tint = RazorTeal,
                            modifier = Modifier.size(8.dp)
                        )
                        Text(
                            text = "SECURE",
                            color = RazorTeal,
                            fontSize = 7.5.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }

                Spacer(modifier = Modifier.height(12.dp))

                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(1.dp)
                        .background(Color.White.copy(0.06f))
                )

                Spacer(modifier = Modifier.height(10.dp))

                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Column {
                        Text(
                            text = "LICENSE PRICE",
                            color = Color.White.copy(0.4f),
                            fontSize = 7.5.sp,
                            fontWeight = FontWeight.Bold,
                            letterSpacing = 0.5.sp
                        )
                        Text(
                            text = "$${String.format("%.2f", product.price)}",
                            color = SafeGold,
                            fontWeight = FontWeight.Black,
                            fontSize = 14.sp
                        )
                    }

                    Button(
                        onClick = onProductClick,
                        colors = ButtonDefaults.buttonColors(containerColor = RazorBlue),
                        shape = RoundedCornerShape(10.dp),
                        contentPadding = PaddingValues(horizontal = 12.dp, vertical = 6.dp),
                        modifier = Modifier
                            .height(30.dp)
                            .testTag("view_details_${product.id}")
                    ) {
                        Text(
                            text = "ACQUIRE",
                            color = Color.Black,
                            fontSize = 9.5.sp,
                            fontWeight = FontWeight.Black,
                            letterSpacing = 0.5.sp
                        )
                    }
                }
            }
        }
    }
}

