@Composable
fun ChatScreen(
    chatMessages: List<ChatMessage>,
    creators: List<Creator>,
    encryptionEnabled: Boolean,
    onToggleEncryption: () -> Unit,
    onSendMessage: (String, String) -> Unit,
    onPayInvoice: (ChatMessage) -> Unit,
    onDeclineInvoice: (ChatMessage) -> Unit,
    onMarkAsSeen: (String) -> Unit,
    initialRecipient: String? = null,
    onDeleteMessageForMe: (ChatMessage) -> Unit = {},
    onDeleteMessageForEveryone: (ChatMessage) -> Unit = {},
    onLoadMoreChatMessages: () -> Unit = {}
) {
    var activeThreadRecipient by remember(initialRecipient) { mutableStateOf<String?>(initialRecipient) }
    androidx.activity.compose.BackHandler(enabled = activeThreadRecipient != null) {
        activeThreadRecipient = null
    }
    var inputMessage by remember { mutableStateOf("") }
    var chatSearchQuery by remember { mutableStateOf("") }
    var selectedCategoryTab by remember { mutableStateOf("All") } // "All", "Creators", "Followers"
    var showAttachmentDialog by remember { mutableStateOf(false) }

    val context = androidx.compose.ui.platform.LocalContext.current

    val documentPickerLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.GetContent()
    ) { uri: android.net.Uri? ->
        uri?.let {
            var fileName: String? = null
            if (it.scheme == "content") {
                val cursor = context.contentResolver.query(it, null, null, null, null)
                try {
                    if (cursor != null && cursor.moveToFirst()) {
                        val index = cursor.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
                        if (index != -1) {
                            fileName = cursor.getString(index)
                        }
                    }
                } finally {
                    cursor?.close()
                }
            }
            if (fileName == null) {
                fileName = it.path
                val cut = fileName?.lastIndexOf('/') ?: -1
                if (cut != -1) {
                    fileName = fileName?.substring(cut + 1)
                }
            }
            val finalName = fileName ?: "document.pdf"
            onSendMessage(activeThreadRecipient ?: "", "📄 Document: $finalName")
        }
    }

    val galleryPickerLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.GetContent()
    ) { uri: android.net.Uri? ->
        uri?.let {
            var fileName: String? = null
            if (it.scheme == "content") {
                val cursor = context.contentResolver.query(it, null, null, null, null)
                try {
                    if (cursor != null && cursor.moveToFirst()) {
                        val index = cursor.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
                        if (index != -1) {
                            fileName = cursor.getString(index)
                        }
                    }
                } finally {
                    cursor?.close()
                }
            }
            if (fileName == null) {
                fileName = it.path
                val cut = fileName?.lastIndexOf('/') ?: -1
                if (cut != -1) {
                    fileName = fileName?.substring(cut + 1)
                }
            }
            val finalName = fileName ?: "image.jpg"
            onSendMessage(activeThreadRecipient ?: "", "🖼️ Image: $finalName")
        }
    }

    val videoPickerLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.GetContent()
    ) { uri: android.net.Uri? ->
        uri?.let {
            var fileName: String? = null
            if (it.scheme == "content") {
                val cursor = context.contentResolver.query(it, null, null, null, null)
                try {
                    if (cursor != null && cursor.moveToFirst()) {
                        val index = cursor.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
                        if (index != -1) {
                            fileName = cursor.getString(index)
                        }
                    }
                } finally {
                    cursor?.close()
                }
            }
            if (fileName == null) {
                fileName = it.path
                val cut = fileName?.lastIndexOf('/') ?: -1
                if (cut != -1) {
                    fileName = fileName?.substring(cut + 1)
                }
            }
            val finalName = fileName ?: "video.mp4"
            onSendMessage(activeThreadRecipient ?: "", "🎥 Video: $finalName")
        }
    }

    val audioPickerLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.GetContent()
    ) { uri: android.net.Uri? ->
        uri?.let {
            var fileName: String? = null
            if (it.scheme == "content") {
                val cursor = context.contentResolver.query(it, null, null, null, null)
                try {
                    if (cursor != null && cursor.moveToFirst()) {
                        val index = cursor.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
                        if (index != -1) {
                            fileName = cursor.getString(index)
                        }
                    }
                } finally {
                    cursor?.close()
                }
            }
            if (fileName == null) {
                fileName = it.path
                val cut = fileName?.lastIndexOf('/') ?: -1
                if (cut != -1) {
                    fileName = fileName?.substring(cut + 1)
                }
            }
            val finalName = fileName ?: "audio.mp3"
            onSendMessage(activeThreadRecipient ?: "", "🎵 Audio: $finalName")
        }
    }

    val onlineUsers = remember {
        androidx.compose.runtime.mutableStateMapOf(
            "Alex Rivera" to true,
            "Sarah Chen" to false,
            "Tokyo Trip" to true,
            "Emma Watson" to true,
            "Lucas Peterson" to false,
            "Sophia Martinez" to false,
            "Liam Johnson" to false
        )
    }

    val recipientName = activeThreadRecipient
    LaunchedEffect(recipientName, chatMessages.size) {
        if (recipientName != null) {
            onMarkAsSeen(recipientName)
        }
    }

    val listState = androidx.compose.foundation.lazy.rememberLazyListState()

    // Mock active followers list
    val followersList = listOf(
        Triple("Emma Watson", "Emma", Color(0xFF00FF88)),
        Triple("Lucas Peterson", "Lucas", Color(0xFF00FF88)),
        Triple("Sophia Martinez", "Sophia", Color(0xFF00FF88)),
        Triple("Liam Johnson", "Liam", Color(0xFF00FF88))
    )

    // Combined contact search/mapping
    val allCreatorsList = creators.map { it.name }

    if (activeThreadRecipient == null) {
        // --- CHAT PORTAL (DM LIST & RECIPIENT SELECTOR) ---
        Column(
            modifier = Modifier
                .fillMaxSize()
                .background(
                    Brush.verticalGradient(
                        colors = listOf(
                            Color(0xFF150D2E), // Rich cosmic dark violet
                            Color(0xFF090514)  // Matte obsidian black
                        )
                    )
                )
        ) {
            // Header
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 18.dp),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Column {
                    Text(
                        text = "Secure DMs",
                        style = MaterialTheme.typography.headlineMedium.copy(
                            fontWeight = FontWeight.Black,
                            letterSpacing = (-0.5).sp
                        ),
                        color = Color.White
                    )
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Icon(
                            imageVector = Icons.Default.Lock,
                            contentDescription = "Encrypted",
                            tint = Color(0xFF00FF88),
                            modifier = Modifier.size(12.dp)
                        )
                        Spacer(modifier = Modifier.width(4.dp))
                        Text(
                            text = "End-to-End Encrypted",
                            color = Color(0xFF00FF88),
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }
            }

            // Category Pill Switcher (All / Creators / Followers)
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 6.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                listOf("All", "Creators", "Followers").forEach { tab ->
                    val isSelected = selectedCategoryTab == tab
                    Box(
                        modifier = Modifier
                            .clip(RoundedCornerShape(20.dp))
                            .background(if (isSelected) RazorTeal else Color(0x15FFFFFF))
                            .border(1.dp, if (isSelected) Color.Transparent else Color(0x22FFFFFF), RoundedCornerShape(20.dp))
                            .clickable { selectedCategoryTab = tab }
                            .padding(horizontal = 14.dp, vertical = 8.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = tab,
                            color = if (isSelected) Color.Black else Color.White,
                            fontSize = 12.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }
            }

            // Unified Search Bar
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 10.dp)
                    .clip(RoundedCornerShape(14.dp))
                    .background(Color(0xFF1F1532))
                    .border(1.dp, Color(0xFF332353), RoundedCornerShape(14.dp))
                    .padding(horizontal = 12.dp, vertical = 12.dp)
            ) {
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Icon(
                        imageVector = Icons.Default.Search,
                        contentDescription = "Search icon",
                        tint = GrayText,
                        modifier = Modifier.size(18.dp)
                    )
                    Spacer(modifier = Modifier.width(8.dp))
                    BasicTextField(
                        value = chatSearchQuery,
                        onValueChange = { chatSearchQuery = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, chatSearchQuery) },
                        textStyle = LocalTextStyle.current.copy(color = Color.White, fontSize = 14.sp),
                        modifier = Modifier.fillMaxWidth(),
                        singleLine = true,
                        decorationBox = { innerTextField ->
                            if (chatSearchQuery.isEmpty()) {
                                Text("Search creators or followers...", color = GrayText, fontSize = 14.sp)
                            }
                            innerTextField()
                        }
                    )
                }
            }

            // Active Now Section
            Column(modifier = Modifier.padding(vertical = 8.dp)) {
                Text(
                    text = "ACTIVE NOW",
                    fontSize = 10.sp,
                    fontWeight = FontWeight.Black,
                    color = Color(0xFF00FF88),
                    letterSpacing = 1.sp,
                    modifier = Modifier.padding(horizontal = 16.dp, vertical = 6.dp)
                )
                
                LazyRow(
                    contentPadding = PaddingValues(horizontal = 16.dp, vertical = 4.dp),
                    horizontalArrangement = Arrangement.spacedBy(14.dp)
                ) {
                    val activePeople = when (selectedCategoryTab) {
                        "Creators" -> creators.map { Triple(it.name, it.name.take(4), Color(0xFF00FF88)) }
                        "Followers" -> followersList
                        else -> {
                            creators.map { Triple(it.name, it.name.take(4), Color(0xFF00FF88)) } + followersList
                        }
                    }

                    items(activePeople) { user ->
                        val isUserOnline = onlineUsers[user.first] ?: true
                        val userStatusColor = if (isUserOnline) Color(0xFF00FF88) else Color(0xFFFF4D4D)
                        Column(
                            horizontalAlignment = Alignment.CenterHorizontally,
                            modifier = Modifier
                                .bounceClick { activeThreadRecipient = user.first }
                                .padding(vertical = 4.dp)
                        ) {
                            Box(contentAlignment = Alignment.BottomEnd) {
                                Box(
                                    modifier = Modifier
                                        .size(54.dp)
                                        .clip(CircleShape)
                                        .background(
                                            Brush.linearGradient(
                                                colors = listOf(RazorBlue, userStatusColor)
                                            )
                                        )
                                        .padding(2.dp),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Box(
                                        modifier = Modifier
                                            .fillMaxSize()
                                            .clip(CircleShape)
                                            .background(Color(0xFF130E22)),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(
                                            text = user.second.take(1).uppercase(),
                                            color = Color.White,
                                            fontWeight = FontWeight.Black,
                                            fontSize = 16.sp
                                        )
                                    }
                                }
                                // Online dot
                                Box(
                                    modifier = Modifier
                                        .size(14.dp)
                                        .clip(CircleShape)
                                        .background(userStatusColor)
                                        .border(2.dp, Color(0xFF0F081D), CircleShape)
                                )
                            }
                            Spacer(modifier = Modifier.height(4.dp))
                            Text(
                                text = user.second,
                                color = Color.White,
                                fontSize = 11.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }
                }
            }

            Text(
                text = "CONVERSATIONS",
                fontSize = 10.sp,
                fontWeight = FontWeight.Black,
                color = GrayText,
                letterSpacing = 1.sp,
                modifier = Modifier.padding(start = 16.dp, top = 16.dp, bottom = 6.dp)
            )

            // Dynamic conversation list mapping
            data class ChatItem(
                val title: String,
                val lastMsg: String,
                val time: String,
                val unseenCount: Int,
                val isCreator: Boolean
            )

            val defaultChats = listOf(
                ChatItem("Alex Rivera", "Hey! Let's check out that new design asset.", "10:42 AM", 0, true),
                ChatItem("Sarah Chen", "Are we still meeting at 5 for coffee?", "Yesterday", 0, true),
                ChatItem("Tokyo Trip", "Did you check out the new design?", "2m ago", 0, true),
                ChatItem("Emma Watson", "Hey! Thanks for sharing the updates!", "Thursday", 0, false),
                ChatItem("Lucas Peterson", "I really enjoyed our chat yesterday!", "Mon", 0, false)
            )

            val recentChatsList = defaultChats.map { defaultChat ->
                val recipient = defaultChat.title
                val threadMsgs = chatMessages.filter {
                    (it.senderName == recipient && it.receiverName == "You") ||
                    (it.senderName == "You" && it.receiverName == recipient) ||
                    (recipient == "Tokyo Trip" && it.receiverName == "Tokyo Trip")
                }
                if (threadMsgs.isNotEmpty()) {
                    val lastMsg = threadMsgs.last()
                    val contentDisclosed = if (lastMsg.isEncrypted) {
                        val cleaned = lastMsg.encryptedContent.trim()
                        val isBase64Pattern = cleaned.isNotEmpty() && !cleaned.contains(" ") && cleaned.all { it.isLetterOrDigit() || it == '+' || it == '/' || it == '=' }
                        if (isBase64Pattern && cleaned != "This message was deleted") {
                            try {
                                val decoded = android.util.Base64.decode(cleaned, android.util.Base64.DEFAULT)
                                String(decoded, Charsets.UTF_8).trim()
                            } catch (e: Exception) {
                                lastMsg.encryptedContent
                            }
                        } else {
                            lastMsg.encryptedContent
                        }
                    } else {
                        lastMsg.encryptedContent
                    }
                    val unseenCount = threadMsgs.count { it.senderName != "You" && !it.isSeen }
                    ChatItem(
                        title = recipient,
                        lastMsg = contentDisclosed,
                        time = formatChatTimestamp(lastMsg.timestamp),
                        unseenCount = unseenCount,
                        isCreator = allCreatorsList.contains(recipient)
                    )
                } else {
                    defaultChat
                }
            }

            // Filter lists based on Search Query and Category Switcher Tab
            val filteredChats = recentChatsList.filter { chat ->
                val matchesQuery = chat.title.contains(chatSearchQuery, ignoreCase = true) ||
                        chat.lastMsg.contains(chatSearchQuery, ignoreCase = true)
                val matchesTab = when (selectedCategoryTab) {
                    "Creators" -> chat.isCreator
                    "Followers" -> !chat.isCreator && chat.title != "Tokyo Trip"
                    else -> true
                }
                matchesQuery && matchesTab
            }

            LazyColumn(
                modifier = Modifier.weight(1f),
                contentPadding = PaddingValues(bottom = 16.dp)
            ) {
                if (filteredChats.isEmpty()) {
                    item {
                        Column(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(32.dp),
                            horizontalAlignment = Alignment.CenterHorizontally
                        ) {
                            Text("No chats found matching filters", color = GrayText, fontSize = 14.sp)
                        }
                    }
                } else {
                    items(filteredChats) { chat ->
                        val isGroup = chat.title == "Tokyo Trip"
                        val isChatOnline = onlineUsers[chat.title] ?: true
                        val dynamicIndicator = if (isChatOnline) Color(0xFF00FF88) else Color(0xFFFF4D4D)
                        
                        ChatConversationRow(
                            title = chat.title,
                            sub = chat.lastMsg,
                            time = chat.time,
                            indicator = dynamicIndicator,
                            isGroup = isGroup,
                            unseenCount = chat.unseenCount,
                            onOpen = { activeThreadRecipient = chat.title }
                        )
                    }
                }
            }
        }
    } else {
        // --- CHAT WINDOW (WHATSAPP-INSPIRED GLASSMORPHIC CHATROOM) ---
        val recipientName = activeThreadRecipient ?: ""
        var chatThemeIndex by remember { mutableStateOf(0) }

        Column(
            modifier = Modifier
                .fillMaxSize()
                .drawBehind {
                    when (chatThemeIndex) {
                        1 -> {
                            // Theme 1: Neon Grid Hologram
                            drawRect(color = Color(0xFF030A1C))
                            val gridSpacing = 40.dp.toPx()
                            val lineOpacity = 0.08f
                            var y = 0f
                            while (y < size.height) {
                                drawLine(
                                    color = RazorTeal,
                                    start = Offset(0f, y),
                                    end = Offset(size.width, y),
                                    strokeWidth = 1f,
                                    alpha = lineOpacity
                                )
                                y += gridSpacing
                            }
                            var x = 0f
                            while (x < size.width) {
                                drawLine(
                                    color = RazorTeal,
                                    start = Offset(x, 0f),
                                    end = Offset(x, size.height),
                                    strokeWidth = 1f,
                                    alpha = lineOpacity
                                )
                                x += gridSpacing
                            }
                        }
                        2 -> {
                            // Theme 2: Solar Flare
                            drawRect(color = Color(0xFF14070B))
                            drawCircle(
                                brush = Brush.radialGradient(
                                    colors = listOf(Color(0xFFFF5E62).copy(alpha = 0.2f), Color.Transparent),
                                    center = Offset(size.width / 2f, size.height / 3f),
                                    radius = size.width
                                )
                            )
                        }
                        3 -> {
                            // Theme 3: Cyberpunk Hologram
                            drawRect(color = Color(0xFF0D0315))
                            val gridSpacing = 8.dp.toPx()
                            var y = 0f
                            while (y < size.height) {
                                drawLine(
                                    color = Color(0xFFFF007F),
                                    start = Offset(0f, y),
                                    end = Offset(size.width, y),
                                    strokeWidth = 1f,
                                    alpha = 0.03f
                                )
                                y += gridSpacing
                            }
                        }
                        else -> {
                            // Theme 0: Deep Cosmic
                            val gradientBrush = Brush.verticalGradient(
                                colors = listOf(
                                    Color(0xFF0F0822),
                                    Color(0xFF05030A)
                                )
                            )
                            drawRect(brush = gradientBrush)
                        }
                    }
                }
        ) {
            // Header: Glassmorphic Floating Top Bar
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0xE61B112D)) // Semi-transparent glass header
                    .padding(horizontal = 8.dp, vertical = 12.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                IconButton(
                    onClick = { activeThreadRecipient = null },
                    modifier = Modifier.testTag("chat_back_btn")
                ) {
                    Icon(imageVector = Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back", tint = Color.White)
                }
                
                Spacer(modifier = Modifier.width(4.dp))
                
                val isOnline = onlineUsers[recipientName] ?: true
                val statusColor = if (isOnline) Color(0xFF00FF88) else Color(0xFFFF4D4D)
                val statusText = if (isOnline) "Online" else "Offline"

                // Avatar with online status ring
                Box(contentAlignment = Alignment.BottomEnd) {
                    Box(
                        modifier = Modifier
                            .size(38.dp)
                            .clip(CircleShape)
                            .background(
                                Brush.linearGradient(
                                    colors = listOf(RazorBlue, statusColor)
                                )
                            ),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = recipientName.take(1).uppercase(),
                            color = Color.White,
                            fontWeight = FontWeight.Bold,
                            fontSize = 14.sp
                        )
                    }
                    // Online indicator
                    Box(
                        modifier = Modifier
                            .size(10.dp)
                            .clip(CircleShape)
                            .background(statusColor)
                            .border(1.5.dp, Color(0xFF1B112D), CircleShape)
                    )
                }

                Spacer(modifier = Modifier.width(10.dp))
                
                Column(modifier = Modifier.weight(1f)) {
                    Text(
                        text = if (recipientName == "Tokyo Trip") "Tokyo Trip 🇯🇵" else recipientName,
                        fontWeight = FontWeight.ExtraBold,
                        color = Color.White,
                        fontSize = 15.sp
                    )
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        modifier = Modifier
                            .clip(RoundedCornerShape(4.dp))
                            .clickable {
                                onlineUsers[recipientName] = !isOnline
                            }
                    ) {
                        Box(
                            modifier = Modifier
                                .size(6.dp)
                                .clip(CircleShape)
                                .background(statusColor)
                        )
                        Spacer(modifier = Modifier.width(4.dp))
                        Text(
                            text = statusText,
                            color = statusColor,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Spacer(modifier = Modifier.width(6.dp))
                        Text(
                            text = "• Click to toggle",
                            color = Color.Gray.copy(alpha = 0.8f),
                            fontSize = 10.sp
                        )
                    }
                }

                // Holographic Theme Switcher Button
                IconButton(
                    onClick = { chatThemeIndex = (chatThemeIndex + 1) % 4 },
                    modifier = Modifier.padding(end = 4.dp).size(34.dp)
                ) {
                    Icon(
                        imageVector = Icons.Default.Palette,
                        contentDescription = "Holographic Themes",
                        tint = when (chatThemeIndex) {
                            1 -> RazorTeal
                            2 -> Color(0xFFFF5E62)
                            3 -> Color(0xFFFF007F)
                            else -> Color.White
                        },
                        modifier = Modifier.size(20.dp)
                    )
                }

                // Small secure padlock badge in header
                Box(
                    modifier = Modifier
                        .padding(end = 8.dp)
                        .clip(RoundedCornerShape(12.dp))
                        .background(Color(0x2200FF88))
                        .padding(horizontal = 8.dp, vertical = 4.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Default.Lock,
                            contentDescription = "Secure",
                            tint = Color(0xFF00FF88),
                            modifier = Modifier.size(11.dp)
                        )
                        Text(
                            text = "E2EE",
                            color = Color(0xFF00FF88),
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }
            }

            // Filter thread messages
            val threadMessages = chatMessages.filter {
                !it.isDeletedForMe && (
                    (it.senderName == recipientName && it.receiverName == "You") ||
                    (it.senderName == "You" && it.receiverName == recipientName) ||
                    (recipientName == "Tokyo Trip" && it.receiverName == "Tokyo Trip")
                )
            }

            // Auto-scroller whenever a new message is loaded or thread changes
            LaunchedEffect(threadMessages.size, recipientName) {
                if (threadMessages.isNotEmpty()) {
                    listState.animateScrollToItem(threadMessages.size - 1)
                }
            }

            // Message history stream
            LazyColumn(
                state = listState,
                modifier = Modifier
                    .weight(1f)
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 4.dp),
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                item {
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 8.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = "LOAD OLDER MESSAGES",
                            color = RazorTeal,
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Bold,
                            letterSpacing = 1.sp,
                            modifier = Modifier
                                .clip(RoundedCornerShape(8.dp))
                                .background(Color(0x1A00FF88))
                                .border(1.dp, RazorTeal.copy(0.3f), RoundedCornerShape(8.dp))
                                .clickable { onLoadMoreChatMessages() }
                                .padding(horizontal = 12.dp, vertical = 6.dp)
                                .testTag("load_more_chats_btn")
                        )
                    }
                }
                if (recipientName == "Tokyo Trip") {
                    item {
                        ChatBubble(
                            sender = "Alex",
                            text = "Hey guys, let me know if you checked out the trip details! 🚄",
                            time = "4:20 PM",
                            isMe = false
                        )
                    }
                    item {
                        ChatBubble(
                            sender = "You",
                            text = "Yes, everything looks fantastic. I am uploading the schedule sheet here.",
                            time = "4:22 PM",
                            isMe = true
                        )
                    }
                }

                items(threadMessages) { msg ->
                    val isMe = msg.senderName == "You"
                    // Transparent decryption under the hood
                    val contentDisclosed = if (msg.isEncrypted) {
                        val cleaned = msg.encryptedContent.trim()
                        val isBase64Pattern = cleaned.isNotEmpty() && !cleaned.contains(" ") && cleaned.all { it.isLetterOrDigit() || it == '+' || it == '/' || it == '=' }
                        if (isBase64Pattern && cleaned != "This message was deleted") {
                            try {
                                String(android.util.Base64.decode(cleaned, android.util.Base64.DEFAULT), Charsets.UTF_8).trim()
                            } catch (e: Exception) {
                                msg.encryptedContent
                            }
                        } else {
                            msg.encryptedContent
                        }
                    } else {
                        msg.encryptedContent
                    }

                    // Check if it is a simulated attachment message
                    val isAttachment = contentDisclosed.startsWith("📄 Document: ") ||
                            contentDisclosed.startsWith("📁 Folder: ") ||
                            contentDisclosed.startsWith("🖼️ Image: ") ||
                            contentDisclosed.startsWith("🎥 Video: ") ||
                            contentDisclosed.startsWith("🎵 Audio: ")

                    if (isAttachment) {
                        val prefix = contentDisclosed.substringBefore(": ")
                        val fileName = contentDisclosed.substringAfter(": ")
                        val (icon, tint, desc) = when (prefix) {
                            "📄 Document" -> Triple(Icons.AutoMirrored.Filled.InsertDriveFile, Color(0xFF42A5F5), "PDF Document • 2.4 MB")
                            "📁 Folder" -> Triple(Icons.Default.Folder, Color(0xFFFFCA28), "Compressed Folder • 12.8 MB")
                            "🖼️ Image" -> Triple(Icons.Default.Image, Color(0xFFEC407A), "JPEG Image • 1.6 MB")
                            "🎥 Video" -> Triple(Icons.Default.Movie, Color(0xFFAB47BC), "MPEG-4 Video • 10.4 MB")
                            "🎵 Audio" -> Triple(Icons.Default.MusicNote, Color(0xFF26A69A), "MP3 Audio • 4.1 MB")
                            else -> Triple(Icons.AutoMirrored.Filled.InsertDriveFile, Color.Gray, "Attachment File")
                        }

                        val alignment = if (isMe) Alignment.End else Alignment.Start
                        val bubbleShape = if (isMe) {
                            RoundedCornerShape(topStart = 16.dp, topEnd = 16.dp, bottomStart = 16.dp, bottomEnd = 2.dp)
                        } else {
                            RoundedCornerShape(topStart = 16.dp, topEnd = 16.dp, bottomEnd = 16.dp, bottomStart = 2.dp)
                        }

                        var showAttachmentMenu by remember { mutableStateOf(false) }

                        Column(
                            horizontalAlignment = alignment,
                            modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp)
                        ) {
                            Box(
                                modifier = Modifier
                                    .widthIn(max = 280.dp)
                                    .clip(bubbleShape)
                                    .background(if (isMe) Color(0x3D00FF88) else Color(0x2422123C))
                                    .border(
                                        width = 1.dp,
                                        color = if (isMe) Color(0xFF00FF88).copy(alpha = 0.3f) else Color.White.copy(alpha = 0.1f),
                                        shape = bubbleShape
                                    )
                                    .then(
                                        if (isMe) {
                                            Modifier.pointerInput(Unit) {
                                                detectTapGestures(
                                                    onLongPress = {
                                                        showAttachmentMenu = true
                                                    }
                                                )
                                            }
                                        } else {
                                            Modifier.clickable { /* Simulate download/open */ }
                                        }
                                    )
                                    .padding(12.dp)
                            ) {
                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(10.dp)
                                ) {
                                    Box(
                                        modifier = Modifier
                                            .size(40.dp)
                                            .clip(RoundedCornerShape(8.dp))
                                            .background(tint.copy(alpha = 0.2f)),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Icon(imageVector = icon, contentDescription = null, tint = tint, modifier = Modifier.size(24.dp))
                                    }
                                    Column(modifier = Modifier.weight(1f)) {
                                        Text(
                                            text = fileName,
                                            color = Color.White,
                                            fontWeight = FontWeight.Bold,
                                            fontSize = 13.sp,
                                            maxLines = 1,
                                            overflow = TextOverflow.Ellipsis
                                        )
                                        Text(
                                            text = desc,
                                            color = GrayText,
                                            fontSize = 11.sp,
                                            fontWeight = FontWeight.Medium
                                        )
                                    }
                                }

                                if (isMe) {
                                    DropdownMenu(
                                        expanded = showAttachmentMenu,
                                        onDismissRequest = { showAttachmentMenu = false },
                                        modifier = Modifier.background(Color(0xFF1B112D)).border(1.dp, Color(0xFF332353), RoundedCornerShape(8.dp))
                                    ) {
                                        DropdownMenuItem(
                                            text = {
                                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                                    Icon(
                                                        imageVector = Icons.Default.Delete,
                                                        contentDescription = "Delete for Me",
                                                        tint = Color.White,
                                                        modifier = Modifier.size(16.dp)
                                                    )
                                                    Text("Delete for me", color = Color.White, fontWeight = FontWeight.SemiBold, fontSize = 13.sp)
                                                }
                                            },
                                            onClick = {
                                                showAttachmentMenu = false
                                                onDeleteMessageForMe(msg)
                                            }
                                        )
                                        DropdownMenuItem(
                                            text = {
                                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                                    Icon(
                                                        imageVector = Icons.Default.DeleteForever,
                                                        contentDescription = "Delete for Everyone",
                                                        tint = Color(0xFFFF4D4D),
                                                        modifier = Modifier.size(16.dp)
                                                    )
                                                    Text("Delete for everyone", color = Color(0xFFFF4D4D), fontWeight = FontWeight.Bold, fontSize = 13.sp)
                                                }
                                            },
                                            onClick = {
                                                showAttachmentMenu = false
                                                onDeleteMessageForEveryone(msg)
                                            }
                                        )
                                    }
                                }
                            }
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                modifier = Modifier.padding(top = 2.dp, start = 4.dp, end = 4.dp)
                            ) {
                                Text(
                                    text = "${formatChatTimestamp(msg.timestamp)} • E2EE Secure 🔒",
                                    color = GrayText,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Medium
                                )
                                if (isMe) {
                                    Spacer(modifier = Modifier.width(4.dp))
                                    when {
                                        msg.isSeen -> {
                                            Row(verticalAlignment = Alignment.CenterVertically) {
                                                Icon(
                                                    imageVector = Icons.Default.DoneAll,
                                                    contentDescription = "Seen",
                                                    tint = Color(0xFF00FF88),
                                                    modifier = Modifier.size(12.dp)
                                                )
                                                Spacer(modifier = Modifier.width(2.dp))
                                                Text("Seen", color = Color(0xFF00FF88), fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                            }
                                        }
                                        msg.isDelivered -> {
                                            Row(verticalAlignment = Alignment.CenterVertically) {
                                                Icon(
                                                    imageVector = Icons.Default.DoneAll,
                                                    contentDescription = "Delivered",
                                                    tint = Color.LightGray,
                                                    modifier = Modifier.size(12.dp)
                                                )
                                                Spacer(modifier = Modifier.width(2.dp))
                                                Text("Delivered", color = GrayText, fontSize = 9.sp)
                                            }
                                        }
                                        else -> {
                                            Row(verticalAlignment = Alignment.CenterVertically) {
                                                Icon(
                                                    imageVector = Icons.Default.Done,
                                                    contentDescription = "Sent",
                                                    tint = Color.LightGray,
                                                    modifier = Modifier.size(12.dp)
                                                )
                                                Spacer(modifier = Modifier.width(2.dp))
                                                Text("Sent", color = GrayText, fontSize = 9.sp)
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    } else {
                        ChatBubble(
                            sender = msg.senderName,
                            text = contentDisclosed,
                            time = "${formatChatTimestamp(msg.timestamp)} • E2EE Secure 🔒",
                            isMe = isMe,
                            isSeen = msg.isSeen,
                            isDelivered = msg.isDelivered,
                            isDeletedForEveryone = msg.isDeletedForEveryone,
                            onDeleteForMe = { onDeleteMessageForMe(msg) },
                            onDeleteForEveryone = { onDeleteMessageForEveryone(msg) }
                        )
                    }
                }
            }

            // Bottom glass typing block
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0xE60F081D)) // Frosted glass input row
                    .padding(horizontal = 8.dp, vertical = 10.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                // Persistent single Plus icon button on the left - NO other media shortcuts
                IconButton(
                    onClick = { showAttachmentDialog = true },
                    modifier = Modifier
                        .padding(end = 4.dp)
                        .size(40.dp)
                        .clip(CircleShape)
                        .background(Color(0xFF1E1535))
                        .border(1.dp, Color(0xFF3B2A65), CircleShape)
                ) {
                    Icon(
                        imageVector = Icons.Default.Add,
                        contentDescription = "Add Attachment",
                        tint = RazorBlue,
                        modifier = Modifier.size(22.dp)
                    )
                }
                
                // Frosted Text Input with integrated security lock status
                Box(
                    modifier = Modifier
                        .weight(1f)
                        .clip(RoundedCornerShape(24.dp))
                        .background(Color(0xFF1F1532))
                        .border(
                            width = 1.2.dp,
                            color = Color(0xFF00FF88).copy(alpha = 0.5f),
                            shape = RoundedCornerShape(24.dp)
                        )
                        .padding(horizontal = 14.dp, vertical = 10.dp)
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        BasicTextField(
                            value = inputMessage,
                            onValueChange = { inputMessage = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, inputMessage) },
                            textStyle = LocalTextStyle.current.copy(color = LightText, fontSize = 14.sp),
                            modifier = Modifier.weight(1f),
                            singleLine = false,
                            decorationBox = { innerTextField ->
                                if (inputMessage.isEmpty()) {
                                    Text(
                                        text = "Send secure message...",
                                        color = Color(0xFF00FF88).copy(alpha = 0.5f),
                                        fontSize = 14.sp
                                    )
                                }
                                innerTextField()
                            }
                        )
                    }
                }
                
                // WhatsApp-Style Circular Glowing Send Button next to input
                Box(
                    modifier = Modifier
                        .padding(start = 8.dp)
                        .size(40.dp)
                        .clip(CircleShape)
                        .background(
                            if (inputMessage.isNotBlank()) {
                                Brush.linearGradient(colors = listOf(Color(0xFF00FF88), Color(0xFF12E193)))
                            } else {
                                Brush.linearGradient(colors = listOf(Color(0xFF2B2144), Color(0xFF1E1535)))
                            }
                        )
                        .bounceClick(enabled = inputMessage.isNotBlank()) {
                            onSendMessage(recipientName, inputMessage)
                            inputMessage = ""
                        }
                        .testTag("chat_send_message_btn"),
                    contentAlignment = Alignment.Center
                ) {
                    Icon(
                        imageVector = Icons.AutoMirrored.Filled.Send,
                        contentDescription = "Send message",
                        tint = if (inputMessage.isNotBlank()) Color.Black else Color.Gray,
                        modifier = Modifier.size(18.dp)
                    )
                }
            }
        }
    }

    // Modern custom Dialog for selecting Attachments
    if (showAttachmentDialog) {
        Dialog(onDismissRequest = { showAttachmentDialog = false }) {
            Card(
                shape = RoundedCornerShape(24.dp),
                colors = CardDefaults.cardColors(containerColor = Color(0xFF1B112D)),
                border = BorderStroke(1.2.dp, Color(0xFF332353)),
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(16.dp)
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(20.dp),
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    Text(
                        text = "Share Attachment",
                        color = Color.White,
                        style = MaterialTheme.typography.titleMedium,
                        fontWeight = FontWeight.Bold,
                        modifier = Modifier.padding(bottom = 16.dp)
                    )
                    
                    val attachmentOptions = listOf(
                        Quadruple("Document / File", Icons.AutoMirrored.Filled.InsertDriveFile, Color(0xFF42A5F5), "📄 Document: Project_Report_Final.pdf"),
                        Quadruple("Folder", Icons.Default.Folder, Color(0xFFFFCA28), "📁 Folder: Design_Resources_v3"),
                        Quadruple("Gallery / Image", Icons.Default.Image, Color(0xFFEC407A), "🖼️ Image: photo_capture.jpg"),
                        Quadruple("Video", Icons.Default.Movie, Color(0xFFAB47BC), "🎥 Video: recording_draft.mp4"),
                        Quadruple("Audio", Icons.Default.MusicNote, Color(0xFF26A69A), "🎵 Audio: speech_memo.mp3")
                    )
                    
                    Column(
                        modifier = Modifier.fillMaxWidth(),
                        verticalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        attachmentOptions.forEach { opt ->
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .clip(RoundedCornerShape(12.dp))
                                    .background(Color(0xFF24173D))
                                    .clickable {
                                        showAttachmentDialog = false
                                        when (opt.first) {
                                            "Document / File" -> {
                                                try {
                                                    documentPickerLauncher.launch("*/*")
                                                } catch (e: Exception) {
                                                    onSendMessage(recipientName ?: "", opt.fourth)
                                                }
                                            }
                                            "Folder" -> {
                                                try {
                                                    documentPickerLauncher.launch("*/*")
                                                } catch (e: Exception) {
                                                    onSendMessage(recipientName ?: "", opt.fourth)
                                                }
                                            }
                                            "Gallery / Image" -> {
                                                try {
                                                    galleryPickerLauncher.launch("image/*")
                                                } catch (e: Exception) {
                                                    onSendMessage(recipientName ?: "", opt.fourth)
                                                }
                                            }
                                            "Video" -> {
                                                try {
                                                    videoPickerLauncher.launch("video/*")
                                                } catch (e: Exception) {
                                                    onSendMessage(recipientName ?: "", opt.fourth)
                                                }
                                            }
                                            "Audio" -> {
                                                try {
                                                    audioPickerLauncher.launch("audio/*")
                                                } catch (e: Exception) {
                                                    onSendMessage(recipientName ?: "", opt.fourth)
                                                }
                                            }
                                            else -> {
                                                onSendMessage(recipientName ?: "", opt.fourth)
                                            }
                                        }
                                    }
                                    .padding(horizontal = 16.dp, vertical = 12.dp),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(12.dp)
                            ) {
                                Box(
                                    modifier = Modifier
                                        .size(36.dp)
                                        .clip(CircleShape)
                                        .background(opt.third.copy(alpha = 0.2f)),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(imageVector = opt.second, contentDescription = null, tint = opt.third, modifier = Modifier.size(20.dp))
                                }
                                Text(
                                    text = opt.first,
                                    color = Color.White,
                                    fontWeight = FontWeight.Bold,
                                    fontSize = 14.sp
                                )
                            }
                        }
                    }
                    
                    Spacer(modifier = Modifier.height(16.dp))
                    
                    TextButton(
                        onClick = { showAttachmentDialog = false },
                        colors = ButtonDefaults.textButtonColors(contentColor = Color.LightGray)
                    ) {
                        Text("Cancel", fontWeight = FontWeight.Bold, fontSize = 14.sp)
                    }
                }
            }
        }
    }
}

data class Quadruple<A, B, C, D>(val first: A, val second: B, val third: C, val fourth: D)

@Composable
fun ChatConversationRow(
    title: String,
    sub: String,
    time: String,
    indicator: Color?,
    isGroup: Boolean = false,
    unseenCount: Int = 0,
    onOpen: () -> Unit
) {
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .bounceClick { onOpen() }
            .padding(horizontal = 16.dp, vertical = 12.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Box(modifier = Modifier.size(48.dp)) {
            Box(
                modifier = Modifier
                    .size(46.dp)
                    .clip(CircleShape)
                    .background(
                        Brush.linearGradient(
                            colors = if (isGroup) {
                                listOf(RazorBlue, RazorTeal)
                            } else {
                                listOf(RazorBlue, InstaPink)
                            }
                        )
                    )
                    .padding(2.5.dp),
                contentAlignment = Alignment.Center
            ) {
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .clip(CircleShape)
                        .background(Color(0xFF0E0B19)),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = title.take(1).uppercase(),
                        color = Color.White,
                        fontWeight = FontWeight.ExtraBold,
                        fontSize = 15.sp
                    )
                }
            }
            if (indicator != null) {
                Box(
                    modifier = Modifier
                        .size(13.dp)
                        .clip(CircleShape)
                        .background(indicator)
                        .border(2.dp, Color(0xFF0F081D), CircleShape)
                        .align(Alignment.BottomEnd)
                )
            }
        }
        Spacer(modifier = Modifier.width(14.dp))
        Column(modifier = Modifier.weight(1f)) {
            Row(verticalAlignment = Alignment.CenterVertically) {
                Text(
                    text = title,
                    fontWeight = FontWeight.ExtraBold,
                    color = Color.White,
                    fontSize = 15.sp,
                    letterSpacing = 0.2.sp
                )
                if (isGroup) {
                    Spacer(modifier = Modifier.width(6.dp))
                    Box(
                        modifier = Modifier
                            .background(RazorBlue.copy(alpha = 0.2f), RoundedCornerShape(4.dp))
                            .padding(horizontal = 6.dp, vertical = 2.dp)
                    ) {
                        Text("GROUP", color = RazorBlue, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                    }
                }
            }
            Spacer(modifier = Modifier.height(2.dp))
            Text(
                text = sub,
                color = if (isGroup) RazorTeal else Color.White.copy(alpha = 0.85f),
                fontSize = 13.sp,
                fontWeight = if (unseenCount > 0) FontWeight.ExtraBold else FontWeight.SemiBold,
                maxLines = 1,
                overflow = TextOverflow.Ellipsis
            )
        }
        Column(horizontalAlignment = Alignment.End) {
            Text(
                text = time,
                color = if (unseenCount > 0) RazorTeal else Color.White.copy(alpha = 0.75f),
                fontSize = 11.sp,
                fontWeight = if (unseenCount > 0) FontWeight.ExtraBold else FontWeight.Bold
            )
            if (unseenCount > 0) {
                Spacer(modifier = Modifier.height(4.dp))
                Box(
                    modifier = Modifier
                        .background(RazorTeal, RoundedCornerShape(10.dp))
                        .padding(horizontal = 6.dp, vertical = 2.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = unseenCount.toString(),
                        color = Color.Black,
                        fontSize = 10.sp,
                        fontWeight = FontWeight.Black
                    )
                }
            }
        }
    }
}

fun formatChatTimestamp(timestamp: Long): String {
    val messageTime = java.util.Calendar.getInstance().apply { timeInMillis = timestamp }
    val now = java.util.Calendar.getInstance()
    
    return when {
        messageTime.get(java.util.Calendar.YEAR) == now.get(java.util.Calendar.YEAR) &&
        messageTime.get(java.util.Calendar.DAY_OF_YEAR) == now.get(java.util.Calendar.DAY_OF_YEAR) -> {
            java.text.SimpleDateFormat("h:mm a", java.util.Locale.getDefault()).format(messageTime.time)
        }
        messageTime.get(java.util.Calendar.YEAR) == now.get(java.util.Calendar.YEAR) &&
        messageTime.get(java.util.Calendar.DAY_OF_YEAR) == now.get(java.util.Calendar.DAY_OF_YEAR) - 1 -> {
            "Yesterday " + java.text.SimpleDateFormat("h:mm a", java.util.Locale.getDefault()).format(messageTime.time)
        }
        else -> {
            java.text.SimpleDateFormat("MMM d, h:mm a", java.util.Locale.getDefault()).format(messageTime.time)
        }
    }
}

@Composable
fun ChatBubble(
    sender: String,
    text: String,
    time: String,
    isMe: Boolean,
    isSeen: Boolean = true,
    isDelivered: Boolean = true,
    isDeletedForEveryone: Boolean = false,
    onDeleteForMe: (() -> Unit)? = null,
    onDeleteForEveryone: (() -> Unit)? = null
) {
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .padding(vertical = 4.dp),
        horizontalArrangement = if (isMe) Arrangement.End else Arrangement.Start,
        verticalAlignment = Alignment.Bottom
    ) {
        if (!isMe) {
            Box(
                modifier = Modifier
                    .padding(end = 8.dp, bottom = 4.dp)
                    .size(28.dp)
                    .clip(CircleShape)
                    .background(Color(0xFF32235E)),
                contentAlignment = Alignment.Center
            ) {
                Text(
                    text = sender.take(1).uppercase(),
                    color = RazorTeal,
                    fontWeight = FontWeight.Black,
                    fontSize = 12.sp
                )
            }
        }

        var showMenu by remember { mutableStateOf(false) }

        Column(
            horizontalAlignment = if (isMe) Alignment.End else Alignment.Start
        ) {
            val bubbleShape = if (isMe) {
                RoundedCornerShape(topStart = 16.dp, topEnd = 16.dp, bottomStart = 16.dp, bottomEnd = 2.dp)
            } else {
                RoundedCornerShape(topStart = 16.dp, topEnd = 16.dp, bottomEnd = 16.dp, bottomStart = 2.dp)
            }

            Box(
                modifier = Modifier
                    .widthIn(max = (androidx.compose.ui.platform.LocalConfiguration.current.screenWidthDp * 0.75).dp)
                    .clip(bubbleShape)
                    .background(
                        if (isDeletedForEveryone) {
                            Color(0x0F888888)
                        } else if (isMe) {
                            Color(0x2E00FF88) // Glowing semi-transparent green glass
                        } else {
                            Color(0x1F22123C) // Cozy dark glass
                        }
                    )
                    .border(
                        width = 1.dp,
                        brush = Brush.linearGradient(
                            colors = if (isDeletedForEveryone) {
                                listOf(Color.White.copy(alpha = 0.05f), Color.Transparent)
                            } else if (isMe) {
                                listOf(Color(0xFF00FF88).copy(alpha = 0.4f), Color.Transparent)
                            } else {
                                listOf(Color.White.copy(alpha = 0.12f), Color.Transparent)
                            }
                        ),
                        shape = bubbleShape
                    )
                    .then(
                        if (!isDeletedForEveryone && (onDeleteForMe != null || onDeleteForEveryone != null)) {
                            Modifier.pointerInput(Unit) {
                                detectTapGestures(
                                    onLongPress = {
                                        showMenu = true
                                    }
                                )
                            }
                        } else {
                            Modifier
                        }
                    )
                    .padding(horizontal = 14.dp, vertical = 10.dp)
            ) {
                Column {
                    if (!isMe && sender.isNotBlank() && sender != "Alex" && sender != "Sarah") {
                        Text(
                            text = sender.uppercase(),
                            fontWeight = FontWeight.ExtraBold,
                            color = RazorTeal,
                            fontSize = 11.sp,
                            letterSpacing = 0.5.sp
                        )
                        Spacer(modifier = Modifier.height(2.dp))
                    }
                    Text(
                        text = if (isDeletedForEveryone) "🚫 This message was deleted" else text,
                        color = if (isDeletedForEveryone) Color.Gray else Color.White,
                        fontSize = 14.sp,
                        fontWeight = if (isDeletedForEveryone) FontWeight.Normal else FontWeight.Bold,
                        fontStyle = if (isDeletedForEveryone) androidx.compose.ui.text.font.FontStyle.Italic else androidx.compose.ui.text.font.FontStyle.Normal,
                        lineHeight = 19.sp
                    )

                    if (!isDeletedForEveryone && (onDeleteForMe != null || onDeleteForEveryone != null)) {
                        DropdownMenu(
                            expanded = showMenu,
                            onDismissRequest = { showMenu = false },
                            modifier = Modifier.background(Color(0xFF1B112D)).border(1.dp, Color(0xFF332353), RoundedCornerShape(8.dp))
                        ) {
                            if (onDeleteForMe != null) {
                                DropdownMenuItem(
                                    text = {
                                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                            Icon(
                                                imageVector = Icons.Default.Delete,
                                                contentDescription = "Delete for Me",
                                                tint = Color.White,
                                                modifier = Modifier.size(16.dp)
                                            )
                                            Text("Delete for me", color = Color.White, fontWeight = FontWeight.SemiBold, fontSize = 13.sp)
                                        }
                                    },
                                    onClick = {
                                        showMenu = false
                                        onDeleteForMe()
                                    }
                                )
                            }
                            if (isMe && onDeleteForEveryone != null) {
                                DropdownMenuItem(
                                    text = {
                                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                            Icon(
                                                imageVector = Icons.Default.DeleteForever,
                                                contentDescription = "Delete for Everyone",
                                                tint = Color(0xFFFF4D4D),
                                                modifier = Modifier.size(16.dp)
                                            )
                                            Text("Delete for everyone", color = Color(0xFFFF4D4D), fontWeight = FontWeight.Bold, fontSize = 13.sp)
                                        }
                                    },
                                    onClick = {
                                        showMenu = false
                                        onDeleteForEveryone()
                                    }
                                )
                            }
                        }
                    }
                }
            }
            
            Row(
                verticalAlignment = Alignment.CenterVertically,
                modifier = Modifier.padding(top = 4.dp, start = if (isMe) 0.dp else 4.dp, end = if (isMe) 4.dp else 0.dp)
            ) {
                Text(
                    text = time,
                    color = GrayText,
                    fontSize = 10.sp,
                    fontWeight = FontWeight.Medium
                )
                if (isMe) {
                    Spacer(modifier = Modifier.width(4.dp))
                    when {
                        isSeen -> {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(
                                    imageVector = Icons.Default.DoneAll,
                                    contentDescription = "Seen",
                                    tint = Color(0xFF00FF88),
                                    modifier = Modifier.size(12.dp)
                                )
                                Spacer(modifier = Modifier.width(2.dp))
                                Text("Seen", color = Color(0xFF00FF88), fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                        isDelivered -> {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(
                                    imageVector = Icons.Default.DoneAll,
                                    contentDescription = "Delivered",
                                    tint = Color.LightGray,
                                    modifier = Modifier.size(12.dp)
                                )
                                Spacer(modifier = Modifier.width(2.dp))
                                Text("Delivered", color = GrayText, fontSize = 9.sp)
                            }
                        }
                        else -> {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(
                                    imageVector = Icons.Default.Done,
                                    contentDescription = "Sent",
                                    tint = Color.LightGray,
                                    modifier = Modifier.size(12.dp)
                                )
                                Spacer(modifier = Modifier.width(2.dp))
                                Text("Sent", color = GrayText, fontSize = 9.sp)
                            }
                        }
                    }
                }
            }
        }
    }
}

// Helper function to save chosen profile media URIs to internal cache to prevent permission issues
fun saveUriToCache(context: android.content.Context, uri: android.net.Uri, prefix: String): String? {
    return try {
        val cachePath = java.io.File(context.cacheDir, "profile_media")
        cachePath.mkdirs()
        val file = java.io.File(cachePath, "${prefix}_${System.currentTimeMillis()}.jpg")
        context.contentResolver.openInputStream(uri)?.use { inputStream ->
            java.io.FileOutputStream(file).use { outputStream ->
                inputStream.copyTo(outputStream)
            }
        }
        file.absolutePath
    } catch (e: Exception) {
        e.printStackTrace()
        null
    }
}

