// SCREEN 6: VIRTUAL WALLET INTEGRATION (Page 6)
// ============================================
@Composable
fun WalletScreen(
    balance: Double,
    transactions: List<Transaction>,
    userName: String,
    userHandle: String,
    userBio: String = "",
    userLink: String = "",
    userDp: String = "",
    userBanner: String = "",
    userVibeIndex: Int = 0,
    onUpdateVibe: (Int) -> Unit = {},
    onUpdateProfile: (String, String, String, String, String, String) -> Unit,
    onLoadFunds: (Double) -> Unit,
    onLoadFundsViaUPI: (Double, String, String) -> Unit = { _, _, _ -> },
    onSendFundsViaUPI: (Double, String, String) -> Unit = { _, _, _ -> },
    onPayPizzaSplit: () -> Unit,
    pizzaSplitPaid: Boolean,
    posts: List<Post>,
    subscriptions: List<Subscription>,
    creators: List<Creator>,
    onLikePost: (Post) -> Unit,
    onCancelSubscription: (String, String) -> Unit,
    userVerified: Boolean = false,
    userBronzeName: String = "Bronze Watcher",
    userBronzePrice: Double = 4.99,
    userBronzePerks: String = "Latest daily stock alerts & tech watchlists.",
    userSilverName: String = "Silver Analyst",
    userSilverPrice: Double = 14.99,
    userSilverPerks: String = "Exclusive audio transcripts & deep portfolio wiring sheets.",
    userGoldName: String = "Gold Partner",
    userGoldPrice: Double = 49.99,
    userGoldPerks: String = "Weekly 1-on-1 portfolio review on secure live rooms.",
    onVerifyUser: () -> Unit = {},
    onUnverifyUser: () -> Unit = {},
    onUpdateUserTiers: (String, Double, String, String, Double, String, String, Double, String) -> Unit = { _,_,_, _,_,_, _,_,_ -> },
    onVerifyCreator: (String, Boolean) -> Unit = { _,_ -> },
    onAddMockTransaction: (String, Double, String) -> Unit = { _,_,_ -> },
    measuredDelayMs: Long = 0L,
    onNavigateToSettings: () -> Unit = {},
    securityLogs: List<String> = emptyList(),
    onBack: (() -> Unit)? = null
) {
    val uriHandler = androidx.compose.ui.platform.LocalUriHandler.current
    var isBalanceVisible by remember { mutableStateOf(true) }
    var isWalletScreenLocked by remember { mutableStateOf(false) }
    var showProfileEditor by remember { mutableStateOf(false) }
    var showProfileShareDialog by remember { mutableStateOf(false) }
    var showTopUpDialog by remember { mutableStateOf(false) }
    var showSecureUpiDialog by remember { mutableStateOf(false) }
    var secureUpiAmount by remember { mutableStateOf(0.0) }
    var secureUpiId by remember { mutableStateOf("") }
    var secureUpiNote by remember { mutableStateOf("") }
    var isUpiPayOutMode by remember { mutableStateOf(false) }
    var showSendMoneyDialog by remember { mutableStateOf(false) }
    var showRequestMoneyDialog by remember { mutableStateOf(false) }
    var showSplitDialog by remember { mutableStateOf(false) }
    var showQrScannerDialog by remember { mutableStateOf(false) }
    
    // External Threat Protection states
    var extBankSyncGuard by remember { mutableStateOf(true) }
    var extAntiPhishingFilter by remember { mutableStateOf(true) }
    var extOverlayBlocker by remember { mutableStateOf(true) }
    var extMalwareIsolation by remember { mutableStateOf(true) }
    var pendingWalletToggleSetting by remember { mutableStateOf<PendingToggle?>(null) }
    
    // Interactive Threat Simulator & Log Stream
    var threatLogs by remember { mutableStateOf(listOf(
        "🛡️ Secure Cryptographic Firewall initialized.",
        "🔑 TEE Hardware isolated wrapping active.",
        "🌐 Virtual payment address verification engine: LIVE."
    )) }
    var showThreatOverlayAlert by remember { mutableStateOf(false) }
    var threatAlertMessage by remember { mutableStateOf("") }
    
    var successMessageToast by remember { mutableStateOf<String?>(null) }
    LaunchedEffect(successMessageToast) {
        if (successMessageToast != null) {
            kotlinx.coroutines.delay(3000)
            successMessageToast = null
        }
    }
    var activeProfileTab by remember { mutableStateOf("profile") }
    var showAppSettingsDialog by remember { mutableStateOf(false) }
    var showAccountPrivacyDialog by remember { mutableStateOf(false) }
    var showNotificationsDialog by remember { mutableStateOf(false) }
    var showSettingsDropdown by remember { mutableStateOf(false) }
    var isPrivateAccount by remember { mutableStateOf(false) }
    var isIncognitoSearch by remember { mutableStateOf(false) }
    var alertOnWalletActivity by remember { mutableStateOf(true) }
    var alertOnLiveStreams by remember { mutableStateOf(true) }

    val context = androidx.compose.ui.platform.LocalContext.current

    var cameraStatus by remember {
        mutableStateOf(
            androidx.core.content.ContextCompat.checkSelfPermission(
                context, android.Manifest.permission.CAMERA
            ) == android.content.pm.PackageManager.PERMISSION_GRANTED
        )
    }
    var micStatus by remember {
        mutableStateOf(
            androidx.core.content.ContextCompat.checkSelfPermission(
                context, android.Manifest.permission.RECORD_AUDIO
            ) == android.content.pm.PackageManager.PERMISSION_GRANTED
        )
    }
    var mediaStatus by remember {
        mutableStateOf(
            if (android.os.Build.VERSION.SDK_INT >= 33) {
                androidx.core.content.ContextCompat.checkSelfPermission(
                    context, android.Manifest.permission.READ_MEDIA_IMAGES
                ) == android.content.pm.PackageManager.PERMISSION_GRANTED ||
                androidx.core.content.ContextCompat.checkSelfPermission(
                    context, android.Manifest.permission.READ_MEDIA_VIDEO
                ) == android.content.pm.PackageManager.PERMISSION_GRANTED ||
                androidx.core.content.ContextCompat.checkSelfPermission(
                    context, android.Manifest.permission.READ_MEDIA_AUDIO
                ) == android.content.pm.PackageManager.PERMISSION_GRANTED
            } else {
                androidx.core.content.ContextCompat.checkSelfPermission(
                    context, android.Manifest.permission.READ_EXTERNAL_STORAGE
                ) == android.content.pm.PackageManager.PERMISSION_GRANTED
            }
        )
    }
    var notificationsStatus by remember {
        mutableStateOf(
            if (android.os.Build.VERSION.SDK_INT >= 33) {
                androidx.core.content.ContextCompat.checkSelfPermission(
                    context, "android.permission.POST_NOTIFICATIONS"
                ) == android.content.pm.PackageManager.PERMISSION_GRANTED
            } else {
                true
            }
        )
    }

    val lifecycleOwner = androidx.lifecycle.compose.LocalLifecycleOwner.current
    androidx.compose.runtime.DisposableEffect(lifecycleOwner) {
        val observer = androidx.lifecycle.LifecycleEventObserver { _, event ->
            if (event == androidx.lifecycle.Lifecycle.Event.ON_RESUME) {
                cameraStatus = androidx.core.content.ContextCompat.checkSelfPermission(
                    context, android.Manifest.permission.CAMERA
                ) == android.content.pm.PackageManager.PERMISSION_GRANTED
                
                micStatus = androidx.core.content.ContextCompat.checkSelfPermission(
                    context, android.Manifest.permission.RECORD_AUDIO
                ) == android.content.pm.PackageManager.PERMISSION_GRANTED
                
                mediaStatus = if (android.os.Build.VERSION.SDK_INT >= 33) {
                    androidx.core.content.ContextCompat.checkSelfPermission(
                        context, android.Manifest.permission.READ_MEDIA_IMAGES
                    ) == android.content.pm.PackageManager.PERMISSION_GRANTED ||
                    androidx.core.content.ContextCompat.checkSelfPermission(
                        context, android.Manifest.permission.READ_MEDIA_VIDEO
                    ) == android.content.pm.PackageManager.PERMISSION_GRANTED ||
                    androidx.core.content.ContextCompat.checkSelfPermission(
                        context, android.Manifest.permission.READ_MEDIA_AUDIO
                    ) == android.content.pm.PackageManager.PERMISSION_GRANTED
                } else {
                    androidx.core.content.ContextCompat.checkSelfPermission(
                        context, android.Manifest.permission.READ_EXTERNAL_STORAGE
                    ) == android.content.pm.PackageManager.PERMISSION_GRANTED
                }
                
                notificationsStatus = if (android.os.Build.VERSION.SDK_INT >= 33) {
                    androidx.core.content.ContextCompat.checkSelfPermission(
                        context, "android.permission.POST_NOTIFICATIONS"
                    ) == android.content.pm.PackageManager.PERMISSION_GRANTED
                } else {
                    true
                }
            }
        }
        lifecycleOwner.lifecycle.addObserver(observer)
        onDispose {
            lifecycleOwner.lifecycle.removeObserver(observer)
        }
    }

    val getUriSize = { uri: android.net.Uri ->
        var size = 0L
        try {
            val cursor = context.contentResolver.query(uri, null, null, null, null)
            cursor?.use {
                if (it.moveToFirst()) {
                    val sizeIndex = it.getColumnIndex(android.provider.OpenableColumns.SIZE)
                    if (sizeIndex != -1) {
                        size = it.getLong(sizeIndex)
                    }
                }
            }
            if (size == 0L) {
                context.contentResolver.openInputStream(uri)?.use { stream ->
                    size = stream.available().toLong()
                }
            }
        } catch (e: Exception) {
            e.printStackTrace()
        }
        size
    }

    var editName by remember(userName) { mutableStateOf(userName) }
    var editHandle by remember(userHandle) { mutableStateOf(userHandle) }
    var editBio by remember(userBio) { mutableStateOf(userBio) }
    var editLink by remember(userLink) { mutableStateOf(userLink) }
    var editDpUri by remember(userDp) { mutableStateOf(userDp) }
    var editBannerUri by remember(userBanner) { mutableStateOf(userBanner) }
    var editVibeIndex by remember(userVibeIndex) { mutableStateOf(userVibeIndex) }
    var sizeErrorMessage by remember { mutableStateOf<String?>(null) }

    val dpLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.GetContent()
    ) { uri ->
        if (uri != null) {
            val sizeBytes = getUriSize(uri)
            val limit = 5L * 1024 * 1024 // 5MB
            if (sizeBytes > limit) {
                sizeErrorMessage = "Profile DP exceeds 5MB limit! Selected: ${String.format("%.2f", sizeBytes / (1024.0 * 1024.0))} MB"
            } else {
                val cachedPath = saveUriToCache(context, uri, "dp")
                editDpUri = cachedPath ?: uri.toString()
                sizeErrorMessage = null
            }
        }
    }

    val bannerLauncher = androidx.activity.compose.rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.GetContent()
    ) { uri ->
        if (uri != null) {
            val sizeBytes = getUriSize(uri)
            val limit = 20L * 1024 * 1024 // 20MB
            if (sizeBytes > limit) {
                sizeErrorMessage = "Banner image exceeds 20MB limit! Selected: ${String.format("%.2f", sizeBytes / (1024.0 * 1024.0))} MB"
            } else {
                val cachedPath = saveUriToCache(context, uri, "banner")
                editBannerUri = cachedPath ?: uri.toString()
                sizeErrorMessage = null
            }
        }
    }

    if (pendingWalletToggleSetting != null) {
        val pending = pendingWalletToggleSetting!!
        AlertDialog(
            onDismissRequest = { pendingWalletToggleSetting = null },
            containerColor = Color(0xFF161135),
            titleContentColor = Color.White,
            textContentColor = Color.LightGray,
            title = {
                Text(
                    text = "CONFIRM SECURITY OPTION",
                    style = MaterialTheme.typography.titleMedium,
                    fontWeight = FontWeight.Bold,
                    color = RazorTeal
                )
            },
            text = {
                Text(
                    text = "Are you sure you want to ${if (pending.currentValue) "DISABLE" else "ENABLE"} the option: '${pending.title}'?",
                    style = MaterialTheme.typography.bodyMedium
                )
            },
            confirmButton = {
                Button(
                    onClick = {
                        pending.onConfirm(!pending.currentValue)
                        pendingWalletToggleSetting = null
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = RazorTeal),
                    shape = RoundedCornerShape(8.dp)
                ) {
                    Text("Confirm", color = Color.Black, fontWeight = FontWeight.Bold)
                }
            },
            dismissButton = {
                TextButton(
                    onClick = { pendingWalletToggleSetting = null }
                ) {
                    Text("Cancel", color = Color.Gray, fontWeight = FontWeight.Medium)
                }
            }
        )
    }

    if (showProfileShareDialog) {
        ShareDialog(
            title = "Check out my Creator Hub on SocialHub!",
            shareUrl = "https://socialhub.com/creators/$userHandle",
            onDismiss = { showProfileShareDialog = false }
        )
    }

    if (showProfileEditor) {
        androidx.compose.ui.window.Dialog(
            onDismissRequest = { showProfileEditor = false },
            properties = androidx.compose.ui.window.DialogProperties(
                usePlatformDefaultWidth = false,
                dismissOnBackPress = true,
                dismissOnClickOutside = true
            )
        ) {
            Card(
                shape = RoundedCornerShape(24.dp),
                colors = CardDefaults.cardColors(containerColor = ObsidianDark),
                border = BorderStroke(1.5.dp, RazorTeal),
                modifier = Modifier
                    .padding(16.dp)
                    .fillMaxWidth(0.96f)
                    .fillMaxHeight(0.92f)
            ) {
                Column(
                    modifier = Modifier
                        .padding(20.dp)
                        .verticalScroll(rememberScrollState())
                ) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text("Edit Creator Profile", color = RazorTeal, fontWeight = FontWeight.Black, style = MaterialTheme.typography.titleMedium)
                        IconButton(onClick = { showProfileEditor = false }) {
                            Icon(imageVector = Icons.Default.Close, contentDescription = "Close", tint = Color.White)
                        }
                    }
                    Spacer(modifier = Modifier.height(10.dp))
                    
                    if (sizeErrorMessage != null) {
                        Card(
                            colors = CardDefaults.cardColors(containerColor = Color(0x33FF5252)),
                            border = BorderStroke(1.dp, Color(0xFFFF5252)),
                            shape = RoundedCornerShape(12.dp),
                            modifier = Modifier.fillMaxWidth().padding(bottom = 12.dp)
                        ) {
                            Row(
                                modifier = Modifier.padding(12.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Text("⚠️", fontSize = 16.sp)
                                Spacer(modifier = Modifier.width(8.dp))
                                Text(sizeErrorMessage ?: "", color = Color(0xFFFFD2D2), fontSize = 12.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                    }

                    // Interactive Profile Card Preview (Dynamic overlapping of DP and Banner)
                    Text("Interactive Banner & DP Preview (Tap to upload)", color = GrayText, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                    Spacer(modifier = Modifier.height(6.dp))
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(160.dp)
                            .clip(RoundedCornerShape(16.dp))
                            .border(1.dp, RazorBlue.copy(alpha = 0.5f), RoundedCornerShape(16.dp))
                            .background(Color(0xFF0E081D))
                    ) {
                        // Banner Area clickable
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(110.dp)
                                .clickable { bannerLauncher.launch("image/*") }
                        ) {
                            if (editBannerUri.isNotBlank()) {
                                AsyncImage(
                                    model = editBannerUri,
                                    contentDescription = "Edit Banner",
                                    modifier = Modifier.fillMaxSize(),
                                    contentScale = androidx.compose.ui.layout.ContentScale.Crop
                                )
                            } else {
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(
                                            Brush.horizontalGradient(
                                                colors = listOf(Color(0xFFC00A63), Color(0xFF4C0860))
                                            )
                                        )
                                )
                            }
                            // Edit overlay badge
                            Box(
                                modifier = Modifier
                                    .align(Alignment.TopEnd)
                                    .padding(10.dp)
                                    .background(Color.Black.copy(alpha = 0.7f), RoundedCornerShape(8.dp))
                                    .padding(horizontal = 8.dp, vertical = 4.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Icon(
                                        imageVector = Icons.Default.Edit,
                                        contentDescription = "Change Banner",
                                        tint = RazorTeal,
                                        modifier = Modifier.size(11.dp)
                                    )
                                    Spacer(modifier = Modifier.width(4.dp))
                                    Text("Change Banner 🖼️", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }

                        // Avatar overlapping clickable
                        Box(
                            modifier = Modifier
                                .align(Alignment.BottomStart)
                                .padding(start = 16.dp, bottom = 10.dp)
                                .size(70.dp)
                                .clip(CircleShape)
                                .background(Color.Black)
                                .border(2.5.dp, RazorTeal, CircleShape)
                                .clickable { dpLauncher.launch("image/*") },
                            contentAlignment = Alignment.Center
                        ) {
                            if (editDpUri.isNotBlank()) {
                                AsyncImage(
                                    model = editDpUri,
                                    contentDescription = "Edit DP",
                                    modifier = Modifier.fillMaxSize(),
                                    contentScale = androidx.compose.ui.layout.ContentScale.Crop
                                )
                            } else {
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(
                                            Brush.linearGradient(
                                                colors = listOf(Color(0xFF00C853), Color(0xFF2E7D32))
                                            )
                                        ),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text(
                                        text = if (editName.isNotEmpty()) editName.take(1).uppercase() else "U",
                                        color = Color.White,
                                        fontSize = 28.sp,
                                        fontWeight = FontWeight.Black
                                    )
                                }
                            }
                            // Camera Overlay icon
                            Box(
                                modifier = Modifier
                                    .fillMaxSize()
                                    .background(Color.Black.copy(alpha = 0.45f)),
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(
                                    imageVector = Icons.Default.Edit,
                                    contentDescription = "Change DP",
                                    tint = Color.White,
                                    modifier = Modifier.size(16.dp)
                                )
                            }
                        }
                    }
                    Spacer(modifier = Modifier.height(16.dp))

                    // Display Name
                    Text("Display Name", color = GrayText, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                    OutlinedTextField(
                        value = editName,
                        onValueChange = { editName = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, editName) },
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedTextColor = Color.White,
                            unfocusedTextColor = Color.White,
                            focusedBorderColor = RazorBlue,
                            unfocusedBorderColor = MinimalBorder
                        ),
                        modifier = Modifier.fillMaxWidth()
                    )
                    Spacer(modifier = Modifier.height(12.dp))
                    
                    // User Handle
                    Text("User Handle", color = GrayText, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                    OutlinedTextField(
                        value = editHandle,
                        onValueChange = { 
                            val deduped = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, editHandle)
                            editHandle = deduped.trim().replace(" ", "") 
                        },
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedTextColor = Color.White,
                            unfocusedTextColor = Color.White,
                            focusedBorderColor = RazorBlue,
                            unfocusedBorderColor = MinimalBorder
                        ),
                        modifier = Modifier.fillMaxWidth()
                    )
                    Spacer(modifier = Modifier.height(12.dp))

                    val bioWords = editBio.trim().split(Regex("\\s+")).filter { it.isNotEmpty() }
                    val bioWordCount = bioWords.size
                    val isBioExceeded = bioWordCount > 20

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text("Bio (Max 20 words)", color = GrayText, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                            Text(
                                text = "${editBio.length}/150 chars",
                                color = if (editBio.length >= 130) Color(0xFFFF9800) else Color.LightGray,
                                fontSize = 11.sp,
                                fontWeight = FontWeight.Bold
                            )
                            Text(
                                text = "$bioWordCount/20 words",
                                color = if (isBioExceeded) Color(0xFFFF5252) else Color(0xFF00FF88),
                                fontSize = 11.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }
                    OutlinedTextField(
                        value = editBio,
                        onValueChange = { 
                            val deduped = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, editBio)
                            if (deduped.length <= 150) {
                                editBio = deduped 
                            }
                        },
                        maxLines = 3,
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedTextColor = Color.White,
                            unfocusedTextColor = Color.White,
                            focusedBorderColor = if (isBioExceeded) Color(0xFFFF5252) else RazorBlue,
                            unfocusedBorderColor = if (isBioExceeded) Color(0x88FF5252) else MinimalBorder
                        ),
                        modifier = Modifier.fillMaxWidth()
                    )
                    if (isBioExceeded) {
                        Text("Bio exceeds the 20-word limit. Please shorten it.", color = Color(0xFFFF5252), fontSize = 10.sp, fontWeight = FontWeight.Medium, modifier = Modifier.padding(top = 2.dp))
                    }
                    Spacer(modifier = Modifier.height(12.dp))

                    // External clickable link
                    Text("External Clickable Link", color = GrayText, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                    OutlinedTextField(
                        value = editLink,
                        onValueChange = { editLink = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, editLink) },
                        placeholder = { Text("https://yourlink.com", color = Color.Gray, fontSize = 13.sp) },
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedTextColor = Color.White,
                            unfocusedTextColor = Color.White,
                            focusedBorderColor = RazorBlue,
                            unfocusedBorderColor = MinimalBorder
                        ),
                        modifier = Modifier.fillMaxWidth()
                    )
                    
                    // Quick Link Helpers/Chips
                    Row(
                        modifier = Modifier.fillMaxWidth().padding(top = 6.dp),
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        listOf("https://", "twitter.com/", "github.com/", "instagram.com/").forEach { chip ->
                            Box(
                                modifier = Modifier
                                    .background(Color(0xFF1F163D), RoundedCornerShape(6.dp))
                                    .border(1.dp, RazorBlue.copy(alpha = 0.3f), RoundedCornerShape(6.dp))
                                    .clickable {
                                        if (chip == "https://") {
                                            if (!editLink.startsWith("https://") && !editLink.startsWith("http://")) {
                                                editLink = "https://" + editLink
                                            }
                                        } else {
                                            if (!editLink.contains(chip)) {
                                                editLink = if (editLink.endsWith("/")) editLink + chip.removeSuffix("/") else editLink + chip
                                            }
                                        }
                                    }
                                    .padding(horizontal = 8.dp, vertical = 5.dp)
                            ) {
                                Text(chip, color = RazorBlue, fontSize = 9.5.sp, fontWeight = FontWeight.SemiBold)
                            }
                        }
                    }
                    
                    Spacer(modifier = Modifier.height(18.dp))
                    Text("Select Creator Aura (Glow Effect)", color = GrayText, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                    Spacer(modifier = Modifier.height(8.dp))
                    
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        listOf(
                            "Default" to Color(0xFF00FF88),
                            "Love" to Color(0xFFFF007F),
                            "Ocean" to Color(0xFF00FFCC),
                            "Sunset" to Color(0xFFFFB300),
                            "Matrix" to Color(0xFF8A2387)
                        ).forEachIndexed { idx, pair ->
                            Box(
                                modifier = Modifier
                                    .weight(1f)
                                    .clip(RoundedCornerShape(10.dp))
                                    .background(if (editVibeIndex == idx) pair.second.copy(alpha = 0.2f) else Color(0xFF130E26))
                                    .border(
                                        width = if (editVibeIndex == idx) 2.dp else 1.dp,
                                        color = if (editVibeIndex == idx) pair.second else Color.White.copy(alpha = 0.08f),
                                        shape = RoundedCornerShape(10.dp)
                                    )
                                    .clickable { editVibeIndex = idx }
                                    .padding(vertical = 10.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                    Box(
                                        modifier = Modifier
                                            .size(16.dp)
                                            .clip(CircleShape)
                                            .background(pair.second)
                                    )
                                    Spacer(modifier = Modifier.height(4.dp))
                                    Text(
                                        text = pair.first,
                                        color = if (editVibeIndex == idx) Color.White else GrayText,
                                        fontSize = 10.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                            }
                        }
                    }
                    
                    Spacer(modifier = Modifier.height(24.dp))
                    
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Button(
                            onClick = { showProfileEditor = false },
                            colors = ButtonDefaults.buttonColors(containerColor = Color.DarkGray),
                            modifier = Modifier.weight(1f)
                        ) {
                            Text("Cancel", color = Color.White)
                        }
                        Button(
