}

// ===============================================
// SCREEN 7: INVESTOR PROFILE DETAIL (Page 7)
// ===============================================
@Composable
fun CreatorDetailScreen(
    creator: Creator,
    subscriptions: List<Subscription>,
    posts: List<Post>,
    events: List<Event>,
    products: List<MarketplaceProduct>,
    onSubscribeClick: (String, Double) -> Unit,
    onCancelSubscription: () -> Unit,
    onFollowToggle: () -> Unit,
    onMessageClick: () -> Unit,
    onLikePost: (Post) -> Unit,
    onBack: () -> Unit,
    onVerifyToggle: (Boolean) -> Unit = {},
    onVideoClick: (Post) -> Unit = {},
    onProductBuyClick: (MarketplaceProduct) -> Unit = {},
    onTipCreatorClick: (Double) -> Unit = {},
    onBuyTicketClick: (Event) -> Unit = {}
) {
    val activeSub = subscriptions.find { it.creatorId == creator.id }
    
    var selectedBadgeDetail by remember { mutableStateOf<Pair<String, String>?>(null) }
    var showShareToast by remember { mutableStateOf(false) }
    
    Column(
        modifier = Modifier
            .fillMaxSize()
            .verticalScroll(rememberScrollState())
    ) {
        // Premium overlapping mobile-first header
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .height(130.dp)
        ) {
            // High-Quality Thematic Cover Banner generated via AI
            Box(
                modifier = Modifier
                    .fillMaxSize()
            ) {
                androidx.compose.foundation.Image(
                    painter = androidx.compose.ui.res.painterResource(id = com.example.R.drawable.creator_cover_placeholder_1783088705194),
                    contentDescription = "Thematic Cover Banner",
                    contentScale = androidx.compose.ui.layout.ContentScale.Crop,
                    modifier = Modifier.fillMaxSize()
                )
                // Gradient overlay to ensure text legibility over the image
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .background(
                            brush = Brush.verticalGradient(
                                colors = listOf(Color.Black.copy(alpha = 0.6f), Color.Transparent, Color.Black.copy(alpha = 0.8f))
                            )
                        )
                )
            }

            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 12.dp, vertical = 8.dp),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                IconButton(
                    onClick = onBack,
                    modifier = Modifier
                        .clip(CircleShape)
                        .background(Color.Black.copy(alpha = 0.4f))
                        .size(34.dp)
                ) {
                    Icon(imageVector = Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back back step", tint = LightText, modifier = Modifier.size(16.dp))
                }
                Text(
                    text = creator.handle.uppercase(),
                    fontWeight = FontWeight.Black,
                    color = LightText,
                    fontSize = 13.sp,
                    fontFamily = FontFamily.Monospace
                )
                IconButton(
                    onClick = { showShareToast = true },
                    modifier = Modifier
                        .clip(CircleShape)
                        .background(Color.Black.copy(alpha = 0.4f))
                        .size(34.dp)
                ) {
                    Icon(imageVector = Icons.Default.Share, contentDescription = "Share Profile", tint = LightText, modifier = Modifier.size(16.dp))
                }
            }
        }

        // Overlapping Avatar & Social Stats Row
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 16.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically
            ) {
                // Professional Avatar
                Box(
                    modifier = Modifier
                        .offset(y = (-30).dp)
                        .size(80.dp)
                        .background(
                            Brush.sweepGradient(
                                colors = listOf(RazorBlue, RazorTeal, RazorBlue)
                            ),
                            CircleShape
                        )
                        .padding(2.dp)
                        .background(Color.Black, CircleShape)
                        .padding(3.dp)
                        .clip(CircleShape)
                ) {
                    Box(
                        modifier = Modifier
                            .fillMaxSize()
                            .background(Color(0xFF130E22)),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = creator.name.take(1).uppercase(),
                            fontWeight = FontWeight.Black,
                            color = RazorBlue,
                            fontSize = 32.sp
                        )
                    }

                    // Verified Badge Overlay
                    if (creator.isVerified) {
                        Box(
                            modifier = Modifier
                                .size(24.dp)
                                .background(RazorTeal, CircleShape)
                                .border(2.dp, Color.Black, CircleShape)
                                .align(Alignment.BottomEnd),
                            contentAlignment = Alignment.Center
                        ) {
                            Icon(imageVector = Icons.Default.Check, contentDescription = "Verified creator", tint = Color.Black, modifier = Modifier.size(12.dp))
                        }
                    }
                }

                // Stats block on the right
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .weight(1f)
                        .padding(start = 16.dp)
                        .offset(y = (-10).dp),
                    horizontalArrangement = Arrangement.SpaceEvenly,
                    verticalAlignment = Alignment.CenterVertically
