@Composable
fun RazorpayCheckoutOverlay(
    checkoutInfo: CheckoutInfo,
    onDismiss: () -> Unit
) {
    var step by remember { mutableStateOf(1) }

    Dialog(onDismissRequest = onDismiss) {
        Card(
            shape = RoundedCornerShape(24.dp),
            colors = CardDefaults.cardColors(containerColor = CardBackground),
            border = BorderStroke(1.5.dp, RazorBlue),
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp)
                .testTag("checkout_dialog_card")
        ) {
            Column(modifier = Modifier.padding(16.dp)) {
                // Header details
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(
                        text = "Google Play Billing Sandbox",
                        fontWeight = FontWeight.Bold,
                        color = RazorBlue,
                        fontSize = 12.sp,
                        fontFamily = FontFamily.Monospace
                    )
                    IconButton(onClick = onDismiss) {
                        Icon(imageVector = Icons.Default.Close, contentDescription = "Close checkouts", tint = GrayText)
                    }
                }

                Crossfade(targetState = step, label = "PaymentSteps") { currentStep ->
                    when (currentStep) {
                        1 -> {
                            Column(modifier = Modifier.fillMaxWidth()) {
                                Spacer(modifier = Modifier.height(6.dp))
                                Text(text = checkoutInfo.title, style = MaterialTheme.typography.titleLarge, fontWeight = FontWeight.Black, color = LightText)
                                Spacer(modifier = Modifier.height(6.dp))
                                Text(text = checkoutInfo.description, color = GrayText, style = MaterialTheme.typography.bodyMedium)
                                
                                Spacer(modifier = Modifier.height(18.dp))

                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .clip(RoundedCornerShape(12.dp))
                                        .background(MinimalSurfaceContainer)
                                        .padding(14.dp),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Text("SANDBOX DEVELOPMENT TEST TRANSACTION", fontSize = 10.sp, color = GrayText, fontWeight = FontWeight.Bold)
                                    Text(
                                        text = "$${String.format("%.2f", checkoutInfo.amount)}",
                                        fontWeight = FontWeight.Black,
                                        color = RazorTeal,
                                        style = MaterialTheme.typography.titleLarge
                                    )
                                }

                                Spacer(modifier = Modifier.height(18.dp))

                                Button(
                                    onClick = { step = 2 },
                                    colors = ButtonDefaults.buttonColors(containerColor = RazorBlue),
                                    shape = RoundedCornerShape(12.dp),
                                    modifier = Modifier.fillMaxWidth()
                                ) {
                                    Icon(imageVector = Icons.Default.Lock, contentDescription = null, tint = Color.Black, modifier = Modifier.size(16.dp))
                                    Spacer(modifier = Modifier.width(6.dp))
                                    Text("Pay with Google Play Test Card", color = Color.Black, fontWeight = FontWeight.Black)
                                }
                            }
                        }
                        2 -> {
                            Column(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(vertical = 30.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                CircularProgressIndicator(color = RazorBlue, strokeWidth = 5.dp)
                                Spacer(modifier = Modifier.height(16.dp))
                                Text(text = "AUTHENTICATING SANDBOX CARD...", fontWeight = FontWeight.Bold, color = LightText, fontSize = 13.sp)
                                Text(text = "Processing virtual payment securely via Google Play Sandbox API.", fontSize = 10.sp, color = GrayText, textAlign = TextAlign.Center)

                                val scope = rememberCoroutineScope()
                                LaunchedEffect(Unit) {
                                    delay(1800)
                                    step = 3
                                    checkoutInfo.action()
                                }
                            }
                        }
                        3 -> {
                            Column(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(vertical = 20.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Box(
                                    modifier = Modifier
                                        .size(60.dp)
                                        .clip(CircleShape)
                                        .background(RazorTeal),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(imageVector = Icons.Default.Check, contentDescription = "Success check", tint = Color.Black, modifier = Modifier.size(36.dp))
                                }
                                Spacer(modifier = Modifier.height(16.dp))
                                Text(text = "SANDBOX PAYMENT SUCCESSFUL", fontWeight = FontWeight.Black, color = RazorTeal, style = MaterialTheme.typography.titleMedium)
                                Spacer(modifier = Modifier.height(6.dp))
                                Text(
                                    text = "Sandbox transaction completed successfully. Virtual purchase unlocked!",
                                    fontSize = 11.sp,
                                    color = GrayText,
                                    textAlign = TextAlign.Center
                                )
                                Spacer(modifier = Modifier.height(20.dp))
                                Button(
                                    onClick = onDismiss,
                                    colors = ButtonDefaults.buttonColors(containerColor = RazorBlue),
                                    shape = RoundedCornerShape(12.dp),
                                    modifier = Modifier.fillMaxWidth()
                                ) {
                                    Text("Back to Hub", fontWeight = FontWeight.Black, color = Color.Black)
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun SecureUpiPaymentDialog(
    amount: Double,
    onDismiss: () -> Unit,
    onSuccess: (String, String) -> Unit,
    initialUpiId: String = ""
) {
    var stage by remember { mutableStateOf(0) } // 0: UPI & Handshake, 1: PIN, 2: App Passcode, 3: Cryptographic Sign, 4: Broadcasting, 5: Receipt
    var upiId by remember { mutableStateOf(initialUpiId) }
    
    // Stage 0: Handshake Logs
    var isHandshaking by remember { mutableStateOf(false) }
    val handshakeLogs = remember { mutableStateListOf<String>() }
    
    // Stage 1: PIN
    var pinCode by remember { mutableStateOf("") }
    
    // Stage 2: Master Passcode
    var masterPasscode by remember { mutableStateOf("") }
    var showMasterPassword by remember { mutableStateOf(false) }
    
    // Stage 3: Passphrase
    var recoveryPassphrase by remember { mutableStateOf("") }
    
    // Stage 4: Broadcast logs
    var broadcastStep by remember { mutableStateOf(0) }
    
    // Calculated Hashes
    val payloadString = remember(upiId, amount) {
        """{"upiId":"$upiId","amount":$amount,"timestamp":${System.currentTimeMillis()},"cipher":"AES_256_GCM"}"""
    }
    
    val sha256Hash = remember(payloadString, recoveryPassphrase) {
        try {
            val bytes = (payloadString + recoveryPassphrase).toByteArray()
            val md = java.security.MessageDigest.getInstance("SHA-256")
            val digest = md.digest(bytes)
            digest.fold("") { str, it -> str + "%02x".format(it) }
        } catch (e: Exception) {
            "e8c8942b0a16b9b1e95e1c0c1b004a4ea6cb9f4d7f8a9d1d9b73467e91ca8fb4"
        }
    }

    val clipboardManager = androidx.compose.ui.platform.LocalClipboardManager.current
    var copiedToast by remember { mutableStateOf(false) }
    
    LaunchedEffect(isHandshaking) {
        if (isHandshaking) {
            handshakeLogs.clear()
            val steps = listOf(
                "Initializing Secure Tunnel Connection...",
                "Contacting NPCI Central UPI Network Router...",
                "Creating RSA-4096 Authenticated Handshake...",
                "ECDH Diffie-Hellman Key Exchange success. Secret key established.",
                "Symmetric block cipher initialized with AES-256-GCM.",
                "Encrypted payload canal online. [SESSION KEY VERIFIED]"
            )
            for (stepText in steps) {
                handshakeLogs.add(stepText)
                delay(400)
            }
            delay(300)
            stage = 1
            isHandshaking = false
        }
    }
    
    LaunchedEffect(stage) {
        if (stage == 4) {
            for (i in 1..4) {
                broadcastStep = i
                delay(700)
            }
            stage = 5
        }
    }

    // Dialog Card UI
    Dialog(onDismissRequest = { if (stage != 4) onDismiss() }) {
        Card(
            shape = RoundedCornerShape(24.dp),
            colors = CardDefaults.cardColors(containerColor = ObsidianDark),
            border = BorderStroke(2.dp, if (stage == 5) RazorTeal else RazorBlue),
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp)
                .testTag("secure_upi_dialog_card")
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(20.dp)
            ) {
                // Header
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Box(
                            modifier = Modifier
                                .size(8.dp)
                                .clip(CircleShape)
                                .background(if (stage == 5) RazorTeal else Color.Green)
                        )
                        Spacer(modifier = Modifier.width(6.dp))
                        Text(
                            text = if (stage == 5) "NPCI SIGNED RECEIPT" else "SECURE UPI TUNNEL",
                            fontWeight = FontWeight.Bold,
                            color = if (stage == 5) RazorTeal else RazorBlue,
                            fontSize = 11.sp,
                            fontFamily = FontFamily.Monospace,
                            letterSpacing = 1.sp
                        )
                    }
                    if (stage != 4 && stage != 5) {
                        IconButton(onClick = onDismiss, modifier = Modifier.size(24.dp)) {
                            Icon(imageVector = Icons.Default.Close, contentDescription = "Close UPI Dialog", tint = GrayText)
                        }
                    }
                }
                
                Spacer(modifier = Modifier.height(10.dp))
                
                // Stage Layouts
                Crossfade(targetState = stage, label = "SecureUpiStages") { currentStage ->
                    when (currentStage) {
                        0 -> {
                            Column(modifier = Modifier.fillMaxWidth()) {
                                Text(
                                    text = "Encrypted UPI Node Gateway",
                                    style = MaterialTheme.typography.titleMedium,
                                    fontWeight = FontWeight.Black,
                                    color = Color.White
                                )
                                Spacer(modifier = Modifier.height(4.dp))
                                Text(
                                    text = "Transfer amount: $$amount (~INR ${String.format("%.2f", amount * 83.5)})",
                                    color = RazorTeal,
                                    fontSize = 12.sp,
                                    fontWeight = FontWeight.Bold
                                )
                                
                                Spacer(modifier = Modifier.height(16.dp))
                                
                                Text("Virtual UPI Address (VPA)", color = GrayText, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                Spacer(modifier = Modifier.height(6.dp))
                                OutlinedTextField(
                                    value = upiId,
                                    onValueChange = { upiId = it.trim() },
                                    placeholder = { Text("e.g. moumita@okhdfcbank", color = GrayText) },
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedTextColor = Color.White,
                                        unfocusedTextColor = Color.White,
                                        focusedBorderColor = RazorTeal,
                                        unfocusedBorderColor = MinimalBorder
                                    ),
                                    modifier = Modifier.fillMaxWidth().testTag("upi_id_input")
                                )
                                
                                val isValidUpi = upiId.contains("@") && upiId.length > 5
                                if (isValidUpi) {
                                    Spacer(modifier = Modifier.height(6.dp))
                                    Row(verticalAlignment = Alignment.CenterVertically) {
                                        Icon(imageVector = Icons.Default.Check, contentDescription = null, tint = RazorTeal, modifier = Modifier.size(14.dp))
                                        Spacer(modifier = Modifier.width(4.dp))
                                        Text("Valid VPA Address format • Security tunnel ready", color = RazorTeal, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                                
                                Spacer(modifier = Modifier.height(12.dp))
                                Text("SUGGESTED FAST-PAY VPAs", color = GrayText, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                Spacer(modifier = Modifier.height(6.dp))
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                                ) {
                                    listOf("moumita@okhdfcbank", "developer@okaxis", "security@oksbi").forEach { preset ->
                                        Box(
                                            modifier = Modifier
                                                .weight(1f)
                                                .clip(RoundedCornerShape(8.dp))
                                                .background(Color.White.copy(alpha = 0.05f))
                                                .border(1.dp, if (upiId == preset) RazorTeal else Color.Transparent, RoundedCornerShape(8.dp))
                                                .clickable { upiId = preset }
                                                .padding(vertical = 8.dp),
                                            contentAlignment = Alignment.Center
                                        ) {
                                            Text(preset, fontSize = 9.sp, color = if (upiId == preset) RazorTeal else LightText, maxLines = 1)
                                        }
                                    }
                                }
                                
                                Spacer(modifier = Modifier.height(20.dp))
                                
                                if (isHandshaking) {
                                    Card(
                                        colors = CardDefaults.cardColors(containerColor = Color.Black),
                                        border = BorderStroke(1.dp, RazorBlue.copy(alpha = 0.3f)),
                                        modifier = Modifier.fillMaxWidth().height(120.dp)
                                    ) {
                                        LazyColumn(
                                            modifier = Modifier.padding(10.dp),
                                            verticalArrangement = Arrangement.spacedBy(4.dp)
                                        ) {
                                            items(handshakeLogs.size) { logIdx ->
                                                Text(
                                                    text = ">>> " + handshakeLogs[logIdx],
                                                    color = if (logIdx == handshakeLogs.size - 1) RazorTeal else Color.Green.copy(alpha = 0.7f),
                                                    fontFamily = FontFamily.Monospace,
                                                    fontSize = 10.sp
                                                )
                                            }
                                        }
                                    }
                                } else {
                                    Button(
                                        onClick = { isHandshaking = true },
                                        enabled = isValidUpi,
                                        colors = ButtonDefaults.buttonColors(
                                            containerColor = RazorBlue,
                                            disabledContainerColor = Color.DarkGray
                                        ),
                                        shape = RoundedCornerShape(12.dp),
                                        modifier = Modifier.fillMaxWidth().testTag("init_gateway_button")
                                    ) {
                                        Icon(imageVector = Icons.Default.Lock, contentDescription = null, tint = Color.Black, modifier = Modifier.size(16.dp))
                                        Spacer(modifier = Modifier.width(6.dp))
                                        Text("Initiate Secure Encrypted Channel", color = Color.Black, fontWeight = FontWeight.Black, fontSize = 12.sp)
                                    }
                                }
                            }
                        }
                        1 -> {
                            Column(modifier = Modifier.fillMaxWidth(), horizontalAlignment = Alignment.CenterHorizontally) {
                                Text(
                                    text = "Layer 1: Standard UPI PIN",
                                    style = MaterialTheme.typography.titleMedium,
                                    fontWeight = FontWeight.Black,
                                    color = Color.White
                                )
                                Spacer(modifier = Modifier.height(4.dp))
                                Text(
                                    text = "Authenticate transaction debit signature",
                                    color = GrayText,
                                    fontSize = 11.sp
                                )
                                
                                Spacer(modifier = Modifier.height(20.dp))
                                
                                // Pin Dots Display
                                Row(
                                    horizontalArrangement = Arrangement.spacedBy(12.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    for (i in 0..5) {
                                        val isFilled = pinCode.length > i
                                        Box(
                                            modifier = Modifier
                                                .size(16.dp)
                                                .clip(CircleShape)
                                                .background(if (isFilled) RazorTeal else Color.Transparent)
                                                .border(2.dp, if (isFilled) RazorTeal else RazorBlue.copy(alpha = 0.5f), CircleShape)
                                        )
                                    }
                                }
                                
                                Spacer(modifier = Modifier.height(24.dp))
                                
                                // Numeric PIN Keypad
                                Column(
                                    verticalArrangement = Arrangement.spacedBy(8.dp),
                                    modifier = Modifier.width(220.dp)
                                ) {
                                    val keys = listOf(
                                        listOf("1", "2", "3"),
                                        listOf("4", "5", "6"),
                                        listOf("7", "8", "9"),
                                        listOf("CLR", "0", "DEL")
                                    )
                                    for (row in keys) {
                                        Row(
                                            modifier = Modifier.fillMaxWidth(),
                                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                                        ) {
                                            for (key in row) {
                                                Box(
                                                    modifier = Modifier
                                                        .weight(1f)
                                                        .height(42.dp)
                                                        .clip(RoundedCornerShape(8.dp))
                                                        .background(Color.White.copy(alpha = 0.05f))
                                                        .clickable {
                                                            if (key == "CLR") {
                                                                pinCode = ""
                                                            } else if (key == "DEL") {
                                                                if (pinCode.isNotEmpty()) pinCode = pinCode.dropLast(1)
                                                            } else {
                                                                if (pinCode.length < 6) pinCode += key
                                                            }
                                                        },
                                                    contentAlignment = Alignment.Center
                                                ) {
                                                    Text(
                                                        text = key,
                                                        color = if (key == "CLR" || key == "DEL") RazorBlue else Color.White,
                                                        fontWeight = FontWeight.Bold,
                                                        fontSize = if (key.length > 1) 10.sp else 16.sp
                                                    )
                                                }
                                            }
                                        }
                                    }
                                }
                                
                                Spacer(modifier = Modifier.height(20.dp))
                                
                                Button(
                                    onClick = { stage = 2 },
                                    enabled = pinCode.length == 6,
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = RazorTeal,
                                        disabledContainerColor = Color.DarkGray
                                    ),
                                    shape = RoundedCornerShape(12.dp),
                                    modifier = Modifier.fillMaxWidth().testTag("verify_pin_button")
                                ) {
                                    Text("Verify PIN (Layer 1 Passed) →", color = Color.Black, fontWeight = FontWeight.Black)
                                }
                            }
                        }
                        2 -> {
                            Column(modifier = Modifier.fillMaxWidth()) {
                                Text(
                                    text = "Layer 2: App Master Passcode",
                                    style = MaterialTheme.typography.titleMedium,
                                    fontWeight = FontWeight.Black,
                                    color = Color.White
                                )
                                Spacer(modifier = Modifier.height(4.dp))
                                Text(
                                    text = "Secondary level App-specific biometric key bypass",
                                    color = GrayText,
                                    fontSize = 11.sp
                                )
                                
                                Spacer(modifier = Modifier.height(18.dp))
                                
                                Text("Master Password / Passcode", color = GrayText, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                Spacer(modifier = Modifier.height(6.dp))
                                OutlinedTextField(
                                    value = masterPasscode,
                                    onValueChange = { masterPasscode = it },
                                    visualTransformation = if (showMasterPassword) androidx.compose.ui.text.input.VisualTransformation.None else androidx.compose.ui.text.input.PasswordVisualTransformation(),
                                    trailingIcon = {
                                        IconButton(onClick = { showMasterPassword = !showMasterPassword }) {
                                            Icon(
                                                imageVector = if (showMasterPassword) Icons.Default.Visibility else Icons.Default.VisibilityOff,
                                                contentDescription = "Toggle password visibility",
                                                tint = GrayText
                                            )
                                        }
                                    },
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedTextColor = Color.White,
                                        unfocusedTextColor = Color.White,
                                        focusedBorderColor = RazorTeal,
                                        unfocusedBorderColor = MinimalBorder
                                    ),
                                    modifier = Modifier.fillMaxWidth().testTag("master_passcode_input")
                                )
                                
                                Spacer(modifier = Modifier.height(10.dp))
                                
                                // Password strength indicator
                                val strength = remember(masterPasscode) {
                                    if (masterPasscode.isEmpty()) 0
                                    else {
                                        var score = 1
                                        if (masterPasscode.length >= 8) score++
                                        if (masterPasscode.any { it.isDigit() }) score++
                                        if (masterPasscode.any { !it.isLetterOrDigit() }) score++
                                        score
                                    }
                                }
                                val strengthText = when (strength) {
                                    0 -> "Enter passcode..."
                                    1 -> "WEAK PASSWORD"
                                    2 -> "MEDIUM SECURE"
                                    else -> "HIGHLY ENCRYPTED"
                                }
                                val strengthColor = when (strength) {
                                    0 -> GrayText
                                    1 -> Color.Red
                                    2 -> Color.Yellow
                                    else -> RazorTeal
                                }
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Box(
                                        modifier = Modifier
                                            .height(4.dp)
                                            .weight(1f)
                                            .clip(RoundedCornerShape(2.dp))
                                            .background(if (strength >= 1) strengthColor else Color.DarkGray)
                                    )
                                    Spacer(modifier = Modifier.width(4.dp))
                                    Box(
                                        modifier = Modifier
                                            .height(4.dp)
                                            .weight(1f)
                                            .clip(RoundedCornerShape(2.dp))
                                            .background(if (strength >= 2) strengthColor else Color.DarkGray)
                                    )
                                    Spacer(modifier = Modifier.width(4.dp))
                                    Box(
                                        modifier = Modifier
                                            .height(4.dp)
                                            .weight(1f)
                                            .clip(RoundedCornerShape(2.dp))
                                            .background(if (strength >= 3) strengthColor else Color.DarkGray)
                                    )
                                    Spacer(modifier = Modifier.width(8.dp))
                                    Text(
                                        text = strengthText,
                                        color = strengthColor,
                                        fontSize = 10.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                                
                                Spacer(modifier = Modifier.height(24.dp))
                                
                                Button(
                                    onClick = { stage = 3 },
                                    enabled = masterPasscode.length >= 4,
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = RazorTeal,
                                        disabledContainerColor = Color.DarkGray
                                    ),
                                    shape = RoundedCornerShape(12.dp),
                                    modifier = Modifier.fillMaxWidth().testTag("verify_master_button")
                                ) {
                                    Text("Unlock with App Passcode →", color = Color.Black, fontWeight = FontWeight.Black)
                                }
                            }
                        }
                        3 -> {
                            Column(modifier = Modifier.fillMaxWidth()) {
                                Text(
                                    text = "Layer 3: Cryptographic Decryption Passphrase",
                                    style = MaterialTheme.typography.titleMedium,
                                    fontWeight = FontWeight.Black,
                                    color = Color.White
                                )
                                Spacer(modifier = Modifier.height(4.dp))
                                Text(
                                    text = "Decrypt payload & apply secure digital signature",
                                    color = GrayText,
                                    fontSize = 11.sp
                                )
                                
                                Spacer(modifier = Modifier.height(14.dp))
                                
                                // Interactive JSON block
                                Card(
                                    colors = CardDefaults.cardColors(containerColor = Color.Black),
                                    border = BorderStroke(1.dp, RazorBlue.copy(alpha = 0.2f)),
                                    modifier = Modifier.fillMaxWidth()
                                ) {
                                    Column(modifier = Modifier.padding(10.dp)) {
                                        Text("ENCRYPTED PAYLOAD (AES-256):", color = RazorBlue, fontSize = 9.sp, fontWeight = FontWeight.Bold, fontFamily = FontFamily.Monospace)
                                        Spacer(modifier = Modifier.height(4.dp))
                                        Text(
                                            text = payloadString,
                                            color = Color.Green.copy(alpha = 0.8f),
                                            fontSize = 9.sp,
                                            fontFamily = FontFamily.Monospace,
                                            maxLines = 2
                                        )
                                        Spacer(modifier = Modifier.height(6.dp))
                                        Text("SHA256 CHECKSUM (RAW DIGEST):", color = RazorBlue, fontSize = 9.sp, fontWeight = FontWeight.Bold, fontFamily = FontFamily.Monospace)
                                        Text(
                                            text = sha256Hash,
                                            color = RazorTeal,
                                            fontSize = 9.sp,
                                            fontFamily = FontFamily.Monospace,
                                            maxLines = 1
                                        )
                                    }
                                }
                                
                                Spacer(modifier = Modifier.height(12.dp))
                                
                                Text("Transaction Sign Private Key / Phrase", color = GrayText, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                Spacer(modifier = Modifier.height(6.dp))
                                OutlinedTextField(
                                    value = recoveryPassphrase,
                                    onValueChange = { recoveryPassphrase = it },
                                    placeholder = { Text("Enter private key/seed token phrase", color = GrayText) },
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedTextColor = Color.White,
                                        unfocusedTextColor = Color.White,
                                        focusedBorderColor = RazorTeal,
                                        unfocusedBorderColor = MinimalBorder
                                    ),
                                    modifier = Modifier.fillMaxWidth().testTag("passphrase_input")
                                )
                                
                                Spacer(modifier = Modifier.height(8.dp))
                                Box(
                                    modifier = Modifier
                                        .clip(RoundedCornerShape(8.dp))
                                        .background(RazorBlue.copy(alpha = 0.1f))
                                        .clickable {
                                            recoveryPassphrase = listOf(
                                                "quantum-galaxy-shield-cyber",
                                                "moumita-secure-vault-token",
                                                "vector-nebula-glowing-shield",
                                                "cyberpunk-pixel-crypto-mint"
                                            ).random()
                                        }
                                        .padding(vertical = 6.dp, horizontal = 12.dp)
                                        .align(Alignment.End)
                                ) {
                                    Text("Generate Token Passphrase", color = RazorBlue, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                }
                                
                                Spacer(modifier = Modifier.height(18.dp))
                                
                                Button(
                                    onClick = { stage = 4 },
                                    enabled = recoveryPassphrase.isNotBlank(),
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = RazorTeal,
                                        disabledContainerColor = Color.DarkGray
                                    ),
                                    shape = RoundedCornerShape(12.dp),
                                    modifier = Modifier.fillMaxWidth().testTag("broadcast_button")
                                ) {
                                    Icon(imageVector = Icons.Default.Lock, contentDescription = null, tint = Color.Black, modifier = Modifier.size(16.dp))
                                    Spacer(modifier = Modifier.width(6.dp))
                                    Text("DECRYPT & SIGN BROADCAST PAYMENT", color = Color.Black, fontWeight = FontWeight.Black)
                                }
                            }
                        }
                        4 -> {
                            Column(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(vertical = 24.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                CircularProgressIndicator(color = RazorTeal, strokeWidth = 5.dp)
                                Spacer(modifier = Modifier.height(20.dp))
                                val progressText = when (broadcastStep) {
                                    1 -> "ENCRYPTING TRANSACTION PAYLOAD..."
                                    2 -> "GENERATING CRYPTOGRAPHIC RSA-4096 SIGNATURE..."
                                    3 -> "BROADCASTING SIGNED PAYLOAD TO UPI-NPCI NETWORK..."
                                    else -> "AWAITING TRANSACTION NETWORK CONSENSUS..."
                                }
                                Text(
                                    text = progressText,
                                    fontWeight = FontWeight.Bold,
                                    color = Color.White,
                                    fontSize = 12.sp,
                                    fontFamily = FontFamily.Monospace,
                                    textAlign = TextAlign.Center
                                )
                                Spacer(modifier = Modifier.height(6.dp))
                                Text(
                                    text = "AES-256 Symmetric encryption payload successfully signed.",
                                    fontSize = 10.sp,
                                    color = GrayText,
                                    textAlign = TextAlign.Center
                                )
                            }
                        }
                        5 -> {
                            Column(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(vertical = 12.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Box(
                                    modifier = Modifier
                                        .size(60.dp)
                                        .clip(CircleShape)
                                        .background(RazorTeal),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(imageVector = Icons.Default.Check, contentDescription = "Success check", tint = Color.Black, modifier = Modifier.size(36.dp))
                                }
                                
                                Spacer(modifier = Modifier.height(16.dp))
                                Text(text = "UPI CRYPTOGRAPHICALLY VERIFIED", fontWeight = FontWeight.Black, color = RazorTeal, style = MaterialTheme.typography.titleMedium, textAlign = TextAlign.Center)
                                Spacer(modifier = Modifier.height(6.dp))
                                Text(
                                    text = "Symmetric encryption handshake finalized. NPCI Central bank ledger updated successfully.",
                                    fontSize = 11.sp,
                                    color = GrayText,
                                    textAlign = TextAlign.Center
                                )
                                
                                Spacer(modifier = Modifier.height(18.dp))
                                
                                Card(
                                    colors = CardDefaults.cardColors(containerColor = Color.Black),
                                    border = BorderStroke(1.dp, RazorTeal.copy(alpha = 0.4f)),
                                    modifier = Modifier.fillMaxWidth()
                                ) {
                                    Column(modifier = Modifier.padding(14.dp)) {
                                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                            Text("SENDER UPI ID:", color = GrayText, fontSize = 10.sp)
                                            Text(upiId, color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                        }
                                        Spacer(modifier = Modifier.height(4.dp))
                                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                            Text("AMOUNT CONFIRMED:", color = GrayText, fontSize = 10.sp)
                                            Text("INR ${String.format("%.2f", amount * 83.5)} ($$amount)", color = RazorTeal, fontSize = 10.sp, fontWeight = FontWeight.Black)
                                        }
                                        Spacer(modifier = Modifier.height(4.dp))
                                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                            Text("GATEWAY STATUS:", color = GrayText, fontSize = 10.sp)
                                            Text("FULLY ENCRYPTED (AES-256-GCM)", color = Color.Green, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                        }
                                        Spacer(modifier = Modifier.height(6.dp))
                                        androidx.compose.material3.HorizontalDivider(color = Color.DarkGray)
                                        Spacer(modifier = Modifier.height(6.dp))
                                        Text("CRYPTOGRAPHIC TRANSACTION SIGNATURE:", color = RazorBlue, fontSize = 8.sp, fontWeight = FontWeight.Bold, fontFamily = FontFamily.Monospace)
                                        Spacer(modifier = Modifier.height(4.dp))
                                        Row(verticalAlignment = Alignment.CenterVertically) {
                                            Text(
                                                text = sha256Hash.take(32) + "...",
                                                color = Color.White.copy(alpha = 0.8f),
                                                fontSize = 8.sp,
                                                fontFamily = FontFamily.Monospace,
                                                modifier = Modifier.weight(1f)
                                            )
                                            Box(
                                                modifier = Modifier
                                                    .clip(RoundedCornerShape(4.dp))
                                                    .background(RazorBlue.copy(alpha = 0.2f))
                                                    .clickable {
                                                        try {
                                                            clipboardManager.setText(androidx.compose.ui.text.AnnotatedString(sha256Hash))
                                                            copiedToast = true
                                                        } catch (e: Exception) {
                                                            e.printStackTrace()
                                                        }
                                                    }
                                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                                            ) {
                                                Text("Copy", color = RazorBlue, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                            }
                                        }
                                    }
                                }
                                
                                if (copiedToast) {
                                    Spacer(modifier = Modifier.height(6.dp))
                                    Text("Copied cryptographic signature to clipboard!", color = RazorTeal, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                    LaunchedEffect(Unit) {
                                        delay(1500)
                                        copiedToast = false
                                    }
                                }
                                
                                Spacer(modifier = Modifier.height(24.dp))
                                
                                Button(
                                    onClick = {
                                        onSuccess(upiId, sha256Hash)
                                    },
                                    colors = ButtonDefaults.buttonColors(containerColor = RazorTeal),
                                    shape = RoundedCornerShape(12.dp),
                                    modifier = Modifier.fillMaxWidth().testTag("dismiss_receipt_button")
                                ) {
                                    Text("Complete Load & Back to Hub", fontWeight = FontWeight.Black, color = Color.Black)
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun UpiQrScannerDialog(
    onDismiss: () -> Unit,
    onQrScanned: (String, Double, String) -> Unit, // upiId, amount, note
    phishingFilterEnabled: Boolean
) {
    var rawInput by remember { mutableStateOf("") }
    var flashOn by remember { mutableStateOf(false) }
    var scanStatusMessage by remember { mutableStateOf("Position QR Code in the frame to scan") }
    var detectedPayee by remember { mutableStateOf<String?>(null) }
    var detectedName by remember { mutableStateOf<String?>(null) }
    var detectedAmount by remember { mutableStateOf<Double?>(null) }
    var isPhishingDetected by remember { mutableStateOf(false) }
    
    // Animation for the scanning laser line
    val infiniteTransition = androidx.compose.animation.core.rememberInfiniteTransition(label = "laser")
    val laserOffset by infiniteTransition.animateFloat(
        initialValue = 0f,
        targetValue = 1f,
        animationSpec = androidx.compose.animation.core.infiniteRepeatable(
            animation = androidx.compose.animation.core.tween(durationMillis = 1800, easing = androidx.compose.animation.core.LinearEasing),
            repeatMode = androidx.compose.animation.core.RepeatMode.Reverse
        ),
        label = "laserOffset"
    )

    Dialog(onDismissRequest = onDismiss) {
        Card(
            shape = RoundedCornerShape(24.dp),
            colors = CardDefaults.cardColors(containerColor = ObsidianDark),
            border = BorderStroke(1.5.dp, if (isPhishingDetected) Color.Red else RazorTeal),
            modifier = Modifier
                .fillMaxWidth()
                .padding(12.dp)
                .testTag("upi_qr_scanner_dialog")
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(18.dp)
            ) {
                // Header
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Icon(imageVector = Icons.Default.QrCode, contentDescription = null, tint = RazorTeal, modifier = Modifier.size(18.dp))
                        Spacer(modifier = Modifier.width(6.dp))
                        Text(
                            text = "SECURE UPI QR SCANNER",
                            style = MaterialTheme.typography.titleSmall,
                            fontWeight = FontWeight.Black,
                            color = Color.White,
                            letterSpacing = 0.5.sp
                        )
                    }
                    IconButton(onClick = onDismiss, modifier = Modifier.size(24.dp)) {
                        Icon(imageVector = Icons.Default.Close, contentDescription = "Close Scanner", tint = GrayText)
                    }
                }
                
                Spacer(modifier = Modifier.height(14.dp))

                // Simulated Viewfinder
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(180.dp)
                        .clip(RoundedCornerShape(16.dp))
                        .background(Color.Black)
                        .border(1.5.dp, if (isPhishingDetected) Color.Red.copy(0.6f) else Color.White.copy(0.15f), RoundedCornerShape(16.dp)),
                    contentAlignment = Alignment.Center
                ) {
                    // Target corners box
                    Box(
                        modifier = Modifier
                            .size(120.dp)
                            .border(2.dp, if (isPhishingDetected) Color.Red else RazorTeal, RoundedCornerShape(8.dp))
                    )

                    // Laser scan line
                    Box(
                        modifier = Modifier
                            .fillMaxWidth(0.6f)
                            .height(2.dp)
                            .align(Alignment.TopCenter)
                            .offset(y = 30.dp + (laserOffset * 120f).dp)
                            .background(
                                Brush.horizontalGradient(
                                    colors = listOf(Color.Transparent, if (isPhishingDetected) Color.Red else RazorTeal, Color.Transparent)
                                )
                            )
                    )

                    // Flash Overlay Indicator
                    if (flashOn) {
                        Box(
                            modifier = Modifier
                                .fillMaxSize()
                                .background(Color.White.copy(alpha = 0.08f))
                        )
                    }

                    Text(
                        text = "SIMULATED UPI OPTICAL LENS",
                        color = Color.White.copy(alpha = 0.3f),
                        fontSize = 8.sp,
                        fontWeight = FontWeight.Bold,
                        fontFamily = FontFamily.Monospace,
                        modifier = Modifier.align(Alignment.BottomCenter).padding(bottom = 8.dp)
                    )
                }

                Spacer(modifier = Modifier.height(10.dp))

                // Flash & Action Row
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    IconButton(
                        onClick = { flashOn = !flashOn },
                        modifier = Modifier
                            .clip(CircleShape)
                            .background(Color.White.copy(0.05f))
                            .size(36.dp)
                    ) {
                        Icon(
                            imageVector = if (flashOn) Icons.Default.Lightbulb else Icons.Outlined.Lightbulb,
                            contentDescription = "Flash Toggle",
                            tint = if (flashOn) Color.Yellow else Color.White,
                            modifier = Modifier.size(18.dp)
                        )
                    }

                    Text(
                        text = scanStatusMessage,
                        color = if (isPhishingDetected) Color.Red else RazorTeal,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold,
                        textAlign = TextAlign.End,
                        modifier = Modifier.weight(1f).padding(start = 10.dp)
                    )
                }

                Spacer(modifier = Modifier.height(12.dp))

                // Fast test presets
                Text("TAP TEST UPI CODES TO SIMULATE QR SCAN:", color = GrayText, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                Spacer(modifier = Modifier.height(6.dp))
                Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                    val presets = listOf(
                        Triple("Moumita (Verified Merchant)", "upi://pay?pa=moumita@okhdfcbank&pn=Moumita&am=120.00&note=StorePurchase", "moumita@okhdfcbank"),
                        Triple("Pizza Split Hub", "upi://pay?pa=pizza_mario@okaxis&pn=Mario%20Pizza&am=21.12&note=PizzaSplit", "pizza_mario@okaxis"),
                        Triple("⚠️ FRAUDULENT SPOOF (Scam)", "upi://pay?pa=moumita-scam@hacker-node&pn=HackerPay&am=999.00&note=UrgentTax", "moumita-scam@hacker-node")
                    )
                    presets.forEach { (label, uri, address) ->
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .clip(RoundedCornerShape(10.dp))
                                .background(Color.White.copy(0.04f))
                                .clickable {
                                    rawInput = uri
                                    scanStatusMessage = "QR Decoded successfully!"
                                    
                                    val uriObj = android.net.Uri.parse(uri)
                                    val pa = uriObj.getQueryParameter("pa") ?: address
                                    val pn = uriObj.getQueryParameter("pn") ?: "Unknown User"
                                    val amStr = uriObj.getQueryParameter("am")
                                    val am = amStr?.toDoubleOrNull() ?: 10.00
                                    
                                    detectedPayee = pa
                                    detectedName = pn
                                    detectedAmount = am
                                    
                                    isPhishingDetected = phishingFilterEnabled && (pa.contains("scam") || pa.contains("hacker") || pa.contains("free-money"))
                                    if (isPhishingDetected) {
                                        scanStatusMessage = "🚨 THREAT ACTIVE: SPOOF/PHISHING BLOCKED!"
                                    }
                                }
                                .padding(8.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Icon(
                                imageVector = if (label.contains("⚠️")) Icons.Default.Warning else Icons.Default.QrCode,
                                contentDescription = null,
                                tint = if (label.contains("⚠️")) Color.Red else RazorTeal,
                                modifier = Modifier.size(16.dp)
                            )
                            Spacer(modifier = Modifier.width(8.dp))
                            Column {
                                Text(label, color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                Text(uri.take(45) + "...", color = GrayText, fontSize = 9.sp, fontFamily = FontFamily.Monospace)
                            }
                        }
                    }
                }

                Spacer(modifier = Modifier.height(12.dp))

                // Custom Address input option
                Text("OR PASTE RAW UPI DATA:", color = GrayText, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                Spacer(modifier = Modifier.height(4.dp))
                OutlinedTextField(
                    value = rawInput,
                    onValueChange = { input ->
                        rawInput = input
                        if (input.contains("upi://pay") || input.contains("@")) {
                            scanStatusMessage = "Data detected"
                            val parsedUpi = if (input.contains("upi://")) input else "upi://pay?pa=$input&pn=CustomUPI&am=10.00"
                            try {
                                val uriObj = android.net.Uri.parse(parsedUpi)
                                detectedPayee = uriObj.getQueryParameter("pa") ?: input
                                detectedName = uriObj.getQueryParameter("pn") ?: "Custom"
                                val amStr = uriObj.getQueryParameter("am")
                                detectedAmount = amStr?.toDoubleOrNull() ?: 10.00
                                isPhishingDetected = phishingFilterEnabled && (detectedPayee!!.contains("scam") || detectedPayee!!.contains("hacker"))
                                if (isPhishingDetected) {
                                    scanStatusMessage = "🚨 PHISHING DETECTED!"
                                } else {
                                    scanStatusMessage = "Parsed correctly!"
                                }
                            } catch (e: Exception) {
                                detectedPayee = input
                                detectedName = "Unknown"
                                detectedAmount = 10.00
                            }
                        }
                    },
                    placeholder = { Text("upi://pay?pa=address@bank&am=amount", color = GrayText, fontSize = 10.sp) },
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedTextColor = Color.White,
                        unfocusedTextColor = Color.White,
                        focusedBorderColor = RazorTeal,
                        unfocusedBorderColor = MinimalBorder
                    ),
                    modifier = Modifier.fillMaxWidth().testTag("scanner_manual_input")
                )

                // Decoded result
                detectedPayee?.let { payee ->
                    Spacer(modifier = Modifier.height(10.dp))
                    Card(
                        colors = CardDefaults.cardColors(containerColor = Color.Black),
                        border = BorderStroke(1.dp, if (isPhishingDetected) Color.Red.copy(0.4f) else RazorTeal.copy(0.4f)),
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Column(modifier = Modifier.padding(10.dp)) {
                            Text("SCANNER DECODING METRICS:", color = RazorBlue, fontSize = 9.sp, fontWeight = FontWeight.Bold, fontFamily = FontFamily.Monospace)
                            Spacer(modifier = Modifier.height(4.dp))
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                Text("Payee Name:", color = GrayText, fontSize = 10.sp)
                                Text(detectedName ?: "Custom", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            }
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                Text("Payee VPA:", color = GrayText, fontSize = 10.sp)
                                Text(payee, color = if (isPhishingDetected) Color.Red else RazorTeal, fontSize = 10.sp, fontWeight = FontWeight.Bold, fontFamily = FontFamily.Monospace)
                            }
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                Text("Pay Amount:", color = GrayText, fontSize = 10.sp)
                                Text("$$ {detectedAmount ?: 10.00} (~INR ${String.format("%.2f", (detectedAmount ?: 10.00) * 83.5)})", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            }
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                Text("Route Shield Status:", color = GrayText, fontSize = 10.sp)
                                Text(
                                    text = if (isPhishingDetected) "BLOCKED [UNSAFE SPOOF]" else "VERIFIED SECURE TUNNEL",
                                    color = if (isPhishingDetected) Color.Red else Color.Green,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }
                }

                Spacer(modifier = Modifier.height(14.dp))

                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    Button(
                        onClick = onDismiss,
                        colors = ButtonDefaults.buttonColors(containerColor = Color.DarkGray),
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier.weight(1f)
                    ) {
                        Text("Cancel", color = Color.White)
                    }

                    Button(
                        onClick = {
                            if (detectedPayee != null && !isPhishingDetected) {
                                onQrScanned(detectedPayee!!, detectedAmount ?: 10.00, detectedName ?: "Secure Payee")
                            }
                        },
                        enabled = detectedPayee != null && !isPhishingDetected,
                        colors = ButtonDefaults.buttonColors(
                            containerColor = RazorTeal,
                            disabledContainerColor = Color.DarkGray
                        ),
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier.weight(1.5f).testTag("scanner_proceed_pay")
                    ) {
                        Text("Proceed Secure Pay", color = Color.Black, fontWeight = FontWeight.Black)
                    }
                }
            }
        }
    }
}

