data class RealShareAppInfo(
    val packageName: String,
    val activityName: String,
    val label: String,
    val icon: android.graphics.drawable.Drawable
)

@Composable
fun RealShareAppItem(
    appInfo: RealShareAppInfo,
    onClick: () -> Unit
) {
    Column(
        horizontalAlignment = Alignment.CenterHorizontally,
        modifier = Modifier
            .clip(RoundedCornerShape(12.dp))
            .clickable { onClick() }
            .padding(6.dp)
            .width(72.dp)
    ) {
        Box(
            modifier = Modifier
                .size(48.dp)
                .background(Color.White.copy(alpha = 0.04f), RoundedCornerShape(12.dp))
                .padding(4.dp),
            contentAlignment = Alignment.Center
        ) {
            androidx.compose.ui.viewinterop.AndroidView(
                factory = { ctx ->
                    android.widget.ImageView(ctx).apply {
                        scaleType = android.widget.ImageView.ScaleType.FIT_CENTER
                    }
                },
                update = { imageView ->
                    imageView.setImageDrawable(appInfo.icon)
                },
                modifier = Modifier.fillMaxSize()
            )
        }
        Spacer(modifier = Modifier.height(6.dp))
        Text(
            text = appInfo.label,
            color = Color.White.copy(alpha = 0.9f),
            fontSize = 9.5.sp,
            fontWeight = FontWeight.Bold,
            maxLines = 1,
            overflow = TextOverflow.Ellipsis,
            textAlign = TextAlign.Center
        )
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ShareDialog(
    title: String,
    shareUrl: String,
    onDismiss: () -> Unit
) {
    val clipboardManager = androidx.compose.ui.platform.LocalClipboardManager.current
    val context = androidx.compose.ui.platform.LocalContext.current
    var isCopied by remember { mutableStateOf(false) }

    val realShareApps = remember {
        try {
            val pm = context.packageManager
            val baseIntent = android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                type = "text/plain"
            }
            val resolvedList = if (android.os.Build.VERSION.SDK_INT >= 33) {
                pm.queryIntentActivities(
                    baseIntent,
                    android.content.pm.PackageManager.ResolveInfoFlags.of(0L)
                )
            } else {
                @Suppress("DEPRECATION")
                pm.queryIntentActivities(baseIntent, 0)
            }
            resolvedList.map { info ->
                RealShareAppInfo(
                    packageName = info.activityInfo.packageName,
                    activityName = info.activityInfo.name,
                    label = info.loadLabel(pm).toString(),
                    icon = info.loadIcon(pm)
                )
            }.distinctBy { it.packageName }
             .filter { it.packageName != context.packageName } // exclude self
        } catch (e: Exception) {
            emptyList<RealShareAppInfo>()
        }
    }

    androidx.compose.ui.window.Dialog(
        onDismissRequest = onDismiss,
        properties = androidx.compose.ui.window.DialogProperties(
            usePlatformDefaultWidth = false,
            dismissOnBackPress = true,
            dismissOnClickOutside = true
        )
    ) {
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color.Black.copy(alpha = 0.5f))
                .clickable { onDismiss() },
            contentAlignment = Alignment.BottomCenter
        ) {
            Card(
                modifier = Modifier
                    .fillMaxWidth()
                    .clickable(enabled = false) { /* Prevent dismissal click */ },
                shape = RoundedCornerShape(topStart = 32.dp, topEnd = 32.dp),
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0C081A)),
                border = BorderStroke(1.5.dp, RazorBlue.copy(alpha = 0.3f))
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(24.dp)
                        .verticalScroll(rememberScrollState()),
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    // Pull/drag indicator bar
                    Box(
                        modifier = Modifier
                            .width(44.dp)
                            .height(5.dp)
                            .background(Color.White.copy(alpha = 0.15f), RoundedCornerShape(100))
                    )

                    Spacer(modifier = Modifier.height(18.dp))

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = "REALTIME SHARE PORTAL",
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Black,
                            color = RazorTeal,
                            letterSpacing = 1.8.sp,
                            fontFamily = FontFamily.Monospace
                        )
                        IconButton(
                            onClick = onDismiss,
                            modifier = Modifier
                                .size(32.dp)
                                .background(Color.White.copy(alpha = 0.05f), CircleShape)
                        ) {
                            Icon(
                                imageVector = Icons.Default.Close,
                                contentDescription = "Close",
                                tint = Color.White.copy(0.7f),
                                modifier = Modifier.size(16.dp)
                            )
                        }
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    // Title of shared content
                    Text(
                        text = title,
                        color = Color.White,
                        fontSize = 15.sp,
                        fontWeight = FontWeight.Bold,
                        textAlign = TextAlign.Center,
                        maxLines = 2,
                        overflow = TextOverflow.Ellipsis,
                        modifier = Modifier.padding(horizontal = 8.dp)
                    )

                    Spacer(modifier = Modifier.height(12.dp))

                    // Link Input Field / Box
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF130E29), RoundedCornerShape(16.dp))
                            .border(1.dp, Color.White.copy(alpha = 0.08f), RoundedCornerShape(16.dp))
                            .clickable {
                                try {
                                    clipboardManager.setText(androidx.compose.ui.text.AnnotatedString(shareUrl))
                                    isCopied = true
                                } catch (e: Exception) {
                                    e.printStackTrace()
                                }
                            }
                            .padding(horizontal = 14.dp, vertical = 14.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Icon(
                            imageVector = Icons.Default.Link,
                            contentDescription = "Link Icon",
                            tint = RazorBlue,
                            modifier = Modifier.size(20.dp)
                        )
                        Spacer(modifier = Modifier.width(10.dp))
                        Text(
                            text = shareUrl,
                            color = RazorTeal,
                            fontSize = 12.sp,
                            fontFamily = FontFamily.Monospace,
                            maxLines = 1,
                            overflow = TextOverflow.Ellipsis,
                            modifier = Modifier.weight(1f)
                        )
                        Spacer(modifier = Modifier.width(10.dp))
                        Icon(
                            imageVector = if (isCopied) Icons.Default.Check else Icons.Default.ContentCopy,
                            contentDescription = "Copy Link",
                            tint = if (isCopied) Color.Green else RazorBlue,
                            modifier = Modifier.size(18.dp)
                        )
                    }

                    if (isCopied) {
                        Spacer(modifier = Modifier.height(8.dp))
                        Text(
                            text = "Link copied to clipboard! Ready to share. 📡",
                            color = Color.Green.copy(0.9f),
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }

                    Spacer(modifier = Modifier.height(24.dp))

                    // Direct share shortcuts
                    Text(
                        text = "QUICK TRANSMIT SHORTCUTS",
                        color = GrayText,
                        fontSize = 10.5.sp,
                        fontWeight = FontWeight.Black,
                        letterSpacing = 1.2.sp,
                        modifier = Modifier.align(Alignment.Start)
                    )

                    Spacer(modifier = Modifier.height(12.dp))

                    val fallbackApps = listOf(
                        Triple("com.whatsapp", "WhatsApp", "🟢"),
                        Triple("org.telegram.messenger", "Telegram", "✈️"),
                        Triple("com.twitter.android", "Twitter", "🐦"),
                        Triple("com.facebook.orca", "Messenger", "💬"),
                        Triple("com.facebook.katana", "Facebook", "👥")
                    )

                    androidx.compose.foundation.lazy.LazyRow(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        contentPadding = PaddingValues(vertical = 4.dp)
                    ) {
                        items(fallbackApps.size) { index ->
                            val (pkg, name, icon) = fallbackApps[index]
                            Column(
                                horizontalAlignment = Alignment.CenterHorizontally,
                                modifier = Modifier
                                    .clip(RoundedCornerShape(12.dp))
                                    .clickable {
                                        val intent = android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                                            type = "text/plain"
                                            putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                            `package` = pkg
                                        }
                                        try {
                                            context.startActivity(intent)
                                        } catch (e: Exception) {
                                            // Open in web browser as a secure fallback
                                            val webUrl = when (pkg) {
                                                "com.whatsapp" -> "https://api.whatsapp.com/send?text=${android.net.Uri.encode("$title - $shareUrl")}"
                                                "org.telegram.messenger" -> "https://t.me/share/url?url=${android.net.Uri.encode(shareUrl)}&text=${android.net.Uri.encode(title)}"
                                                "com.twitter.android" -> "https://twitter.com/intent/tweet?text=${android.net.Uri.encode("$title - $shareUrl")}"
                                                "com.facebook.katana" -> "https://www.facebook.com/sharer/sharer.php?u=${android.net.Uri.encode(shareUrl)}"
                                                else -> null
                                            }
                                            if (webUrl != null) {
                                                try {
                                                    val webIntent = android.content.Intent(android.content.Intent.ACTION_VIEW, android.net.Uri.parse(webUrl))
                                                    context.startActivity(webIntent)
                                                } catch (ex: Exception) {
                                                    // Fallback to Native Share Sheet
                                                    val chooser = android.content.Intent.createChooser(
                                                        android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                                                            type = "text/plain"
                                                            putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                                        }, "Share via"
                                                    )
                                                    context.startActivity(chooser)
                                                }
                                            } else {
                                                // General fallback chooser
                                                val chooser = android.content.Intent.createChooser(
                                                    android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                                                        type = "text/plain"
                                                        putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                                    }, "Share via"
                                                )
                                                context.startActivity(chooser)
                                            }
                                        }
                                    }
                                    .padding(6.dp)
                                    .width(68.dp)
                            ) {
                                Box(
                                    modifier = Modifier
                                        .size(52.dp)
                                        .background(Color.White.copy(alpha = 0.04f), RoundedCornerShape(16.dp))
                                        .border(1.dp, Color.White.copy(alpha = 0.08f), RoundedCornerShape(16.dp)),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text(text = icon, fontSize = 24.sp)
                                }
                                Spacer(modifier = Modifier.height(8.dp))
                                Text(
                                    text = name,
                                    color = Color.White.copy(alpha = 0.85f),
                                    fontSize = 10.5.sp,
                                    fontWeight = FontWeight.Bold,
                                    maxLines = 1,
                                    overflow = TextOverflow.Ellipsis,
                                    textAlign = TextAlign.Center
                                )
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(24.dp))

                    // Real scan apps section
                    if (realShareApps.isNotEmpty()) {
                        Text(
                            text = "INSTALLED APPS (REALTIME SCAN)",
                            color = GrayText,
                            fontSize = 10.5.sp,
                            fontWeight = FontWeight.Black,
                            letterSpacing = 1.2.sp,
                            modifier = Modifier.align(Alignment.Start)
                        )

                        Spacer(modifier = Modifier.height(12.dp))

                        androidx.compose.foundation.lazy.LazyRow(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(14.dp),
                            contentPadding = PaddingValues(vertical = 4.dp)
                        ) {
                            items(realShareApps.size) { index ->
                                val app = realShareApps[index]
                                RealShareAppItem(
                                    appInfo = app,
                                    onClick = {
                                        val intent = android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                                            type = "text/plain"
                                            putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                            setClassName(app.packageName, app.activityName)
                                        }
                                        try {
                                            context.startActivity(intent)
                                        } catch (e: Exception) {
                                            val chooser = android.content.Intent.createChooser(
                                                android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                                                    type = "text/plain"
                                                    putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                                }, "Share via"
                                            )
                                            context.startActivity(chooser)
                                        }
                                    }
                                )
                            }
                        }

                        Spacer(modifier = Modifier.height(24.dp))
                    }

                    // System Share button
                    Button(
                        onClick = {
                            val sendIntent = android.content.Intent().apply {
                                action = android.content.Intent.ACTION_SEND
                                putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                type = "text/plain"
                            }
                            val shareIntent = android.content.Intent.createChooser(sendIntent, "Share post link")
                            context.startActivity(shareIntent)
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = RazorBlue),
                        modifier = Modifier.fillMaxWidth(),
                        shape = RoundedCornerShape(16.dp),
                        contentPadding = PaddingValues(vertical = 14.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Default.Share,
                            contentDescription = null,
                            tint = Color.Black,
                            modifier = Modifier.size(18.dp)
                        )
                        Spacer(modifier = Modifier.width(10.dp))
                        Text(
                            text = "SYSTEM SHARE SHEET",
                            fontWeight = FontWeight.Black,
                            color = Color.Black,
                            fontSize = 12.sp,
                            letterSpacing = 1.sp
                        )
                    }

                    Spacer(modifier = Modifier.height(12.dp))

                    OutlinedButton(
                        onClick = onDismiss,
                        border = BorderStroke(1.2.dp, Color.White.copy(0.15f)),
                        shape = RoundedCornerShape(16.dp),
                        modifier = Modifier.fillMaxWidth(),
                        contentPadding = PaddingValues(vertical = 14.dp)
                    ) {
                        Text(
                            text = "CLOSE SHARE HUB",
                            color = Color.White,
                            fontSize = 12.sp,
                            fontWeight = FontWeight.Bold,
                            letterSpacing = 1.sp
                        )
                    }
                }
            }
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun OldShareDialog(
    title: String,
    shareUrl: String,
    onDismiss: () -> Unit
) {
    val clipboardManager = androidx.compose.ui.platform.LocalClipboardManager.current
    val context = androidx.compose.ui.platform.LocalContext.current
    var isCopied by remember { mutableStateOf(false) }

    androidx.compose.ui.window.Dialog(onDismissRequest = onDismiss) {
        Card(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp),
            shape = RoundedCornerShape(28.dp),
            colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0B21)),
            border = BorderStroke(1.5.dp, RazorBlue)
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(24.dp),
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                // Header
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(
                        text = "SECURE SHARE HUB",
                        fontSize = 12.sp,
                        fontWeight = FontWeight.Black,
                        color = RazorTeal,
                        letterSpacing = 1.5.sp
                    )
                    IconButton(
                        onClick = onDismiss,
                        modifier = Modifier.size(28.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Default.Close,
                            contentDescription = "Close",
                            tint = Color.White.copy(0.6f),
                            modifier = Modifier.size(16.dp)
                        )
                    }
                }

                Spacer(modifier = Modifier.height(16.dp))

                // Large Decorative Icon
                Box(
                    modifier = Modifier
                        .size(64.dp)
                        .background(RazorBlue.copy(alpha = 0.15f), CircleShape),
                    contentAlignment = Alignment.Center
                ) {
                    Icon(
                        imageVector = Icons.Default.Share,
                        contentDescription = null,
                        tint = RazorBlue,
                        modifier = Modifier.size(32.dp)
                    )
                }

                Spacer(modifier = Modifier.height(12.dp))

                Text(
                    text = title,
                    color = Color.White,
                    fontWeight = FontWeight.Bold,
                    fontSize = 16.sp,
                    textAlign = androidx.compose.ui.text.style.TextAlign.Center
                )

                Spacer(modifier = Modifier.height(8.dp))

                Text(
                    text = "Share this secure link across decentralized nodes.",
                    color = GrayText,
                    fontSize = 11.sp,
                    textAlign = androidx.compose.ui.text.style.TextAlign.Center
                )

                Spacer(modifier = Modifier.height(20.dp))

                // Beautiful Link Container with click-to-copy
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color(0xFF130E29), RoundedCornerShape(16.dp))
                        .border(1.dp, Color.White.copy(alpha = 0.08f), RoundedCornerShape(16.dp))
                        .clickable {
                            try {
                                clipboardManager.setText(androidx.compose.ui.text.AnnotatedString(shareUrl))
                                isCopied = true
                            } catch (e: Exception) {
                                e.printStackTrace()
                            }
                        }
                        .padding(horizontal = 14.dp, vertical = 12.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.SpaceBetween
                ) {
                    Text(
                        text = shareUrl,
                        color = RazorTeal,
                        fontSize = 11.sp,
                        fontFamily = FontFamily.Monospace,
                        maxLines = 1,
                        overflow = TextOverflow.Ellipsis,
                        modifier = Modifier.weight(1f)
                    )
                    
                    Spacer(modifier = Modifier.width(8.dp))

                    Icon(
                        imageVector = if (isCopied) Icons.Default.Check else Icons.Default.ContentCopy,
                        contentDescription = "Copy Link",
                        tint = if (isCopied) Color.Green else RazorBlue,
                        modifier = Modifier.size(18.dp)
                    )
                }

                if (isCopied) {
                    Spacer(modifier = Modifier.height(8.dp))
                    Text(
                        text = "Link copied to clipboard! Ready to transmit. 📡",
                        color = Color.Green.copy(0.8f),
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                }

                Spacer(modifier = Modifier.height(24.dp))

                // Social platforms grid
                Text(
                    text = "QUICK TRANSMIT",
                    color = GrayText,
                    fontSize = 10.sp,
                    fontWeight = FontWeight.Bold,
                    letterSpacing = 1.sp,
                    modifier = Modifier.align(Alignment.Start)
                )

                Spacer(modifier = Modifier.height(10.dp))

                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween
                ) {
                    // WhatsApp
                    SocialShareItem(
                        icon = "🟢",
                        name = "WhatsApp",
                        onClick = {
                            val intent = android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                                type = "text/plain"
                                putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                `package` = "com.whatsapp"
                            }
                            try {
                                context.startActivity(intent)
                            } catch (e: Exception) {
                                // Fallback native share
                                val chooser = android.content.Intent.createChooser(
                                    android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                                        type = "text/plain"
                                        putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                    }, "Share via"
                                )
                                context.startActivity(chooser)
                            }
                        }
                    )

                    // Twitter/X
                    SocialShareItem(
                        icon = "🐦",
                        name = "Twitter",
                        onClick = {
                            val intent = android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                                type = "text/plain"
                                putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                `package` = "com.twitter.android"
                            }
                            try {
                                context.startActivity(intent)
                            } catch (e: Exception) {
                                val chooser = android.content.Intent.createChooser(
                                    android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                                        type = "text/plain"
                                        putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                    }, "Share via"
                                )
                                context.startActivity(chooser)
                            }
                        }
                    )

                    // Telegram
                    SocialShareItem(
                        icon = "✈️",
                        name = "Telegram",
                        onClick = {
                            val intent = android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                                type = "text/plain"
                                putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                `package` = "org.telegram.messenger"
                            }
                            try {
                                context.startActivity(intent)
                            } catch (e: Exception) {
                                val chooser = android.content.Intent.createChooser(
                                    android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                                        type = "text/plain"
                                        putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                    }, "Share via"
                                )
                                context.startActivity(chooser)
                            }
                        }
                    )

                    // System Share
                    SocialShareItem(
                        icon = "🛡️",
                        name = "Native",
                        onClick = {
                            val sendIntent: android.content.Intent = android.content.Intent().apply {
                                action = android.content.Intent.ACTION_SEND
                                putExtra(android.content.Intent.EXTRA_TEXT, "$title - $shareUrl")
                                type = "text/plain"
                            }
                            val shareIntent = android.content.Intent.createChooser(sendIntent, "Secure Share")
                            context.startActivity(shareIntent)
                        }
                    )
                }

                Spacer(modifier = Modifier.height(24.dp))

                Button(
                    onClick = onDismiss,
                    colors = ButtonDefaults.buttonColors(containerColor = RazorBlue),
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(16.dp)
                ) {
                    Text(
                        text = "CLOSE HUB",
                        fontWeight = FontWeight.Bold,
                        color = Color.Black,
                        letterSpacing = 1.sp
                    )
                }
            }
        }
    }
}

@Composable
fun SocialShareItem(
    icon: String,
    name: String,
    onClick: () -> Unit
) {
    Column(
        horizontalAlignment = Alignment.CenterHorizontally,
        modifier = Modifier
            .clickable { onClick() }
            .padding(8.dp)
    ) {
        Box(
            modifier = Modifier
                .size(48.dp)
                .background(Color(0xFF130E29), CircleShape)
                .border(1.dp, Color.White.copy(alpha = 0.05f), CircleShape),
            contentAlignment = Alignment.Center
        ) {
            Text(text = icon, fontSize = 22.sp)
        }
        Spacer(modifier = Modifier.height(6.dp))
        Text(text = name, color = GrayText, fontSize = 11.sp, fontWeight = FontWeight.Medium)
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun CommentDialog(
    post: Post,
    comments: List<String>,
    onAddComment: (String) -> Unit,
    onDismiss: () -> Unit
) {
    var newCommentText by remember { mutableStateOf("") }
    
    // Track who we are replying to
    var replyingToComment by remember { mutableStateOf<FacebookComment?>(null) }

    // Lazy load state to paginate and save rendering/server overhead
    var visibleCommentsLimit by remember { mutableStateOf(4) }
    
    // Rich comments state list memoized from comments list
    val richComments = remember(comments) {
        val list = androidx.compose.runtime.mutableStateListOf<FacebookComment>()
        comments.forEachIndexed { index, text ->
            val name = when(index % 4) {
                0 -> "Joe Alpha"
                1 -> "Mary Nodes"
                2 -> "Anon Cyber"
                else -> "Pixel King"
            }
            val handle = when(index % 4) {
                0 -> "joe_alpha"
                1 -> "mary_nodes"
                2 -> "anon_cyber"
                else -> "pixel_king"
            }
            val avatar = when(index % 4) {
                0 -> "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=150"
                1 -> "https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=150"
                2 -> "https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=150"
                else -> "https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=150"
            }
            
            val repliesList = androidx.compose.runtime.mutableStateListOf<FacebookCommentReply>()
            if (index == 0) {
                repliesList.add(
                    FacebookCommentReply(
                        id = "reply_0",
                        userName = "Mary Nodes",
                        userAvatar = "https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=150",
                        text = "Exactly! Couldn't agree more with this approach.",
                        timestamp = "1m ago"
                    )
                )
            }
            
            list.add(
                FacebookComment(
                    id = "comment_$index",
                    userName = name,
                    userHandle = handle,
                    userAvatar = avatar,
                    text = text,
                    timestamp = "${index + 2}m ago",
                    likesCount = if (index % 2 == 0) index + 1 else 0,
                    isLiked = false,
                    replies = repliesList
                )
            )
        }
        list
    }

    val lazyListState = androidx.compose.foundation.lazy.rememberLazyListState()

    // Auto-scroll to bottom when new comment is added
    LaunchedEffect(richComments.size) {
        if (richComments.isNotEmpty()) {
            lazyListState.animateScrollToItem(richComments.size - 1)
        }
    }

    Dialog(
        onDismissRequest = onDismiss,
        properties = androidx.compose.ui.window.DialogProperties(
            usePlatformDefaultWidth = false,
            decorFitsSystemWindows = false
        )
    ) {
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color(0xFF070412)) // Elegant Obsidian style deep background
        ) {
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .systemBarsPadding()
                    .imePadding()
            ) {
                // Facebook-style Top Navigation Header
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 16.dp, vertical = 12.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    IconButton(onClick = onDismiss) {
                        Icon(
                            imageVector = Icons.AutoMirrored.Filled.ArrowBack,
                            contentDescription = "Close",
                            tint = Color.White
                        )
                    }
                    Spacer(modifier = Modifier.width(12.dp))
                    Column {
                        Text(
                            text = "Comments",
                            fontSize = 18.sp,
                            fontWeight = FontWeight.Bold,
                            color = Color.White
                        )
                        Text(
                            text = "${richComments.size} replies on ${post.creatorName}'s post",
                            fontSize = 12.sp,
                            color = GrayText
                        )
                    }
                }

                androidx.compose.material3.HorizontalDivider(
                    color = Color.White.copy(0.08f),
                    thickness = 1.dp
                )

                // original post preview row
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color.White.copy(alpha = 0.03f))
                        .padding(horizontal = 16.dp, vertical = 12.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Box(
                        modifier = Modifier
                            .size(36.dp)
                            .clip(CircleShape)
                            .background(RazorBlue.copy(0.15f)),
                        contentAlignment = Alignment.Center
                    ) {
                        if (post.creatorAvatar.startsWith("http") || post.creatorAvatar.startsWith("content://") || post.creatorAvatar.startsWith("/data/")) {
                            AsyncImage(
                                model = post.creatorAvatar,
                                contentDescription = "Creator Avatar",
                                modifier = Modifier.fillMaxSize(),
                                contentScale = ContentScale.Crop
                            )
                        } else {
                            Text(post.creatorName.take(1).uppercase(), color = RazorBlue, fontWeight = FontWeight.Bold, fontSize = 13.sp)
                        }
                    }
                    Spacer(modifier = Modifier.width(12.dp))
                    Column(modifier = Modifier.weight(1f)) {
                        Text(post.creatorName, color = Color.White, fontSize = 13.sp, fontWeight = FontWeight.Bold)
                        Text(
                            post.caption,
                            color = LightText.copy(0.8f),
                            fontSize = 12.sp,
                            maxLines = 2,
                            overflow = TextOverflow.Ellipsis
                        )
                    }
                }

                androidx.compose.material3.HorizontalDivider(
                    color = Color.White.copy(0.08f),
                    thickness = 1.dp
                )

                // Scrollable comments list (Optimized with LazyColumn)
                Box(
                    modifier = Modifier
                        .weight(1f)
                        .fillMaxWidth()
                ) {
                    if (richComments.isEmpty()) {
                        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                Icon(
                                    imageVector = Icons.Default.ChatBubbleOutline,
                                    contentDescription = "No comments",
                                    tint = GrayText,
                                    modifier = Modifier.size(48.dp)
                                )
                                Spacer(modifier = Modifier.height(8.dp))
                                Text("Be the first to add a comment!", color = GrayText, fontSize = 14.sp)
                            }
                        }
                    } else {
                        androidx.compose.foundation.lazy.LazyColumn(
                            state = lazyListState,
                            modifier = Modifier.fillMaxSize(),
                            contentPadding = PaddingValues(horizontal = 16.dp, vertical = 12.dp),
                            verticalArrangement = Arrangement.spacedBy(14.dp)
                        ) {
                            if (richComments.size > visibleCommentsLimit) {
                                item {
                                    Box(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .padding(vertical = 4.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        androidx.compose.material3.TextButton(
                                            onClick = {
                                                visibleCommentsLimit += 5
                                            }
                                        ) {
                                            Row(
                                                verticalAlignment = Alignment.CenterVertically,
                                                horizontalArrangement = Arrangement.spacedBy(4.dp)
                                            ) {
                                                Icon(
                                                    imageVector = Icons.Default.Refresh,
                                                    contentDescription = "Load older comments",
                                                    tint = RazorTeal,
                                                    modifier = Modifier.size(14.dp)
                                                )
                                                Text(
                                                    text = "Load older comments (${richComments.size - visibleCommentsLimit} remaining)",
                                                    color = RazorTeal,
                                                    fontSize = 12.sp,
                                                    fontWeight = FontWeight.SemiBold
                                                )
                                            }
                                        }
                                    }
                                }
                            }

                            val commentsToShow = richComments.takeLast(visibleCommentsLimit)
                            items(commentsToShow.size) { index ->
                                val comment = commentsToShow[index]
                                Column(modifier = Modifier.fillMaxWidth()) {
                                    // Main Comment Row
                                    Row(
                                        modifier = Modifier.fillMaxWidth(),
                                        verticalAlignment = Alignment.Top
                                    ) {
                                        // User profile avatar
                                        AsyncImage(
                                            model = comment.userAvatar,
                                            contentDescription = comment.userName,
                                            modifier = Modifier
                                                .size(36.dp)
                                                .clip(CircleShape)
                                                .background(Color.White.copy(0.1f)),
                                            contentScale = ContentScale.Crop
                                        )
                                        Spacer(modifier = Modifier.width(8.dp))
                                        
                                        Column(modifier = Modifier.weight(1f)) {
                                            // Facebook-style Bubble
                                            Box(
                                                modifier = Modifier
                                                    .background(Color(0xFF130E29), RoundedCornerShape(16.dp))
                                                    .border(1.dp, Color.White.copy(alpha = 0.05f), RoundedCornerShape(16.dp))
                                                    .padding(horizontal = 12.dp, vertical = 8.dp)
                                            ) {
                                                Column {
                                                    Text(
                                                        text = comment.userName,
                                                        color = RazorTeal,
                                                        fontSize = 12.sp,
                                                        fontWeight = FontWeight.Bold
                                                    )
                                                    Spacer(modifier = Modifier.height(2.dp))
                                                    Text(
                                                        text = comment.text,
                                                        color = Color.White.copy(0.95f),
                                                        fontSize = 13.sp
                                                    )
                                                }
                                                
                                                // Floating Facebook-style like indicator badge
                                                if (comment.likesCount > 0) {
                                                    Row(
                                                        modifier = Modifier
                                                            .align(Alignment.BottomEnd)
                                                            .offset(x = 6.dp, y = 14.dp)
                                                            .background(Color(0xFF0F0B21), RoundedCornerShape(10.dp))
                                                            .border(1.dp, RazorBlue.copy(0.3f), RoundedCornerShape(10.dp))
                                                            .padding(horizontal = 6.dp, vertical = 2.dp),
                                                        verticalAlignment = Alignment.CenterVertically
                                                    ) {
                                                        Text("👍", fontSize = 10.sp)
                                                        Spacer(modifier = Modifier.width(2.dp))
                                                        Text(
                                                            text = "${comment.likesCount}",
                                                            color = RazorBlue,
                                                            fontSize = 9.sp,
                                                            fontWeight = FontWeight.Bold
                                                        )
                                                    }
                                                }
                                            }
                                            
                                            Spacer(modifier = Modifier.height(4.dp))
                                            
                                            // Actions Row: Like • Reply • Timestamp
                                            Row(
                                                modifier = Modifier.padding(start = 4.dp),
                                                verticalAlignment = Alignment.CenterVertically,
                                                horizontalArrangement = Arrangement.spacedBy(16.dp)
                                            ) {
                                                Text(
                                                    text = if (comment.isLiked) "Liked" else "Like",
                                                    color = if (comment.isLiked) RazorBlue else GrayText,
                                                    fontSize = 11.sp,
                                                    fontWeight = FontWeight.Bold,
                                                    modifier = Modifier.clickable {
                                                        comment.isLiked = !comment.isLiked
                                                        comment.likesCount += if (comment.isLiked) 1 else -1
                                                    }
                                                )
                                                
                                                Text(
                                                    text = "Reply",
                                                    color = GrayText,
                                                    fontSize = 11.sp,
                                                    fontWeight = FontWeight.Bold,
                                                    modifier = Modifier.clickable {
                                                        replyingToComment = comment
                                                        newCommentText = "@${comment.userName} "
                                                    }
                                                )
                                                
                                                Text(
                                                    text = comment.timestamp,
                                                    color = GrayText.copy(alpha = 0.6f),
                                                    fontSize = 11.sp
                                                )
                                            }
                                        }
                                    }
                                    
                                    // Nested Sub-replies (Facebook-style threaded)
                                    if (comment.replies.isNotEmpty()) {
                                        Spacer(modifier = Modifier.height(8.dp))
                                        comment.replies.forEach { reply ->
                                            Row(
                                                modifier = Modifier
                                                    .fillMaxWidth()
                                                    .padding(start = 44.dp, top = 6.dp),
                                                verticalAlignment = Alignment.Top
                                            ) {
                                                AsyncImage(
                                                    model = reply.userAvatar,
                                                    contentDescription = reply.userName,
                                                    modifier = Modifier
                                                        .size(28.dp)
                                                        .clip(CircleShape)
                                                        .background(Color.White.copy(0.1f)),
                                                    contentScale = ContentScale.Crop
                                                )
                                                Spacer(modifier = Modifier.width(8.dp))
                                                Column {
                                                    Box(
                                                        modifier = Modifier
                                                            .background(Color(0xFF130E29).copy(alpha = 0.7f), RoundedCornerShape(14.dp))
                                                            .border(1.dp, Color.White.copy(alpha = 0.03f), RoundedCornerShape(14.dp))
                                                            .padding(horizontal = 10.dp, vertical = 6.dp)
                                                    ) {
                                                        Column {
                                                            Text(
                                                                text = reply.userName,
                                                                color = RazorTeal,
                                                                fontSize = 11.sp,
                                                                fontWeight = FontWeight.Bold
                                                            )
                                                            Spacer(modifier = Modifier.height(2.dp))
                                                            Text(
                                                                text = reply.text,
                                                                color = Color.White.copy(0.9f),
                                                                fontSize = 12.sp
                                                            )
                                                        }
                                                    }
                                                    
                                                    Spacer(modifier = Modifier.height(2.dp))
                                                    
                                                    Row(
                                                        modifier = Modifier.padding(start = 4.dp),
                                                        verticalAlignment = Alignment.CenterVertically,
                                                        horizontalArrangement = Arrangement.spacedBy(12.dp)
                                                    ) {
                                                        Text(
                                                            text = if (reply.isLiked) "Liked" else "Like",
                                                            color = if (reply.isLiked) RazorBlue else GrayText,
                                                            fontSize = 10.sp,
                                                            fontWeight = FontWeight.Bold,
                                                            modifier = Modifier.clickable {
                                                                reply.isLiked = !reply.isLiked
                                                                reply.likesCount += if (reply.isLiked) 1 else -1
                                                            }
                                                        )
                                                        Text(
                                                            text = reply.timestamp,
                                                            color = GrayText.copy(alpha = 0.5f),
                                                            fontSize = 10.sp
                                                        )
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                androidx.compose.material3.HorizontalDivider(
                    color = Color.White.copy(0.08f),
                    thickness = 1.dp
                )

                // Sticky replying info bar if active
                if (replyingToComment != null) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(RazorBlue.copy(0.12f))
                            .padding(horizontal = 16.dp, vertical = 8.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = "Replying to ${replyingToComment?.userName}",
                            color = RazorBlue,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Text(
                            text = "Cancel",
                            color = InstaPink,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold,
                            modifier = Modifier
                                .clickable {
                                    replyingToComment = null
                                    if (newCommentText.startsWith("@")) {
                                        newCommentText = ""
                                    }
                                }
                                .padding(horizontal = 8.dp, vertical = 2.dp)
                        )
                    }
                    androidx.compose.material3.HorizontalDivider(
                        color = Color.White.copy(0.08f),
                        thickness = 1.dp
                    )
                }

                // Quick Reaction Bar directly above text entry (Facebook style)
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color(0xFF0F0B21))
                        .horizontalScroll(rememberScrollState())
                        .padding(horizontal = 16.dp, vertical = 8.dp),
                    horizontalArrangement = Arrangement.spacedBy(16.dp, Alignment.CenterHorizontally),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    listOf("👍", "❤️", "😂", "😮", "😢", "🔥", "👏", "🙌").forEach { emoji ->
                        Text(
                            text = emoji,
                            fontSize = 22.sp,
                            modifier = Modifier
                                .clickable {
                                    val replyTo = replyingToComment
                                    if (replyTo != null) {
                                        val idx = richComments.indexOfFirst { it.id == replyTo.id }
                                        if (idx != -1) {
                                            richComments[idx].replies.add(
                                                FacebookCommentReply(
                                                    id = "reply_${System.currentTimeMillis()}",
                                                    userName = "You",
                                                    userAvatar = "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=150",
                                                    text = emoji,
                                                    timestamp = "Just now"
                                                )
                                            )
                                        }
                                        replyingToComment = null
                                    } else {
                                        onAddComment(emoji)
                                        richComments.add(
                                            FacebookComment(
                                                id = "comment_${System.currentTimeMillis()}",
                                                userName = "You",
                                                userHandle = "current_user",
                                                userAvatar = "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=150",
                                                text = emoji,
                                                timestamp = "Just now",
                                                likesCount = 0,
                                                isLiked = false
                                            )
                                        )
                                    }
                                }
                                .padding(4.dp)
                        )
                    }
                }

                // Comment Text Input Bar
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color(0xFF0C081A))
                ) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(horizontal = 14.dp)
                            .padding(top = 12.dp, bottom = 48.dp), // Elevated bottom padding to safely clear system navigation gestures and pills
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        // Current User Avatar placeholder
                        AsyncImage(
                            model = "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=150",
                            contentDescription = "My avatar",
                            modifier = Modifier
                                .size(34.dp)
                                .clip(CircleShape)
                                .background(Color.White.copy(0.1f)),
                            contentScale = ContentScale.Crop
                        )
                        Spacer(modifier = Modifier.width(10.dp))
                        
                        Row(
                            modifier = Modifier
                                .weight(1f)
                                .background(Color(0xFF130E29), RoundedCornerShape(22.dp))
                                .border(1.dp, Color.White.copy(0.1f), RoundedCornerShape(22.dp))
                                .padding(horizontal = 14.dp, vertical = 4.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            androidx.compose.foundation.text.BasicTextField(
                                value = newCommentText,
                                onValueChange = { newCommentText = it },
                                textStyle = MaterialTheme.typography.bodyMedium.copy(color = Color.White),
                                modifier = Modifier
                                    .weight(1f)
                                    .padding(vertical = 8.dp),
                                decorationBox = { innerTextField ->
                                    if (newCommentText.isEmpty()) {
                                        Text("Write a public comment...", color = GrayText, fontSize = 13.sp)
                                    }
                                    innerTextField()
                                }
                            )
                            
                            Spacer(modifier = Modifier.width(4.dp))
                            
                            val quickEmojis = listOf("❤️", "🔥", "😂")
                            quickEmojis.forEach { emoji ->
                                Text(
                                    text = emoji,
                                    fontSize = 18.sp,
                                    modifier = Modifier
                                        .padding(horizontal = 4.dp)
                                        .clickable { newCommentText += emoji }
                                )
                            }
                        }
                        
                        Spacer(modifier = Modifier.width(8.dp))
                        
                        IconButton(
                            onClick = {
                                if (newCommentText.isNotBlank()) {
                                    val textToSend = newCommentText
                                    val replyTo = replyingToComment
                                    
                                    if (replyTo != null) {
                                        val idx = richComments.indexOfFirst { it.id == replyTo.id }
                                        if (idx != -1) {
                                            richComments[idx].replies.add(
                                                FacebookCommentReply(
                                                    id = "reply_${System.currentTimeMillis()}",
                                                    userName = "You",
                                                    userAvatar = "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=150",
                                                    text = textToSend,
                                                    timestamp = "Just now"
                                                )
                                            )
                                        }
                                        replyingToComment = null
                                    } else {
                                        onAddComment(textToSend)
                                        richComments.add(
                                            FacebookComment(
                                                id = "comment_${System.currentTimeMillis()}",
                                                userName = "You",
                                                userHandle = "current_user",
                                                userAvatar = "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=150",
                                                text = textToSend,
                                                timestamp = "Just now",
                                                likesCount = 0,
                                                isLiked = false
                                            )
                                        )
                                    }
                                    newCommentText = ""
                                }
                            },
                            modifier = Modifier.size(36.dp),
                            enabled = newCommentText.isNotBlank()
                        ) {
                            Icon(
                                imageVector = Icons.AutoMirrored.Filled.Send,
                                contentDescription = "Send comment",
                                tint = if (newCommentText.isNotBlank()) RazorTeal else GrayText,
                                modifier = Modifier.size(20.dp)
                            )
                        }
                    }
                }
            }
        }
    }
}

// =========================================================================
// PREMIUM GOOGLE SEARCH TRENDING TOPICS COMPOSABLE (Jetpack Compose / M3)
// =========================================================================
@Composable
fun TrendingTopicsCard(
    topics: List<String>,
    isFetching: Boolean,
    selectedInsight: String?,
    isGenerating: Boolean,
    onTopicClick: (String) -> Unit,
    onGenerateInsight: (String) -> Unit,
    onClearInsight: () -> Unit,
    onRefresh: () -> Unit
) {
    var activeTopic by remember { mutableStateOf<String?>(null) }

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 14.dp, vertical = 6.dp),
        colors = CardDefaults.cardColors(containerColor = Color(0x0EFFFFFF)),
        shape = RoundedCornerShape(16.dp),
        border = BorderStroke(1.dp, Color.White.copy(alpha = 0.08f))
    ) {
        Column(modifier = Modifier.padding(14.dp)) {
            // Header Row
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Row(verticalAlignment = Alignment.CenterVertically) {
                    // Pulsing Search Dot
                    Box(
                        modifier = Modifier
                            .size(8.dp)
                            .background(RazorTeal, CircleShape)
                    )
                    Spacer(modifier = Modifier.width(8.dp))
                    Text(
                        text = "LIVE GOOGLE SEARCH TRENDS",
                        color = Color.White,
                        fontWeight = FontWeight.Black,
                        fontSize = 11.sp,
                        letterSpacing = 0.6.sp
                    )
                }
                
                IconButton(
                    onClick = {
                        onRefresh()
                        activeTopic = null
                        onClearInsight()
                    },
                    modifier = Modifier.size(24.dp)
                ) {
                    Icon(
                        imageVector = Icons.Default.Refresh,
                        contentDescription = "Sync Search Tags",
                        tint = RazorTeal.copy(alpha = 0.8f),
                        modifier = Modifier.size(14.dp)
                    )
                }
            }

            Spacer(modifier = Modifier.height(10.dp))

            if (isFetching) {
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 12.dp),
                    horizontalArrangement = Arrangement.Center,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    CircularProgressIndicator(
                        color = RazorBlue,
                        strokeWidth = 2.dp,
                        modifier = Modifier.size(16.dp)
                    )
                    Spacer(modifier = Modifier.width(8.dp))
                    Text("Fetching trends...", color = GrayText, fontSize = 11.sp)
                }
            } else {
                LazyRow(
                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    items(topics) { topic ->
                        val isSelected = activeTopic == topic
                        val chipBg = if (isSelected) {
                            Brush.linearGradient(colors = listOf(RazorBlue.copy(alpha = 0.3f), InstaPink.copy(alpha = 0.3f)))
                        } else {
                            Brush.linearGradient(colors = listOf(Color(0x13FFFFFF), Color(0x13FFFFFF)))
                        }
                        val chipBorderColor = if (isSelected) RazorBlue else Color.White.copy(alpha = 0.08f)

                        Box(
                            modifier = Modifier
                                .clip(RoundedCornerShape(12.dp))
                                .background(chipBg)
                                .border(1.dp, chipBorderColor, RoundedCornerShape(12.dp))
                                .clickable {
                                    if (activeTopic == topic) {
                                        activeTopic = null
                                        onClearInsight()
                                    } else {
                                        activeTopic = topic
                                        onGenerateInsight(topic)
                                    }
                                }
                                .padding(horizontal = 12.dp, vertical = 8.dp)
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(
                                    imageVector = Icons.AutoMirrored.Filled.TrendingUp,
                                    contentDescription = null,
                                    tint = if (isSelected) RazorTeal else RazorBlue,
                                    modifier = Modifier.size(12.dp)
                                )
                                Spacer(modifier = Modifier.width(6.dp))
                                Text(
                                    text = topic,
                                    color = if (isSelected) Color.White else LightText,
                                    fontWeight = FontWeight.Bold,
                                    fontSize = 11.sp
                                )
                            }
                        }
                    }
                }
            }

            // Expanded Insight Panel based on google search trends
            if (activeTopic != null) {
                Spacer(modifier = Modifier.height(12.dp))
                
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clip(RoundedCornerShape(12.dp))
                        .background(Color(0x0BFFFFFF))
                        .border(1.dp, Color.White.copy(alpha = 0.05f), RoundedCornerShape(12.dp))
                        .padding(12.dp)
                ) {
                    Column(modifier = Modifier.fillMaxWidth()) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(
                                    imageVector = Icons.Default.Lightbulb,
                                    contentDescription = "Insights",
                                    tint = SafeGold,
                                    modifier = Modifier.size(14.dp)
                                )
                                Spacer(modifier = Modifier.width(6.dp))
                                Text(
                                    text = "Google Search Insight: $activeTopic",
                                    color = SafeGold,
                                    fontWeight = FontWeight.Bold,
                                    fontSize = 11.sp
                                )
                            }

                            // Filter Feed Button
                            TextButton(
                                onClick = { onTopicClick(activeTopic!!) },
                                contentPadding = PaddingValues(0.dp),
                                modifier = Modifier.height(24.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Icon(
                                        imageVector = Icons.Default.Search,
                                        contentDescription = "Search category",
                                        tint = RazorTeal,
                                        modifier = Modifier.size(12.dp)
                                    )
                                    Spacer(modifier = Modifier.width(4.dp))
                                    Text("Filter Feed", color = RazorTeal, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }

                        Spacer(modifier = Modifier.height(6.dp))

                        if (isGenerating) {
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(vertical = 8.dp),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.Center
                            ) {
                                CircularProgressIndicator(
                                    color = RazorTeal,
                                    strokeWidth = 2.dp,
                                    modifier = Modifier.size(14.dp)
                                )
                                Spacer(modifier = Modifier.width(8.dp))
                                Text(
                                    text = "Synching telemetry logs...",
                                    color = GrayText,
                                    fontSize = 11.sp
                                )
                            }
                        } else if (selectedInsight != null) {
                            Text(
                                text = selectedInsight,
                                color = LightText,
                                fontSize = 12.sp,
                                lineHeight = 18.sp,
                                style = MaterialTheme.typography.bodyMedium
                            )
                        }
                    }
                }
            }
        }
    }
}

// =========================================================================
// GLOBAL SEARCH RESULTS PANEL (Jetpack Compose / M3)
// =========================================================================
@Composable
fun GlobalSearchResultsPanel(
    creators: List<Creator>,
    posts: List<Post>,
    onCreatorClick: (String) -> Unit,
    onPostClick: (String) -> Unit,
    modifier: Modifier = Modifier
) {
    var selectedSearchTab by remember { mutableStateOf(0) } // 0 = Accounts, 1 = Posts

    Card(
        modifier = modifier
            .fillMaxWidth()
            .padding(14.dp),
        shape = RoundedCornerShape(24.dp),
        colors = CardDefaults.cardColors(containerColor = ObsidianDark),
        border = BorderStroke(1.2.dp, RazorBlue.copy(alpha = 0.4f))
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp)
        ) {
            // Header Row
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                modifier = Modifier.padding(bottom = 12.dp)
            ) {
                Icon(
                    imageVector = Icons.Default.Search,
                    contentDescription = null,
                    tint = RazorTeal,
                    modifier = Modifier.size(20.dp)
                )
                Text(
                    text = "UNIFIED HUB SEARCH",
                    color = RazorTeal,
                    fontSize = 12.sp,
                    fontWeight = FontWeight.Black,
                    fontFamily = FontFamily.Monospace,
                    letterSpacing = 1.2.sp
                )
            }

            // Tab selection pills
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(bottom = 12.dp),
                horizontalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                // Accounts Tab Pill
                Box(
                    modifier = Modifier
                        .weight(1f)
                        .clip(RoundedCornerShape(12.dp))
                        .background(if (selectedSearchTab == 0) RazorBlue.copy(alpha = 0.15f) else Color.White.copy(alpha = 0.04f))
                        .border(1.dp, if (selectedSearchTab == 0) RazorBlue else Color.White.copy(alpha = 0.08f), RoundedCornerShape(12.dp))
                        .clickable { selectedSearchTab = 0 }
                        .padding(vertical = 10.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = "Accounts (${creators.size})",
                        color = if (selectedSearchTab == 0) RazorBlue else LightText,
                        fontWeight = FontWeight.Bold,
                        fontSize = 11.5.sp
                    )
                }

                // Posts Tab Pill
                Box(
                    modifier = Modifier
                        .weight(1f)
                        .clip(RoundedCornerShape(12.dp))
                        .background(if (selectedSearchTab == 1) RazorTeal.copy(alpha = 0.15f) else Color.White.copy(alpha = 0.04f))
                        .border(1.dp, if (selectedSearchTab == 1) RazorTeal else Color.White.copy(alpha = 0.08f), RoundedCornerShape(12.dp))
                        .clickable { selectedSearchTab = 1 }
                        .padding(vertical = 10.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = "Feed Posts (${posts.size})",
                        color = if (selectedSearchTab == 1) RazorTeal else LightText,
                        fontWeight = FontWeight.Bold,
                        fontSize = 11.5.sp
                    )
                }
            }

            if (selectedSearchTab == 0) {
                // Accounts list
                if (creators.isEmpty()) {
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 32.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            Icon(
                                imageVector = Icons.Default.AccountCircle,
                                contentDescription = "No Accounts",
                                tint = GrayText,
                                modifier = Modifier.size(36.dp)
                            )
                            Spacer(modifier = Modifier.height(8.dp))
                            Text("No matching creators found", color = GrayText, fontSize = 12.sp)
                        }
                    }
                } else {
                    androidx.compose.foundation.lazy.LazyColumn(
                        modifier = Modifier
                            .fillMaxWidth()
                            .heightIn(max = 240.dp),
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        items(creators) { creator ->
                            val itemInteractionSource = remember { androidx.compose.foundation.interaction.MutableInteractionSource() }
                            val isItemHovered by itemInteractionSource.collectIsHoveredAsState()
                            val itemScale by androidx.compose.animation.core.animateFloatAsState(
                                targetValue = if (isItemHovered) 1.04f else 1f,
                                animationSpec = androidx.compose.animation.core.spring(dampingRatio = androidx.compose.animation.core.Spring.DampingRatioMediumBouncy, stiffness = androidx.compose.animation.core.Spring.StiffnessLow),
                                label = "itemScale"
                            )
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .scale(itemScale)
                                    .hoverable(itemInteractionSource)
                                    .clip(RoundedCornerShape(12.dp))
                                    .background(Color.White.copy(alpha = 0.04f))
                                    .clickable { onCreatorClick(creator.id) }
                                    .padding(12.dp),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(12.dp),
                                    modifier = Modifier.weight(1f)
                                ) {
                                    Box(
                                        modifier = Modifier
                                            .size(40.dp)
                                            .clip(CircleShape)
                                            .background(RazorBlue),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(
                                            text = creator.name.take(1).uppercase(),
                                            color = Color.Black,
                                            fontWeight = FontWeight.Bold,
                                            fontSize = 16.sp
                                        )
                                    }

                                    Column {
                                        Row(verticalAlignment = Alignment.CenterVertically) {
                                            Text(
                                                text = creator.name,
                                                color = Color.White,
                                                fontWeight = FontWeight.Bold,
                                                fontSize = 14.sp
                                            )
                                            if (creator.isVerified) {
                                                Spacer(modifier = Modifier.width(4.dp))
                                                Icon(
                                                    imageVector = Icons.Default.CheckCircle,
                                                    contentDescription = "Verified",
                                                    tint = RazorTeal,
                                                    modifier = Modifier.size(14.dp)
                                                )
                                            }
                                        }
                                        Text(
                                            text = "@${creator.handle}",
                                            color = GrayText,
                                            fontSize = 12.sp,
                                            fontFamily = FontFamily.Monospace
                                        )
                                    }
                                }

                                Icon(
                                    imageVector = Icons.AutoMirrored.Filled.ArrowForward,
                                    contentDescription = "View Profile",
                                    tint = RazorTeal,
                                    modifier = Modifier.size(18.dp)
                                )
                            }
                        }
                    }
                }
            } else {
                // Posts list
                if (posts.isEmpty()) {
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 32.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            Icon(
                                imageVector = Icons.AutoMirrored.Filled.Feed,
                                contentDescription = "No Posts",
                                tint = GrayText,
                                modifier = Modifier.size(36.dp)
                            )
                            Spacer(modifier = Modifier.height(8.dp))
                            Text("No matching posts found", color = GrayText, fontSize = 12.sp)
                        }
                    }
                } else {
                    androidx.compose.foundation.lazy.LazyColumn(
                        modifier = Modifier
                            .fillMaxWidth()
                            .heightIn(max = 240.dp),
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        items(posts) { post ->
                            val itemInteractionSource = remember { androidx.compose.foundation.interaction.MutableInteractionSource() }
                            val isItemHovered by itemInteractionSource.collectIsHoveredAsState()
                            val itemScale by androidx.compose.animation.core.animateFloatAsState(
                                targetValue = if (isItemHovered) 1.02f else 1f,
                                animationSpec = androidx.compose.animation.core.spring(dampingRatio = androidx.compose.animation.core.Spring.DampingRatioMediumBouncy, stiffness = androidx.compose.animation.core.Spring.StiffnessLow),
                                label = "itemScale"
                            )
                            Column(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .scale(itemScale)
                                    .hoverable(itemInteractionSource)
                                    .clip(RoundedCornerShape(12.dp))
                                    .background(Color.White.copy(alpha = 0.04f))
                                    .clickable { onPostClick(post.creatorId) }
                                    .padding(12.dp)
                            ) {
                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                                ) {
                                    Box(
                                        modifier = Modifier
                                            .size(24.dp)
                                            .clip(CircleShape)
                                            .background(RazorTeal),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(
                                            text = post.creatorName.take(1).uppercase(),
                                            color = Color.Black,
                                            fontWeight = FontWeight.Bold,
                                            fontSize = 11.sp
                                        )
                                    }
                                    Text(
                                        text = post.creatorName,
                                        color = Color.White,
                                        fontWeight = FontWeight.Bold,
                                        fontSize = 13.sp
                                    )
                                    Text(
                                        text = "@${post.creatorHandle}",
                                        color = RazorTeal,
                                        fontSize = 11.sp,
                                        fontFamily = FontFamily.Monospace
                                    )
                                }

                                Spacer(modifier = Modifier.height(6.dp))

                                Text(
                                    text = post.caption,
                                    color = LightText,
                                    fontSize = 12.sp,
                                    maxLines = 2,
                                    overflow = TextOverflow.Ellipsis
                                )

                                Spacer(modifier = Modifier.height(6.dp))

                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(14.dp)
                                ) {
                                    Row(verticalAlignment = Alignment.CenterVertically) {
                                        Icon(
                                            imageVector = Icons.Default.Favorite,
                                            contentDescription = "Likes",
                                            tint = Color(0xFFFF5252),
                                            modifier = Modifier.size(13.dp)
                                        )
                                        Spacer(modifier = Modifier.width(4.dp))
                                        Text(
                                            text = post.likesCount.toString(),
                                            color = GrayText,
                                            fontSize = 11.sp
                                        )
                                    }

                                    Row(verticalAlignment = Alignment.CenterVertically) {
                                        Icon(
                                            imageVector = Icons.Default.CheckCircle,
                                            contentDescription = "Tips",
                                            tint = RazorTeal,
                                            modifier = Modifier.size(13.dp)
                                        )
                                        Spacer(modifier = Modifier.width(4.dp))
                                        Text(
                                            text = "$${post.tipsTotal}",
                                            color = GrayText,
                                            fontSize = 11.sp
                                        )
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

