data class CreatorSnap(
    val id: String,
    val creatorId: String,
    val creatorName: String,
    val creatorHandle: String,
    val creatorAvatar: String,
    val imageUrl: String,
    val caption: String,
    val durationSeconds: Int = 10,
    val isPremium: Boolean = false,
    val requiredTier: String = "BRONZE",
    val likesCount: Int = 120
)

@Composable
fun CreatorSnapsGrid(
    snaps: List<CreatorSnap>,
    subscriptions: List<Subscription>,
    onSnapClick: (CreatorSnap) -> Unit
) {
    val chunkedSnaps = remember(snaps) { snaps.chunked(2) }

    Column(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 14.dp, vertical = 8.dp),
        verticalArrangement = Arrangement.spacedBy(10.dp)
    ) {
        chunkedSnaps.forEach { rowSnaps ->
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                rowSnaps.forEach { snap ->
                    Box(modifier = Modifier.weight(1f)) {
                        SnapCard(
                            snap = snap,
                            subscriptions = subscriptions,
                            onSnapClick = { onSnapClick(snap) }
                        )
                    }
                }
                if (rowSnaps.size < 2) {
                    Spacer(modifier = Modifier.weight(1f))
                }
            }
        }
    }
}

@Composable
fun SnapCard(
    snap: CreatorSnap,
    subscriptions: List<Subscription>,
    onSnapClick: () -> Unit
) {
    val hasSubscription = subscriptions.any {
        it.creatorId == snap.creatorId &&
        (it.tierName == "GOLD" || 
         (it.tierName == "SILVER" && snap.requiredTier != "GOLD") || 
         (it.tierName == "BRONZE" && snap.requiredTier == "BRONZE"))
    }
    val isLocked = false // Premium lock removed for stories/shots as requested

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .aspectRatio(0.68f)
            .clip(RoundedCornerShape(16.dp))
            .border(
                width = 1.dp,
                brush = Brush.linearGradient(
                    colors = if (isLocked) listOf(InstaPink.copy(alpha = 0.5f), Color.Transparent)
                            else listOf(RazorTeal.copy(alpha = 0.6f), RazorBlue.copy(alpha = 0.6f))
                ),
                shape = RoundedCornerShape(16.dp)
            )
            .bounceClick { onSnapClick() },
        colors = CardDefaults.cardColors(containerColor = Color(0xFF130E29))
    ) {
        Box(modifier = Modifier.fillMaxSize()) {
            AsyncImage(
                model = snap.imageUrl,
                contentDescription = "Snap preview",
                modifier = Modifier
                    .fillMaxSize()
                    .alpha(if (isLocked) 0.35f else 0.82f),
                contentScale = ContentScale.Crop
            )

            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .background(
                        Brush.verticalGradient(
                            colors = listOf(
                                Color.Black.copy(alpha = 0.35f),
                                Color.Black.copy(alpha = 0.85f)
                            )
                        )
                    )
            )

            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(8.dp)
                    .align(Alignment.TopStart),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(6.dp))
                        .background(if (isLocked) InstaPink else RazorTeal)
                        .padding(horizontal = 6.dp, vertical = 2.dp)
                ) {
                    Text(
                        text = if (isLocked) "PREMIUM" else "SNAP",
                        color = Color.Black,
                        fontSize = 8.sp,
                        fontWeight = FontWeight.Black,
                        letterSpacing = 0.5.sp
                    )
                }

                if (isLocked) {
                    Icon(
                        imageVector = Icons.Default.Lock,
                        contentDescription = "Locked Snap",
                        tint = InstaPink,
                        modifier = Modifier.size(14.dp)
                    )
                } else {
                    Row(
                        modifier = Modifier
                            .clip(RoundedCornerShape(6.dp))
                            .background(Color.Black.copy(0.4f))
                            .padding(horizontal = 6.dp, vertical = 4.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Icon(imageVector = Icons.Default.PlayArrow, contentDescription = null, tint = RazorTeal, modifier = Modifier.size(12.dp))
                    }
                }
            }

            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(10.dp)
                    .align(Alignment.BottomStart)
            ) {
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Box(
                        modifier = Modifier
                            .size(24.dp)
                            .clip(CircleShape)
                            .background(RazorBlue)
                            .border(1.dp, Color.White, CircleShape),
                        contentAlignment = Alignment.Center
                    ) {
                        if (snap.creatorAvatar.startsWith("http")) {
                            AsyncImage(
                                model = snap.creatorAvatar,
                                contentDescription = "Creator Avatar",
                                modifier = Modifier.fillMaxSize(),
                                contentScale = ContentScale.Crop
                            )
                        } else {
                            Text(
                                text = snap.creatorName.take(1).uppercase(),
                                color = Color.Black,
                                fontWeight = FontWeight.Bold,
                                fontSize = 10.sp
                            )
                        }
                    }
                    Spacer(modifier = Modifier.width(6.dp))
                    Text(
                        text = "@${snap.creatorHandle}",
                        color = Color.White,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold,
                        maxLines = 1,
                        overflow = TextOverflow.Ellipsis
                    )
                }
                Spacer(modifier = Modifier.height(4.dp))
                Text(
                    text = snap.caption,
                    color = LightText.copy(0.9f),
                    fontSize = 10.sp,
                    maxLines = 2,
                    overflow = TextOverflow.Ellipsis,
                    lineHeight = 13.sp
                )
            }
        }
    }
}

data class StoryMedia(
    val url: String,
    val isVideo: Boolean = false,
    val filter: String = "None",
    val sticker: String? = null
)

fun parseStoryMedia(serialized: String): List<StoryMedia> {
    if (serialized.isBlank()) return emptyList()
    
    // Check if it contains structured format indicators
    if (serialized.contains(",") || serialized.contains("|")) {
        return serialized.split(",").map { item ->
            val parts = item.split("|")
            val url = parts.getOrNull(0) ?: ""
            val isVideo = parts.getOrNull(1)?.toBoolean() ?: false
            val filter = parts.getOrNull(2) ?: "None"
            val sticker = parts.getOrNull(3)?.takeIf { it != "null" && it.isNotEmpty() }
            StoryMedia(url, isVideo, filter, sticker)
        }
    } else {
        // Fallback for legacy plain URLs
        val isMockVideo = serialized.contains("photo-1509198397868") || 
                          serialized.contains("photo-1492691527719") ||
                          serialized.contains("photo-1519608487953") ||
                          serialized.contains("photo-1538481199705")
        return listOf(
            StoryMedia(
                url = serialized,
                isVideo = isMockVideo,
                filter = "None",
                sticker = null
            )
        )
    }
}

@Composable
fun SnapPlaybackOverlay(
    snaps: List<CreatorSnap>,
    initialSnap: CreatorSnap,
    subscriptions: List<Subscription>,
    likedSnapIds: List<String> = emptyList(),
    onLikeToggle: (CreatorSnap, Boolean) -> Unit,
    onVisitProfile: (String) -> Unit,
    onDismiss: () -> Unit
) {
    var currentIndex by remember { mutableStateOf(snaps.indexOf(initialSnap).coerceAtLeast(0)) }
    val currentSnap = snaps.getOrNull(currentIndex) ?: initialSnap

    val hasSubscription = subscriptions.any {
        it.creatorId == currentSnap.creatorId &&
        (it.tierName == "GOLD" || 
         (it.tierName == "SILVER" && currentSnap.requiredTier != "GOLD") || 
         (it.tierName == "BRONZE" && currentSnap.requiredTier == "BRONZE"))
    }
    val isLocked = false // Premium lock removed for stories/shots as requested

    Dialog(
        onDismissRequest = onDismiss,
        properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = false)
    ) {
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color.Black.copy(alpha = 0.92f))
        ) {
            androidx.compose.foundation.layout.BoxWithConstraints(
                modifier = Modifier
                    .fillMaxSize()
                    .align(Alignment.Center)
            ) {
                val containerWidth = maxWidth
                val containerHeight = maxHeight

                // Calculate the optimal 9:16 aspect ratio size that will not exceed screen boundaries
                val calculatedWidth = containerHeight * (9f / 16f)
                val (finalWidth, finalHeight) = if (calculatedWidth <= containerWidth) {
                    calculatedWidth to containerHeight
                } else {
                    containerWidth to (containerWidth * (16f / 9f))
                }

                Box(
                    modifier = Modifier
                        .size(finalWidth, finalHeight)
                        .align(Alignment.Center)
                        .clip(RoundedCornerShape(16.dp))
                        .background(ObsidianDark)
                        .border(1.dp, Color.White.copy(alpha = 0.15f), RoundedCornerShape(16.dp))
                ) {
                if (isLocked) {
                    Column(
                        modifier = Modifier
                            .fillMaxSize()
                            .padding(24.dp),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.Center
                    ) {
                        Icon(
                            imageVector = Icons.Default.Lock,
                            contentDescription = "Premium lock",
                            tint = InstaPink,
                            modifier = Modifier.size(56.dp)
                        )
                        Spacer(modifier = Modifier.height(16.dp))
                        Text(
                            text = "Premium Snap Closed",
                            fontWeight = FontWeight.Black,
                            fontSize = 18.sp,
                            color = Color.White,
                            textAlign = TextAlign.Center
                        )
                        Spacer(modifier = Modifier.height(10.dp))
                        Text(
                            text = "This story requires a @${currentSnap.creatorHandle} ${currentSnap.requiredTier} access tier.",
                            textAlign = TextAlign.Center,
                            fontSize = 13.sp,
                            color = GrayText
                        )
                        Spacer(modifier = Modifier.height(24.dp))
                        Button(
                            onClick = { onVisitProfile(currentSnap.creatorId) },
                            colors = ButtonDefaults.buttonColors(containerColor = RazorTeal)
                        ) {
                            Text("Unlock on Profile", color = Color.Black, fontWeight = FontWeight.Bold)
                        }
                        Spacer(modifier = Modifier.height(12.dp))
                        TextButton(onClick = onDismiss) {
                            Text("Not Now", color = GrayText, fontWeight = FontWeight.Bold)
                        }
                    }
                } else {
                    // Multi-media carousel inside the current story snap
                    val storyItems = remember(currentSnap) { parseStoryMedia(currentSnap.imageUrl) }
                    var activeMediaIndex by remember(currentSnap) { mutableStateOf(0) }
                    val activeMedia = storyItems.getOrNull(activeMediaIndex) ?: StoryMedia(currentSnap.imageUrl)

                    var progress by remember(currentIndex, activeMediaIndex) { mutableStateOf(0f) }
                    var isPlayActive by remember { mutableStateOf(true) }
                    var isLikedLocal by remember(currentIndex, likedSnapIds.size) { mutableStateOf(likedSnapIds.contains(currentSnap.id)) }
                    var likesLocal by remember(currentIndex) { mutableStateOf(currentSnap.likesCount) }

                    var activeRealtimeLikeBy by remember(currentIndex) { mutableStateOf<String?>(null) }
                    var activeRealtimeLikeHandle by remember(currentIndex) { mutableStateOf<String?>(null) }

                    LaunchedEffect(isPlayActive, currentIndex, activeMediaIndex) {
                        if (isPlayActive) {
                            val durationSeconds = currentSnap.durationSeconds.coerceAtLeast(5)
                            val steps = durationSeconds * 20
                            val delayMs = 50L
                            
                            // Start a coroutine to trigger a real-time simulated story like after 2-4 seconds
                            val likeSimulationJob = kotlinx.coroutines.GlobalScope.launch(kotlinx.coroutines.Dispatchers.Main) {
                                delay(3000L + (500..1500).random().toLong())
                                if (isPlayActive) {
                                    val creatorsList = listOf(
                                        "Aura Rhythm" to "aura_beats",
                                        "Pixel Queen" to "pixel_q",
                                        "Alex Chen" to "chen_wealth",
                                        "ALX_FUTURE" to "future_alx",
                                        "Nexa Spark" to "nexa_spark",
                                        "Retro Glitch" to "retro_glitch"
                                    )
                                    val (name, handle) = creatorsList.random()
                                    activeRealtimeLikeBy = name
                                    activeRealtimeLikeHandle = handle
                                    likesLocal += 1
                                }
                            }

                            for (i in (progress * steps).toInt()..steps) {
                                delay(delayMs)
                                progress = i.toFloat() / steps
                            }
                            
                            likeSimulationJob.cancel()
                            
                            // Advance within active story or jump to next story
                            if (activeMediaIndex + 1 < storyItems.size) {
                                activeMediaIndex++
                            } else {
                                if (currentIndex + 1 < snaps.size) {
                                    currentIndex++
                                } else {
                                    onDismiss()
                                }
                            }
                        }
                    }

                    Box(
                        modifier = Modifier
                            .fillMaxSize()
                            .pointerInput(currentIndex, activeMediaIndex) {
                                detectTapGestures(
                                    onTap = { offset ->
                                        val width = size.width
                                        if (offset.x < width * 0.35f) {
                                            // Tap Left: Go to previous item or previous story
                                            if (activeMediaIndex > 0) {
                                                activeMediaIndex--
                                            } else if (currentIndex > 0) {
                                                currentIndex--
                                            } else {
                                                progress = 0f
                                            }
                                        } else {
                                            // Tap Right: Go to next item or next story
                                            if (activeMediaIndex + 1 < storyItems.size) {
                                                activeMediaIndex++
                                            } else if (currentIndex + 1 < snaps.size) {
                                                currentIndex++
                                            } else {
                                                onDismiss()
                                            }
                                        }
                                    },
                                    onLongPress = {
                                        isPlayActive = false
                                    },
                                    onPress = {
                                        tryAwaitRelease()
                                        isPlayActive = true
                                    }
                                )
                            }
                    ) {
                        Box(modifier = Modifier.fillMaxSize()) {
                            // Apply custom visual filters on the preview
                            val matrix = remember(activeMedia.filter) {
                                androidx.compose.ui.graphics.ColorMatrix().apply {
                                    if (activeMedia.filter == "Mono Cyber") {
                                        setToSaturation(0f)
                                    }
                                }
                            }

                            AsyncImage(
                                model = activeMedia.url,
                                contentDescription = "Active story snap",
                                modifier = Modifier.fillMaxSize(),
                                contentScale = ContentScale.Crop,
                                colorFilter = if (activeMedia.filter == "Mono Cyber") androidx.compose.ui.graphics.ColorFilter.colorMatrix(matrix) else null
                            )

                            // Tonal color filters
                            when (activeMedia.filter) {
                                "Cyber Neon" -> {
                                    Box(
                                        modifier = Modifier
                                            .fillMaxSize()
                                            .background(
                                                Brush.linearGradient(
                                                    colors = listOf(
                                                        Color(0xFFFF007F).copy(alpha = 0.22f),
                                                        Color(0xFF00F0FF).copy(alpha = 0.22f)
                                                    )
                                                )
                                            )
                                    )
                                }
                                "Glitch Vapor" -> {
                                    Box(
                                        modifier = Modifier
                                            .fillMaxSize()
                                            .background(
                                                Brush.radialGradient(
                                                    colors = listOf(
                                                        Color(0xFF8B008B).copy(alpha = 0.35f),
                                                        Color.Transparent
                                                    )
                                                )
                                            )
                                    )
                                }
                                "Aqua Haze" -> {
                                    Box(
                                        modifier = Modifier
                                            .fillMaxSize()
                                            .background(
                                                Brush.verticalGradient(
                                                    colors = listOf(
                                                        Color(0xFF00FFFF).copy(alpha = 0.18f),
                                                        Color(0xFF008080).copy(alpha = 0.15f)
                                                    )
                                                )
                                            )
                                    )
                                }
                                "Synthwave Sunset" -> {
                                    Box(
                                        modifier = Modifier
                                            .fillMaxSize()
                                            .background(
                                                Brush.linearGradient(
                                                    colors = listOf(
                                                        Color(0xFFFF5E36).copy(alpha = 0.22f),
                                                        Color(0xFFFF007F).copy(alpha = 0.22f)
                                                    )
                                                )
                                            )
                                    )
                                }
                                "Mono Cyber" -> {
                                    Box(
                                        modifier = Modifier
                                            .fillMaxSize()
                                            .border(3.dp, Color(0xFF39FF14).copy(alpha = 0.4f))
                                    )
                                }
                            }

                            // Dynamic Video badge
                            if (activeMedia.isVideo) {
                                Box(
                                    modifier = Modifier
                                        .align(Alignment.Center)
                                        .size(64.dp)
                                        .clip(CircleShape)
                                        .background(Color.Black.copy(0.35f)),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.PlayArrow,
                                        contentDescription = "Playing Video",
                                        tint = Color.White.copy(0.85f),
                                        modifier = Modifier.size(36.dp)
                                    )
                                }
                                
                                // Rotating digital tuner graphic bottom-right
                                Row(
                                    modifier = Modifier
                                        .align(Alignment.BottomEnd)
                                        .padding(bottom = 80.dp, end = 16.dp)
                                        .clip(RoundedCornerShape(8.dp))
                                        .background(Color.Black.copy(0.6f))
                                        .padding(horizontal = 8.dp, vertical = 4.dp),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                                ) {
                                    Icon(imageVector = Icons.AutoMirrored.Filled.VolumeUp, contentDescription = "Audio on", tint = RazorTeal, modifier = Modifier.size(12.dp))
                                    Text("STEREO AUDIO", color = RazorTeal, fontSize = 8.sp, fontWeight = FontWeight.Bold, fontFamily = FontFamily.Monospace)
                                }
                            }

                            // Interactive Sticker rendering
                            activeMedia.sticker?.let { sticker ->
                                Box(
                                    modifier = Modifier
                                        .align(Alignment.Center)
                                        .padding(bottom = 120.dp)
                                ) {
                                    when (sticker) {
                                        "LIVE 🔴" -> {
                                            Row(
                                                modifier = Modifier
                                                    .clip(RoundedCornerShape(8.dp))
                                                    .background(Color.Black.copy(alpha = 0.85f))
                                                    .border(1.2.dp, Color.Red, RoundedCornerShape(8.dp))
                                                    .padding(horizontal = 14.dp, vertical = 6.dp),
                                                verticalAlignment = Alignment.CenterVertically,
                                                horizontalArrangement = Arrangement.spacedBy(6.dp)
                                            ) {
                                                Box(
                                                    modifier = Modifier
                                                        .size(8.dp)
                                                        .clip(CircleShape)
                                                        .background(Color.Red)
                                                )
                                                Text(
                                                    text = "LIVE",
                                                    color = Color.White,
                                                    fontSize = 11.sp,
                                                    fontWeight = FontWeight.Black,
                                                    letterSpacing = 1.sp
                                                )
                                            }
                                        }
                                        "NEW SHOT 🔥" -> {
                                            Row(
                                                modifier = Modifier
                                                    .clip(RoundedCornerShape(8.dp))
                                                    .background(Brush.linearGradient(listOf(Color(0xFFFF5E36), Color(0xFFFF007F))))
                                                    .padding(horizontal = 14.dp, vertical = 6.dp),
                                                verticalAlignment = Alignment.CenterVertically,
                                                horizontalArrangement = Arrangement.spacedBy(6.dp)
