                                Spacer(modifier = Modifier.width(8.dp))
                                Column {
                                    Text(
                                        text = currentSnap.creatorName,
                                        color = Color.White,
                                        fontSize = 12.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                    Text(
                                        text = "@${currentSnap.creatorHandle}",
                                        color = RazorTeal,
                                        fontSize = 10.sp,
                                        fontWeight = FontWeight.SemiBold
                                    )
                                }
                            }

                            Row(verticalAlignment = Alignment.CenterVertically) {
                                if (storyItems.size > 1) {
                                    Box(
                                        modifier = Modifier
                                            .clip(RoundedCornerShape(6.dp))
                                            .background(Color.Black.copy(0.4f))
                                            .padding(horizontal = 6.dp, vertical = 2.dp)
                                    ) {
                                        Text("${activeMediaIndex + 1}/${storyItems.size}", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                    }
                                    Spacer(modifier = Modifier.width(8.dp))
                                }
                                if (!isPlayActive) {
                                    Box(
                                        modifier = Modifier
                                            .clip(RoundedCornerShape(6.dp))
                                            .background(Color.Black.copy(0.5f))
                                            .padding(horizontal = 6.dp, vertical = 2.dp)
                                    ) {
                                        Text("PAUSED", color = RazorTeal, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                    }
                                    Spacer(modifier = Modifier.width(6.dp))
                                }
                                IconButton(
                                    onClick = onDismiss,
                                    modifier = Modifier
                                        .size(28.dp)
                                        .background(Color.Black.copy(0.4f), CircleShape)
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Close,
                                        contentDescription = "Close snap story",
                                        tint = Color.White,
                                        modifier = Modifier.size(16.dp)
                                    )
                                }
                            }
                        }
                    }

                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .align(Alignment.BottomStart)
                            .padding(16.dp)
                    ) {
                        Text(
                            text = currentSnap.caption,
                            color = Color.White,
                            fontSize = 12.sp,
                            fontWeight = FontWeight.Bold,
                            lineHeight = 16.sp
                        )
                        Spacer(modifier = Modifier.height(14.dp))

                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.SpaceBetween
                        ) {
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                modifier = Modifier
                                    .clip(RoundedCornerShape(20.dp))
                                    .background(Color.Black.copy(alpha = 0.5f))
                                    .clickable {
                                        isLikedLocal = !isLikedLocal
                                        likesLocal += if (isLikedLocal) 1 else -1
                                        onLikeToggle(currentSnap, isLikedLocal)
                                    }
                                    .padding(horizontal = 12.dp, vertical = 6.dp)
                            ) {
                                Icon(
                                    imageVector = if (isLikedLocal) Icons.Default.Favorite else Icons.Default.FavoriteBorder,
                                    contentDescription = "Like story snap",
                                    tint = if (isLikedLocal) InstaPink else Color.White,
                                    modifier = Modifier.size(16.dp)
                                )
                                Spacer(modifier = Modifier.width(6.dp))
                                Text(
                                    text = "$likesLocal",
                                    color = Color.White,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }

                            Text(
                                text = "Tap left/right to browse",
                                color = LightText.copy(0.5f),
                                fontSize = 9.sp,
                                fontFamily = FontFamily.Monospace,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }

                    // Floating Real-Time Like Toast
                    androidx.compose.animation.AnimatedVisibility(
                        visible = activeRealtimeLikeBy != null,
                        enter = androidx.compose.animation.fadeIn() + androidx.compose.animation.slideInVertically(),
                        exit = androidx.compose.animation.fadeOut() + androidx.compose.animation.slideOutVertically(),
                        modifier = Modifier
                            .align(Alignment.BottomCenter)
                            .padding(bottom = 120.dp)
                            .padding(horizontal = 24.dp)
                    ) {
                        Row(
                            modifier = Modifier
                                .clip(RoundedCornerShape(16.dp))
                                .background(Color.Black.copy(alpha = 0.85f))
                                .border(1.2.dp, RazorTeal, RoundedCornerShape(16.dp))
                                .padding(horizontal = 14.dp, vertical = 10.dp),
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Default.Favorite,
                                contentDescription = "Real-Time Like",
                                tint = InstaPink,
                                modifier = Modifier.size(16.dp)
                            )
                            Column {
                                Text(
                                    text = "${activeRealtimeLikeBy} liked this story!",
                                    color = Color.White,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.Bold
                                )
                                Text(
                                    text = "@${activeRealtimeLikeHandle} • Just now",
                                    color = RazorTeal,
                                    fontSize = 9.sp,
                                    fontWeight = FontWeight.SemiBold
                                )
                            }
                        }
                    }
                }
            }
            }
        }
    }
}

@Composable
fun InstagramAdCard(
    sponsorName: String,
    sponsorAvatar: String,
    caption: String,
    imageUrl: String,
    ctaText: String,
    onDismissAd: () -> Unit,
    onCtaClick: () -> Unit,
    isInViewport: Boolean = true
) {
    var progress by remember { mutableStateOf(0f) }

    if (isInViewport) {
        val infiniteTransition = rememberInfiniteTransition(label = "ad_animation")
        val animatedProgress by infiniteTransition.animateFloat(
            initialValue = 0f,
            targetValue = 1f,
            animationSpec = infiniteRepeatable(
                animation = tween(durationMillis = 4000, easing = LinearEasing),
                repeatMode = RepeatMode.Restart
            ),
            label = "ad_progress"
        )
        progress = animatedProgress
    } else {
        progress = 0f
    }

    val scale = 1f + (progress * 0.05f) // Subtle Ken Burns zoom effect

    val interactionSource = remember { androidx.compose.foundation.interaction.MutableInteractionSource() }
    val isHovered by interactionSource.collectIsHoveredAsState()
    val hoverScale by androidx.compose.animation.core.animateFloatAsState(
        targetValue = if (isHovered) 1.02f else 1f,
        animationSpec = androidx.compose.animation.core.spring(dampingRatio = androidx.compose.animation.core.Spring.DampingRatioMediumBouncy, stiffness = androidx.compose.animation.core.Spring.StiffnessLow),
        label = "hoverScaleAd"
    )

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 14.dp, vertical = 8.dp)
            .scale(hoverScale)
            .hoverable(interactionSource),
        shape = RoundedCornerShape(24.dp),
        colors = CardDefaults.cardColors(containerColor = CardBackground),
        border = BorderStroke(1.dp, MinimalBorder)
    ) {
        Column(modifier = Modifier.fillMaxWidth()) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(14.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                // Circular Avatar
                Box(
                    modifier = Modifier
                        .size(44.dp)
                        .clip(CircleShape)
                        .background(
                            Brush.linearGradient(
                                colors = listOf(RazorBlue, InstaPink)
                            )
                        )
                        .padding(2.5.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Box(
                        modifier = Modifier
                            .fillMaxSize()
                            .clip(CircleShape)
                            .background(ObsidianDark),
                        contentAlignment = Alignment.Center
                    ) {
                        AsyncImage(
                            model = sponsorAvatar,
                            contentDescription = "Sponsor Avatar",
                            modifier = Modifier.fillMaxSize(),
                            contentScale = ContentScale.Crop
                        )
                    }
                }
                Spacer(modifier = Modifier.width(10.dp))
                Column {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Text(
                            text = sponsorName,
                            style = MaterialTheme.typography.titleMedium,
                            fontWeight = FontWeight.Bold,
                            color = LightText
                        )
                        Spacer(modifier = Modifier.width(6.dp))
                        Box(
                            modifier = Modifier
                                .background(RazorTeal.copy(alpha = 0.15f), RoundedCornerShape(4.dp))
                                .padding(horizontal = 4.dp, vertical = 2.dp)
                        ) {
                            Text("Ad", color = RazorTeal, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                        }
                    }
                    Text(
                        text = "Sponsored",
                        style = MaterialTheme.typography.bodySmall,
                        color = RazorTeal,
                        fontWeight = FontWeight.Bold
                    )
                }
                Spacer(modifier = Modifier.weight(1f))
                
                // Close button to not disturb user
                IconButton(onClick = onDismissAd) {
                    Icon(
                        imageVector = Icons.Default.Close,
                        contentDescription = "Hide Advertisement",
                        tint = GrayText,
                        modifier = Modifier.size(20.dp)
                    )
                }
            }

            // Ad Image
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .aspectRatio(1.25f)
                    .background(Color(0xFF130E22))
                    .clip(RoundedCornerShape(bottomStart = 0.dp, bottomEnd = 0.dp))
            ) {
                AsyncImage(
                    model = imageUrl,
                    contentDescription = "Sponsored Content Image",
                    modifier = Modifier
                        .fillMaxSize()
                        .graphicsLayer {
                            scaleX = scale
                            scaleY = scale
                        },
                    contentScale = ContentScale.Crop
                )
                
                // Overlay label
                Box(
                    modifier = Modifier
                        .align(Alignment.TopStart)
                        .padding(14.dp)
                        .clip(RoundedCornerShape(6.dp))
                        .background(Color.Black.copy(0.6f))
                        .padding(horizontal = 8.dp, vertical = 4.dp)
                ) {
                    Text("LIMITED CAMPAIGN", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Black)
                }

                // Auto-running linear progress tracker overlay at bottom of the ad image
                Box(
                    modifier = Modifier
                        .align(Alignment.BottomStart)
                        .fillMaxWidth()
                        .height(3.dp)
                        .background(Color.White.copy(alpha = 0.15f))
                ) {
                    Box(
                        modifier = Modifier
                            .fillMaxHeight()
                            .fillMaxWidth(progress)
                            .background(
                                Brush.horizontalGradient(
                                    colors = listOf(RazorTeal, InstaPink)
                                )
                            )
                    )
                }
            }

            // Full-width elegant Instagram-style CTA bar
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(RazorBlue)
                    .clickable { onCtaClick() }
                    .padding(horizontal = 14.dp, vertical = 12.dp),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween
            ) {
                Text(
                    text = ctaText,
                    color = Color.Black,
                    fontWeight = FontWeight.Black,
                    fontSize = 12.sp,
                    letterSpacing = 0.5.sp
                )
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Text(
                        text = "VISIT PAGE",
                        color = Color.Black.copy(0.7f),
                        fontSize = 10.sp,
                        fontWeight = FontWeight.Bold
                    )
                    Spacer(modifier = Modifier.width(4.dp))
                    Icon(
                        imageVector = Icons.AutoMirrored.Filled.ArrowForward,
                        contentDescription = "Visit sponsor site",
                        tint = Color.Black,
                        modifier = Modifier.size(14.dp)
                    )
                }
            }

            // Caption block
            Column(modifier = Modifier.padding(14.dp)) {
                Text(
                    text = buildAnnotatedString {
                        withStyle(style = SpanStyle(fontWeight = FontWeight.Bold, color = LightText)) {
                            append("$sponsorName ")
                        }
                        withStyle(style = SpanStyle(color = LightText)) {
                            append(caption)
                        }
                    },
                    style = MaterialTheme.typography.bodyMedium
                )
                Spacer(modifier = Modifier.height(8.dp))
                Text(
                    text = "SocialHub Verified Ad Partner • Secure Delivery",
                    color = GrayText,
                    fontSize = 10.sp,
                    fontWeight = FontWeight.Medium
                )
            }
        }
    }
}

