@Composable
fun SecurityGuardOverlay(onDismiss: () -> Unit) {
    var step by remember { mutableStateOf(0) }
    var logs by remember { mutableStateOf(listOf("Initializing Triple Layer Guard System...")) }
    
    LaunchedEffect(Unit) {
        kotlinx.coroutines.delay(800)
        logs = logs + "Layer 1: Network Firewall & HTTPS Enforcement [OK]"
        step = 1
        kotlinx.coroutines.delay(1000)
        logs = logs + "Layer 2: Local Encryption & Anti-Leakage Shield [OK]"
        step = 2
        kotlinx.coroutines.delay(1200)
        logs = logs + "Layer 3: Behavioral Threat Detection..."
        step = 3
        kotlinx.coroutines.delay(600)
        logs = logs + "[!] INTRUSION ATTEMPT DETECTED! [!]"
        step = 4
        kotlinx.coroutines.delay(800)
        logs = logs + ">> Locking potential vulnerabilities..."
        kotlinx.coroutines.delay(600)
        logs = logs + ">> Capture Lock Protocol Activated on Hacker IP"
        step = 5
        kotlinx.coroutines.delay(1500)
        logs = logs + "System Secure. Environment is 100% guarded."
        step = 6
        kotlinx.coroutines.delay(1000)
        onDismiss()
    }

    Dialog(
        onDismissRequest = {},
        properties = androidx.compose.ui.window.DialogProperties(
            usePlatformDefaultWidth = false,
            decorFitsSystemWindows = false
        )
    ) {
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color(0xE60A0A12))
                .systemBarsPadding()
                .padding(24.dp),
            contentAlignment = Alignment.Center
        ) {
            Column(
                horizontalAlignment = Alignment.CenterHorizontally,
                verticalArrangement = Arrangement.Center,
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0xFF1A1A24), RoundedCornerShape(24.dp))
                    .border(2.dp, if (step >= 4) Color(0xFFFF3B30) else RazorTeal, RoundedCornerShape(24.dp))
                    .padding(24.dp)
            ) {
                Icon(
                    imageVector = if (step >= 4 && step < 6) Icons.Default.Warning else Icons.Default.Security,
                    contentDescription = "Security Shield",
                    tint = if (step >= 4 && step < 6) Color(0xFFFF3B30) else RazorTeal,
                    modifier = Modifier.size(64.dp)
                )
                
                Spacer(modifier = Modifier.height(16.dp))
                
                Text(
                    text = if (step >= 6) "SYSTEM SECURE" else if (step >= 4) "THREAT DETECTED" else "TRIPLE LAYER GUARD",
                    color = if (step >= 4 && step < 6) Color(0xFFFF3B30) else Color.White,
                    fontWeight = FontWeight.Black,
                    fontSize = 20.sp
                )
                
                Spacer(modifier = Modifier.height(24.dp))
                
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(200.dp)
                        .background(Color.Black, RoundedCornerShape(8.dp))
                        .border(1.dp, Color.White.copy(0.1f), RoundedCornerShape(8.dp))
                        .padding(12.dp)
                        .verticalScroll(rememberScrollState())
                ) {
                    logs.forEach { logText ->
                        Text(
                            text = logText,
                            color = if (logText.contains("INTRUSION")) Color(0xFFFF3B30) else if (logText.contains("Secure")) RazorTeal else Color(0xFF00FF00),
                            fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace,
                            fontSize = 11.sp,
                            modifier = Modifier.padding(bottom = 4.dp)
                        )
                    }
                }
                
                if (step >= 6) {
                    Spacer(modifier = Modifier.height(16.dp))
                    Button(
                        onClick = onDismiss,
                        colors = ButtonDefaults.buttonColors(containerColor = RazorTeal)
                    ) {
                        Text("Enter Secured App", color = Color.Black)
                    }
                } else {
                    Spacer(modifier = Modifier.height(16.dp))
                    androidx.compose.material3.CircularProgressIndicator(
                        color = if (step >= 4) Color(0xFFFF3B30) else RazorTeal,
                        modifier = Modifier.size(24.dp),
                        strokeWidth = 2.dp
                    )
                }
            }
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun NotificationCenterDialog(
    viewModel: SocialHubViewModel,
    onDismiss: () -> Unit
) {
    val notifications by viewModel.notificationsList.collectAsStateWithLifecycle()
    val pushEnabled by viewModel.pushNotificationsEnabled.collectAsStateWithLifecycle()
    val soundEnabled by viewModel.soundEnabled.collectAsStateWithLifecycle()
    val vibrateEnabled by viewModel.vibrationEnabled.collectAsStateWithLifecycle()
    val walletAlerts by viewModel.walletAlertsEnabled.collectAsStateWithLifecycle()
    val creatorAlerts by viewModel.creatorAlertsEnabled.collectAsStateWithLifecycle()
    val chatAlerts by viewModel.chatAlertsEnabled.collectAsStateWithLifecycle()
    val watchdogStatus by viewModel.watchdogStatus.collectAsStateWithLifecycle()

    val context = androidx.compose.ui.platform.LocalContext.current

    var activeTab by remember { mutableStateOf(0) } // 0: Notifications, 1: Settings

    androidx.compose.ui.window.Dialog(
        onDismissRequest = onDismiss,
        properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = false)
    ) {
        Surface(
            modifier = Modifier.fillMaxSize(),
            color = SolidObsidianDark
        ) {
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .windowInsetsPadding(WindowInsets.statusBars)
            ) {
                // HEADER ROW
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 16.dp, vertical = 12.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    IconButton(onClick = onDismiss) {
                        Icon(imageVector = Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back", tint = Color.White)
                    }
                    Text(
                        text = "NOTIFICATION CENTER",
                        color = RazorBlue,
                        fontWeight = FontWeight.Black,
                        fontSize = 16.sp,
                        letterSpacing = 1.2.sp
                    )
                    IconButton(onClick = { viewModel.clearAllNotifications() }) {
                        Icon(imageVector = Icons.Default.Delete, contentDescription = "Clear All", tint = Color.White.copy(0.6f))
                    }
                }

                // SUB-TAB CONTROLS
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 24.dp, vertical = 8.dp)
                        .background(Color.White.copy(alpha = 0.04f), RoundedCornerShape(12.dp))
                        .padding(4.dp)
                ) {
                    Box(
                        modifier = Modifier
                            .weight(1f)
                            .clip(RoundedCornerShape(8.dp))
                            .background(if (activeTab == 0) RazorBlue.copy(alpha = 0.15f) else Color.Transparent)
                            .border(if (activeTab == 0) BorderStroke(1.dp, RazorBlue) else BorderStroke(0.dp, Color.Transparent), RoundedCornerShape(8.dp))
                            .clickable { activeTab = 0 }
                            .padding(vertical = 10.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = "NOTIFICATIONS",
                            color = if (activeTab == 0) Color.White else Color.White.copy(0.6f),
                            fontWeight = FontWeight.Bold,
                            fontSize = 12.sp,
                            letterSpacing = 0.5.sp
                        )
                    }
                    Box(
                        modifier = Modifier
                            .weight(1f)
                            .clip(RoundedCornerShape(8.dp))
                            .background(if (activeTab == 1) RazorBlue.copy(alpha = 0.15f) else Color.Transparent)
                            .border(if (activeTab == 1) BorderStroke(1.dp, RazorBlue) else BorderStroke(0.dp, Color.Transparent), RoundedCornerShape(8.dp))
                            .clickable { activeTab = 1 }
                            .padding(vertical = 10.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = "ALERT SETTINGS",
                            color = if (activeTab == 1) Color.White else Color.White.copy(0.6f),
                            fontWeight = FontWeight.Bold,
                            fontSize = 12.sp,
                            letterSpacing = 0.5.sp
                        )
                    }
                }

                Spacer(modifier = Modifier.height(12.dp))

                if (activeTab == 0) {
                    // TAB 0: NOTIFICATIONS FEED
                    if (notifications.isEmpty()) {
                        Column(
                            modifier = Modifier
                                .fillMaxWidth()
                                .weight(1f)
                                .padding(32.dp),
                            horizontalAlignment = Alignment.CenterHorizontally,
                            verticalArrangement = Arrangement.Center
                        ) {
                            Icon(
                                imageVector = Icons.Default.Notifications,
                                contentDescription = "Empty",
                                tint = Color.White.copy(0.2f),
                                modifier = Modifier.size(72.dp)
                            )
                            Spacer(modifier = Modifier.height(16.dp))
                            Text(
                                text = "ALL CLEAR",
                                color = Color.White,
                                fontWeight = FontWeight.Black,
                                fontSize = 16.sp,
                                letterSpacing = 1.sp
                            )
                            Text(
                                text = "Your in-app event, tipping, and network feeds are completely up to date.",
                                color = Color.White.copy(0.5f),
                                fontSize = 12.sp,
                                textAlign = androidx.compose.ui.text.style.TextAlign.Center,
                                modifier = Modifier.padding(top = 6.dp)
                            )
                        }
                    } else {
                        Column(modifier = Modifier.weight(1f)) {
                            // Quick control header
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(horizontal = 24.dp, vertical = 4.dp),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Text(
                                    text = "${notifications.size} LOGS CAPTURED",
                                    color = Color.White.copy(0.5f),
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold,
                                    letterSpacing = 0.5.sp
                                )
                                Text(
                                    text = "MARK ALL READ",
                                    color = RazorBlue,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold,
                                    letterSpacing = 0.5.sp,
                                    modifier = Modifier.clickable { viewModel.markAllNotificationsAsRead() }
                                )
                            }

                            LazyColumn(
                                modifier = Modifier
                                    .fillMaxSize()
                                    .padding(horizontal = 16.dp),
                                contentPadding = PaddingValues(vertical = 8.dp),
                                verticalArrangement = Arrangement.spacedBy(10.dp)
                            ) {
                                items(notifications) { notif ->
                                    val icon = when (notif.type) {
                                        "WALLET" -> Icons.Default.ShoppingCart
                                        "CREATOR" -> Icons.Default.Star
                                        "CHAT" -> Icons.Default.Mail
                                        else -> Icons.Default.Settings
                                    }
                                    val iconColor = when (notif.type) {
                                        "WALLET" -> RazorBlue
                                        "CREATOR" -> InstaPink
                                        "CHAT" -> RazorTeal
                                        else -> Color.White
                                    }

                                    Card(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .clickable { viewModel.markNotificationAsRead(notif.id) },
                                        shape = RoundedCornerShape(16.dp),
                                        colors = CardDefaults.cardColors(
                                            containerColor = if (notif.isRead) Color.White.copy(0.02f) else Color.White.copy(0.06f)
                                        ),
                                        border = BorderStroke(
                                            width = 1.dp,
                                            color = if (notif.isRead) Color.White.copy(0.04f) else RazorBlue.copy(0.2f)
                                        )
                                    ) {
                                        Row(
                                            modifier = Modifier
                                                .fillMaxWidth()
                                                .padding(14.dp),
                                            verticalAlignment = Alignment.Top
                                        ) {
                                            Box(
                                                modifier = Modifier
                                                    .size(38.dp)
                                                    .clip(CircleShape)
                                                    .background(iconColor.copy(0.12f)),
                                                contentAlignment = Alignment.Center
                                            ) {
                                                Icon(
                                                    imageVector = icon,
                                                    contentDescription = notif.type,
                                                    tint = iconColor,
                                                    modifier = Modifier.size(18.dp)
                                                )
                                            }

                                            Spacer(modifier = Modifier.width(12.dp))

                                            Column(modifier = Modifier.weight(1f)) {
                                                Row(
                                                    modifier = Modifier.fillMaxWidth(),
                                                    horizontalArrangement = Arrangement.SpaceBetween,
                                                    verticalAlignment = Alignment.CenterVertically
                                                ) {
                                                    Text(
                                                        text = notif.title,
                                                        color = Color.White,
                                                        fontWeight = FontWeight.Bold,
                                                        fontSize = 13.sp
                                                    )
                                                    if (!notif.isRead) {
                                                        Box(
                                                            modifier = Modifier
                                                                .size(6.dp)
                                                                .background(Color(0xFFFF5252), CircleShape)
                                                        )
                                                    }
                                                }
                                                Text(
                                                    text = notif.message,
                                                    color = Color.White.copy(0.7f),
                                                    fontSize = 11.sp,
                                                    modifier = Modifier.padding(top = 4.dp, bottom = 6.dp)
                                                )

                                                val minutesAgo = ((System.currentTimeMillis() - notif.timestamp) / 60000).coerceAtLeast(0)
                                                val timeText = when {
                                                    minutesAgo < 1 -> "Just now"
                                                    minutesAgo < 60 -> "${minutesAgo}m ago"
                                                    else -> "${minutesAgo / 60}h ago"
                                                }
                                                Text(
                                                    text = timeText,
                                                    color = Color.White.copy(0.4f),
                                                    fontSize = 9.sp,
                                                    fontWeight = FontWeight.Bold
                                                )
                                            }

                                            Spacer(modifier = Modifier.width(4.dp))

                                            IconButton(
                                                onClick = { viewModel.deleteNotification(notif.id) },
                                                modifier = Modifier.size(24.dp)
                                            ) {
                                                Icon(
                                                    imageVector = Icons.Default.Close,
                                                    contentDescription = "Delete",
                                                    tint = Color.White.copy(0.3f),
                                                    modifier = Modifier.size(14.dp)
                                                )
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                } else {
                    // TAB 1: SYSTEM SETTINGS
                    Column(
                        modifier = Modifier
                            .fillMaxSize()
                            .padding(horizontal = 20.dp)
                            .verticalScroll(rememberScrollState()),
                        verticalArrangement = Arrangement.spacedBy(16.dp)
                    ) {
                        Text(
                            text = "SYSTEM SIGNAL CONTROLS",
                            color = RazorBlue,
                            fontWeight = FontWeight.Black,
                            fontSize = 12.sp,
                            letterSpacing = 0.5.sp,
                            modifier = Modifier.padding(top = 8.dp)
                        )

                        // Real-time Watchdog Connection & Latency Card (Issue 11)
                        Card(
                            modifier = Modifier.fillMaxWidth(),
                            colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0F1A)),
                            shape = RoundedCornerShape(16.dp),
                            border = BorderStroke(1.dp, RazorTeal.copy(0.3f))
                        ) {
                            Column(modifier = Modifier.padding(16.dp)) {
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Row(verticalAlignment = Alignment.CenterVertically) {
                                        Box(
                                            modifier = Modifier
                                                .size(8.dp)
                                                .clip(CircleShape)
                                                .background(if (watchdogStatus.contains("Healthy")) Color(0xFF00FF88) else Color(0xFFFF9800))
                                        )
                                        Spacer(modifier = Modifier.width(8.dp))
                                        Text(
                                            text = "NETWORK & RESOURCE WATCHDOG",
                                            color = Color.White,
                                            fontWeight = FontWeight.Bold,
                                            fontSize = 10.sp,
                                            fontFamily = FontFamily.Monospace,
                                            letterSpacing = 1.sp
                                        )
                                    }
                                    Box(
                                        modifier = Modifier
                                            .background(RazorTeal.copy(0.15f), RoundedCornerShape(6.dp))
                                            .padding(horizontal = 6.dp, vertical = 2.dp)
                                    ) {
                                        Text(
                                            text = "LIVE",
                                            color = RazorTeal,
                                            fontSize = 8.sp,
                                            fontWeight = FontWeight.Black
                                        )
                                    }
                                }
                                Spacer(modifier = Modifier.height(10.dp))
                                Text(
                                    text = watchdogStatus,
                                    color = Color.White,
                                    fontWeight = FontWeight.Bold,
                                    fontSize = 14.sp
                                )
                                Spacer(modifier = Modifier.height(4.dp))
                                Text(
                                    text = "Watchdog runs automated high-frequency main thread thread-sleep sensing loops and memory leak traps to detect background overlay hijacking or CPU stress vectors instantly.",
                                    color = GrayText,
                                    fontSize = 10.sp,
                                    lineHeight = 14.sp
                                )
                            }
                        }

                        Card(
                            modifier = Modifier.fillMaxWidth(),
                            colors = CardDefaults.cardColors(containerColor = Color.White.copy(0.03f)),
                            shape = RoundedCornerShape(16.dp),
                            border = BorderStroke(1.dp, Color.White.copy(0.05f))
                        ) {
                            Column(modifier = Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(14.dp)) {
                                NotificationToggleRow(
                                    title = "Push Notifications Enabled",
                                    subtitle = "Allow system signals to broadcast in background",
                                    checked = pushEnabled,
                                    onCheckedChange = { viewModel.setPushNotificationsEnabled(it) }
                                )
                                HorizontalDivider(color = Color.White.copy(0.06f))
                                NotificationToggleRow(
                                    title = "System Audio Feedback",
                                    subtitle = "Play a high-fidelity digital chime for alerts",
                                    checked = soundEnabled,
                                    onCheckedChange = { viewModel.setSoundEnabled(it) }
                                )
                                HorizontalDivider(color = Color.White.copy(0.06f))
                                NotificationToggleRow(
                                    title = "Haptic Vibration Chords",
                                    subtitle = "Trigger synchronized physical haptic feedback",
                                    checked = vibrateEnabled,
                                    onCheckedChange = { viewModel.setVibrationEnabled(it) }
                                )
                            }
                        }

                        Text(
                            text = "CHANNEL SPECIFIC LOGS",
                            color = RazorBlue,
                            fontWeight = FontWeight.Black,
                            fontSize = 12.sp,
                            letterSpacing = 0.5.sp,
                            modifier = Modifier.padding(top = 8.dp)
                        )

                        Card(
                            modifier = Modifier.fillMaxWidth(),
                            colors = CardDefaults.cardColors(containerColor = Color.White.copy(0.03f)),
                            shape = RoundedCornerShape(16.dp),
                            border = BorderStroke(1.dp, Color.White.copy(0.05f))
                        ) {
                            Column(modifier = Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(14.dp)) {
                                NotificationToggleRow(
                                    title = "Wallet & Tipping Sync",
                                    subtitle = "Log virtual node wallet transactions & micro-tips",
                                    checked = walletAlerts,
                                    onCheckedChange = { viewModel.setWalletAlertsEnabled(it) }
                                )
                                HorizontalDivider(color = Color.White.copy(0.06f))
                                NotificationToggleRow(
                                    title = "Creator Tiers & Subscriptions",
                                    subtitle = "Log follows, publications, and subscription tier events",
                                    checked = creatorAlerts,
                                    onCheckedChange = { viewModel.setCreatorAlertsEnabled(it) }
                                )
                                HorizontalDivider(color = Color.White.copy(0.06f))
                                NotificationToggleRow(
                                    title = "Secure Encrypted Chats",
                                    subtitle = "Notify when receiving end-to-end encrypted direct signals",
                                    checked = chatAlerts,
                                    onCheckedChange = { viewModel.setChatAlertsEnabled(it) }
                                )
                            }
                        }



                        Spacer(modifier = Modifier.height(30.dp))
                    }
                }
            }
        }
    }
}

@Composable
fun NotificationToggleRow(
    title: String,
    subtitle: String,
    checked: Boolean,
    onCheckedChange: (Boolean) -> Unit
) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Column(modifier = Modifier.weight(1f)) {
            Text(text = title, color = Color.White, fontWeight = FontWeight.Bold, fontSize = 13.sp)
            Text(text = subtitle, color = Color.White.copy(0.5f), fontSize = 10.sp, modifier = Modifier.padding(top = 2.dp))
        }
        Switch(
            checked = checked,
            onCheckedChange = onCheckedChange,
            colors = SwitchDefaults.colors(
                checkedThumbColor = Color.Black,
                checkedTrackColor = RazorBlue,
                uncheckedThumbColor = Color.White.copy(0.6f),
                uncheckedTrackColor = Color.White.copy(0.12f)
            )
        )
    }
}

@Composable
fun AnalyticsKpiCard(title: String, value: String, change: String, isPositive: Boolean, modifier: Modifier = Modifier) {
    Card(
        modifier = modifier,
        shape = RoundedCornerShape(12.dp),
        colors = CardDefaults.cardColors(containerColor = CardBackground),
        border = BorderStroke(1.dp, MinimalBorder.copy(alpha = 0.5f))
    ) {
        Column(modifier = Modifier.padding(12.dp)) {
            Text(text = title, color = GrayText, fontSize = 10.sp, fontWeight = FontWeight.Bold)
            Spacer(modifier = Modifier.height(4.dp))
            Text(text = value, color = Color.White, fontWeight = FontWeight.Black, fontSize = 16.sp)
            Spacer(modifier = Modifier.height(6.dp))
            Row(verticalAlignment = Alignment.CenterVertically) {
                Icon(
                    imageVector = if (isPositive) Icons.AutoMirrored.Filled.TrendingUp else Icons.AutoMirrored.Filled.TrendingDown,
                    contentDescription = null,
                    tint = if (isPositive) RazorTeal else Color(0xFFFF3B30),
                    modifier = Modifier.size(12.dp)
                )
                Spacer(modifier = Modifier.width(4.dp))
                Text(
                    text = change,
                    color = if (isPositive) RazorTeal else Color(0xFFFF3B30),
                    fontSize = 10.sp,
                    fontWeight = FontWeight.Bold
                )
            }
        }
    }
}

@Composable
fun AnalyticsDemographicRow(label: String, percentage: Float, color: Color) {
    Column(modifier = Modifier.fillMaxWidth().padding(vertical = 6.dp)) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween
        ) {
            Text(text = label, color = LightText, fontSize = 11.sp, fontWeight = FontWeight.Medium)
            Text(text = "${percentage.toInt()}%", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
        }
        Spacer(modifier = Modifier.height(6.dp))
        LinearProgressIndicator(
            progress = { percentage / 100f },
            color = color,
            trackColor = MinimalSurfaceContainer,
            modifier = Modifier.fillMaxWidth().height(6.dp).clip(CircleShape)
        )
    }
}

data class PendingToggle(
    val title: String,
    val currentValue: Boolean,
    val onConfirm: (Boolean) -> Unit
)

@Composable
fun SettingsScreen(
    viewModel: SocialHubViewModel,
    onLogout: () -> Unit,
    onBack: () -> Unit
) {
    var pendingToggleSetting by remember { mutableStateOf<PendingToggle?>(null) }
    var pendingActionDialogTitle by remember { mutableStateOf<String?>(null) }
    var pendingActionDialogMessage by remember { mutableStateOf<String?>(null) }
    var pendingActionOnConfirm by remember { mutableStateOf<(() -> Unit)?>(null) }

    val isPrivateAccount by viewModel.isPrivateAccount.collectAsStateWithLifecycle()
    val isIncognitoSearch by viewModel.isIncognitoSearch.collectAsStateWithLifecycle()
    val extBankSyncGuard by viewModel.extBankSyncGuard.collectAsStateWithLifecycle()
    val extAntiPhishingFilter by viewModel.extAntiPhishingFilter.collectAsStateWithLifecycle()
    val extOverlayBlocker by viewModel.extOverlayBlocker.collectAsStateWithLifecycle()
    val extMalwareIsolation by viewModel.extMalwareIsolation.collectAsStateWithLifecycle()
    val pushNotificationsEnabled by viewModel.pushNotificationsEnabled.collectAsStateWithLifecycle()
    val creatorAlertsEnabled by viewModel.creatorAlertsEnabled.collectAsStateWithLifecycle()

    // 2-Step Verification & Cryptographic Security
    val isTwoStepEnabled by viewModel.isTwoStepEnabled.collectAsStateWithLifecycle()
    val twoStepMethod by viewModel.twoStepMethod.collectAsStateWithLifecycle()
    val extZeroTrustRotator by viewModel.extZeroTrustRotator.collectAsStateWithLifecycle()
    val extBiometricStartupLock by viewModel.extBiometricStartupLock.collectAsStateWithLifecycle()
    val extPayloadEncryption by viewModel.extPayloadEncryption.collectAsStateWithLifecycle()
    val extAntiHackerGuard by viewModel.extAntiHackerGuard.collectAsStateWithLifecycle()
    val watchdogStatus by viewModel.watchdogStatus.collectAsStateWithLifecycle()

    var searchQuery by remember { mutableStateOf("") }
    
    // Track which section is expanded
    var expandedSection by remember { mutableStateOf<String?>(null) } // "privacy", "notifications", "security", "permissions", "twoStep"

    // 2FA Setup walkthrough states
    val clipboardManager = androidx.compose.ui.platform.LocalClipboardManager.current
    val view = androidx.compose.ui.platform.LocalView.current
    var codeCopiedToastMessage by remember { mutableStateOf<String?>(null) }

    LaunchedEffect(codeCopiedToastMessage) {
        if (codeCopiedToastMessage != null) {
            kotlinx.coroutines.delay(2000)
            codeCopiedToastMessage = null
        }
    }

    var twoStepSetupStep by remember { mutableStateOf(0) } // 0: Select Method, 1: Verify PIN, 2: Show Backup Codes
    var selectedMethodOpt by remember { mutableStateOf("Authenticator App") }
    var enteredPin by remember { mutableStateOf("") }
    var pinError by remember { mutableStateOf(false) }
    var countdownSeconds by remember { mutableStateOf(59) }

    // Live Zero-Trust access token rotation countdown
    LaunchedEffect(key1 = extZeroTrustRotator) {
        if (extZeroTrustRotator) {
            while (true) {
                kotlinx.coroutines.delay(1000)
                if (countdownSeconds > 0) {
                    countdownSeconds--
                } else {
                    countdownSeconds = 59
                }
            }
        }
    }

    val context = androidx.compose.ui.platform.LocalContext.current

    var cameraStatus by remember {
        mutableStateOf(
            androidx.core.content.ContextCompat.checkSelfPermission(
                context, android.Manifest.permission.CAMERA
            ) == android.content.pm.PackageManager.PERMISSION_GRANTED
        )
    }
    var micStatus by remember {
        mutableStateOf(
            androidx.core.content.ContextCompat.checkSelfPermission(
                context, android.Manifest.permission.RECORD_AUDIO
            ) == android.content.pm.PackageManager.PERMISSION_GRANTED
        )
    }
    var mediaStatus by remember {
        mutableStateOf(
            if (android.os.Build.VERSION.SDK_INT >= 33) {
                androidx.core.content.ContextCompat.checkSelfPermission(
                    context, android.Manifest.permission.READ_MEDIA_IMAGES
                ) == android.content.pm.PackageManager.PERMISSION_GRANTED ||
                androidx.core.content.ContextCompat.checkSelfPermission(
                    context, android.Manifest.permission.READ_MEDIA_VIDEO
                ) == android.content.pm.PackageManager.PERMISSION_GRANTED ||
                androidx.core.content.ContextCompat.checkSelfPermission(
                    context, android.Manifest.permission.READ_MEDIA_AUDIO
                ) == android.content.pm.PackageManager.PERMISSION_GRANTED
            } else {
                androidx.core.content.ContextCompat.checkSelfPermission(
                    context, android.Manifest.permission.READ_EXTERNAL_STORAGE
                ) == android.content.pm.PackageManager.PERMISSION_GRANTED
            }
        )
    }
    var notificationsStatus by remember {
        mutableStateOf(
            if (android.os.Build.VERSION.SDK_INT >= 33) {
                androidx.core.content.ContextCompat.checkSelfPermission(
                    context, android.Manifest.permission.POST_NOTIFICATIONS
                ) == android.content.pm.PackageManager.PERMISSION_GRANTED
            } else true
        )
    }

    if (pendingToggleSetting != null) {
        val pending = pendingToggleSetting!!
        AlertDialog(
            onDismissRequest = { pendingToggleSetting = null },
            containerColor = Color(0xFF161135),
            titleContentColor = Color.White,
            textContentColor = Color.LightGray,
            title = {
                Text(
                    text = "CONFIRM SECURITY OPTION",
                    style = MaterialTheme.typography.titleMedium,
                    fontWeight = FontWeight.Bold,
                    color = RazorTeal
                )
            },
            text = {
                Text(
                    text = "Are you sure you want to ${if (pending.currentValue) "DISABLE" else "ENABLE"} the option: '${pending.title}'?",
                    style = MaterialTheme.typography.bodyMedium
                )
            },
            confirmButton = {
                Button(
                    onClick = {
                        pending.onConfirm(!pending.currentValue)
                        pendingToggleSetting = null
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = RazorTeal),
                    shape = RoundedCornerShape(8.dp)
                ) {
                    Text("Confirm", color = Color.Black, fontWeight = FontWeight.Bold)
                }
            },
            dismissButton = {
                TextButton(
                    onClick = { pendingToggleSetting = null }
                ) {
                    Text("Cancel", color = Color.Gray, fontWeight = FontWeight.Medium)
                }
            }
        )
    }

    if (pendingActionOnConfirm != null) {
        AlertDialog(
            onDismissRequest = {
                pendingActionOnConfirm = null
                pendingActionDialogTitle = null
                pendingActionDialogMessage = null
            },
            containerColor = Color(0xFF161135),
            titleContentColor = Color.White,
            textContentColor = Color.LightGray,
            title = {
                Text(
                    text = pendingActionDialogTitle ?: "CONFIRM ACTION",
                    style = MaterialTheme.typography.titleMedium,
                    fontWeight = FontWeight.Bold,
                    color = RazorTeal
                )
            },
            text = {
                Text(
                    text = pendingActionDialogMessage ?: "Are you sure you want to perform this action?",
                    style = MaterialTheme.typography.bodyMedium
                )
            },
            confirmButton = {
                Button(
                    onClick = {
                        pendingActionOnConfirm?.invoke()
                        pendingActionOnConfirm = null
                        pendingActionDialogTitle = null
                        pendingActionDialogMessage = null
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = RazorTeal),
                    shape = RoundedCornerShape(8.dp)
                ) {
                    Text("Confirm", color = Color.Black, fontWeight = FontWeight.Bold)
                }
            },
            dismissButton = {
                TextButton(
                    onClick = {
                        pendingActionOnConfirm = null
                        pendingActionDialogTitle = null
                        pendingActionDialogMessage = null
                    }
                ) {
                    Text("Cancel", color = Color.Gray, fontWeight = FontWeight.Medium)
                }
            }
        )
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(ObsidianDark)
            .statusBarsPadding()
    ) {
        // Top bar
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 12.dp, vertical = 14.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            IconButton(onClick = onBack) {
                Icon(
                    imageVector = Icons.AutoMirrored.Filled.ArrowBack,
                    contentDescription = "Back",
                    tint = Color.White,
                    modifier = Modifier.size(24.dp)
                )
            }
            Spacer(modifier = Modifier.width(12.dp))
            Text(
                text = "Settings and activity",
                color = Color.White,
                fontSize = 18.sp,
                fontWeight = FontWeight.Black,
                fontFamily = FontFamily.SansSerif
            )
        }

        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .padding(horizontal = 16.dp),
            verticalArrangement = Arrangement.spacedBy(10.dp)
        ) {
            // Instagram-Style Search Bar
            item {
                OutlinedTextField(
                    value = searchQuery,
                    onValueChange = { searchQuery = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, searchQuery) },
                    placeholder = { Text("Search settings", color = Color.Gray, fontSize = 14.sp) },
                    leadingIcon = { Icon(imageVector = Icons.Default.Search, contentDescription = null, tint = Color.Gray) },
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedContainerColor = Color(0xFF1E1E24),
                        unfocusedContainerColor = Color(0xFF1E1E24),
                        focusedBorderColor = Color.Transparent,
                        unfocusedBorderColor = Color.Transparent,
                        focusedTextColor = Color.White,
                        unfocusedTextColor = Color.White
                    ),
                    shape = RoundedCornerShape(12.dp),
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 4.dp),
                    singleLine = true
                )
            }

            // Section 1: How you use SocialHub
            item {
                Text(
                    text = "How you use SocialHub",
                    color = Color.Gray,
                    fontSize = 12.sp,
                    fontWeight = FontWeight.Bold,
                    modifier = Modifier.padding(bottom = 8.dp)
                )

                // Row: Account Privacy
                SettingsOptionRow(
                    icon = Icons.Default.Lock,
                    iconColor = RazorTeal,
                    title = "Account Privacy",
                    subtitle = if (isPrivateAccount) "Private" else "Public",
                    isExpanded = expandedSection == "privacy",
                    onClick = {
                        expandedSection = if (expandedSection == "privacy") null else "privacy"
                    }
                )

                AnimatedVisibility(
                    visible = expandedSection == "privacy",
                    enter = fadeIn() + expandVertically(),
                    exit = fadeOut() + shrinkVertically()
                ) {
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(top = 8.dp),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF16161D)),
                        shape = RoundedCornerShape(12.dp)
                    ) {
                        Column(modifier = Modifier.padding(16.dp)) {
                            SettingsSwitchRow(
                                title = "Private Creator Account",
                                subtitle = "Only approved followers can view your channel metrics and drops.",
                                checked = isPrivateAccount,
                                onCheckedChange = { newValue ->
                                    pendingToggleSetting = PendingToggle("Private Creator Account", isPrivateAccount) { viewModel.setPrivateAccount(it) }
                                }
                            )
                            Spacer(modifier = Modifier.height(14.dp))
                            SettingsSwitchRow(
                                title = "Incognito Profile Search",
                                subtitle = "Prevents your handle from appearing in the discovery listings.",
                                checked = isIncognitoSearch,
                                onCheckedChange = { newValue ->
                                    pendingToggleSetting = PendingToggle("Incognito Profile Search", isIncognitoSearch) { viewModel.setIncognitoSearch(it) }
                                }
                            )
                        }
                    }
                }
            }

            // Section 2: Notifications
            item {
                // Row: Notifications Preferences
                SettingsOptionRow(
