                                                fontWeight = FontWeight.Bold,
                                                modifier = Modifier.padding(top = 4.dp)
                                            )
                                        } else {
                                            Text(
                                                text = "Hint: Enter test simulation code '120796' to bypass.",
                                                color = RazorTeal.copy(0.6f),
                                                fontSize = 10.sp,
                                                fontWeight = FontWeight.Bold,
                                                modifier = Modifier.padding(top = 4.dp)
