                                        val backupKeys = listOf("HUB-8820-F9", "HUB-4411-E1", "HUB-2104-Y2", "HUB-9150-Z8")
                                        Column(
                                            modifier = Modifier.fillMaxWidth(),
                                            verticalArrangement = Arrangement.spacedBy(6.dp)
                                        ) {
                                            Row(horizontalArrangement = Arrangement.spacedBy(8.dp), modifier = Modifier.fillMaxWidth()) {
                                                backupKeys.take(2).forEach { key ->
                                                    Box(
                                                        modifier = Modifier
                                                            .weight(1f)
                                                            .clip(RoundedCornerShape(6.dp))
                                                            .background(Color.White.copy(0.04f))
                                                            .border(1.dp, Color.White.copy(0.08f), RoundedCornerShape(6.dp))
                                                            .padding(6.dp),
                                                        contentAlignment = Alignment.Center
                                                    ) {
                                                        Text(key, color = Color.White, fontFamily = FontFamily.Monospace, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                                    }
                                                }
                                            }
                                            Row(horizontalArrangement = Arrangement.spacedBy(8.dp), modifier = Modifier.fillMaxWidth()) {
                                                backupKeys.drop(2).forEach { key ->
                                                    Box(
                                                        modifier = Modifier
                                                            .weight(1f)
                                                            .clip(RoundedCornerShape(6.dp))
                                                            .background(Color.White.copy(0.04f))
                                                            .border(1.dp, Color.White.copy(0.08f), RoundedCornerShape(6.dp))
                                                            .padding(6.dp),
                                                        contentAlignment = Alignment.Center
                                                    ) {
                                                        Text(key, color = Color.White, fontFamily = FontFamily.Monospace, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                                    }
