                                Spacer(modifier = Modifier.height(14.dp))
                                
                                Text(
                                    text = "MULTIPLE EXTRA BACKEND SECURITY SYSTEMS",
                                    color = RazorBlue,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold,
