                                )
                                Spacer(modifier = Modifier.height(12.dp))
                                
                                // Zero-Trust Access Token Rotator (Live Countdown & Key Rotation)
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.SpaceBetween
                                ) {
                                    Column(modifier = Modifier.weight(0.7f)) {
                                        Text("Zero-Trust JWT Token Rotator", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                        Text("Rotates the OAuth / API bearer tokens every 60s dynamically.", color = GrayText, fontSize = 10.sp)
                                        if (extZeroTrustRotator) {
                                            Text(
                                                text = "Simulated Token: Bearer eyJhbGci... • Next rotation in ${countdownSeconds}s",
                                                color = RazorTeal,
                                                fontFamily = FontFamily.Monospace,
                                                fontSize = 9.sp,
                                                fontWeight = FontWeight.Bold,
                                                modifier = Modifier.padding(top = 2.dp)
                                            )
                                        }
                                    }
                                    Switch(
                                        checked = extZeroTrustRotator,
                                        onCheckedChange = { newValue ->
                                            pendingToggleSetting = PendingToggle("Zero-Trust JWT Token Rotator", extZeroTrustRotator) { viewModel.setExtZeroTrustRotator(it) }
                                        },
                                        colors = SwitchDefaults.colors(checkedThumbColor = RazorTeal, checkedTrackColor = RazorTeal.copy(0.4f))
                                    )
                                }
                                
                                Spacer(modifier = Modifier.height(14.dp))
                                
                                // Payload AES-256 Encryption
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.SpaceBetween
                                ) {
                                    Column(modifier = Modifier.weight(0.7f)) {
                                        Text("AES-256 Outgoing Payload Encryption", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                        Text("Secures captions and metadata on-device before backend broadcast.", color = GrayText, fontSize = 10.sp)
                                        Box(
                                            modifier = Modifier
                                                .padding(top = 4.dp)
                                                .clip(RoundedCornerShape(4.dp))
                                                .background(if (extPayloadEncryption) RazorTeal.copy(0.1f) else Color.White.copy(0.04f))
                                                .border(0.5.dp, if (extPayloadEncryption) RazorTeal else Color.Gray, RoundedCornerShape(4.dp))
