                                        }
                                    }
                                    Switch(
                                        checked = extPayloadEncryption,
                                        onCheckedChange = { newValue ->
                                            pendingToggleSetting = PendingToggle("AES-256 Outgoing Payload Encryption", extPayloadEncryption) { viewModel.setExtPayloadEncryption(it) }
                                        },
                                        colors = SwitchDefaults.colors(checkedThumbColor = RazorTeal, checkedTrackColor = RazorTeal.copy(0.4f))
                                    )
                                }
                                
                                Spacer(modifier = Modifier.height(14.dp))
                                
                                // Anti-Hacker Sandbox Guard
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.SpaceBetween
                                ) {
                                    Column(modifier = Modifier.weight(0.7f)) {
                                        Text("Anti-Hacker Memory Guard", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                        Text("Monitors runtime debugger injection, hook frameworks (e.g. Frida), and roots.", color = GrayText, fontSize = 10.sp)
                                        if (extAntiHackerGuard) {
                                            Row(
                                                verticalAlignment = Alignment.CenterVertically,
                                                modifier = Modifier.padding(top = 4.dp)
                                            ) {
                                                Box(modifier = Modifier.size(6.dp).clip(CircleShape).background(RazorTeal))
                                                Spacer(modifier = Modifier.width(4.dp))
                                                Text("Anti-Reverse Engineering Telemetry active", color = RazorTeal, fontSize = 9.sp, fontWeight = FontWeight.Bold)
