@Composable
fun SettingsOptionRow(
    icon: ImageVector,
    iconColor: Color,
    title: String,
    subtitle: String,
    isExpanded: Boolean,
    onClick: () -> Unit
) {
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .clickable(onClick = onClick)
            .padding(vertical = 8.dp),
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.SpaceBetween
    ) {
        Row(
            verticalAlignment = Alignment.CenterVertically,
            modifier = Modifier.weight(1f)
        ) {
            Box(
                modifier = Modifier
                    .size(36.dp)
                    .clip(CircleShape)
                    .background(iconColor.copy(alpha = 0.15f)),
                contentAlignment = Alignment.Center
            ) {
                Icon(
                    imageVector = icon,
                    contentDescription = null,
                    tint = iconColor,
                    modifier = Modifier.size(18.dp)
                )
            }
            Spacer(modifier = Modifier.width(14.dp))
            Column {
                Text(
                    text = title,
                    color = Color.White,
                    fontSize = 14.sp,
                    fontWeight = FontWeight.Bold
                )
                Text(
                    text = subtitle,
                    color = Color.Gray,
                    fontSize = 11.sp
                )
            }
        }
        
        Icon(
            imageVector = if (isExpanded) Icons.Default.KeyboardArrowUp else Icons.Default.ChevronRight,
            contentDescription = if (isExpanded) "Collapse" else "Expand",
            tint = Color.Gray,
            modifier = Modifier.size(20.dp)
        )
    }
}

@Composable
fun SettingsSwitchRow(
    title: String,
    subtitle: String,
    checked: Boolean,
    onCheckedChange: (Boolean) -> Unit
) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Column(modifier = Modifier.weight(1f)) {
            Text(
                text = title,
                color = Color.White,
                fontSize = 13.sp,
                fontWeight = FontWeight.Bold
            )
            Spacer(modifier = Modifier.height(2.dp))
            Text(
                text = subtitle,
                color = Color.Gray,
                fontSize = 10.sp,
                lineHeight = 14.sp
            )
        }
        Spacer(modifier = Modifier.width(8.dp))
        Switch(
            checked = checked,
            onCheckedChange = onCheckedChange,
            colors = SwitchDefaults.colors(
                checkedThumbColor = RazorTeal,
                checkedTrackColor = RazorTeal.copy(alpha = 0.4f),
                uncheckedThumbColor = Color.Gray,
                uncheckedTrackColor = Color.DarkGray
            )
        )
    }
}

@Composable
fun PermissionRow(label: String, granted: Boolean) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Text(text = label, color = Color.LightGray, fontSize = 11.sp)
        Text(
            text = if (granted) "CONNECTED & ACTIVE 🟢" else "LOCKED & ISOLATED 🛡️",
            color = if (granted) RazorTeal else Color.Red,
            fontSize = 10.sp,
            fontWeight = FontWeight.Bold,
            fontFamily = FontFamily.Monospace
        )
    }
}

@Composable
fun MandatoryEmailVerificationScreen(
    emailOtpSent: Boolean,
    isOtpVerifying: Boolean,
    otpErrorMessage: String?,
    userEmail: String,
    onSendOtp: (String) -> Unit,
    onVerifyOtp: (String) -> Boolean,
    onLogout: () -> Unit
) {
    var emailInput by remember { mutableStateOf(userEmail) }
    var otpInput by remember { mutableStateOf("") }

    val focusManager = androidx.compose.ui.platform.LocalFocusManager.current
    val keyboardController = androidx.compose.ui.platform.LocalSoftwareKeyboardController.current

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(Color(0xFF0F0B21))
            .clickable(
                indication = null,
                interactionSource = remember { androidx.compose.foundation.interaction.MutableInteractionSource() }
            ) {
                focusManager.clearFocus()
                keyboardController?.hide()
            }
            .imePadding(),
        contentAlignment = Alignment.Center
    ) {
        // Decorative grid lines
        androidx.compose.foundation.Canvas(modifier = Modifier.fillMaxSize()) {
            val gridSpacing = 40.dp.toPx()
            for (x in 0..size.width.toInt() step gridSpacing.toInt()) {
                drawLine(
                    color = Color(0xFF1B1437).copy(alpha = 0.3f),
                    start = androidx.compose.ui.geometry.Offset(x.toFloat(), 0f),
                    end = androidx.compose.ui.geometry.Offset(x.toFloat(), size.height),
                    strokeWidth = 1f
                )
            }
            for (y in 0..size.height.toInt() step gridSpacing.toInt()) {
                drawLine(
                    color = Color(0xFF1B1437).copy(alpha = 0.3f),
                    start = androidx.compose.ui.geometry.Offset(0f, y.toFloat()),
                    end = androidx.compose.ui.geometry.Offset(size.width, y.toFloat()),
                    strokeWidth = 1f
                )
            }
        }

        // Floating Back Button to return to previous state / Login Screen
        IconButton(
            onClick = {
                focusManager.clearFocus()
                keyboardController?.hide()
                onLogout()
            },
            modifier = Modifier
                .align(Alignment.TopStart)
                .padding(top = 40.dp, start = 16.dp) // adjusted for system bar
                .clip(CircleShape)
                .background(Color.White.copy(alpha = 0.08f))
        ) {
            Icon(
                imageVector = Icons.AutoMirrored.Filled.ArrowBack,
                contentDescription = "Back to Login",
                tint = Color.White
            )
        }

        // Scrollable content wrapper for Card
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(top = 80.dp)
                .verticalScroll(androidx.compose.foundation.rememberScrollState())
                .padding(16.dp),
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center
        ) {
            Card(
                modifier = Modifier
                    .fillMaxWidth(0.9f)
                    .padding(vertical = 16.dp),
                shape = RoundedCornerShape(24.dp),
                colors = CardDefaults.cardColors(containerColor = Color(0xFF161135)),
                border = BorderStroke(1.5.dp, RazorTeal.copy(alpha = 0.7f))
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(24.dp),
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.Center
                ) {
                    // Cyber security badge
                    Box(
                        modifier = Modifier
                            .size(64.dp)
                            .clip(CircleShape)
                            .background(RazorTeal.copy(alpha = 0.15f))
                            .border(1.5.dp, RazorTeal, CircleShape),
                        contentAlignment = Alignment.Center
                    ) {
                        Icon(
                            imageVector = Icons.Default.Security,
                            contentDescription = "Security Gateway",
                            tint = RazorTeal,
                            modifier = Modifier.size(32.dp)
                        )
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    Text(
                        text = "MANDATORY SECURITY GATEWAY",
                        color = Color.White,
                        style = MaterialTheme.typography.titleMedium,
                        fontWeight = FontWeight.Black,
                        letterSpacing = 1.sp
                    )

                    Text(
                        text = "Verify your email to establish an authenticated secure user session",
                        color = Color.LightGray,
                        fontSize = 11.sp,
                        textAlign = TextAlign.Center,
                        modifier = Modifier.padding(top = 4.dp)
                    )

                    Spacer(modifier = Modifier.height(24.dp))

                    if (!emailOtpSent) {
                        // Step 1: Input Email
                        OutlinedTextField(
                            value = emailInput,
                            onValueChange = { emailInput = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, emailInput) },
                            label = { Text("Secure Email Address", color = RazorTeal) },
                            textStyle = LocalTextStyle.current.copy(color = Color.White, fontSize = 14.sp),
                            placeholder = { Text("user@securedomain.com", color = Color.Gray) },
                            singleLine = true,
                            modifier = Modifier.fillMaxWidth(),
                            colors = OutlinedTextFieldDefaults.colors(
                                focusedBorderColor = RazorTeal,
                                unfocusedBorderColor = Color.White.copy(alpha = 0.15f),
                                focusedContainerColor = Color.Black.copy(alpha = 0.3f),
                                unfocusedContainerColor = Color.Black.copy(alpha = 0.15f)
                            ),
                            shape = RoundedCornerShape(12.dp)
                        )

                        Spacer(modifier = Modifier.height(16.dp))

                        if (otpErrorMessage != null) {
                            Text(
                                text = otpErrorMessage,
                                color = Color.Red,
                                fontSize = 11.sp,
                                fontWeight = FontWeight.Bold,
                                modifier = Modifier.padding(bottom = 8.dp)
                            )
                        }

                        Button(
                            onClick = {
                                focusManager.clearFocus()
                                keyboardController?.hide()
                                onSendOtp(emailInput)
                            },
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(48.dp),
                            colors = ButtonDefaults.buttonColors(containerColor = RazorTeal),
                            shape = RoundedCornerShape(12.dp),
                            enabled = !isOtpVerifying
                        ) {
                            if (isOtpVerifying) {
                                CircularProgressIndicator(modifier = Modifier.size(20.dp), color = Color.Black, strokeWidth = 2.dp)
                            } else {
                                Text("Request Authorization Code 📡", color = Color.Black, fontWeight = FontWeight.Bold)
                            }
                        }
                    } else {
                        // Step 2: Input OTP
                        Text(
                            text = "Authentication Code sent to\n$emailInput",
                            color = RazorTeal,
                            fontSize = 12.sp,
                            fontWeight = FontWeight.Bold,
                            textAlign = TextAlign.Center,
                            modifier = Modifier.padding(bottom = 16.dp)
                        )

                        OutlinedTextField(
                            value = otpInput,
                            onValueChange = { 
                                val deduped = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, otpInput)
                                if (deduped.length <= 6) otpInput = deduped 
                            },
                            label = { Text("6-Digit OTP Code", color = RazorTeal) },
                            textStyle = LocalTextStyle.current.copy(color = Color.White, fontSize = 18.sp, fontWeight = FontWeight.Bold, textAlign = TextAlign.Center),
                            placeholder = { Text("******", color = Color.Gray) },
                            singleLine = true,
                            modifier = Modifier.fillMaxWidth(),
                            colors = OutlinedTextFieldDefaults.colors(
                                focusedBorderColor = RazorTeal,
                                unfocusedBorderColor = Color.White.copy(alpha = 0.15f),
                                focusedContainerColor = Color.Black.copy(alpha = 0.3f),
                                unfocusedContainerColor = Color.Black.copy(alpha = 0.15f)
                            ),
                            shape = RoundedCornerShape(12.dp)
                        )

                        Spacer(modifier = Modifier.height(16.dp))

                        if (otpErrorMessage != null) {
                            Text(
                                text = otpErrorMessage,
                                color = Color.Red,
                                fontSize = 11.sp,
                                fontWeight = FontWeight.Bold,
                                modifier = Modifier.padding(bottom = 8.dp)
                            )
                        }

                        Button(
                            onClick = {
                                focusManager.clearFocus()
                                keyboardController?.hide()
                                onVerifyOtp(otpInput)
                            },
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(48.dp),
                            colors = ButtonDefaults.buttonColors(containerColor = RazorTeal),
                            shape = RoundedCornerShape(12.dp)
                        ) {
                            Text("Verify & Authenticate Session 🔑", color = Color.Black, fontWeight = FontWeight.Bold)
                        }

                        Spacer(modifier = Modifier.height(12.dp))

                        TextButton(
                            onClick = {
                                focusManager.clearFocus()
                                keyboardController?.hide()
                                onSendOtp(emailInput)
                            }
                        ) {
                            Text("Resend Code", color = Color.LightGray, fontSize = 12.sp, textDecoration = androidx.compose.ui.text.style.TextDecoration.Underline)
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun AppLockScreen(
    onUnlockWithPin: (String) -> Boolean,
    onUnlockWithBiometric: () -> Unit,
    onLogout: () -> Unit
) {
    var pinInput by remember { mutableStateOf("") }
    var pinError by remember { mutableStateOf(false) }
    var isScanning by remember { mutableStateOf(false) }
    val scope = rememberCoroutineScope()

    val focusManager = androidx.compose.ui.platform.LocalFocusManager.current
    val keyboardController = androidx.compose.ui.platform.LocalSoftwareKeyboardController.current

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(Color(0xFF090616))
            .clickable(
                indication = null,
                interactionSource = remember { androidx.compose.foundation.interaction.MutableInteractionSource() }
            ) {
                focusManager.clearFocus()
                keyboardController?.hide()
            }
            .imePadding(),
        contentAlignment = Alignment.Center
    ) {
        // Futuristic tech grid background
        androidx.compose.foundation.Canvas(modifier = Modifier.fillMaxSize()) {
            val spacing = 50.dp.toPx()
            for (x in 0..size.width.toInt() step spacing.toInt()) {
                drawLine(
                    color = Color(0xFF191336).copy(alpha = 0.4f),
                    start = androidx.compose.ui.geometry.Offset(x.toFloat(), 0f),
                    end = androidx.compose.ui.geometry.Offset(x.toFloat(), size.height)
                )
            }
            for (y in 0..size.height.toInt() step spacing.toInt()) {
                drawLine(
                    color = Color(0xFF191336).copy(alpha = 0.4f),
                    start = androidx.compose.ui.geometry.Offset(0f, y.toFloat()),
                    end = androidx.compose.ui.geometry.Offset(size.width, y.toFloat())
                )
            }
        }

        // Logout/Back button in top left
        IconButton(
            onClick = {
                focusManager.clearFocus()
                keyboardController?.hide()
                onLogout()
            },
            modifier = Modifier
                .align(Alignment.TopStart)
                .padding(top = 40.dp, start = 16.dp)
                .clip(CircleShape)
                .background(Color.White.copy(alpha = 0.05f))
        ) {
            Icon(
                imageVector = Icons.AutoMirrored.Filled.ArrowBack,
                contentDescription = "Logout",
                tint = Color.LightGray
            )
        }

        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(top = 80.dp)
                .verticalScroll(androidx.compose.foundation.rememberScrollState())
                .fillMaxWidth(0.85f)
                .padding(24.dp),
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center
        ) {
            // Glowing Lock Icon
            Box(
                modifier = Modifier
                    .size(80.dp)
                    .clip(CircleShape)
                    .background(RazorTeal.copy(alpha = 0.1f))
                    .border(2.dp, RazorTeal, CircleShape),
                contentAlignment = Alignment.Center
            ) {
                Icon(
                    imageVector = Icons.Default.Lock,
                    contentDescription = "Enclave Locked",
                    tint = RazorTeal,
                    modifier = Modifier.size(36.dp)
                )
            }

            Spacer(modifier = Modifier.height(24.dp))

            Text(
                text = "ENCLAVE DEVICE LOCK",
                color = Color.White,
                fontSize = 18.sp,
                fontWeight = FontWeight.Black,
                letterSpacing = 2.sp
            )

            Spacer(modifier = Modifier.height(6.dp))

            Text(
                text = "Biometric validation or security PIN required",
                color = Color.Gray,
                fontSize = 11.sp,
                textAlign = TextAlign.Center
            )

            Spacer(modifier = Modifier.height(32.dp))

            // 1. Biometric Scanner Simulation Button
            Button(
                onClick = {
                    focusManager.clearFocus()
                    keyboardController?.hide()
                    scope.launch {
                        isScanning = true
                        kotlinx.coroutines.delay(1200) // simulated scanning scan latency
                        isScanning = false
                        onUnlockWithBiometric()
                    }
                },
                modifier = Modifier
                    .fillMaxWidth()
                    .height(56.dp)
                    .border(1.5.dp, RazorTeal, RoundedCornerShape(14.dp)),
                colors = ButtonDefaults.buttonColors(containerColor = Color.Transparent),
                shape = RoundedCornerShape(14.dp),
                enabled = !isScanning
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.Center
                ) {
                    if (isScanning) {
                        CircularProgressIndicator(
                            modifier = Modifier.size(20.dp),
                            color = RazorTeal,
                            strokeWidth = 2.dp
                        )
                        Spacer(modifier = Modifier.width(12.dp))
                        Text("SCANNING BIOMETRICS...", color = RazorTeal, fontWeight = FontWeight.Bold, fontSize = 12.sp)
                    } else {
                        Icon(
                            imageVector = Icons.Default.Fingerprint,
                            contentDescription = "Fingerprint Scan",
                            tint = RazorTeal,
                            modifier = Modifier.size(24.dp)
                        )
                        Spacer(modifier = Modifier.width(10.dp))
                        Text("SCAN DEVICE FINGERPRINT", color = RazorTeal, fontWeight = FontWeight.Black, fontSize = 12.sp)
                    }
                }
            }

            Spacer(modifier = Modifier.height(16.dp))

            Text("— OR ENTER PIN —", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Bold)

            Spacer(modifier = Modifier.height(16.dp))

            // 2. PIN TextField Input
            OutlinedTextField(
                value = pinInput,
                onValueChange = {
                    val deduped = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, pinInput)
                    if (deduped.length <= 8) {
                        pinInput = deduped
                        pinError = false
                    }
                },
                visualTransformation = androidx.compose.ui.text.input.PasswordVisualTransformation(),
                keyboardOptions = KeyboardOptions(
                    keyboardType = androidx.compose.ui.text.input.KeyboardType.Number
                ),
                singleLine = true,
                placeholder = { Text("Enter Passcode PIN", color = Color.Gray.copy(0.5f), fontSize = 14.sp) },
                textStyle = LocalTextStyle.current.copy(
                    color = Color.White,
                    fontSize = 18.sp,
                    fontWeight = FontWeight.Bold,
                    textAlign = TextAlign.Center
                ),
                colors = OutlinedTextFieldDefaults.colors(
                    focusedBorderColor = if (pinError) Color.Red else RazorTeal,
                    unfocusedBorderColor = if (pinError) Color.Red else Color.White.copy(0.12f),
                    focusedContainerColor = Color.Black.copy(alpha = 0.3f),
                    unfocusedContainerColor = Color.Black.copy(alpha = 0.15f)
                ),
                shape = RoundedCornerShape(12.dp),
                modifier = Modifier.fillMaxWidth().testTag("app_lock_pin_field")
            )

            if (pinError) {
                Text(
                    text = "INCORRECT SECURITY ACCESS CODE",
                    color = Color.Red,
                    fontSize = 10.sp,
                    fontWeight = FontWeight.Bold,
                    modifier = Modifier.padding(top = 4.dp)
                )
            } else {
                Text(
                    text = "Hint: Use test simulation code '1234' or '120796'",
                    color = RazorTeal.copy(0.5f),
                    fontSize = 9.sp,
                    modifier = Modifier.padding(top = 4.dp)
                )
            }

            Spacer(modifier = Modifier.height(20.dp))

            // 3. Confirm PIN Submit Button
            Button(
                onClick = {
                    focusManager.clearFocus()
                    keyboardController?.hide()
                    val success = onUnlockWithPin(pinInput)
                    if (!success) {
                        pinError = true
                        pinInput = ""
                    }
                },
                modifier = Modifier
                    .fillMaxWidth()
                    .heightIn(min = 48.dp),
                colors = ButtonDefaults.buttonColors(containerColor = RazorTeal),
                shape = RoundedCornerShape(12.dp)
            ) {
                Text("VERIFY & ACCESS ENCLAVE", color = Color.Black, fontWeight = FontWeight.Bold)
            }
        }
    }
}

@Composable
fun CyberLoginAndSignUpScreen(
    isAuthenticating: Boolean,
    loginErrorMessage: String?,
    registerErrorMessage: String?,
    onLogin: (String, String) -> Unit,
    onRegister: (String, String, String, String) -> Unit,
    onTabChanged: () -> Unit = {},
    onGoogleLogin: (String) -> Unit,
    welcomeMessage: String = "SOCIAL HUB SECURE LOGIN",
    welcomeSubMessage: String = "Enter credentials to load your encrypted profile session"
) {
    var isLoginTab by remember { mutableStateOf(true) }
    var emailInput by remember { mutableStateOf("") }
    var phoneInput by remember { mutableStateOf("") }
    var passwordInput by remember { mutableStateOf("") }
    var confirmPasswordInput by remember { mutableStateOf("") }
    var isPasswordVisible by remember { mutableStateOf(false) }

    var isHumanVerified by remember { mutableStateOf(false) }
    var sliderValue by remember { mutableStateOf(0f) }
    var captchaErrorMessage by remember { mutableStateOf<String?>(null) }
    val gestureLogs = remember { androidx.compose.runtime.mutableStateListOf<Pair<Long, Float>>() }

    var showGoogleChooser by remember { mutableStateOf(false) }
    var googleChooserConnectingEmail by remember { mutableStateOf<String?>(null) }
    var showCustomEmailField by remember { mutableStateOf(false) }
    var customGoogleEmailInput by remember { mutableStateOf("") }
    var showGoogleErrorHelpDialog by remember { mutableStateOf(false) }

    LaunchedEffect(loginErrorMessage) {
        if (loginErrorMessage != null && loginErrorMessage.contains("Google Sign-In failed")) {
            showGoogleErrorHelpDialog = true
        }
    }

    LaunchedEffect(googleChooserConnectingEmail) {
        val email = googleChooserConnectingEmail
        if (email != null) {
            kotlinx.coroutines.delay(1200) // Aesthetic progress latency
            onGoogleLogin(email)
            showGoogleChooser = false
            googleChooserConnectingEmail = null
        }
    }

    val focusManager = androidx.compose.ui.platform.LocalFocusManager.current
    val keyboardController = androidx.compose.ui.platform.LocalSoftwareKeyboardController.current

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(Color(0xFF0F0B21))
            .clickable(
                indication = null,
                interactionSource = remember { androidx.compose.foundation.interaction.MutableInteractionSource() }
            ) {
                focusManager.clearFocus()
                keyboardController?.hide()
            }
            .imePadding(),
        contentAlignment = Alignment.Center
    ) {
        // Decorative grid lines
        androidx.compose.foundation.Canvas(modifier = Modifier.fillMaxSize()) {
            val gridSpacing = 40.dp.toPx()
            for (x in 0..size.width.toInt() step gridSpacing.toInt()) {
                drawLine(
                    color = Color(0xFF1B1437).copy(alpha = 0.3f),
                    start = androidx.compose.ui.geometry.Offset(x.toFloat(), 0f),
                    end = androidx.compose.ui.geometry.Offset(x.toFloat(), size.height),
                    strokeWidth = 1f
                )
            }
            for (y in 0..size.height.toInt() step gridSpacing.toInt()) {
                drawLine(
                    color = Color(0xFF1B1437).copy(alpha = 0.3f),
                    start = androidx.compose.ui.geometry.Offset(0f, y.toFloat()),
                    end = androidx.compose.ui.geometry.Offset(size.width, y.toFloat()),
                    strokeWidth = 1f
                )
            }
        }

        if (showGoogleErrorHelpDialog) {
            androidx.compose.material3.AlertDialog(
                onDismissRequest = { 
                    showGoogleErrorHelpDialog = false 
                },
                title = {
                    Text(
                        "Google Accounts Setup Info 🌐",
                        fontWeight = FontWeight.Bold,
                        color = Color.White,
                        fontSize = 18.sp
                    )
                },
                text = {
                    Column {
                        Text(
                            "The application attempted to connect to Google Accounts, but failed with exception:\n",
                            color = Color.LightGray,
                            fontSize = 13.sp
                        )
                        Text(
                            "${loginErrorMessage ?: "Unknown Error"}",
                            color = Color(0xFFFF5252),
                            fontWeight = FontWeight.Bold,
                            fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace,
                            fontSize = 12.sp,
                            modifier = Modifier.padding(vertical = 4.dp)
                        )
                        Spacer(modifier = Modifier.height(12.dp))
                        Text(
                            "💡 Why did this happen?\n" +
                            "1. This is common if the developer's SHA-1 and SHA-256 fingerprints are not registered in the Firebase Console yet.\n" +
                            "2. The google-services.json might be missing or pending configuration.\n\n" +
                            "✨ What can you do?\n" +
                            "• Use the secure 'Sandbox Gmail' input below to test the full Google Login and registration flow offline instantly!\n" +
                            "• To connect your live production Firebase, register the SHA fingerprints provided in the app information.",
                            color = Color.LightGray,
                            fontSize = 12.sp,
                            lineHeight = 17.sp
                        )
                    }
                },
                confirmButton = {
                    Button(
                        onClick = {
                            showGoogleErrorHelpDialog = false
                            showGoogleChooser = true // Re-opens chooser so they can use sandbox
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = RazorTeal)
                    ) {
                        Text("Use Sandbox Mode 🟢", color = Color.Black, fontWeight = FontWeight.Bold)
                    }
                },
                dismissButton = {
                    TextButton(
                        onClick = {
                            showGoogleErrorHelpDialog = false
                        }
                    ) {
                        Text("Dismiss", color = Color.Gray)
                    }
                },
                containerColor = Color(0xFF1E1E2F)
            )
        }

        // Scrollable content wrapper for Card
        Column(
            modifier = Modifier
                .fillMaxSize()
                .verticalScroll(androidx.compose.foundation.rememberScrollState())
                .padding(16.dp),
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center
        ) {
            Card(
                modifier = Modifier
                    .fillMaxWidth(0.9f)
                    .padding(vertical = 16.dp),
                shape = RoundedCornerShape(24.dp),
                colors = CardDefaults.cardColors(containerColor = Color(0xFF161135)),
                border = BorderStroke(1.5.dp, RazorTeal.copy(alpha = 0.7f))
            ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(24.dp),
                horizontalAlignment = Alignment.CenterHorizontally,
                verticalArrangement = Arrangement.Center
            ) {
                // Cyber security badge
                Box(
                    modifier = Modifier
                        .size(64.dp)
                        .clip(CircleShape)
                        .background(RazorTeal.copy(alpha = 0.15f))
                        .border(1.5.dp, RazorTeal, CircleShape),
                    contentAlignment = Alignment.Center
                ) {
                    Icon(
                        imageVector = Icons.Default.Lock,
                        contentDescription = "Session Security",
                        tint = RazorTeal,
                        modifier = Modifier.size(32.dp)
                    )
                }

                Spacer(modifier = Modifier.height(16.dp))

                Text(
                    text = welcomeMessage.uppercase(),
                    color = Color.White,
                    style = MaterialTheme.typography.titleMedium,
                    fontWeight = FontWeight.Black,
                    letterSpacing = 0.5.sp,
                    textAlign = TextAlign.Center,
                    modifier = Modifier.padding(horizontal = 16.dp)
                )

                Text(
                    text = welcomeSubMessage,
                    color = RazorTeal,
                    fontSize = 11.sp,
                    fontWeight = FontWeight.SemiBold,
                    textAlign = TextAlign.Center,
                    modifier = Modifier.padding(top = 6.dp, bottom = 16.dp, start = 16.dp, end = 16.dp)
                )

                // Tabs for Login vs Register
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clip(RoundedCornerShape(10.dp))
                        .background(Color.Black.copy(alpha = 0.3f))
                        .padding(4.dp),
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    Button(
                        onClick = {
                            if (!isLoginTab) {
                                isLoginTab = true
                                onTabChanged()
                            }
                        },
                        modifier = Modifier
                            .weight(1f)
                            .height(36.dp),
                        colors = ButtonDefaults.buttonColors(
                            containerColor = if (isLoginTab) RazorTeal else Color.Transparent
                        ),
                        shape = RoundedCornerShape(8.dp),
                        contentPadding = PaddingValues(0.dp)
                    ) {
                        Text(
                            text = "Log In",
                            color = if (isLoginTab) Color.Black else Color.LightGray,
                            fontWeight = FontWeight.Bold,
                            fontSize = 12.sp
                        )
                    }

                    Button(
                        onClick = {
                            if (isLoginTab) {
                                isLoginTab = false
                                onTabChanged()
                            }
                        },
                        modifier = Modifier
                            .weight(1f)
                            .height(36.dp),
                        colors = ButtonDefaults.buttonColors(
                            containerColor = if (!isLoginTab) RazorTeal else Color.Transparent
                        ),
                        shape = RoundedCornerShape(8.dp),
                        contentPadding = PaddingValues(0.dp)
                    ) {
                        Text(
                            text = "Sign Up",
                            color = if (!isLoginTab) Color.Black else Color.LightGray,
                            fontWeight = FontWeight.Bold,
                            fontSize = 12.sp
                        )
                    }
                }

                Spacer(modifier = Modifier.height(14.dp))

                // Input Email
                OutlinedTextField(
                    value = emailInput,
                    onValueChange = { emailInput = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, emailInput) },
                    label = { Text("Email Address", color = RazorTeal) },
                    textStyle = LocalTextStyle.current.copy(color = Color.White, fontSize = 14.sp),
                    placeholder = { Text("yourname@domain.com", color = Color.Gray) },
                    singleLine = true,
                    keyboardOptions = KeyboardOptions(
                        keyboardType = androidx.compose.ui.text.input.KeyboardType.Email,
                        autoCorrectEnabled = false
                    ),
                    modifier = Modifier.fillMaxWidth().testTag("auth_email_input"),
                    leadingIcon = {
                        Icon(imageVector = Icons.Default.Email, contentDescription = null, tint = RazorTeal.copy(0.7f))
                    },
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedBorderColor = RazorTeal,
                        unfocusedBorderColor = Color.White.copy(alpha = 0.15f),
                        focusedContainerColor = Color.Black.copy(alpha = 0.3f),
                        unfocusedContainerColor = Color.Black.copy(alpha = 0.15f)
                    ),
                    shape = RoundedCornerShape(12.dp)
                )

                if (!isLoginTab) {
                    Spacer(modifier = Modifier.height(12.dp))

                    // Input Phone Number
                    OutlinedTextField(
                        value = phoneInput,
                        onValueChange = { phoneInput = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, phoneInput) },
                        label = { Text("Phone Number", color = RazorTeal) },
                        textStyle = LocalTextStyle.current.copy(color = Color.White, fontSize = 14.sp),
                        placeholder = { Text("+1 (123) 456-7890", color = Color.Gray) },
                        singleLine = true,
                        keyboardOptions = KeyboardOptions(
                            keyboardType = androidx.compose.ui.text.input.KeyboardType.Phone,
                            autoCorrectEnabled = false
                        ),
                        modifier = Modifier.fillMaxWidth().testTag("auth_phone_input"),
                        leadingIcon = {
                            Icon(imageVector = Icons.Default.Phone, contentDescription = null, tint = RazorTeal.copy(0.7f))
                        },
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor = RazorTeal,
                            unfocusedBorderColor = Color.White.copy(alpha = 0.15f),
                            focusedContainerColor = Color.Black.copy(alpha = 0.3f),
                            unfocusedContainerColor = Color.Black.copy(alpha = 0.15f)
                        ),
                        shape = RoundedCornerShape(12.dp)
                    )
                }

                Spacer(modifier = Modifier.height(12.dp))

                // Input Password
                OutlinedTextField(
                    value = passwordInput,
                    onValueChange = { passwordInput = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, passwordInput) },
                    label = { Text("Password", color = RazorTeal) },
                    textStyle = LocalTextStyle.current.copy(color = Color.White, fontSize = 14.sp),
                    singleLine = true,
                    keyboardOptions = KeyboardOptions(
                        keyboardType = androidx.compose.ui.text.input.KeyboardType.Password,
                        autoCorrectEnabled = false
                    ),
                    modifier = Modifier.fillMaxWidth().testTag("auth_password_input"),
                    visualTransformation = if (isPasswordVisible) androidx.compose.ui.text.input.VisualTransformation.None else androidx.compose.ui.text.input.PasswordVisualTransformation(),
                    leadingIcon = {
                        Icon(imageVector = Icons.Default.VpnKey, contentDescription = null, tint = RazorTeal.copy(0.7f))
                    },
                    trailingIcon = {
                        val image = if (isPasswordVisible) Icons.Default.Visibility else Icons.Default.VisibilityOff
                        IconButton(onClick = { isPasswordVisible = !isPasswordVisible }) {
                            Icon(imageVector = image, contentDescription = null, tint = RazorTeal.copy(0.7f))
                        }
                    },
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedBorderColor = RazorTeal,
                        unfocusedBorderColor = Color.White.copy(alpha = 0.15f),
                        focusedContainerColor = Color.Black.copy(alpha = 0.3f),
                        unfocusedContainerColor = Color.Black.copy(alpha = 0.15f)
                    ),
                    shape = RoundedCornerShape(12.dp)
                )

                if (!isLoginTab) {
                    val passwordStrength = remember(passwordInput) {
                        when {
                            passwordInput.isEmpty() -> 0
                            passwordInput.length < 6 -> 1
                            passwordInput.any { it.isUpperCase() } && passwordInput.any { it.isDigit() } && passwordInput.any { !it.isLetterOrDigit() } -> 3
                            else -> 2
                        }
                    }

                    if (passwordInput.isNotEmpty()) {
                        Spacer(modifier = Modifier.height(6.dp))
                        val strengthText = when (passwordStrength) {
                            1 -> "Weak Password (Need at least 6 characters) ⚠️"
                            2 -> "Medium Password (Add uppercase, digit, and special char) ⚙️"
                            else -> "Strong Cryptographic Password! 🛡️"
                        }
                        val strengthColor = when (passwordStrength) {
                            1 -> Color(0xFFFF5252)
                            2 -> SafeGold
                            else -> RazorTeal
                        }
                        Row(
                            modifier = Modifier.fillMaxWidth().padding(horizontal = 4.dp),
                            horizontalArrangement = Arrangement.spacedBy(4.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Box(modifier = Modifier.weight(1f).height(4.dp).clip(RoundedCornerShape(2.dp)).background(if (passwordStrength >= 1) strengthColor else Color.White.copy(0.1f)))
                            Box(modifier = Modifier.weight(1f).height(4.dp).clip(RoundedCornerShape(2.dp)).background(if (passwordStrength >= 2) strengthColor else Color.White.copy(0.1f)))
                            Box(modifier = Modifier.weight(1f).height(4.dp).clip(RoundedCornerShape(2.dp)).background(if (passwordStrength >= 3) strengthColor else Color.White.copy(0.1f)))
                        }
                        Spacer(modifier = Modifier.height(4.dp))
                        Text(
                            text = strengthText,
                            color = strengthColor,
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Bold,
                            modifier = Modifier.align(Alignment.Start).padding(horizontal = 4.dp)
                        )
                    }

                    Spacer(modifier = Modifier.height(12.dp))

                    // Input Confirm Password
                    OutlinedTextField(
                        value = confirmPasswordInput,
                        onValueChange = { confirmPasswordInput = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, confirmPasswordInput) },
                        label = { Text("Confirm Password", color = RazorTeal) },
                        textStyle = LocalTextStyle.current.copy(color = Color.White, fontSize = 14.sp),
                        singleLine = true,
                        keyboardOptions = KeyboardOptions(
                            keyboardType = androidx.compose.ui.text.input.KeyboardType.Password,
                            autoCorrectEnabled = false
                        ),
                        modifier = Modifier.fillMaxWidth().testTag("auth_confirm_password_input"),
                        visualTransformation = if (isPasswordVisible) androidx.compose.ui.text.input.VisualTransformation.None else androidx.compose.ui.text.input.PasswordVisualTransformation(),
                        leadingIcon = {
                            Icon(imageVector = Icons.Default.VpnKey, contentDescription = null, tint = RazorTeal.copy(0.7f))
                        },
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor = RazorTeal,
                            unfocusedBorderColor = Color.White.copy(alpha = 0.15f),
                            focusedContainerColor = Color.Black.copy(alpha = 0.3f),
                            unfocusedContainerColor = Color.Black.copy(alpha = 0.15f)
                        ),
                        shape = RoundedCornerShape(12.dp)
                    )
                }



                // Sliding CAPTCHA Card for Zero-Bot Registration & Secure Login
                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 12.dp)
                        .border(1.dp, if (isHumanVerified) RazorTeal.copy(0.4f) else Color.White.copy(0.1f), RoundedCornerShape(16.dp)),
                    colors = CardDefaults.cardColors(containerColor = Color(0x1F110B29)),
                    shape = RoundedCornerShape(16.dp)
                ) {
                    Column(modifier = Modifier.padding(14.dp)) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(8.dp),
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Icon(
                                imageVector = if (isHumanVerified) Icons.Default.VerifiedUser else Icons.Default.Security,
                                contentDescription = "Bot Protection",
                                tint = if (isHumanVerified) RazorTeal else RazorBlue,
                                modifier = Modifier.size(16.dp)
                            )
                            Text(
                                text = "ANTI-BOT SECURITY SHIELD",
                                fontSize = 10.sp,
                                fontWeight = FontWeight.Bold,
                                color = if (isHumanVerified) RazorTeal else Color.White.copy(0.7f),
                                letterSpacing = 0.5.sp
                            )
                        }
                        
                        Spacer(modifier = Modifier.height(8.dp))
                        
                        Text(
                            text = if (isHumanVerified) "✅ HUMAN VERIFIED - ACCESS GRANTED" else "Slide the trigger to the right to verify you are a human user.",
                            fontSize = 11.sp,
                            color = if (isHumanVerified) RazorTeal else GrayText,
                            fontWeight = FontWeight.Medium
                        )

                        Spacer(modifier = Modifier.height(12.dp))

                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(38.dp)
                                .clip(RoundedCornerShape(19.dp))
                                .background(Color.Black.copy(0.4f))
                                .border(0.5.dp, if (isHumanVerified) RazorTeal.copy(0.3f) else Color.White.copy(0.06f), RoundedCornerShape(19.dp)),
                            contentAlignment = Alignment.CenterStart
                        ) {
                            if (!isHumanVerified) {
                                Text(
                                    text = ">>> SLIDE RIGHT >>>",
                                    color = Color.White.copy(0.18f),
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Black,
                                    letterSpacing = 1.sp,
                                    modifier = Modifier.align(Alignment.Center)
                                )
                            }

                            Slider(
                                value = sliderValue,
                                onValueChange = { newValue ->
                                    if (!isHumanVerified) {
                                        sliderValue = newValue
                                        val currentTime = System.currentTimeMillis()
                                        gestureLogs.add(Pair(currentTime, newValue))
                                        
                                        if (newValue >= 0.98f) {
                                            val logSnapshot = gestureLogs.toList()
                                            if (logSnapshot.size < 5) {
                                                captchaErrorMessage = "⚠️ INTEGRITY ALERT: Instant slide detected. Bot bypass blocked!"
                                                sliderValue = 0f
                                                gestureLogs.clear()
                                            } else {
                                                val startTime = logSnapshot.first().first
                                                val endTime = logSnapshot.last().first
                                                val duration = endTime - startTime
                                                
                                                if (duration < 280) {
                                                    captchaErrorMessage = "⚠️ TELEMETRY FAULT: Speed is sub-human (${duration}ms). Script bypass blocked!"
                                                    sliderValue = 0f
                                                    gestureLogs.clear()
                                                } else if (duration > 8000) {
                                                    captchaErrorMessage = "⚠️ SESSION EXPIRED: Interaction timed out. Please slide again."
                                                    sliderValue = 0f
                                                    gestureLogs.clear()
                                                } else {
                                                    // Calculate velocity standard deviation to check for robotic uniform motion
                                                    val velocities = mutableListOf<Float>()
                                                    for (i in 1 until logSnapshot.size) {
                                                        val dt = (logSnapshot[i].first - logSnapshot[i-1].first).coerceAtLeast(1)
                                                        val dx = logSnapshot[i].second - logSnapshot[i-1].second
                                                        velocities.add(dx / dt.toFloat())
                                                    }
                                                    
                                                    val mean = velocities.average()
                                                    val variance = velocities.map { (it - mean) * (it - mean) }.sum() / velocities.size
                                                    val stdDev = Math.sqrt(variance)
                                                    
                                                    // Standard deviation of a human slide will have dynamic variations (stdDev > 0.0)
                                                    // Uniform scripts slide with mathematically perfect intervals and speeds (stdDev near 0.0)
                                                    if (stdDev < 0.00003) {
                                                        captchaErrorMessage = "⚠️ ANOMALOUS GESTURE: Perfect linear movement. Bot protection activated!"
                                                        sliderValue = 0f
                                                        gestureLogs.clear()
                                                    } else {
                                                        isHumanVerified = true
                                                        sliderValue = 1f
                                                        captchaErrorMessage = null
                                                    }
                                                }
                                            }
                                        }
                                    }
                                },
                                onValueChangeFinished = {
                                    if (!isHumanVerified) {
                                        sliderValue = 0f
                                        gestureLogs.clear()
                                    }
                                },
                                colors = SliderDefaults.colors(
                                    thumbColor = if (isHumanVerified) RazorTeal else RazorBlue,
                                    activeTrackColor = if (isHumanVerified) RazorTeal.copy(alpha = 0.4f) else RazorBlue.copy(alpha = 0.3f),
                                    inactiveTrackColor = Color.Transparent
                                ),
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(horizontal = 4.dp)
                            )
                        }
                    }
                }

                Spacer(modifier = Modifier.height(12.dp))

                // Errors
                val err = if (isLoginTab) loginErrorMessage else registerErrorMessage
                val activeError = captchaErrorMessage ?: err
                if (activeError != null) {
                    Text(
                        text = activeError,
                        color = Color.Red,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold,
                        textAlign = TextAlign.Center,
                        modifier = Modifier.padding(bottom = 8.dp)
                    )
                }

                Button(
                    onClick = {
                        focusManager.clearFocus()
                        keyboardController?.hide()
                        if (!isHumanVerified) {
                            captchaErrorMessage = "⚠️ PLEASE SLIDE THE ANTI-BOT SHIELD TO VERIFY SESSION SECURITY FIRST!"
                        } else {
                            captchaErrorMessage = null
                            if (isLoginTab) {
                                onLogin(emailInput, passwordInput)
                            } else {
                                onRegister(emailInput, phoneInput, passwordInput, confirmPasswordInput)
                            }
                        }
                    },
                    modifier = Modifier
                        .fillMaxWidth()
                        .heightIn(min = 48.dp)
                        .testTag("auth_submit_btn"),
                    colors = ButtonDefaults.buttonColors(containerColor = RazorTeal),
                    shape = RoundedCornerShape(12.dp),
                    enabled = !isAuthenticating
                ) {
                    if (isAuthenticating) {
                        CircularProgressIndicator(modifier = Modifier.size(20.dp), color = Color.Black, strokeWidth = 2.dp)
                    } else {
                        Text(
                            text = if (isLoginTab) "Authenticate Session 📡" else "Create Cyber Account 🚀",
                            color = Color.Black,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }

                Spacer(modifier = Modifier.height(20.dp))
                
                // Divider
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    HorizontalDivider(modifier = Modifier.weight(1f), color = Color.White.copy(alpha = 0.12f))
                    Text(
                        text = " OR SECURE HANDSHAKE VIA ",
                        color = Color.Gray,
                        fontSize = 9.sp,
                        fontWeight = FontWeight.Bold,
                        letterSpacing = 1.sp,
                        modifier = Modifier.padding(horizontal = 8.dp)
                    )
                    HorizontalDivider(modifier = Modifier.weight(1f), color = Color.White.copy(alpha = 0.12f))
                }
                
                Spacer(modifier = Modifier.height(16.dp))
                
                // Single Clean Google Login Option
                Button(
                    onClick = {
                        focusManager.clearFocus()
                        keyboardController?.hide()
                        showGoogleChooser = true
                    },
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(44.dp)
                        .border(1.dp, Color.White.copy(alpha = 0.15f), RoundedCornerShape(12.dp)),
                    colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF1B163B)),
                    shape = RoundedCornerShape(12.dp),
                    contentPadding = PaddingValues(horizontal = 8.dp)
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.Center
                    ) {
                        Box(
                            modifier = Modifier
                                .size(16.dp)
                                .clip(CircleShape)
                                .background(Color.White),
                            contentAlignment = Alignment.Center
                        ) {
                            Text(
                                text = "G",
                                color = Color(0xFF4285F4),
                                fontWeight = FontWeight.Black,
                                fontSize = 11.sp
                            )
                        }
                        Spacer(modifier = Modifier.width(8.dp))
                        Text(
                            text = "Sign In with Google",
                            color = Color.White,
                            fontSize = 12.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }
            }
        }
    }

        // Custom, stunning Google Account Chooser bottom sheet overlay
        if (showGoogleChooser) {
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .background(Color.Black.copy(alpha = 0.6f))
                    .clickable { showGoogleChooser = false }
            )
            
            Box(
                modifier = Modifier.fillMaxSize(),
                contentAlignment = Alignment.BottomCenter
            ) {
                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clip(RoundedCornerShape(topStart = 28.dp, topEnd = 28.dp))
                        .clickable(enabled = false) {}, // Consume clicks
                    colors = CardDefaults.cardColors(containerColor = Color.White),
                    elevation = CardDefaults.cardElevation(defaultElevation = 16.dp)
                ) {
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(24.dp),
                        horizontalAlignment = Alignment.CenterHorizontally
                    ) {
                        // Drag handle
                        Box(
                            modifier = Modifier
                                .width(36.dp)
                                .height(4.dp)
                                .clip(RoundedCornerShape(2.dp))
                                .background(Color.LightGray)
                        )
                        
                        Spacer(modifier = Modifier.height(16.dp))
                        
                        // Google Header
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.Center
                        ) {
                            Box(
                                modifier = Modifier
                                    .size(24.dp)
                                    .clip(CircleShape)
                                    .background(Color.White)
                                    .border(1.dp, Color.LightGray, CircleShape),
                                contentAlignment = Alignment.Center
                            ) {
                                Text(
                                    text = "G",
                                    color = Color(0xFF4285F4),
                                    fontWeight = FontWeight.Black,
                                    fontSize = 14.sp
                                )
                            }
                            Spacer(modifier = Modifier.width(8.dp))
                            Text(
                                text = "Sign in with Google",
                                color = Color(0xFF1F1F1F),
                                fontWeight = FontWeight.Bold,
                                fontSize = 18.sp
                            )
                        }
                        
                        Spacer(modifier = Modifier.height(4.dp))
                        
                        Text(
                            text = "to continue to Social Hub",
                            color = Color(0xFF5F6368),
                            fontSize = 14.sp
                        )
                        
                        Spacer(modifier = Modifier.height(24.dp))
                        
                        if (googleChooserConnectingEmail != null) {
                            Column(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(vertical = 32.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                CircularProgressIndicator(
                                    modifier = Modifier.size(40.dp),
                                    color = Color(0xFF4285F4),
                                    strokeWidth = 3.dp
                                )
                                Spacer(modifier = Modifier.height(16.dp))
                                Text(
                                    text = if (googleChooserConnectingEmail!!.isEmpty()) "Opening Google Accounts..." else "Connecting to ${googleChooserConnectingEmail}...",
                                    color = Color(0xFF1F1F1F),
                                    fontWeight = FontWeight.SemiBold,
                                    fontSize = 14.sp
                                )
                            }
                        } else {
                            Column(modifier = Modifier.fillMaxWidth().padding(vertical = 12.dp)) {
                                // Real Google Sign-In Trigger button
                                Button(
                                    onClick = {
                                        googleChooserConnectingEmail = "" // Triggers empty onGoogleLogin() to invoke actual Google Accounts SDK
                                    },
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .height(48.dp),
                                    colors = ButtonDefaults.buttonColors(containerColor = Color(0xFFF2F2F2)),
                                    shape = RoundedCornerShape(100.dp),
                                    border = BorderStroke(1.dp, Color(0xFFE0E0E0))
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.AccountCircle,
                                        contentDescription = null,
                                        tint = Color(0xFF4285F4),
                                        modifier = Modifier.size(20.dp)
                                    )
                                    Spacer(modifier = Modifier.width(8.dp))
                                    Text(
                                        text = "Use System Google Accounts",
                                        color = Color(0xFF1F1F1F),
                                        fontWeight = FontWeight.Bold,
                                        fontSize = 14.sp
                                    )
                                }
                                
                                Spacer(modifier = Modifier.height(16.dp))
                                
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    HorizontalDivider(modifier = Modifier.weight(1f), color = Color(0xFFE0E0E0))
                                    Text(
                                        text = " OR USE SANDBOX GMAIL ",
                                        color = Color.Gray,
                                        fontSize = 9.sp,
                                        fontWeight = FontWeight.Bold,
                                        modifier = Modifier.padding(horizontal = 8.dp)
                                    )
                                    HorizontalDivider(modifier = Modifier.weight(1f), color = Color(0xFFE0E0E0))
                                }
                                
                                Spacer(modifier = Modifier.height(16.dp))
                                
                                OutlinedTextField(
                                    value = customGoogleEmailInput,
                                    onValueChange = { customGoogleEmailInput = com.example.data.FormSecuritySanitizer.preventDoubleTyping(it, customGoogleEmailInput) },
                                    label = { Text("Email or phone", color = Color(0xFF4285F4)) },
                                    textStyle = LocalTextStyle.current.copy(color = Color.Black, fontSize = 14.sp),
                                    placeholder = { Text("example@gmail.com", color = Color.Gray) },
                                    singleLine = true,
                                    modifier = Modifier.fillMaxWidth(),
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedBorderColor = Color(0xFF4285F4),
                                        unfocusedBorderColor = Color.LightGray,
                                        focusedContainerColor = Color.White,
                                        unfocusedContainerColor = Color.White,
                                        focusedTextColor = Color.Black,
                                        unfocusedTextColor = Color.Black
                                    ),
                                    shape = RoundedCornerShape(8.dp)
                                )
                                
                                Spacer(modifier = Modifier.height(16.dp))
                                
                                Button(
                                    onClick = {
                                        if (customGoogleEmailInput.isNotBlank() && customGoogleEmailInput.contains("@")) {
                                            googleChooserConnectingEmail = customGoogleEmailInput.trim()
                                        }
                                    },
                                    modifier = Modifier.fillMaxWidth(),
                                    colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF4285F4)),
                                    shape = RoundedCornerShape(100.dp)
                                ) {
                                    Text("Next", color = Color.White, fontWeight = FontWeight.Bold, fontSize = 14.sp)
                                }
                            }
                        }
                        
                        Spacer(modifier = Modifier.height(16.dp))
                        
                        Text(
                            text = "To continue, Google will share your name, email address, language preference, and profile picture with Social Hub. Before using this app, you can review its privacy policy and terms of service.",
                            color = Color(0xFF757575),
                            fontSize = 11.sp,
                            lineHeight = 15.sp,
                            textAlign = TextAlign.Start,
                            modifier = Modifier.padding(bottom = 8.dp)
                        )
                    }
                }
            }
        }
    }
}
